window.HADITH_CACHE["ibnu-majah_7"] = {"3501":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا أَبُو بَكْرٍ الْعَنْسِيُّ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ وَمُحَمَّدِ بْنِ يَزِيدَ الْمِصْرِيَّيْنِ قَالَا حَدَّثَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَقَالَتْ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ لَا يَزَالُ يُصِيبُكَ كُلَّ عَامٍ وَجَعٌ مِنْ الشَّاةِ الْمَسْمُومَةِ الَّتِي أَكَلْتَ قَالَ مَا أَصَابَنِي شَيْءٌ مِنْهَا إِلَّا وَهُوَ مَكْتُوبٌ عَلَيَّ وَآدَمُ فِي طِينَتِهِ","id":"Telah menceritakan kepada kami [Yahya bin Utsman bin Sa'id bin Latsir bin Dinar Al Himshi] telah menceritakan kepada kami [Baqiyah] telah menceritakan kepada kami [Abu Bakar Al 'Ansiy] dari [Yazid bin Abu Habib] dan [Muhammad bin Yazid Al Mishriyyaini] keduanya berkata; telah menceritakan kepada kami [Nafi'] dari [Ibnu Umar] dia berkata; Ummu Salamah berkata, \"Wahai Rasulullah, setiap tahun anda masih saja mengalami sakit akibat racun yang ada pada daging kambing yang anda makan.\" Beliau menjawab: \"Tidaklah rasa sakit akibat dari kambing yang di beri racun itu menimpaku kecuali dia telah ditentukan bagiku, begitu juga dalam penciptaannya.\""},"3502":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا وَهْبٌ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ يَعْقُوبَ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ مَالِكٍ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ أَحَدَكُمْ إِذَا نَزَلَ مَنْزِلًا قَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ شَرِّ مَا خَلَقَ لَمْ يَضُرَّهُ فِي ذَلِكَ الْمَنْزِلِ شَيْءٌ حَتَّى يَرْتَحِلَ مِنْهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wahb] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Ajlan] dari [Ya'qub bin Abdullah bin Al Asyaj] dari [Sa'id bin Al Musayyab] dari [Sa'd bin Malik] dari [Khaulah binti Hakim], bahwa Nabi shallallahu 'alaihi wasallam bersabda; \"Sekiranya salah seorang dari kalian singgah di suatu tempat tinggal lalu mengucapkan 'A'UUDZU BIKALIMATIT TAAMMAAT MIN SYARRI MAA KHALAQ (Aku berlindung dengan kalimat Allah yang sempurna dari kejahatan makhluk-nya) ', niscaya dia tidak akan di celakai oleh sesuatu di tempat persinggahannya tersebut sampai ia meninggalkannya.\""},"3503":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنِي عُيَيْنَةُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنِي أَبِي عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَلَمَّا اسْتَعْمَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الطَّائِفِ جَعَلَ يَعْرِضُ لِي شَيْءٌ فِي صَلَاتِي حَتَّى مَا أَدْرِي مَا أُصَلِّي فَلَمَّا رَأَيْتُ ذَلِكَ رَحَلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ابْنُ أَبِي الْعَاصِ قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ مَا جَاءَ بِكَ قُلْتُ يَا رَسُولَ اللَّهِ عَرَضَ لِي شَيْءٌ فِي صَلَوَاتِي حَتَّى مَا أَدْرِي مَا أُصَلِّي قَالَ ذَاكَ الشَّيْطَانُ ادْنُهْ فَدَنَوْتُ مِنْهُ فَجَلَسْتُ عَلَى صُدُورِ قَدَمَيَّ قَالَ فَضَرَبَ صَدْرِي بِيَدِهِ وَتَفَلَ فِي فَمِي وَقَالَ اخْرُجْ عَدُوَّ اللَّهِ فَفَعَلَ ذَلِكَ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ الْحَقْ بِعَمَلِكَقَالَ فَقَالَ عُثْمَانُ فَلَعَمْرِي مَا أَحْسِبُهُ خَالَطَنِي بَعْدُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] telah menceritakan kepadaku ['Uyainah bin Abdurrahman] telah menceritakan kepadaku [Ayahku] dari [Utsman bin Abu Al 'Ash] dia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam menugaskan aku di Tha`if, tiba-tiba ada sesuatu yang selalu menggangguku di dalam shalat sehingga aku tidak menyadari shalat yang aku kerjakan. Ketika aku sadari, maka aku lekas pergi kembali menemui Rasulullah shallallahu 'alaihi wasallam, beliau lalu bertanya: \"Ibnu Abu Al 'Ash?\" Aku menjawab, Ya, wahai Rasulullah.\" Beliau bertanya lagi: \"Kabar apa yang kamu bawa?\" Aku menjawab, \"Ada sesuatu yang mengganguku di dalam shalat, sehingga aku tidak menyadari shalat yang aku kerjakan.\" Beliau bersabda: \"Itu adalah setan, mendekatlah kamu.\" Maka aku pun mendekat kepada beliau, dan aku duduk di atas kedua telapak kakiku. Dia melanjutkan, \"Kemudian beliau menyentuh dadaku dengan tangannya, lalu meludah di mulutku dan bersabda: \"Keluarlah wahai musuh Allah.\" Beliau melakukan hal itu hingga tiga kali, kemudian bersabda: \"Kembalilah kepada tugasmu semula.\" (Perawi) berkata, \"Utsman berkata, \"Demi Dzat yang menghidupkan aku, aku tidak pernah lagi merasakan ada yang menggangguku.\""},"3504":{"ar":"حَدَّثَنَا هَارُونُ بْنُ حَيَّانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَنْبَأَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو جَنَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ أَبِي لَيْلَى قَالَكُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ أَعْرَابِيٌّ فَقَالَ إِنَّ لِي أَخًا وَجِعًا قَالَ مَا وَجَعُ أَخِيكَ قَالَ بِهِ لَمَمٌ قَالَ اذْهَبْ فَأْتِنِي بِهِ قَالَ فَذَهَبَ فَجَاءَ بِهِ فَأَجْلَسَهُ بَيْنَ يَدَيْهِ فَسَمِعْتُهُ عَوَّذَهُ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ الْبَقَرَةِ وَآيَتَيْنِ مِنْ وَسَطِهَا{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ خَاتِمَتِهَا وَآيَةٍ مِنْ آلِ عِمْرَانَ أَحْسِبُهُ قَالَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ }الْآيَةَ وَآيَةٍ مِنْ الْمُؤْمِنِينَ{ وَمَنْ يَدْعُ مَعَ اللَّهِ إِلَهًا آخَرَ لَا بُرْهَانَ لَهُ بِهِ }وَآيَةٍ مِنْ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا مَا اتَّخَذَ صَاحِبَةً وَلَا وَلَدًا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الْأَعْرَابِيُّ قَدْ بَرَأَ لَيْسَ بِهِ بَأْسٌ","id":"Telah menceritakan kepada kami [Harun bin Hayyan] telah menceritakan kepada kami [Ibrahim bin Musa] telah memberitakan kepada kami ['Abdah bin Sulaiman] telah menceritakan kepada kami [Abu Janab] dari [Abdurrahman bin Abu Laila] dari ayahnya [Abu Laila] dia berkata, \"Ketika aku sedang duduk di samping Nabi shallallahu 'alaihi wasallam, tiba-tiba datang seorang Arab Badui seraya berkata, 'Sesungguhnya aku mempunyai saudara yang menderita sakit.\" Beliau bertanya: \"Apa sakit yang meninmpa saudaramu?\" Dia menjawab, \"Dia terserang ayan.\" Beliau bersabda: \"Pergi dan bawalah dia kesini.\" Maka dia pergi dan kembali (kepada beliau) bersama saudaranya dan mendudukkannya di depan beliau, maka aku mendengar beliau memberikan perlindungan kepadanya dengan Al Fatihah, empat ayat dari permulaan surat Al Baqarah, dua ayat dari tengahnya dan (ayat) WA ILAAHUKUM ILAAHUWWAAHID (dan tuhan kalian adalah tuhan yang satu), ayat kursi, tiga ayat dari penghujung surat Al Baqarah, dan satu ayat dari surat Ali 'Imran. Aku yakin beliau mengucapkan: \"SYAHIDALLAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah bersaksi bahwa tidak ada ilah yang berhak disembah kecuali Dia) '. Beliau juga membaca satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAHULLADZI KHALAQ (sesungguhnya Rabb kalian adalah yang menciptakan) ', satu ayat dari surat Al MuKminun: WA MAN YADA'U MA'ALLAHI ILAAHNA AAKHAR LAA BURHAANA LAHU BIHI '(Dan barang siapa yang menyeru bersama dengan Allah yaitu ilah yang lain, maka tidak ada petunjuk baginya), satu ayat dari surat Al Jin: WA ANNAHU TA'ALA JADDU RABBINAA MATTAKHADZA SHAAHIBATAN WA LAA WALADA (Dan bahwasannya Maha Tinggi kebesaran Rabb kami, Dia tidak beristeri dan tidak (pula) beranak) '. Sepuluh ayat dari surat Ash Shaffaat, tiga ayat dari akhir surat Al Hasyr, dan QULHUWALLAHU AHAD, dan dua mu'awidzatain. Kemudian orang Arab Badui itu bangun dan sembuh seakan-akan tidak menderita sakit.\""},"3505":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَمِيصَةٍ لَهَا أَعْلَامٌ فَقَالَ شَغَلَنِي أَعْلَامُ هَذِهِ اذْهَبُوا بِهَا إِلَى أَبِي جَهْمٍ وَأْتُونِي بِأَنْبِجَانِيَّتِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat dengan mengenakan kain wool yang bergaris, maka beliau bersabda: \"Aku merasa terganggu dengan garis-garis ini, bawalah ia kepada Abu Jahm dan bawakan kepadaku baju wool yang tidak bergaris.\""},"3506":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ أَخْبَرَنِي سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ قَالَدَخَلْتُ عَلَى عَائِشَةَ فَأَخْرَجَتْ لِي إِزَارًا غَلِيظًا مِنْ الَّتِي تُصْنَعُ بِالْيَمَنِ وَكِسَاءً مِنْ هَذِهِ الْأَكْسِيَةِ الَّتِي تُدْعَى الْمُلَبَّدَةَ وَأَقْسَمَتْ لِي لَقُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Abu Usamah] Telah mengabarkan kepadaku [Sulaiman bin Al Mughirah] dari [Humaid bin Hilal] dari [Abu Burdah] dia berkata, \"Saya menemui [Aisyah], lantas ia mengeluarkan kain tebal yang terbuat dari daerah Yaman dan satu potong baju dari baju-baju ini yang di sebut dengan Al Mulabbadah (baju yang kasar), lantas ia bersumpah kepadaku, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam wafat dengan menggunakan keduanya.\""},"3507":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْأَحْوَصِ بْنِ حَكِيمٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي شَمْلَةٍ قَدْ عَقَدَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Ahmad bin Tsabit Al Jahdari] Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Al Ahwash bin Hakim] dari [Khalid bin Ma'dan] dari ['Ubadah bin Ash Shamit], bahwa Rasulullah shallallahu 'alaihi wasallam melakukan shalat dengan mantel yang beliau kenakan.\""},"3508":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ رِدَاءٌ نَجْرَانِيٌّ غَلِيظُ الْحَاشِيَةِ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la] Telah menceritakan kepada kami [Ibnu Wahb] Telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] dia berkata, \"Aku bersama Nabi shallallahu 'alaihi wasallam sedangkan beliau mengenakan kain Najrani yang pinggirnya tebal.\""},"3509":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدٍ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الْأَسْوَدِ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسُبُّ أَحَدًا وَلَا يُطْوَى لَهُ ثَوْبٌ","id":"Telah menceritakan kepada kami [Abdul Quddus bin Muhammad] Telah menceritakan kepada kami [Bisyr bin 'Umar] Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Abu Al Aswad] dari ['Ashim bin Umar bin Qatadah] dari [Ali bin Al Husain] dari [Aisyah] dia berkata, \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam mencaci maki seseorang dan juga tidak melipat bajunya.\""},"3510":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّأَنَّ امْرَأَةً جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبُرْدَةٍ قَالَ وَمَا الْبُرْدَةُ قَالَ الشَّمْلَةُ قَالَتْ يَا رَسُولَ اللَّهِ نَسَجْتُ هَذِهِ بِيَدِي لِأَكْسُوَكَهَا فَأَخَذَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجًا إِلَيْهَا فَخَرَجَ عَلَيْنَا فِيهَا وَإِنَّهَا لَإِزَارُهُ فَجَاءَ فُلَانُ بْنُ فُلَانٍ رَجُلٌ سَمَّاهُ يَوْمَئِذٍ فَقَالَ يَا رَسُولَ اللَّهِ مَا أَحْسَنَ هَذِهِ الْبُرْدَةَ اكْسُنِيهَا قَالَ نَعَمْ فَلَمَّا دَخَلَ طَوَاهَا وَأَرْسَلَ بِهَا إِلَيْهِ فَقَالَ لَهُ الْقَوْمُ وَاللَّهِ مَا أَحْسَنْتَ كُسِيَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجًا إِلَيْهَا ثُمَّ سَأَلْتَهُ إِيَّاهَا وَقَدْ عَلِمْتَ أَنَّهُ لَا يَرُدُّ سَائِلًا فَقَالَ إِنِّي وَاللَّهِ مَا سَأَلْتُهُ إِيَّاهَا لِأَلْبَسَهَا وَلَكِنْ سَأَلْتُهُ إِيَّاهَا لِتَكُونَ كَفَنِي فَقَالَ سَهْلٌ فَكَانَتْ كَفَنَهُ يَوْمَ مَاتَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] Telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Ayahnya] dari [Sahl bin Sa'd As Sa'idi], bahwa seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam dengan membawa kain burdah -perawai berkata, 'Apakah kain burdah itu? Ia Dijawab, 'Yaitu kain mantel.'- Wanita itu berkata, \"Wahai Rasulullah, sungguh aku telah merajut sendiri jubah ini supaya anda memakainya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mengambilnya karena beliau butuh jubah tersebut, kemudian beliau memperlihatkan jubah tersebut kepada kami yang bentuknya seperti kain. Lalu datanglah fulan bin fulan -seorang laki-laki yang di kenal masa itu- seraya berkata, \"Wahai Rasulullah, sungguh sangat indah jubah ini, pakaikanlah untukku! \" Beliau menjawab: \"Baiklah.\" Beliau kemudian masuk dan melipat kain tersebut, lalu mengirimkannya kepada laki-laki tersebut, orang-orang lalu berkata kepadanya, \"Demi Allah, sungguh beruntung kamu, (padahal) Nabi shallallahu 'alaihi wasallam memakainya karena butuh terhadap jubah itu, kemudian kamu memintanya. Kamu sebenarnya sangat tahu bahwa beliau tidak pernah bisa menolak orang yang meminta.\" Laki-laki itu berkata, \"Demi Allah, sesungguhnya aku tidaklah meminta jubah itu untuk aku pakai, tetapi aku minta itu untuk aku pakai sebagai kain kafanku.\" Sahl berkata, \"Maka jubah itu pun menjadi kain kafan lelaki tersebut ketika ia meninggal dunia.\""},"3511":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ يُوسُفَ بْنِ أَبِي كَثِيرٍ عَنْ نُوحِ بْنِ ذَكْوَانَ عَنْ الْحَسَنِ عَنْ أَنَسٍ قَالَلَبِسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّوفَ وَاحْتَذَى الْمَخْصُوفَ وَلَبِسَ ثَوْبًا خَشِنًا خَشِنًا","id":"Telah menceritakan kepada kami [Yahya bin 'Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] Telah menceritakan kepada kami [Baqiyah bin Al Walid] dari [Yusuf bin Abu Katsir] dari [Nuh bin Dzakwan] dari [Al Hasan] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengenakan kain shuf (wol) dan mengenakan terompah yang di tambal, beliau juga mengenakan pakaian yang kasar.\""},"3512":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا أَصْبَغُ بْنُ زَيْدٍ حَدَّثَنَا أَبُو الْعَلَاءِ عَنْ أَبِي أُمَامَةَ قَالَلَبِسَ عُمَرُ بْنُ الْخَطَّابِ ثَوْبًا جَدِيدًا فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي كَسَانِي مَا أُوَارِي بِهِ عَوْرَتِي وَأَتَجَمَّلُ بِهِ فِي حَيَاتِي ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ لَبِسَ ثَوْبًا جَدِيدًا فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي كَسَانِي مَا أُوَارِي بِهِ عَوْرَتِي وَأَتَجَمَّلُ بِهِ فِي حَيَاتِي ثُمَّ عَمَدَ إِلَى الثَّوْبِ الَّذِي أَخْلَقَ أَوْ أَلْقَى فَتَصَدَّقَ بِهِ كَانَ فِي كَنَفِ اللَّهِ وَفِي حِفْظِ اللَّهِ وَفِي سِتْرِ اللَّهِ حَيًّا وَمَيِّتًا قَالَهَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Yazid bin Harun] dia berkata; Telah menceritakan kepada kami [Ashbagh bin Zaid] Telah menceritakan kepada kami [Abu Al 'Ala] dari [Abu Umamah] dia berkata, \" [Umar bin Al Khaththab] memakai baju baru, kemudian dia mengucapkan, 'ALHAMDULILLAHILLADZII KASAANI MAA UWAARIBIHI 'AURATII WA ATAJAMMALU BIHI FII HAYAATI (Segala puji bagi Allah yang telah memberiku pakaian untuk menutupi 'auratku dan menghiasi diriku didalam kehidupanku) '. Kemudian dia berkata, \"Aku mendengar RAsulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakai baju baru lalu mengucapkan 'ALHAMDULILLAHILLADZII KASAANI MAA UWAARIBIHI 'AURATII WA ATAJAMMALU BIHI FII HAYAATI (Segala puji bagi Allah yang telah memberiku pakaian untuk menutupi auratku dan menghiasi diriku didalam kehidupanku) ', kemudian dia mengambil pakaian yang telah usang atau yang sudah di tinggalkan, dan menyedekahkannya, maka hidup dan matinya, ia akan selalu berada dalam naungan Allah dan perlindungan Allah serta di dalam penjagaan Allah baik.\" Beliau mengulanginya hingga tiga kali.\""},"3513":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عَلَى عُمَرَ قَمِيصًا أَبْيَضَ فَقَالَ ثَوْبُكَ هَذَا غَسِيلٌ أَمْ جَدِيدٌ قَالَ لَا بَلْ غَسِيلٌ قَالَ الْبَسْ جَدِيدًا وَعِشْ حَمِيدًا وَمُتْ شَهِيدًا","id":"Telah menceritakan kepada kami [Al Husain bin Mahdi] Telah menceritakan kepada kami [Abdurrazaq] Telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam melihat Umar mengenakan pakaian putih, maka beliau pun bertanya, \"Apakah pakaianmu ini habis di cuci atau benar-benar baru?\" dia menjawab, \"Tidak, akan tetapi bajuku habis di cuci.\" Beliau bersabda: \"ILBAS JADIDAN WA 'ISY HAMIDAN WA MUT SYAHIDAN (Pakailah baju baru dan hiduplah dengan terhormat serta matilah sebagai syahid) '.\""},"3514":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأ��نَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لِبْسَتَيْنِ فَأَمَّا اللِّبْسَتَانِ فَاشْتِمَالُ الصَّمَّاءِ وَالِاحْتِبَاءُ فِي الثَّوْبِ الْوَاحِدِ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌ","id":"Telah menceritakan kepada kami [Abu Bakar] Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Atha bin Zaid Al Laitsi] dari [Abu Sa'id Al Khudri], bahwa Nabi shallallahu 'alaihi wasallam melarang mengenakan dua cara berpakaian; memakai pakaian shama` dan ihtiba` dengan satu kain sehingga tidak ada sesuatu yang menutupi kemaluannya.\" "},"3515":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لِبْسَتَيْنِ عَنْ اشْتِمَالِ الصَّمَّاءِ وَعَنْ الِاحْتِبَاءِ فِي الثَّوْبِ الْوَاحِدِ يُفْضِي بِفَرْجِهِ إِلَى السَّمَاءِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari ['Ubaidillah bin Umar] dari [Khubaib bin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam melarang mengenakan dua jenis pakaian; pakaian shama` dan ikhtiba` dengan satu kain seraya menengadahkan kemaluannya ke langit.\" "},"3516":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ سَعْدِ بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لِبْسَتَيْنِ اشْتِمَالِ الصَّمَّاءِ وَالِاحْتِبَاءِ فِي ثَوْبٍ وَاحِدٍ وَأَنْتَ مُفْضٍ فَرْجَكَ إِلَى السَّمَاءِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Sa'id bin Sa'id] dari ['Amrah] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarang dua jenis pakaian; shama` dan ikhtiba` dengan satu kain seraya menengadahkan kemaluannya ke langit.\" Ket; shama` adalah seseorang yang menyelimutui seluruh tubuhnya dan tidak ada yang terlihat; dan ihtiba` adalah duduk di atas bokong sementara kedua tangan mendekap kedua lututnya menempel dada."},"3517":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ قَتَادَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَقَالَ لِي يَا بُنَيَّ لَوْ شَهِدْتَنَا وَنَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصَابَتْنَا السَّمَاءُ لَحَسِبْتَ أَنَّ رِيحَنَا رِيحُ الضَّأْنِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Al Hasan bin Musa] dari [Syaiban] dari [Qatadah] dari [Abu Burdah] dari [Ayahnya] dia berkata, \"Ayahku berkata kepadaku, \"Wahai anakku, sekiranya kamu menyaksikan saat kami bersama Rasulullah shallallahu 'alaihi wasallam ketika terkena angin, niscaya kamu akan mengira bahwa bau tubuh kami adalah bau domba.\""},"3518":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ كَرَامَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْأَحْوَصُ بْنُ حَكِيمٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ وَعَلَيْهِ جُبَّةٌ رُومِيَّةٌ مِنْ صُوفٍ ضَيِّقَةُ الْكُمَّيْنِ فَصَلَّى بِنَا فِيهَا لَيْسَ عَلَيْهِ شَيْءٌ غَيْرُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Utsman bin Karamah] Telah menceritakan kepada kami [Abu Usamah] Telah menceritakan kepada kami [Al Ahwash bin Hakim] dari [Khalid bin Ma'dan] dari ['Ubadah bin Ash Shamit] dia berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam mendatangi kami, dan beliau mengenakan jubbah buatan romawi yang terbuat dari wool yang sempit kedua lengannya. Kemudian beliau mengimami kami dengan mengenakan baju itu tanpa ada sesuatu yang menempel padanya.\""},"3519":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ وَأَحْمَدُ بْنُ الْأَزْهَرِ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ بْنُ السِّمْطِ حَدَّثَنِي الْوَضِينُ بْنُ عَطَاءٍ عَنْ مَحْفُوظِ بْنِ عَلْقَمَةَ عَنْ سَلْمَانَ الْفَارِسِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَقَلَبَ جُبَّةَ صُوفٍ كَانَتْ عَلَيْهِ فَمَسَحَ بِهَا وَجْهَهُ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Al Walid Ad Dimasyqi] dan [Ahmad bin Al Azhar] keduanya berkata; Telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Yazid bin As Simth] telah menceritakan kepadaku [Al Wadlin bin 'Atha] dari [Mahfudz bin 'Alqamah] dari [Salman Al Farisi], bahwa Rasulullah shallallahu 'alaihi wasallam berwudlu dengan membalikkan jubah wool yang di kenakannya, kemudian beliau membasuh mukanya.\""},"3520":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مُوسَى بْنُ الْفَضْلِ عَنْ شُعْبَةَ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِمُ غَنَمًا فِي آذَانِهَا وَرَأَيْتُهُ مُتَّزِرًا بِكِسَاءٍ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] Telah menceritakan kepada kami [Musa bin Al Fadl] dari [Syu'bah] dari [Hisyam bin Zaid] dari [Anas bin Malik] dia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam memberi tanda di telinga kambing dan saya melihat beliau mengenakan pakaian sarung.\""},"3521":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ ابْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ ثِيَابِكُمْ الْبَيَاضُ فَالْبَسُوهَا وَكَفِّنُوا فِيهَا مَوْتَاكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] Telah memberitakan kepada kami [Abdullah bin Raja Al Makki] dari [Ibnu Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik baju kalian adalah baju putih, maka pakailah oleh kalian (baju putih) dan kafanilah mayat kalian dengannya.\""},"3522":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَسُوا ثِيَابَ الْبَيَاضِ فَإِنَّهَا أَطْهَرُ وَأَطْيَبُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Maimun bin Abu Syabib] dari [Samrah bin Jundab] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pakailah baju putih, karena sesungguhnya baju putih lebih suci dan lebih baik.\""},"3523":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَسَّانَ الْأَزْرَقُ حَدَّثَنَا عَبْدُ الْمَجِيدِ بْنُ أَبِي رَوَّادٍ حَدَّثَنَا مَرْوَانُ بْنُ سَالِمٍ عَنْ صَفْوَانَ بْنِ عَمْرٍو عَنْ شُرَيْحِ بْنِ عُبَيْدٍ الْحَضْرَمِيِّ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحْسَنَ مَا زُرْتُمْ اللَّهَ بِهِ فِي قُبُورِكُمْ وَمَسَاجِدِكُمْ الْبَيَاضُ","id":"Telah menceritakan kepada kami [Muhammad bin Hassan Al Azraq] telah menceritakan kepada kami [Abdul Majid bin Abu Rawwad] telah menceritakan kepada kami [Marwan bin Salim] dari [Shafwan bin 'Amru] dari [Syuraih bin 'Ubaid Al Hadlrami] dari [Abu Ad Darda] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik pakaian yang kalian kenakan untuk mengunjungi Allah di kuburan dan masjid kalian adalah pakaian putih.\""},"3524":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ جَمِيعًا عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الَّذِي يَجُرُّ ثَوْبَهُ مِنْ الْخُيَلَاءِ لَا يَنْظُرُ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah]. (dalam riwayat lain disebutkan) telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abdullah bin Numair] semuanya dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang memanjangkan kainnya dengan sombong, maka Allah tidak akan memandang kepadanya pada hari Kiamat.\""},"3525":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَرَّ إِزَارَهُ مِنْ الْخُيَلَاءِ لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِقَالَ فَلَقِيتُ ابْنَ عُمَرَ بِالْبَلَاطِ فَذَكَرْتُ لَهُ حَدِيثَ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَأَشَارَ إِلَى أُذُنَيْهِ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari ['Athiyah] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memanjangkan kainnya dengan sombong, niscaya Allah tidak akan memandangnya pada hari Kiamat.\" 'Athiyah berkata, \"Lalu aku bertemu dengan [Ibnu Umar] di Balath, kemudian aku menyebutkan hadits yang di riwayatkan oleh Abu Sa'id dari Nabi shallallahu 'alaihi wasallam tersebut, maka sambil memberi isyarat ke telinganya, Ibnu Umar berkata, \"Kedua telingaku telah mendengarnya dan hatiku juga telah meyakininya.\""},"3526":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَمَرَّ بِأَبِي هُرَيْرَةَ فَتًى مِنْ قُرَيْشٍ يَجُرُّ سَبَلَهُ فَقَالَ يَا ابْنَ أَخِي إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ جَرَّ ثَوْبَهُ مِنْ الْخُيَلَاءِ لَمْ يَنْظُرْ اللَّهُ لَهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Seorang pemuda Quraisy yang pakaiannya melebihi mata kaki lewat di hadapan Abu Hurairah, lalu ia pun menegurnya seraya mengatakan, \"Wahai anak pamanku, sesungguhnya saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memanjangkan kainnya dengan sombong, niscaya Allah tidak akan memandangnya pada hari Kiamat kelak.\""},"3527":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ مُسْلِمِ بْنِ نُذَيْرٍ عَنْ حُذَيْفَةَ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَسْفَلِ عَضَلَةِ سَاقِي أَوْ سَاقِهِ فَقَالَ هَذَا مَوْضِعُ الْإِزَارِ فَإِنْ أَبَيْتَ فَأَسْفَلَ فَإِنْ أَبَيْتَ فَأَسْفَلَ فَإِنْ أَبَيْتَ فَلَا حَقَّ لِلْإِزَارِ فِي الْكَعْبَيْنِحَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ مُسْلِمِ بْنِ نُذَيْرٍ عَنْ حُذَيْفَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Muslim bin Nudzair] dari [Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memegang bagian bawah kedua betisku -atau kedua betisnya- kemudian bersabda: \"Sampai di sinilah batas kain sarung, apabila kamu enggan maka rendahkanlah (sedikit ke bawah), jika kamu masih enggan maka lebih rendahkanlah lagi, dan jika kamu masih enggan, maka tidak ada hak bagi kain sarung untuk (melebihi) kedua mata kaki.\" Telah menceritakan kepada kami [Ali bin Muhammad] Telah menceritakan kepada kami [Sufyan bin 'Uyainah] Telah menceritakan kepadaku [Abu Ishaq] dari [Muslim bin Nudzair] dari [Hudzaifah] dari Nabi shallallahu 'alaihi wasallam.\""},"3528":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ قَالَقُلْتُ لِأَبِي سَعِيدٍ هَلْ سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فِي الْإِزَارِ قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِزْرَةُ الْمُؤْمِنِ إِلَى أَنْصَافِ سَاقَيْهِ لَا جُنَاحَ عَلَيْهِ مَا بَيْنَهُ وَبَيْنَ الْكَعْبَيْنِ وَمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ فِي النَّارِ يَقُولُ ثَلَاثًا لَا يَنْظُرُ اللَّهُ إِلَى مَنْ جَرَّ إِزَارَهُ بَطَرًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Al 'Ala bin Abdurrahman] dari [Ayahnya] dia berkata, \"Saya berkata kepada [Abu Sa'id], \"Apakah kamu pernah mendengar sesuatu dari Rasulullah shallallahu 'alaihi wasallam mengenai kain sarung?\" dia menjawab, \"Ya. Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kain sarung seorang mukmin itu hingga (menutupi) kedua betisnya, dan tidak ada larangan baginya antara betis tersebut hingga kedua mata kaki, sedangkan yang melebihi mata kaki maka tempatnya di dalam neraka.\" Beliau mengatakannya hingga tiga kali, (kemudian bersabda): \"Allah tidak akan memandang seseorang yang memanjangkan kain sarungnya dengan sombong.\""},"3529":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا شَرِيكٌ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ حُصَيْنِ بْنِ قَبِيصَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا سُفْيَانَ بْنَ سَهْلٍ لَا تُسْبِلْ فَإِنَّ اللَّهَ لَا يُحِبُّ الْمُسْبِلِينَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Syarik] dari [Abdul Malik bin 'Umair] dari [Hushain bin Qabishah] dari [Al Mughirah bin Syu'bah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Sufyan bin Sahl, janganlah kamu memanjangkan kain sarung atau celana melebihi mata kaki, karena Allah membenci orang-orang yang memanjangkan kain sarung atau celananya melebihi mata kaki.\""},"3530":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ عَبْدِ الْمُؤْمِنِ بْنِ خَالِدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَ قَالَتْلَمْ يَكُنْ ثَوْبٌ أَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْقَمِيصِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi] telah menceritakan kepada kami [Abu Tumailah] dari [Abdul Mukmin bin Khalid] dari [Ibnu Buraidah] dari [Ibunya] dari [Ummu Salamah] dia berkata, \"Tidak ada pakaian yang lebih dicintai oleh Rasulullah shallallahu 'alaihi wasallam selain gamis.\""},"3531":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ ابْنِ أَبِي رَوَّادٍ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِسْبَالُ فِي الْإِزَارِ وَالْقَمِيصِ وَالْعِمَامَةِ مَنْ جَرَّ شَيْئًا خُيَلَاءَ لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِقَالَ أَبُو بَكْرٍ مَا أَغْرَبَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Al Husain bin Ali] dari [Ibnu Abu Rawwad] dari [Salim] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Isbal itu terdapat juga pada kain sarung (celana), pakaian (gamis) dan surban. Barangsiapa memanjangkan sesuatu (seperti tadi) dengan sombong, niscaya Allah tidak akan melihat kepadanya pada hari Kiamat kelak.\" Abu Bakar berkata; \"Husain bin Ali tidak menganggap asing hadits di atas.\" "},"3532":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ الْأَوْدِيُّ حَدَّثَنَا أَبُو غَسَّانَ وَحَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عُبَيْدُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا حَسَنُ بْنُ صَالِحٍ ح و حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبِي عَنْ الْحَسَنِ بْنِ صَالِحٍ عَنْ مُسْلِمٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُ قَمِيصًا قَصِيرَ الْيَدَيْنِ وَالطُّولِ","id":"Telah menceritakan kepada kami [Ahmad bin Utsman bin Hakim Al Audi] telah menceritakan kepada kami [Abu Ghassan] dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami ['Ubaid bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Al Hasan bin Shalih]. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Ayahku] dari [Al Hasan bin Shalih] dari [Muslim] dari [Mujahid] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam selalu mengenakan gamis yang kedua lengannya pendek dan panjang.\""},"3533":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا ابْنُ دُكَيْنٍ عَنْ زُهَيْرٍ عَنْ عُرْوَةَ بْنِ عَبْدِ اللَّهِ بْنِ قُشَيْرٍ حَدَّثَنِي مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْتُهُ وَإِنَّ زِرَّ قَمِيصِهِ لَمُطْلَقٌقَالَ عُرْوَةُ فَمَا رَأَيْتُ مُعَاوِيَةَ وَلَا ابْنَهُ فِي شِتَاءٍ وَلَا صَيْفٍ إِلَّا مُطْلَقَةً أَزْرَارُهُمَا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Ibnu Dukain] dari [Zuhair] dari ['Urwah bin Abdullah bin Qusyair] telah menceritakan kepadaku [Mu'awiyah bin Qurrah] dari [Ayahnya] dia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam lalu berbai'at kepadanya, dan sungguh kancing gamis beliau terbuka.\" 'Urwah berkata, \"Aku tidak pernah melihat Mu'awiyah maupun anaknya baik di musim dingin maupun panas kecuali kancing-kancing bajunya terbuka.\""},"3534":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى وَعَبْدُ الرَّحْمَنِ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكِ بْنِ ��َرْبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ قَالَأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَاوَمَنَا سَرَاوِيلَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki']. (dalam riwayat lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya] dan [Abdurrahman] mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Simak bin Harb] dari [Suwaid bin Qais] dia berkata, \"Nabi shallallahu 'alaihi wasallam menemui kami dan menawarkan celana panjang kepada kami.\""},"3535":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُمِّ سَلَمَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمْ تَجُرُّ الْمَرْأَةُ مِنْ ذَيْلِهَا قَالَ شِبْرًا قُلْتُ إِذًا يَنْكَشِفُ عَنْهَا قَالَ ذِرَاعٌ لَا تَزِيدُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari ['Ubaidillah bin Umar] dari [Nafi'] dari [Sulaiman bin Yasar] dari [Ummu Salamah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam di tanya, \"Berapakah seharusnya seorang wanita memanjangkan kainnya?\" beliau menjawab: \"Satu jengkal.\" Aku berkata, \"Jika demikian, maka masih memungkinkan untuk tersingkap.\" Maka beliau bersabda: \"(Lebihkanlah) satu hasta, dan jangan sampai lebih dari itu.\""},"3536":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ زَيْدٍ الْعَمِّيِّ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ ابْنِ عُمَرَأَنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُخِّصَ لَهُنَّ فِي الذَّيْلِ ذِرَاعًا فَكُنَّ يَأْتِيَنَّا فَنَذْرَعُ لَهُنَّ بِالْقَصَبِ ذِرَاعًا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Zaid Al 'Ammi] dari [Abu Ash Shiddiq An Naji] dari [Ibnu Umar], bahwa isteri-isteri Nabi shallallahu 'alaihi wasallam diberi keringanan untuk melebihkan kain baju bagian bawah (jubahnya) satu hasta. Saat mereka mendatangi kami, maka kami pun mengukurnya dengan kayu dan ternyata panjangnya sehasta.\""},"3537":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الْمُهَزِّمِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِفَاطِمَةَ أَوْ لِأُمِّ سَلَمَةَ ذَيْلُكِ ذِرَاعٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Al Muhazzim] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada Fatimah dan Ummu Salamah: \"Panjang kainmu bagian bawah adalah satu hasta.\""},"3538":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا حَبِيبٌ الْمُعَلِّمُ عَنْ أَبِي الْمُهَزِّمِ عَنْ أَبِي هُرَيْرَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي ذُيُولِ النِّسَاءِ شِبْرًا فَقَالَتْ عَائِشَةُ إِذًا تَخْرُجَ سُوقُهُنَّ قَالَ فَذِرَاعٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Habib Al Mu'allim] dari [Abu Al Muhazzim] dari [Abu Hurairah] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam bersabda mengenai kain (jubah bagian) bawah para wanita, yaitu di lebihkan satu jengkal.\" Aisyah berkata, \"Saya berkata, \"Kalau begitu betis mereka masih terlihat! \" Beliau bersabda: \"Jika seperti itu, tambahlah satu hasta.\""},"3539":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُسَاوِرٍ الْوَرَّاقِ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى الْمِنْبَرِ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan bin 'Uyaianh] dari [Musawir Al Warraq] dari [Ja'far bin 'Amru bin Huraits] dari [Ayahnya] dia berkata, \"Saya melihat Nabi shallallahu 'alaihi wasallam khutbah di atas minbar dengan mengenakan surban berwarna hitam.\""},"3540":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Az Zubair] dari [Jabir], bahwa Nabi shallallahu 'alaihi wasallam memasuki kota Makkah dengan mengenakan surban berwarna hitam.\""},"3541":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ أَنْبَأَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ يَوْمَ فَتْحِ مَكَّةَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Ubaidullah] telah memberitakan kepada kami [Musa bin 'Ubaidah] dari [Abdullah bin Dinar] dari [Ibnu Umar], bahwa ketika penaklukan kota Makkah, Rasulullah shallallahu 'alaihi wasallam masuk kota dengan mengenakan imamah (surban) berwarna hitam.\""},"3542":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُسَاوِرٍ حَدَّثَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِ قَالَكَأَنِّي أَنْظُرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ قَدْ أَرْخَى طَرَفَيْهَا بَيْنَ كَتِفَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Musawir] telah menceritakan kepadaku [Ja'far bin 'Amru bin Huraits] dari [Ayahnya] dia berkata, \"Seakan aku melihat Rasulullah shallallahu 'alaihi wasallam mengenakan surban hitam yang kedua ujungnya dibiarkan menjuntai antara kedua pundak beliau.\""},"3543":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَبِسَ الْحَرِيرَ فِي الدُّنْيَا لَمْ يَلْبَسْهُ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakai kain sutera di dunia, maka ia tidak akan memakainya di Akhirat kelak.\""},"3544":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الشَّيْبَانِيِّ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدٍ عَنْ الْبَرَاءِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدِّيبَاجِ وَالْحَرِيرِ وَالْإِسْتَبْرَقِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Asy Syaibani] dari [Asy'ats bin Abu Asy Sya'tsa`] dari [Mu'awiyah bin Suwaid] dari [Al Barra`] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengenakan pakaian dibaj (kain bersulam sutera), kain sutera murni dan istabraq (pakaian tebal yang bercampur sutera).\""},"3545":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ حُذَيْفَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبْسِ الْحَرِيرِ وَالذَّهَبِ وَقَالَ هُوَ لَهُمْ فِي الدُّنْيَا وَلَنَا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengenakan kain sutera dan emas, sabdanya: \"Itu untuk mereka di dunia dan untuk kita di Akhirat.\""},"3546":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَأَى حُلَّةً سِيَرَاءَ مِنْ حَرِيرٍ فَقَالَ يَا رَسُولَ اللَّهِ لَوْ ابْتَعْتَ هَذِهِ الْحُلَّةَ لِلْوَفْدِ وَلِيَوْمِ الْجُمُعَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Ubaidullah bin Umar] dari [Nafi'] bahwa [Abdullah bin Umar] telah mengabarkan kepadanya, bahwa Umar bin Al Khaththab melihat pakaian yang terbuat dari sutera murni, dia lalu berkata, \"Wahai Rasulullah, sekiranya anda mengenakan pakaian ini untuk menerima utusan dan ketika hari Jum'at.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hanyasanya yang memakai kain ini adalah orang-orang yang tidak akan mendapatkan kebaikan di Akhirat.\""},"3547":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ نَبَّأَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لِلزُّبَيْرِ بْنِ الْعَوَّامِ وَلِعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ فِي قَمِيصَيْنِ مِنْ حَرِيرٍ مِنْ وَجَعٍ كَانَ بِهِمَا حِكَّةٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas bin Malik] telah mengabarkan kepada mereka, bahwa Rasulullah shallallahu 'alaihi wasallam memberi keringanan kepada Zubair bin 'Awwam dan Abdurrahman bin 'Auf untuk mengenakan kain sutera karena keduanya menderita penyakit gatal.\""},"3548":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ عُمَرَأَنَّهُ كَانَ يَنْهَى عَنْ الْحَرِيرِ وَالدِّيبَاجِ إِلَّا مَا كَانَ هَكَذَا ثُمَّ أَشَارَ بِإِصْبَعِهِ ثُمَّ الثَّانِيَةِ ثُمَّ الثَّالِثَةِ ثُمَّ الرَّابِعَةِ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا عَنْهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari ['Ashim] dari [Abu 'Utsman] dari [Umar], bahwa dia melarang mengenakan pakaian yang terbuat dari sutera murni atau dibaj (campuran sutera), kecuali jika ia seperti ini.\" Kemudian dia memberi isyarat dengan jarinya, lalu yang kedua, lalu yang ketiga, lalu yang ke empat kali seraya berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang kita untuk mengenakannya.\""},"3549":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ مُغِيرَةَ بْنِ زِيَادٍ عَنْ أَبِي عُمَرَ مَوْلَى أَسْمَاءَ قَالَرَأَيْتُ ابْنَ عُمَرَ اشْتَرَى عِمَامَةً لَهَا عَلَمٌ فَدَعَا بِالْجَلَمَيْنِ فَقَصَّهُ فَدَخَلْتُ عَلَى أَسْمَاءَ فَذَكَرْتُ ذَلِكَ لَهَا فَقَالَتْ بُؤْسًا لِعَبْدِ اللَّهِ يَا جَارِيَةُ هَاتِي جُبَّةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَتْ بِجُبَّةٍ مَكْفُوفَةِ الْكُمَّيْنِ وَالْجَيْبِ وَالْفَرْجَيْنِ بِالدِّيبَاجِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Mughirah bin Ziyad] dari [Abu Umar] mantan budak Asma, dia berkata, \"Saya melihat Ibnu Umar membeli surban yang bergambar, kemudian dia meminta di ambilkan gunting lalu mengguntingnya. Setelah itu aku menjumpai Asma dan kuceritakan hal itu kepadanya, [Asma] lantas berkata, \"Sungguh buruk apa yang telah di lakukan oleh Abdullah! Wahai pembantu, ambilkanlah jubah Rasulullah shallallahu 'alaihi wasallam.\" Kemudian pembantu wanita itu datang dengan membawa jubah berlengan dan bersaku serta kedua selanya bergaris yang terbuat dari dibaj (campuran sutera).\""},"3550":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي الصَّعْبَةِ عَنْ أَبِي الْأَفْلَحِ الْهَمْدَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ زُرَيْرٍ الْغَافِقِيِّ سَمِعْتُهُ يَقُولُ سَمِعْتُ عَلِيَّ بْنَ أَبِي طَالِبٍ يَقُولُأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرِيرًا بِشِمَالِهِ وَذَهَبًا بِيَمِينِهِ ثُمَّ رَفَعَ بِهِمَا يَدَيْهِ فَقَالَ إِنَّ هَذَيْنِ حَرَامٌ عَلَى ذُكُورِ أُمَّتِي حِلٌّ لِإِنَاثِهِمْ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Abdul Aziz bi Abu As Sha'bah] dari [Abu Al Aflah Al Hamdani] dari [Abdullah bin Zurair Al Ghafiqi] saya mendengar [Ali bin Abu Thalib] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengambil sutera dengan tangan kirinya dan emas dengan tangan kanannya, kemudian beliau mengangkat kedua tangannya sambil bersabda: \"Sesungguhnya kedua benda ini haram bagi kaum laki-laki dari umatku dan halal bagi kaum wanita.\""},"3551":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ أَبِي فَاخِتَةَ حَدَّثَنِي هُبَيْرَةُ بْنُ يَرِيمَ عَنْ عَلِيٍّأَنَّهُ أُهْدِيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةٌ مَكْفُوفَةٌ بِحَرِيرٍ إِمَّا سَدَاهَا وَإِمَّا لَحْمَتُهَا فَأَرْسَلَ بِهَا إِلَيَّ فَأَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَصْنَعُ بِهَا أَلْبَسُهَا قَالَ لَا وَلَكِنْ اجْعَلْهَا خُمُرًا بَيْنَ الْفَوَاطِمِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Yazid bin Abu Ziyad] dari [Abu Fakhitah] telah menceritakan kepadaku [Hubairah bin Yarim] dari [Ali], bahwa telah di hadiahkan pakaian yang terbuat dari sutera kepada Rasulullah shallallahu 'alaihi wasallam, yaitu yang panjang atau lebar kainnya bersulam sutera. Kemudian beliau mengirimnya kembali kepadaku, lantas kudatangi beliau seraya berkata, \"Wahai Rasulullah, apa yang harus kuperbuat dengannya? Apakah aku boleh mengenakannya?\" beliau menjawab: \"Tidak, akan tetapi buatlah kerudung untuk para Fatimah.\" "},"3552":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ الْإِفْرِيقِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي إِحْدَى يَدَيْهِ ثَوْبٌ مِنْ حَرِيرٍ وَفِي الْأُخْرَى ذَهَبٌ فَقَالَ إِنَّ هَذَيْنِ مُحَرَّمٌ عَلَى ذُكُورِ أُمَّتِي حِلٌّ لِإِنَاثِهِمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Al Ifriqi] dari [Abdurrahman bin Rafi'] dari [Abdullah bin 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemui kami, satu tangannya memegang sutera dan tangan yang lain memegang emas, lalu beliau bersabda: \"Sesungguhnya kedua benda ini diharamkan bagi kaum lelaki umatku dan di halalkan bagi kaum wanitanya.\""},"3553":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَرَأَيْتُ عَلَى زَيْنَبَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَ حَرِيرٍ سِيَرَاءَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Isa bin Yunus] dari [Ma'mar] dari [Az Zuhri] dari [Anas] dia berkata, \"Aku melihat Zainab binti Rasulullah shallallahu 'alaihi wasallam mengenakan gamis sutera yang bergaris.\""},"3554":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ الْقَاضِي عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَمَا رَأَيْتُ أَجْمَلَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَرَجِّلًا فِي حُلَّةٍ حَمْرَاءَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dari [Syarik bin Abdullah Al Qadli] dari [Abu Ishaq] dari [Al Barra] dia berkata, \"Saya tidak pernah melihat yang lebih indah dari sosok Rasulullah shallallahu 'alaihi wasallam kecuali saat beliau berjalan dengan mengenakan pakaian merah.\""},"3555":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ بَرَّادِ بْنِ يُوسُفَ بْنِ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا حُسَيْنُ بْنُ وَاقِدٍ قَاضِي مَرْوَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ أَنَّ أَبَاهُ حَدَّثَهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَأَقْبَلَ حَسَنٌ وَحُسَيْنٌ عَلَيْهِمَا السَّلَام عَلَيْهِمَا قَمِيصَانِ أَحْمَرَانِ يَعْثُرَانِ وَيَقُومَانِ فَنَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَهُمَا فَوَضَعَهُمَا فِي حِجْرِهِ فَقَالَ صَدَقَ اللَّهُ وَرَسُولُهُ{ إِنَّمَا أَمْوَالُكُمْ وَأَوْلَادُكُمْ فِتْنَةٌ }رَأَيْتُ هَذَيْنِ فَلَمْ أَصْبِرْ ثُمَّ أَخَذَ فِي خُطْبَتِهِ","id":"Telah menceritakan kepada kami [Abu 'Amir Abdullah bin 'Amir bin Barrad bin Yusuf bin Abu Burdah bin Abu Musa Al Asy'ari] dia berkata; telah menceritakan kepada kami [Zaid bin Hubab] telah menceritakan kepada kami [Husain bin Waqid Qadli Marwa] telah menceritakan kepadaku [Abdullah bin Buraidah] bahwa [Ayahnya] telah menceritakan kepadanya, dia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam berkhutbah, kemudian Hasan dan Husain 'alaihima salam menghampiri beliau dengan mengenakan baju warna merah dan keduanya berdiri. Nabi shallallahu 'alaihi wasallam lalu mengambil keduanya serta meletakkannya di pangkuan, beliau lalu bersabda: \"Maha benar Allah dan Rasul-Nya; 'Sesungguhnya hartamu dan anak-anakmu hanyalah cobaan (bagimu)...' (QS. At Taghabun; 15), aku melihat kedua anak ini dan aku tidak sanggup menahan diri (untuk memeluknya).\" Kemudian beliau melanjutkan khutbahnya.\""},"3556":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ الْحَسَنِ بْنِ سُهَيْلٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُفَدَّمِقَالَ يَزِيدُ قُلْتُ لِلْحَسَنِ مَا الْمُفَدَّمُ قَالَ الْمُشْبَعُ بِالْعُصْفُرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Yazid bin Abu Ziyad] dari [Al Hasan bin Suhail] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Al Mufaddam.\" Yazid berkata, \"Aku bertanya kepada Al Hasan, \"Apakah al Mufaddam itu?\" Dia menjawab: \"(Pakaian) yang di celup dengan pohon 'ushfur (sejenis tumbuhan pewarna).\""},"3557":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ قَالَ سَمِعْتُ عَلِيًّا يَقُولُنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَقُولُ نَهَاكُمْ عَنْ لُبْسِ الْمُعَصْفَرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Usamah bin Zaid] dari [Abdullah bin Hunain] dia berkata; saya mendengar [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku, dan aku tidak mengatakan beliau melarang kalian dari memakai pakaian yang dicelup (diberi warna).\""},"3558":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامِ بْنِ الْغَازِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَأَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ثَنِيَّةِ أَذَاخِرَ فَالْتَفَتَ إِلَيَّ وَعَلَيَّ رَيْطَةٌ مُضَرَّجَةٌ بِالْعُصْفُرِ فَقَالَ مَا هَذِهِ فَعَرَفْتُ مَا كَرِهَ فَأَتَيْتُ أَهْلِي وَهُمْ يَسْجُرُونَ تَنُّورَهُمْ فَقَذَفْتُهَا فِيهِ ثُمَّ أَتَيْتُهُ مِنْ الْغَدِ فَقَالَ يَا عَبْدَ اللَّهِ مَا فَعَلَتْ الرَّيْطَةُ فَأَخْبَرْتُهُ فَقَالَ أَلَا كَسَوْتَهَا بَعْضَ أَهْلِكَ فَإِنَّهُ لَا بَأْسَ بِذَلِكَ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Isa bin Yunus] dari [Hisyam bin Al Ghaz] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] dia berkata, \"Kami berjumpa dengan Rasulullah shallallahu 'alaihi wasallam ketika berada di Tsaniyah Adzakhir, dan beliau menoleh kepadaku sedangkan aku mengenakan pakaian yang dicelup dengan pohon 'ushfur, maka beliau bersabda: 'Apakah ini? ', akupun bahwa beliau tidak menyukainya. Kemudian aku menemui keluargaku ketika mereka sedang menyalakan tungku api, lalu kulemparkan mantelku ke dalam tungku api. Keesokan harinya aku mendatangi Rasulullah shallallahu 'alaihi wasallam, beliau lalu bertanya: \"Wahai Abdullah, apa yang telah kamu perbuat dengan mantelmu?\" lalu kuberitahukan kepada beliau bahwa aku telah membakarnya, maka beliau pun bersabda: \"Kenapa tidak kamu berikan kepada istrimu? Karena mantel yang seperti itu tidak mengapa jika di pakai oleh kaum wanita.\""},"3559":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي لَيْلَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ شُرَحْبِيلَ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْنَا لَهُ مَاءً يَتَبَرَّدُ بِهِ فَاغْتَسَلَ ثُمَّ أَتَيْتُهُ بِمِلْحَفَةٍ صَفْرَاءَ فَرَأَيْتُ أَثَرَ الْوَرْسِ عَلَى عُكَنِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Laila] dari [Muhammad bin Abdurrahman] dari [Muhammad bin Syurahbil] dari [Qais bin Sa'd] dia berkata, \"Nabi shallallahu 'alaihi wasallam menemui kami, lalu kami menyiapkan air agar beliau bisa mendinginkan badannya, beliau pun mandi, kemudian aku berikan kain selimut berwarna kuning, sehingga aku pun dapat melihat bekas warna kuning pada leher beliau.\""},"3560":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّ�� اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا وَاشْرَبُوا وَتَصَدَّقُوا وَالْبَسُوا مَا لَمْ يُخَالِطْهُ إِسْرَافٌ أَوْ مَخِيلَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Hammam] dari [Qatadah] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makan dan minumlah, bersedekah dan berpakaianlah kalian dengan tidak berlebih-lebihan atau kesombongan.\""},"3561":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَادَةَ وَمُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ الْوَاسِطِيَّانِ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا شَرِيكٌ عَنْ عُثْمَانَ بْنِ أَبِي زُرْعَةَ عَنْ مُهَاجِرٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَبِسَ ثَوْبَ شُهْرَةٍ أَلْبَسَهُ اللَّهُ يَوْمَ الْقِيَامَةِ ثَوْبَ مَذَلَّةٍ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubadah] dan [Muhammad bin Abdul Malik Al Washatiyani] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Syarik] dari [Utsman bin Abu Zur'ah] dari [Muhajir] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengenakan pakaian dengan penuh kesombongan (pamer), maka Allah akan memakaikan kepadanya pakaian kehinaan pada hari Kiamat.\""},"3562":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ عَنْ الْمُهَاجِرِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ مَنْ لَبِسَ ثَوْبَ شُهْرَةٍ فِي الدُّنْيَا أَلْبَسَهُ اللَّهُ ثَوْبَ مَذَلَّةٍ يَوْمَ الْقِيَامَةِ ثُمَّ أَلْهَبَ فِيهِ نَارًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Abu 'Awanah] dari ['Utsman bin Al Mughirah] dari [Al Muhajir] dari [Abdullah bin Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengenakan pakaian dengan penuh kesombongan (pamer) di dunia, maka Allah akan mengenakan pakaian kehinaan pada hari Kiamat dan dia akan di masukkan ke dalam api Neraka.\""},"3563":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ يَزِيدَ الْبَحْرَانِيُّ حَدَّثَنَا وَكِيعُ بْنُ مُحْرِزٍ النَّاجِيُّ حَدَّثَنَا عُثْمَانُ بْنُ جَهْمٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَبِسَ ثَوْبَ شُهْرَةٍ أَعْرَضَ اللَّهُ عَنْهُ حَتَّى يَضَعَهُ مَتَى وَضَعَهُ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Yazid Al Bahrani] telah menceritakan kepada kami [Waki' bin Muhris An Naji] telah menceritakan kepada kami [Utsman bin Jahm] dari [Zirr bin Hubaisy] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mengenakan pakaian dengan penuh kesombongan (pamer), maka Allah akan berpaling darinya sampai dia melepaskan pakaian tersebut, kapan saja dia melepasnya.\""},"3564":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ وَعْلَةَ عَنْ ابْنِ عَبَّاسٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا إِهَابٍ دُبِغَ فَقَدْ طَهُرَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Zaid bin Aslam] dari [Abdurrahman bin Wa'lah] dari [Ibnu Abbas] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kulit (binatang) apa saja yang telah di samak, maka ia menjadi suci.\""},"3565":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ شَاةً لِمَوْلَاةِ مَيْمُونَةَ مَرَّ بِهَا يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُعْطِيَتْهَا مِنْ الصَّدَقَةِ مَيْتَةً فَقَالَ هَلَّا أَخَذُوا إِهَابَهَا فَدَبَغُوهُ فَانْتَفَعُوا بِهِ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّهَا مَيْتَةٌ قَالَ إِنَّمَا حُرِّمَ أَكْلُهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah], bahwa kambing milik mantan budak Maimunah yang telah ia berikan kepadanya sebagai sedekah lalu mati, diliwati oleh beliau -Nabi shallallahu 'alaihi wasallam-, maka beliau bersabda: \"Kenapa kalian tidak mengambil kulitnya dan menyamaknya hingga mereka dapat memanfaatkannya?\" mereka menjawab, \"Wahai Rasulullah, kambing itu telah mati! \" Beliau lalu bersabda: \"Yang diharamkan adalah memakannya.\""},"3566":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ لَيْثٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ سَلْمَانَ قَالَكَانَ لِبَعْضِ أُمَّهَاتِ الْمُؤْمِنِينَ شَاةٌ فَمَاتَتْ فَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهَا فَقَالَ مَا ضَرَّ أَهْلَ هَذِهِ لَوْ انْتَفَعُوا بِإِهَابِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Laits] dari [Syahr bin Hausyab] dari [Salman] dia berkata, \"Beberapa orang dari Ummul Mukminin memiliki kambing lalu mati, kemudian Rasulullah shallallahu 'alaihi wasallam lewat di dekatnya, maka beliau bertanya, \"Tidak mengapa jika pemilik kambing ini ingin memanfaatkan kulitnya.\""},"3567":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ يَزِيدَ بْنِ قُسَيْطٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُسْتَمْتَعَ بِجُلُودِ الْمَيْتَةِ إِذَا دُبِغَتْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Khalid bin Makhlad] dari [Malik bin Anas] dari [Yazid bin Qusaith] dari [Muhammad bin Abdurrahman] dari [Ibunya] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk memanfaatkan kulit bangkai binatang jika telah di samak.\""},"3568":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الشَّيْبَانِيِّ ح و حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ كُلُّهُمْ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَأَتَانَا كِتَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Jarir] dari [Manshur]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [As Syaibani]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] semuanya dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Abdullah bin 'Ukaim] dia berkata, \"Surat Nabi shallallahu 'alaihi wasallam datang menemui kami (isinya): \"Janganlah kalian mengambil manfaat dari bangkai, baik kulit maupun tulangnya.\""},"3569":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ الْعَبَّاسِ قَالَكَانَ لِنَعْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَالَانِ مَثْنِيٌّ شِرَاكُهُمَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Khalid Al Khadzdza`] dari [Abdullah bin Al Harits] dari [Abdullah bin Abbas] dia berkata, \"Sandal Nabi shallallahu 'alaihi wasallam memiliki dua tali yang bercabang dua.\""},"3570":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هَمَّامٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ لِنَعْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِبَالَانِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Hammam] dari [Qatadah] dari [Anas] dia berkata, \"Sandal Nabi shallallahu 'alaihi wasallam memiliki dua tali.\""},"3571":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا انْتَعَلَ أَحَدُكُمْ فَلْيَبْدَأْ بِالْيُمْنَى وَإِذَا خَلَعَ فَلْيَبْدَأْ بِالْيُسْرَى","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian memakai sandal, hendaklah ia memulainya dengan yang kanan, dan jika melepasnya hendaknya ia memulainya dari yang sebelah kiri.\""},"3572":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَمْشِي أَحَدُكُمْ فِي نَعْلٍ وَاحِدٍ وَلَا خُفٍّ وَاحِدٍ لِيَخْلَعْهُمَا جَمِيعًا أَوْ لِيَمْشِ فِيهِمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Idris] dari [Ibnu Ajlan] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian berjalan dengan mengenakan satu sandal atau satu khuf (sepatu), hendaknya ia melepas kedua-duanya atau memakainya semua.\""},"3573":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْتَعِلَ الرَّجُلُ قَائِمًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang memakai sandal sambil berdiri.\""},"3574":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْتَعِلَ الرَّجُلُ قَائِمًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang memakai sandal sambil berdiri.\""},"3575":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا دَلْهَمُ بْنُ صَالِحٍ الْكِنْدِيُّ عَنْ حُجَيْرِ بْنِ عَبْدِ اللَّهِ الْكِنْدِيِّ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّجَاشِيَّ أَهْدَى لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُفَّيْنِ سَاذَجَيْنِ أَسْوَدَيْنِ فَلَبِسَهُمَا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Dalham bin Shalih Al Kindi] dari [Hujair bin Abdullah Al Kindi] dari [Ibnu Buraidah] dari [ayahnya], bahwa An Najasyi memberi hadiah kepada Rasulullah shallallahu 'alaihi wasallam dua khuf (sepatu) yang berwarna hitam polos, kemudian beliau mengenakannya.\""},"3576":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ سَمِعَ أَبَا سَلَمَةَ وَسُلَيْمَانَ بْنَ يَسَارٍ يُخْبِرَانِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْيَهُودَ وَالنَّصَارَى لَا يَصْبُغُونَ فَخَالِفُوهُمْ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dia mendengar [Abu Salamah] dan [Sulaiman bin Yasar], keduanya mengabarkan kepadanya dari [Abu Hurairah] dan sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang-orang Yahudi dan Nashrani tidak menyemir rambut, oleh karena itu selisihilah mereka.\""},"3577":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْأَجْلَحِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ الدَّيْلَمِيِّ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحْسَنَ مَا غَيَّرْتُمْ بِهِ الشَّيْبَ الْحِنَّاءُ وَالْكَتَمُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Idris] dari [Al Ajlah] dari [Abdullah bin Buraidah] dari [Abu Al Aswad Ad Dailami] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, sebaik-baik yang kalian gunakan untuk merubah uban adalah pohon pacar (inai) dan katam (sejenis tumbuhan).\""},"3578":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا سَلَّامُ بْنُ أَبِي مُطِيعٍ عَنْ عُثْمَانَ بْنِ مَوْهَبٍ قَالَدَخَلْتُ عَلَى أُمِّ سَلَمَةَ قَالَ فَأَخْرَجَتْ إِلَيَّ شَعَرًا مِنْ شَعْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَخْضُوبًا بِالْحِنَّاءِ وَالْكَتَمِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Sallam bin Abu Muthi'] dari [Utsman bin Mauhab] dia berkata, \"Saya menemui Ummu Salamah.\" Utsman melanjutkan, \"Kemudian [Ummu Salamah] mengeluarkan sehelai rambut dari rambut Rasulullah shallallahu 'alaihi wasallam yang telah di semir dengan inai dan katam (semacam tumbuhan).\""},"3579":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ لَيْثٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَجِيءَ بِأَبِي قُحَافَةَ يَوْمَ الْفَتْحِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَأَنَّ رَأْسَهُ ثَغَامَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبُوا بِهِ إِلَى بَعْضِ نِسَائِهِ فَلْتُغَيِّرْهُ وَجَنِّبُوهُ السَّوَادَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Laits] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Ketika penaklukan kota Makkah Abu Quhafah di datangkan kepada Nabi shallallahu 'alaihi wasallam dan seakan-akan rambutnya seperti pohon tsaghamah (sejenis pohon yang buah dan bunganya berwarna putih). Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Bawalah ia menemui salah seorang dari isterinya supaya ia menyemir rambutnya, dan hindarilah warna hitam.\""},"3580":{"ar":"حَدَّثَنَا أَبُو هُرَيْرَةَ الصَّيْرَفِيُّ مُحَمَّدُ بْنُ فِرَاسٍ حَدَّثَنَا عُمَرُ بْنُ الْخَطَّابِ بْنِ زَكَرِيَّا الرَّاسِبِيُّ حَدَّثَنَا دَفَّاعُ بْنُ دَغْفَلٍ السَّدُوسِيُّ عَنْ عَبْدِ الْحَمِيدِ بْنِ صَيْفِيٍّ عَنْ أَبِيهِ عَنْ جَدِّهِ صُهَيْبِ الْخَيْرِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحْسَنَ مَا اخْتَضَبْتُمْ بِهِ لَهَذَا السَّوَادُ أَرْغَبُ لِنِسَائِكُمْ فِيكُمْ وَأَهْيَبُ لَكُمْ فِي صُدُورِ عَدُوِّكُمْ","id":"Telah menceritakan kepada kami [Abu Hurairah Ash Shairafi Muhammad bin Firas] telah menceritakan kepada kami [Umar bin Al Khaththab bin Zakaria Ar Rasibi] telah menceritakan kepada kami [Daffa' bin Daghfal As Sadusi] dari [Abdul Hamid bin Shaifi] dari [Ayahnya] dari kakeknya [Shuihaib Al Khair] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, sesuatu yang paling baik kalian gunakan untuk mengecat rambut adalah warna hitam ini, karena dia lebih disukai oleh isteri-isteri kalian, dan kalian bisa membuat takut musuh-musuh kalian.\""},"3581":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ أَنَّ عُبَيْدَ بْنَ جُرَيْجٍ سَأَلَ ابْنَ عُمَرَ قَالَرَأَيْتُكَ تُصَفِّرُ لِحْيَتَكَ بِالْوَرْسِ فَقَالَ ابْنُ عُمَرَ أَمَّا تَصْفِيرِي لِحْيَتِي فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَفِّرُ لِحْيَتَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari ['Ubaidullah bin Umar] dari [Sa'id bin Abu Sa'id] bahwa [Ubaid bin Juraij] bertanya kepada [Ibnu Umar] ia berkata, \"Aku melihatmu mengecat kuning jenggotmu dengan Al Wars (sejenis tumbuhan).\" Lantas Ibnu Umar berkata, \"Aku mengecat kuning jenggotku ini, karena aku melihat Rasulullah shallallahu 'alaihi wasallam mengecat kuning jenggotnya.\""},"3582":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ عَنْ حُمَيْدِ بْنِ وَهْبٍ عَنْ ابْنِ طَاوُسٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ قَدْ خَضَبَ بِالْحِنَّاءِ فَقَالَ مَا أَحْسَنَ هَذَا ثُمَّ مَرَّ بِآخَرَ قَدْ خَضَبَ بِالْحِنَّاءِ وَالْكَتَمِ فَقَالَ هَذَا أَحْسَنُ مِنْ هَذَا ثُمَّ مَرَّ بِآخَرَ قَدْ خَضَبَ بِالصُّفْرَةِ فَقَالَ هَذَا أَحْسَنُ مِنْ هَذَا كُلِّهِقَالَ وَكَانَ طَاوُسٌ يُصَفِّرُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Muhammad bin Thalhah] dari [Humaid bin Wahb] dari [Ibnu Thawus] dari [Thawus] dari [Ibnu Abbas] dia berkata, \"Nabi shallallahu 'alaihi wasallam melewati seorang lelaki yang telah mengecat rambutnya dengan inai, maka beliau bersabda: \"Alangkah bagusnya ini.\" Kemudian beliau melewati orang lain yang telah mengecat dengan inai dan katam (sejenis pohon inai), maka beliau bersabda: \"Ini lebih bagus ketimbang yang ini.\" Kemudian beliau melewati orang yang lainnya yang telah mengecat dengan shufrah (sejenis tumbuhan yang baunya wangi dan berwarna kuning), maka beliau bersabda: \"Ini lebih baik dari semuanya.\" Ibnu Thawus berkata, \"Oleh karenanya Thawus mengecat (rambutnya) dengan shufrah.\""},"3583":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي جُحَيْفَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ مِنْهُ بَيْضَاءُ يَعْنِي عَنْفَقَتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Abu Juhaifah] dia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam pada bagian ininya putih.\" -maksudnya adalah pada bagian rambut di bawah bibir-."},"3584":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ وَابْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ قَالَ سُئِلَ أَنَسُ بْنُ مَالِكٍأَخَضَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهُ لَمْ يَرَ مِنْ الشَّيْبِ إِلَّا نَحْوَ سَبْعَةَ عَشَرَ أَوْ عِشْرِينَ شَعَرَةً فِي مُقَدَّمِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Khalid bin Al Harits] dan [Ibnu Abu 'Adi] dari [Humaid] dia berkata, \" [Anas bin Malik] ditanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam menyemir rambutnya?\" dia menjawab, \"Sesungguhnya uban beliau tidak terlihat kecuali hanya tujuh belas helai atau dua puluh helai di jenggot bagian depan.\""},"3585":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ الْوَلِيدِ الْكِنْدِيُّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ شَرِيكٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ شَيْبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ عِشْرِينَ شَعَرَةً","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Al Walid Al Kindi] telah menceritakan kepada kami [Yahya bin Adam] dari [Syarik] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rambut uban Rasulullah shallallahu 'alaihi wasallam hanya sekitar dua puluh helai.\""},"3586":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَ قَالَتْ أُمُّ هَانِئٍدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَلَهُ أَرْبَعُ غَدَائِرَ تَعْنِي ضَفَائِرَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dia berkata, \" [Ummu Hani`] berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam memasuki kota Makkah, beliau memiliki empat ghada`ir, yaitu jalinan rambut yang terurai.\""},"3587":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ أَهْلُ الْكِتَابِ يَسْدُلُونَ أَشْعَارَهُمْ وَكَانَ الْمُشْرِكُونَ يَفْرُقُونَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ مُوَافَقَةَ أَهْلِ الْكِتَابِ قَالَ فَسَدَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاصِيَتَهُ ثُمَّ فَرَقَ بَعْدُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] dari [Ibrahim bin Sa'd] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dia berkata, \"Para ahli kitab (Yahudi dan Nashrani) membelah dua rambut mereka, sedangkan orang-orang Musyrik mengurai rambut mereka, dan Rasulullah shallallahu 'alaihi wasallam senang seperti ahli Kitab.\" Anas berkata, \"Rasulullah shallallahu 'alaihi wasallam mengurai rambutnya dan membelah menjadi dua.\" "},"3588":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ ابْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَفْرِقُ خَلْفَ يَافُوخِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَسْدِلُ نَاصِيَتَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ishaq bin Manshur] dari [Ibrahim bin Sa'd] dari [Ibnu Ishaq] dari [Yahya bin 'Abbad] dari [ayahnya] dari [Aisyah] dia berkata, \"Aku membelah (rambut) di belakang ubun-ubun Rasulullah shallallahu 'alaihi wasallam, kemudian aku menguraikannya hingga ke dahi.\""},"3589":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ شَعَرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَعَرًا رَجِلًا بَيْنَ أُذُنَيْهِ وَمَنْكِبَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Jariri bin Hazim] dari [Qatadah] dari [Anas] dia berkata, \"Rambut Rasulullah shallallahu 'alaihi wasallam lurus ikal, terurai antara telinga dan pundaknya.\""},"3590":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي الزِّنَادِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَعَرٌ دُونَ الْجُمَّةِ وَفَوْقَ الْوَفْرَةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Abdurrahman bin Abu Az Zinad] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam memiliki rambut yang menjuntai tidak lebih dari pundaknya, dan di atas kedua daun telinganya.\""},"3591":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ وَسُفْيَانُ بْنُ عُقْبَةَ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَآنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِي شَعَرٌ طَوِيلٌ فَقَالَ ذُبَابٌ ذُبَابٌ فَانْطَلَقْتُ فَأَخَذْتُهُ فَرَآنِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي لَمْ أَعْنِكَ وَهَذَا أَحْسَنُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dan [Sufyan bin 'Uqbah] dari [Sufyan] dari ['Ashim bin Kulaib] dari [Ayahnya] dari [Wa`il bin Hujr] dia berkata, \"Nabi shallallahu 'alaihi wasallam melihatku sementara aku memiliki rambut yang panjang, beliau lalu bersabda: \"Lalat, lalat (maksudnya sesuatu yang buruk).\" Maka aku pun pergi dan memotongnya, kemudian beliau melihatku dan bersabda: \"Sesungguhnya aku tidak bermaksud menyakitimu, akan tetapi hal ini lebih baik.\""},"3592":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ عُمَرَ بْنِ نَافِعٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَزَعِقَالَ وَمَا الْقَزَعُ قَالَ أَنْ يُحْلَقَ مِنْ رَأْسِ الصَّبِيِّ مَكَانٌ وَيُتْرَكَ مَكَانٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Ubaidullah bin Umar] dari [Umar bin Nafi'] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari qaza'.\" Nafi' berkata, \"Apakah yang di maksud dengan qaza' itu?\" Ibnu Umar menjawab, \"Yaitu mencukur sebagian rambut anak kecil dan membiarkan sebagian yang lain.\""},"3593":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَزَعِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari qaza'.\" "},"3594":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَاتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ وَرِقٍ ثُمَّ نَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ فَقَالَ لَا يَنْقُشْ أَحَدٌ عَلَى نَقْشِ خَاتَمِي هَذَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ayyub bin Musa] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam membuat cincin dari perak, kemudian mengukirnya dengan tulisan 'Muhammad Rasulullah'.\" Lalu beliau bersabda: \"Janganlah salah seseorang mengukir cincinnya seperti cincinku ini.\""},"3595":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَاصْطَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا فَقَالَ إِنَّا قَدْ اصْطَنَعْنَا خَاتَمًا وَنَقَشْنَا فِيهِ نَقْشًا فَلَا يَنْقُشْ عَلَيْهِ أَحَدٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam membuat cincin, lalu beliau bersabda: \"Sesungguhnya aku telah membuat cincin dan telah mengukirnya dengan suatu ukiran, maka janganlah salah seorang mengukirnya (seperti ukiran yang serupa).\""},"3596":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ لَهُ فَصٌّ حَبَشِيٌّ وَنَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam membuat cincin dari perak yang mata batunya dari negeri Habsyah dan berukirkan 'Muhammad Rasulullah'.\""},"3597":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ حُنَيْنٍ مَوْلَى عَلِيٍّ عَنْ عَلِيٍّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّخَتُّمِ بِالذَّهَبِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Hunain] mantan budak Ali, dari [Ali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengenakan cincin (yang terbuat) dari emas.\""},"3598":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ الْحَسَنِ بْنِ سُهَيْلٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Ali bin Mushir] dari [Yazid bin Abu Ziyad] dari [Al Hasan bin Suhail] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang (mengenakan) cincin dari emas.\""},"3599":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْأَهْدَى النَّجَاشِيُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَلْقَةً فِيهَا خَاتَمُ ذَهَبٍ فِيهِ فَصٌّ حَبَشِيٌّ فَأَخَذَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعُودٍ وَإِنَّهُ لَمُعْرِضٌ عَنْهُ أَوْ بِبَعْضِ أَصَابِعِهِ ثُمَّ دَعَا بِابْنَةِ ابْنَتِهِ أُمَامَةَ بِنْتِ أَبِي الْعَاصِ فَقَالَ تَحَلِّي بِهَذَا يَا بُنَيَّةُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dari [Muhammad bin Ishaq] dari [Yahya bin 'Abbad bin Abdullah bin Az Zubair] dari [Ayahnya] dari [Aisyah] Ummul Mukminin, dia berkata, \"Raja Najasyi menghadiahkan kepada Nabi shallallahu 'alaihi wasallam perhiasan yang di antaranya ada cincin emas yang batu cincinnya dari Habasyah. Rasulullah shallallahu 'alaihi wasallam lalu mengambilnya dengan sebatang kayu dan beliau berpaling darinya -atau mengambilnya dengan jari-jari tangannya-, kemudian beliau memanggil cucu perempuannya, Umamah binti Al 'Ash, sambil bersabda: \"Berhiaslah kamu dengan ini wahai puteriku.\""},"3600":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْعَلُ فَصَّ خَاتَمِهِ مِمَّا يَلِي كَفَّهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ayyub bin Musa] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam menghadapkan batu cincinnya pada telapak tangannya.\""},"3601":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يُونُسَ بْنِ يَزِيدَ الْأَيْلِيِّ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبِسَ خَاتَمَ فِضَّةٍ فِيهِ فَصٌّ حَبَشِيٌّ كَانَ يَجْعَلُ فَصَّهُ فِي بَطْنِ كَفِّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Isma'il bin Abu Uwais] telah menceritakan kepadaku [Sulaiman bin Bilal] dari [Yunus bin Yazid Al Aili] dari [Ibnu Syihab] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam mengenakan cincin yang terbuat dari perak dan mata batunya dari Habasyah, beliau lalu menghadapkan batu cincinnya ke arah telapak tangan.\""},"3602":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ إِبْرَاهِيمَ بْنِ الْفَضْلِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَخَتَّمُ فِي يَمِينِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numir] dari [Ibrahim bin Al Fadll] dari [Abdullah bin Muhammad bin 'Aqil] dari [Abdullah bin Ja'far], bahwa Nabi shallallahu 'alaihi wasallam mengenakan cincin di tangan kanannya.\""},"3603":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ عَاصِمٍ عَنْ أَبِي بُرْدَةَ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَتَخَتَّمَ فِي هَذِهِ وَفِي هَذِهِ يَعْنِي الْخِنْصَرَ وَالْإِبْهَامَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari ['Ashim] dari [Abu Burdah] dari [Ali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku mengenakan cincin di sini dan di sini.\" -yaitu di jari kelingking dan jempol-."},"3604":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ أَبِي طَلْحَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Abu Thalhah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat anjing dan gambar.\""},"3605":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ عَنْ عَبْدِ اللَّهِ بْنِ نُجَيٍّ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَلَائِكَةَ لَا تَدْخُلُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Ali bin Mudrik] dari [Abu Zur'ah] dari [Abdullah bin Nujjay] dari [Ayahnya] dari [Ali bin Abu Thalib] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Malaikat tidak akan masuk ke dalam rumah yang di dalamnya terdapat anjing dan gambar.\""},"3606":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْوَاعَدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِبْرِيلُ عَلَيْهِ السَّلَام فِي سَاعَةٍ يَأْتِيهِ فِيهَا فَرَاثَ عَلَيْهِ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ بِجِبْرِيلَ قَائِمٌ عَلَى الْبَابِ فَقَالَ مَا مَنَعَكَ أَنْ تَدْخُلَ قَالَ إِنَّ فِي الْبَيْتِ كَلْبًا وَإِنَّا لَا نَدْخُلُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Aisyah] dia berkata, \"Jibril berjanji akan bertemu Rasulullah shallallahu 'alaihi wasallam pada waktu yang telah di tentukan, dan beliau menunggu lama. Kemudian Nabi shallallahu 'alaihi wasallam keluar rumah, dan ternyata Jibril tengah berdiri di depan pintu, beliau pun bertanya: \"Apa yang menghalangimu masuk?\" Jibril menjawab, \"Di dalam rumahmu ada anjing, dan sungguh kami tidak akan masuk ke dalam rumah yang di dalamnya terdapat anjing dan gambar.\""},"3607":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا عُفَيْرُ بْنُ مَعْدَانَ حَدَّثَنَا سُلَيْمُ بْنُ عَامِرٍ عَنْ أَبِي أُمَامَةَأَنَّ امْرَأَةً أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَتْهُ أَنَّ زَوْجَهَا فِي بَعْضِ الْمَغَازِي فَاسْتَأْذَنَتْهُ أَنْ تُصَوِّرَ فِي بَيْتِهَا نَخْلَةً فَمَنَعَهَا أَوْ نَهَاهَا","id":"Telah menceritakan kepada kami [Al 'Abbas bin 'Utsman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami ['Ufair bin Ma'dan] telah menceritakan kepada kami [Sulaim bin 'Amir] dari [Abu Umamah], bahwa seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam dan memberitahukan kepada beliau bahwa suaminya berada di kancah pertempuran, kemudian dia meminta izin kepada beliau untuk menggambar pohon kurma di dalam rumahnya, namun beliau mencegahnya atau melarangnya.\""},"3608":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْسَتَرْتُ سَهْوَةً لِي تَعْنِي الدَّاخِلَ بِسِتْرٍ فِيهِ تَصَاوِيرُ فَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَتَكَهُ فَجَعَلْتُ مِنْهُ مَنْبُوذَتَيْنِ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا عَلَى إِحْدَاهُمَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Usamah bin Zaid] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Aisyah] dia berkata, \"Aku menutup bufetku yaitu yang ada di dalam dengan menggunakan kain yang bergambar, ketika Nabi shallallahu 'alaihi wasallam datang beliau langsung memotongnya, maka aku pun menjadikannya dua bantal, (suatu ketika) aku melihat Rasulullah shallallahu 'alaihi wasallam bersandar pada salah satunya.\""},"3609":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ هُبَيْرَةَ عَنْ عَلِيٍّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ الْمِيثَرَةِ يَعْنِي الْحَمْرَاءَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Hubairah] dari [Ali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang penggunaan cincin emas dan alas pelana yang terbuat dari sutera.\""},"3610":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي عَيَّاشُ بْنُ عَبَّاسٍ الْحِمْيَرِيُّ عَنْ أَبِي حُصَيْنٍ الْحَجْرِيِّ الْهَيْثَمِ عَنْ عَامِرٍ الْحَجْرِيِّ قَالَ سَمِعْتُ أَبَا رَيْحَانَةَ صَاحِبَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ رُكُوبِ النُّمُورِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Hubab] telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepadaku ['Ayyasy bin 'Abbas al Himyari] dari [Abu Hushain Al Hajri Al Haitsam] dari ['Amir Al Hajri] dia berkata; saya mendengar [Abu Raihanah] salah seorang sahabat Nabi shallallahu 'alaihi wasallam, berkata, \"Nabi shallallahu 'alaihi wasallam melarang untuk menunggangi harimau.\""},"3611":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ أَبِي الْمُعْتَمِرِ عَنْ ابْنِ سِيرِينَ عَنْ مُعَاوِيَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ رُكُوبِ النُّمُورِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Abu Mu'tamir] dari [Ibnu Sirin] dari [Mu'awiyah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang untuk mengendarai harimau.\""},"3612":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ مَنْصُورٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَلِيٍّ عَنْ ابْنِ سَلَامَةَ السُّلَمِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُوصِي امْرَأً بِأُمِّهِ أُوصِي امْرَأً بِأُمِّهِ أُوصِي امْرَأً بِأُمِّهِ ثَلَاثًا أُوصِي امْرَأً بِأَبِيهِ أُوصِي امْرَأً بِمَوْلَاهُ الَّذِي يَلِيهِ وَإِنْ كَانَ عَلَيْهِ مِنْهُ أَذًى يُؤْذِيهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Syarik bin Abdullah] dari [Manshur] dari ['Ubaidullah bin Ali] dari [Ibnu Salamah As Sulami] dia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Suruhlah seseorang berbuat baik kepada ibunya, suruhlah seseorang berbuat baik terhadap ibunya, suruhlah seseorang berbuat baik terhadap ibunya -beliau mengucapkannya hingga tiga kali-. Suruhlah seseorang berbuat baik terhadap ayahnya, dan suruhlah seseorang berbuat baik terhadap kerabatnya, walaupun kerabatnya itu menyakiti dia.\""},"3613":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَيْمُونٍ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالُوا يَا رَسُولَ اللَّهِ مَنْ أَبَرُّ قَالَ أُمَّكَ قَالَ ثُمَّ مَنْ قَالَ أُمَّكَ قَالَ ثُمَّ مَنْ قَالَ أَبَاكَ قَالَ ثُمَّ مَنْ قَالَ الْأَدْنَى فَالْأَدْنَى","id":"Telah menceritakan kepada kami [Muhammad bin Maimun Al Makki] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Umarah bin Al qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Para sahabat bertanya, \"Wahai Rasulullah, siapakah orang (yang layak) aku berbakti kepadanya?\" beliau bersabda: \"Ibumu.\" Abu Hurairah bertanya lagi, \"Kemudian siapa?\" beliau menjawab: \"Ibumu.\" Dia bertanya lagi, \"Kemudian siapa?\" beliau menjawab: \"Ibumu.\" Dia bertanya lagi, \"Kemudian siapa lagi?\" beliau menjawab: \"Ayahmu.\" Dia bertanya lagi, \"Kemudian siapa?\" beliau menjawab: \"Orang yang ada di bawahnya dan seterusnya.\""},"3614":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَجْزِي وَلَدٌ وَالِدًا إِلَّا أَنْ يَجِدَهُ مَمْلُوكًا فَيَشْتَرِيَهُ فَيُعْتِقَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang anak belum di anggap berbakti terhadap orang tuanya kecuali jika ia mendapati orang tuanya telah menjadi budak, kemudian ia membelinya dan memerdekakannya.\""},"3615":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْقِنْطَارُ اثْنَا عَشَرَ أَلْفَ أُوقِيَّةٍ كُلُّ أُوقِيَّةٍ خَيْرٌ مِمَّا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرَّجُلَ لَتُرْفَعُ دَرَجَتُهُ فِي الْجَنَّةِ فَيَقُولُ أَنَّى هَذَا فَيُقَالُ بِاسْتِغْفَارِ وَلَدِكَ لَكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdush Shamad bin Abdul Warits] dari [Hammad bin Salamah] dari ['Ashim] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Satu Qinthar adalah dua belas ribu uqiyah, dan setiap satu uqiyah lebih baik dari pada apa yang ada di antara langit dan bumi.\" Rasulullah shallallahu 'alaihi wasallam juga bersabda: \"Sesungguhnya seseorang akan di angkat derajatnya di surga, lalu orang tersebut akan bertanya, 'Bagaimana ini bisa terjadi? ' lalu dijawab, 'Karena anakmu telah memohonkan ampun untukmu'.\""},"3616":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ بْنِ مَعْدِ يكَرِبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يُوصِيكُمْ بِأُمَّهَاتِكُمْ ثَلَاثًا إِنَّ اللَّهَ يُوصِيكُمْ بِآبَائِكُمْ إِنَّ اللَّهَ يُوصِيكُمْ بِالْأَقْرَبِ فَالْأَقْرَبِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'dikarib], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah mewasiyatkan kalian supaya berbakti kepada ibu-ibu kalian -beliau mengucapkan hingga tiga kali-, berbakti kepada bapak-bapak kalian, berbakti kepada kaum kerabat kalian, lalu kepada kerabat yang lebih dekat lagi.\""},"3617":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي الْعَاتِكَةِ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ مَا حَقُّ الْوَالِدَيْنِ عَلَى وَلَدِهِمَا قَالَ هُمَا جَنَّتُكَ وَنَارُكَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Shadaqah bin Khalid] telah menceritakan kepada kami [Utsman bin Abu Al 'Atikah] dari [Ali bin Yazid] dari [Al Qasim] dari [Abu Umamah], bahwa seorang lelaki bertanya, \"Wahai Rasulullah, apakah hak kedua orang tua terhadap anaknya?\" Beliau menjawab: \"Keduanya adalah surgamu dan nerakamu.\""},"3618":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَطَاءٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي الدَّرْدَاءِسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْوَالِدُ أَوْسَطُ أَبْوَابِ الْجَنَّةِ فَأَضِعْ ذَلِكَ الْبَابَ أَوْ احْفَظْهُ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabbah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Atha] dari [Abu Abdurrahman] dari [Abu Ad Darda] dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Orang tua ibarat penengah pintu-pintu surga, oleh karena itu (jika kamu mau) hilangkanlah ia atau jagalah ia baik-baik.\""},"3619":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سُلَيْمَانَ عَنْ أَسِيدِ بْنِ عَلِيِّ بْنِ عُبَيْدٍ مَوْلَى بَنِي سَاعِدَةَ عَنْ أَبِيهِ عَنْ أَبِي أُسَيْدٍ مَالِكِ بْنِ رَبِيعَةَ قَالَبَيْنَمَا نَحْنُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَجُلٌ مِنْ بَنِي سَلَمَةَ فَقَالَ يَا رَسُولَ اللَّهِ أَبَقِيَ مِنْ بِرِّ أَبَوَيَّ شَيْءٌ أَبَرُّهُمَا بِهِ مِنْ بَعْدِ مَوْتِهِمَا قَالَ نَعَمْ الصَّلَاةُ عَلَيْهِمَا وَالِاسْتِغْفَارُ لَهُمَا وَإِيفَاءٌ بِعُهُودِهِمَا مِنْ بَعْدِ مَوْتِهِمَا وَإِكْرَامُ صَدِيقِهِمَا وَصِلَةُ الرَّحِمِ الَّتِي لَا تُوصَلُ إِلَّا بِهِمَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abdullah bin Idris] dari [Abdurrahman bin Sulaiman] dari [Asid bin Ali bin 'Ubaid] mantan budak Bani Sa'idah, dari [Ayahnya] dari [Abu Usaid Malik bin Rabi'ah] dia berkata, \"Ketika kami berada di samping Nabi shallallahu 'alaihi wasallam, tiba-tiba seorang laki-laki dari Bani Salamah datang kepada beliau dan bertanya, Wahai Rasulullah, apakah masih tersisa sesuatu untuk berbakti kepada kedua orang tuaku setelah keduanya meninggal?\" Beliau menjawab: \"Ya, yaitu berdo'a kepada keduanya, meminta ampun untuk keduanya, melaksanakan janji-janji keduanya setelah keduanya meninggal, memuliakan teman keduanya dan tidak menyambung silaturrahim kecuali karena keduanya.\""},"3620":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَدِمَ نَاسٌ مِنْ الْأَعْرَابِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا أَتُقَبِّلُونَ صِبْيَانَكُمْ قَالُوا نَعَمْ فَقَالُوا لَكِنَّا وَاللَّهِ مَا نُقَبِّلُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمْلِكُ أَنْ كَانَ اللَّهُ قَدْ نَزَعَ مِنْكُمْ الرَّحْمَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata, \"Sekelompok orang badui datang menemui Rasulullah shallallahu 'alaihi wasallam, mereka berkata, \"Apakah kalian mencium anak-anak kalian?\" Para sahabat menjawab, \"Ya.\" Maka orang-orang Arab badui itu berkata, \"Demi Allah, kami tidak pernah melakukannya.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku memiliki apa yang telah Allah hilangkan dari sikap kasih sayang kalian.\""},"3621":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ أَبِي رَاشِدٍ عَنْ يَعْلَى الْعَامِرِيِّأَنَّهُ قَالَ جَاءَ الْحَسَنُ وَالْحُسَيْنُ يَسْعَيَانِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَمَّهُمَا إِلَيْهِ وَقَالَ إِنَّ الْوَلَدَ مَبْخَلَةٌ مَجْبَنَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin 'Utsman bin Khutsaim] dari [Sa'id bin Abu Rasyid] dari [Ya'la Al 'Amiri] bahwa dia berkata, \"Al Hasan dan Al Husain berusaha datang kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau memeluk mereka berdua sambil bersabda: \"Sesungguhnya anak adalah tempat kebakhilan dan kekhawatiran.\""},"3622":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مُوسَى بْنِ عُلَيٍّ سَمِعْتُ أَبِي يَذْكُرُ عَنْ سُرَاقَةَ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أَدُلُّكُمْ عَلَى أَفْضَلِ الصَّدَقَةِ ابْنَتُكَ مَرْدُودَةً إِلَيْكَ لَيْسَ لَهَا كَاسِبٌ غَيْرُكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Hubab] dari [Musa bin Ali] saya mendengar [Ayahku] menyebutkan dari [Suraqah bin Malik], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Maukah aku tunjukkan kepada kalian sebaik-baik sedekah? Yaitu puterimu di kembalikan kepadamu, sedangkan ia tidak memiliki sandaran hidup (yang membiayai) selain dirimu.\""},"3623":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مِسْعَرٍ أَخْبَرَنِي سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ الْحَسَنِ عَنْ صَعْصَعَةَ عَمِّ الْأَحْنَفِ قَالَدَخَلَتْ عَلَى عَائِشَةَ امْرَأَةٌ مَعَهَا ابْنَتَانِ لَهَا فَأَعْطَتْهَا ثَلَاثَ تَمَرَاتٍ فَأَعْطَتْ كُلَّ وَاحِدَةٍ مِنْهُمَا تَمْرَةً ثُمَّ صَدَعَتْ الْبَاقِيَةَ بَيْنَهُمَا قَالَتْ فَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثَتْهُ فَقَالَ مَا عَجَبُكِ لَقَدْ دَخَلَتْ بِهِ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Mis'ar] telah mengabarkan kepadaku [Sa'd bin Ibrahim] dari [Al Hasan] dari [Sha'sha'ah] pamannya Al Ahnaf, dia berkata, \"Seorang wanita yang membawa dua anaknya datang menemui Aisyah, Aisyah lalu memberinya tiga butir kurma. Wanita itu kemudian memberi dari masing-masing anaknya satu buah, lalu ia membelah sisanya untuk keduanya itu.\" [Aisyah] berkata, \"Ketika Nabi shallallahu 'alaihi wasallam datang, aku kemudian menceritakannya kepada beliau, maka beliau bersabda: \"Apa yang membuatmu heran dengan sikap wanita itu? Dengannya wanita itu akan masuk surga.\""},"3624":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ حَرْمَلَةَ بْنِ عِمْرَانَ قَالَ سَمِعْتُ أَبَا عُشَانَةَ الْمُعَافِرِيَّ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ لَهُ ثَلَاثُ بَنَاتٍ فَصَبَرَ عَلَيْهِنَّ وَأَطْعَمَهُنَّ وَسَقَاهُنَّ وَكَسَاهُنَّ مِنْ جِدَتِهِ كُنَّ لَهُ حِجَابًا مِنْ النَّارِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Al Husain bin Hasan Al Mawarzi] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Harmalah bin 'Imran] dia berkata; saya mendengar [Abu 'Usyanah Al Mu'afiri] berkata; saya mendengar ['Uqbah bin 'Amir] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki tiga orang anak perempuan, lalu ia dapat bersabar dalam mengurusi mereka, memberinya makan, minum serta pakaian kepada mereka dari usaha kerasnya, maka mereka akan menjadi penghalang baginya dari api neraka di hari Kiamat kelak.\""},"3625":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْحَسَنِ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ فِطْرٍ عَنْ أَبِي سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ رَجُلٍ تُدْرِكُ لَهُ ابْنَتَانِ فَيُحْسِنُ إِلَيْهِمَا مَا صَحِبَتَاهُ أَوْ صَحِبَهُمَا إِلَّا أَدْخَلَتَاهُ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Al Husain bin Al Hasan] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Fithr] dari [Abu Sa'id] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki mengurusi (beban hidup) kedua puterinya, dia berbuat baik kepada keduanya selama keduanya bersama dia, atau dia bersama keduanya, kecuali keduanya akan memasukkannya ke dalam surga.\""},"3626":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ حَدَّثَنَا سَعِيدُ بْنُ عُمَارَةَ أَخْبَرَنِي الْحَارِثُ بْنُ النُّعْمَانِ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَكْرِمُوا أَوْلَادَكُمْ وَأَحْسِنُوا أَدَبَهُمْ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Al Walid Ad Dimasyqi] telah menceritakan kepada kami [Ali bin 'Ayyasy] telah menceritakan kepada kami [Sa'id bin 'Umarah] telah mengabarkan kepadaku [Al Harits bin An Nu'man] saya mendengar [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Muliakanlah anak-anak kalian dan perbaikilah tingkah laku mereka.\""},"3627":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ نَافِعَ بْنَ جُبَيْرٍ يُخْبِرُ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُحْسِنْ إِلَى جَارِهِ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَسْكُتْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru bin Dinar] dia mendengar [Nafi' bin Jubair] mengabarkan dari [Abu Syuraih Al Khuza'i], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman pada Allah dan hari Akhir hendaknya ia berbuat baik terhadap tetangganya, dan barangsiapa beriman kepada Allah dan hari Akhir hendaknya ia memuliakan tamunya, dan barangsiapa beriman kepada Allah dan hari Akhir hendaknya ia berbicara baik atau diam.\""},"3628":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ وَعَبْدَةُ بْنُ سُلَيْمَانَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ جَمِيعًا عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا زَالَ جِبْرِيلُ يُوصِينِي بِالْجَارِ حَتَّى ظَنَنْتُ أَنَّهُ سَيُوَرِّثُهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin harun] dan ['Abdah bin Sulaiman]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] semuanya dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari ['Amrah] dari [Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril masih terus berwasiat kepadaku untuk berbuat baik terhadap tetangga, sampai aku mengira bahwa tetangga akan menjadi ahli waris.\""},"3629":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ مُجَاهِدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا زَالَ جِبْرَائِيلُ يُوصِينِي بِالْجَارِ حَتَّى ظَنَنْتُ أَنَّهُ سَيُوَرِّثُهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Mujahid] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril masih saja berwasiat kepadaku untuk berbuat baik kepada tetangga, sampai aku mengira bahwa tetangga juga akan menjadi ahli waris.\""},"3630":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَجَائِزَتُهُ يَوْمٌ وَلَيْلَةٌ وَلَا يَحِلُّ لَهُ أَنْ يَثْوِيَ عِنْدَ صَاحِبِهِ حَتَّى يُحْرِجَهُ الضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ وَمَا أَنْفَقَ عَلَيْهِ بَعْدَ ثَلَاثَةِ أَيَّامٍ فَهُوَ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu 'Ajlan] dari [Sa'id bin Abu Sa'id] dari [Abu Syuraih Al Khuza'i] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa beriman kepada Allah dan hari Akhir hendaknya ia memuliakan tamunya dan menjamunya sehari semalam, dan tidak boleh baginya (tamu) untuk menginap di rumah saudaranya hingga (saudaranya) merasa terganggu. Masa bertamu itu hanya tiga hari, dan apa yang di berikan untuk tamunya setelah tiga hari maka baginya adalah sedekah.\""},"3631":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَنَّهُ قَالَقُلْنَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ تَبْعَثُنَا فَنَنْزِلُ بِقَوْمٍ فَلَا يَقْرُونَا فَمَا تَرَى فِي ذَلِكَ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ نَزَلْتُمْ بِقَوْمٍ فَأَمَرُوا لَكُمْ بِمَا يَنْبَغِي لِلضَّيْفِ فَاقْبَلُوا وَإِنْ لَمْ يَفْعَلُوا فَخُذُوا مِنْهُمْ حَقَّ الضَّيْفِ الَّذِي يَنْبَغِي لَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] bahwa dia berkata, \"Kami berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Anda pernah mengutus kami, lalu kami singgah di suatu kaum, namun mereka menolak untuk menjamu kami, apa pendapat anda tentang hal itu?\" Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Apabila kalian singgah di suatu kaum, lalu mereka memerintahkan agar kalian di jamu layaknya tamu maka terimalah. Namun jika mereka tidak mengerjakan hal itu, maka ambillah dari mereka hak tamu yang layak.\""},"3632":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ الْمِقْدَامِ أَبِي كَرِيمَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةُ الضَّيْفِ وَاجِبَةٌ فَإِنْ أَصْبَحَ بِفِنَائِهِ فَهُوَ دَيْنٌ عَلَيْهِ فَإِنْ شَاءَ اقْتَضَى وَإِنْ شَاءَ تَرَكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [As Sya'bi] dari [Al Miqdam Abu Karimah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menjamu tamu (selama) satu malam adalah wajib, dan jika di pagi harinya tamu tersebut masih berada di pekarangan (rumah), maka ia adalah utang baginya. Jika mau ia boleh menjamunya (lagi), jika tidak maka ia boleh membiarkannya.\""},"3633":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أُحَرِّجُ حَقَّ الضَّعِيفَيْنِ الْيَتِيمِ وَالْمَرْأَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Ibnu 'Ajlan] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, sesungguhnya aku telah menetapkan sanksi atas hak dua orang yang lemah, yaitu hak anak yatim dan hak seorang wanita.\" "},"3634":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ سَعِيدِ بْنِ أَبِي أَيُّوبَ عَنْ يَحْيَى بْنِ سُلَيْمَانَ عَنْ زَيْدِ بْنِ أَبِي عَتَّابٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ بَيْتٍ فِي الْمُسْلِمِينَ بَيْتٌ فِيهِ يَتِيمٌ يُحْسَنُ إِلَيْهِ وَشَرُّ بَيْتٍ فِي الْمُسْلِمِينَ بَيْتٌ فِيهِ يَتِيمٌ يُسَاءُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Sa'id bin Abu Ayyub] dari [Yahya bin Sulaiman] dari [Zaid bin Abu 'Attab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik rumah di kalangan kaum muslimin adalah rumah yang terdapat anak yatim yang diperlakukan dengan baik. Dan sejelek-jelek rumah di kalangan kaum muslimin adalah rumah yang terdapat anak yatim dan dia diperlakukan dengan buruk.\""},"3635":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَمَّادُ بْنُ عَبْدِ الرَّحْمَنِ الْكَلْبِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ الْأَنْصَارِيُّ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَالَ ثَلَاثَةً مِنْ الْأَيْتَامِ كَانَ كَمَنْ قَامَ لَيْلَهُ وَصَامَ نَهَارَهُ وَغَدَا وَرَاحَ شَاهِرًا سَيْفَهُ فِي سَبِيلِ اللَّهِ وَكُنْتُ أَنَا وَهُوَ فِي الْجَنَّةِ أَخَوَيْنِ كَهَاتَيْنِ أُخْتَانِ وَأَلْصَقَ إِصْبَعَيْهِ السَّبَّابَةَ وَالْوُسْطَى","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Hammad bin Abdurrahman Al Kalbi] telah menceritakan kepada kami [Isma'il bin Ibrahim Al Anshari] dari ['Atha bin Abu Rabah] dari [Abdullah bin Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengurus tiga anak yatim maka ia ibarat orang yang melakukan qiyamul lail pada malam harinya, berpuasa pada siang harinya, berangkat pagi dan sore hari dengan pedang terhunus di jalan Allah, aku dan dia berada di surga seperti dua saudara sebagaimana dua ini yang bersaudara.\" Dan beliau menempelkan dua jarinya, yaitu jari telunjuk dan jari tengah.\""},"3636":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ أَبَانَ بْنِ صَمْعَةَ عَنْ أَبِي الْوَازِعِ الرَّاسِبِيِّ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ دُلَّنِي عَلَى عَمَلٍ أَنْتَفِعُ بِهِ قَالَ اعْزِلْ الْأَذَى عَنْ طَرِيقِ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Aban bin Sham'ah] dari [Abu Al Wazi' Ar Rasibi] dari [Abu Barzah Al Aslami] dia berkata, \"Saya berkata, \"Wahai Rasulullah, tunjukkanlah kepadaku suatu amalan yang dapat memberiku manfaat?\" beliau bersabda: \"Singkirkanlah gangguan (sesuatu yang membahayakan) dari jalan kaum Muslimin.\""},"3637":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ عَلَى الطَّرِيقِ غُصْنُ شَجَرَةٍ يُؤْذِي النَّاسَ فَأَمَاطَهَا رَجُلٌ فَأُدْخِلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada suatu jalan terdapat ranting pohon yang mengganggu orang-orang (yang lewat), lalu ada seseorang yang menyingkirkannya, maka ia pun di masukkan ke dalam surga.\""},"3638":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا هِشَامُ بْنُ حَسَّانَ عَنْ وَاصِلٍ مَوْلَى أَبِي عُيَيْنَةَ عَنْ يَحْيَى بْنِ عُقَيْلٍ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُرِضَتْ عَلَيَّ أُمَّتِي بِأَعْمَالِهَا حَسَنِهَا وَسَيِّئِهَا فَرَأَيْتُ فِي مَحَاسِنِ أَعْمَالِهَا الْأَذَى يُنَحَّى عَنْ الطَّرِيقِ وَرَأَيْتُ فِي سَيِّئِ أَعْمَالِهَا النُّخَاعَةَ فِي الْمَسْجِدِ لَا تُدْفَنُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Hisyam bin Hassan] dari [Washil] mantan budak Abu 'Uyainah, dari [Yahya bin 'Uqail] dari [Yahya bin Ya'mar] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ditampakkan kepadaku amalan-amalan yang pernah di kerjakan oleh ummatku, baik yang amalan jelek ataupun yang baik. Lalu aku melihat di dalam amal baiknya terdapat (ketika ia) menyingkirkan sesuatu yang membahayakan dari jalan, dan aku lihat dari amal-amal buruknya adalah berdahak di dalam masjid, namun dia tidak ditimbunnya.\""},"3639":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ صَاحِبِ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ عُبَادَةَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ سَقْيُ الْمَاءِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Hisyam pemilik Ad Dastuwa`i] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Sa'd bin 'Ubadah] dia berkata, \"Aku bertanya, \"Wahai Rasulullah, sedekah apakah yang paling utama?\" Beliau menjawab: \"Memberi air.\""},"3640":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُفُّ النَّاسُ يَوْمَ الْقِيَامَةِ صُفُوفًا وَقَالَ ابْنُ نُمَيْرٍ أَهْلُ الْجَنَّةِ فَيَمُرُّ الرَّجُلُ مِنْ أَهْلِ النَّارِ عَلَى الرَّجُلِ فَيَقُولُ يَا فُلَانُ أَمَا تَذْكُرُ يَوْمَ اسْتَسْقَيْتَ فَسَقَيْتُكَ شَرْبَةً قَالَ فَيَشْفَعُ لَهُ وَيَمُرُّ الرَّجُلُ فَيَقُولُ أَمَا تَذْكُرُ يَوْمَ نَاوَلْتُكَ طَهُورًا فَيَشْفَعُ لَهُ قَالَ ابْنُ نُمَيْرٍ وَيَقُولُ يَا فُلَانُ أَمَا تَذْكُرُ يَوْمَ بَعَثْتَنِي فِي حَاجَةِ كَذَا وَكَذَا فَذَهَبْتُ لَكَ فَيَشْفَعُ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Yazid bin Ar Ruqasyi] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang akan membuat shaf-shaf pada hari kiamat.\" Ibnu Numair menyebutkan, \"Yaitu penghuni surga, lalu seorang lelaki dari ahli neraka melewati seorang lelaki (dari ahli surga), kemudian dia berkata, \"Wahai fulan, masihkah kamu ingat di hari ketika kamu meminta minum kemudian aku memberimu minuman?\" Ibnu Numair melanjutkan, \"Maka dia memberi syafaat kepada laki-laki (ahli neraka) tersebut. Dan lewat pula seorang lelaki dan berkata, \"Masih ingatkah kamu di hari ketika aku memberimu air untuk bersuci?\" Maka laki-laki itu pun memberi syafaat kepadanya.\" Ibnu Numair melanjutkan, \"Lalu (seorang laki-laki) berkata, \"Wahai fulan, masih ingatkah kamu di hari ketika kamu mengutusku untuk satu kebutuhan seperti ini dan seperti ini, maka aku pergi untukmu?\" Maka dia pun memberi syafaat kepadanya.\""},"3641":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَالِكِ بْنِ جُعْشُمٍ عَنْ أَبِيهِ عَنْ عَمِّهِ سُرَاقَةَ بْنِ جُعْشُمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ضَالَّةِ الْإِبِلِ تَغْشَى حِيَاضِي قَدْ لُطْتُهَا لِإِبِلِي فَهَلْ لِي مِنْ أَجْرٍ إِنْ سَقَيْتُهَا قَالَ نَعَمْ فِي كُلِّ ذَاتِ كَبِدٍ حَرَّى أَجْرٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari [Abdurrahman bin Malik bin Ju'tsam] dari [Ayahnya] dari pamannya [Suraqah bin Ju'tsam] dia berkata, \"Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai unta yang hilang, lalu ia singgah di tempat airku yang telah aku perbaiki untuk untaku, apakah aku mendapatkan pahala jika aku beri minum?\" beliau menjawab: \"Ya, dan di setiap sesuatu yang memiliki hati, (yang hidup) maka akan mendapatkan pahala.\""},"3642":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هِلَالٍ الْعَبْسِيِّ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُحْرَمْ الرِّفْقَ يُحْرَمْ الْخَيْرَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Tamim bin Salamah] dari [Abdurrahman bin Hilal Al 'Absi] dari [Jarir bin Abdullah Al Bajali] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menolak perasaan lemah lembut, maka ia pun akan di tolak dari kebaikan.\""},"3643":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ حَفْصٍ الْأُبُلِّيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ رَفِيقٌ يُحِبُّ الرِّفْقَ وَيُعْطِي عَلَيْهِ مَا لَا يُعْطِي عَلَى الْعُنْفِ","id":"Telah menceritakan kepada kami [Isma'il bin Hafsh Al Ubuli] telah menceritakan kepada kami [Abu Bakar bin Ayyasy] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah Maha lembut dan mencintai kelembutan, dan Dia memberi atas dasar kelembutan sebagaimana Dia tidak memberi atas dasar kekerasan.\""},"3644":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ عَنْ الْأَوْزَاعِيِّ ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ رَفِيقٌ يُحِبُّ الرِّفْقَ فِي الْأَمْرِ كُلِّهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Mush'ab] dari [Al Auza'i]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Abdurrahman bin Ibrahim] keduanya berkata; telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah Maha lembut dan mencintai kelembutan dalam segala perkara.\""},"3645":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِخْوَانُكُمْ جَعَلَهُمْ اللَّهُ تَحْتَ أَيْدِيكُمْ فَأَطْعِمُوهُمْ مِمَّا تَأْكُلُونَ وَأَلْبِسُوهُمْ مِمَّا تَلْبَسُونَ وَلَا تُكَلِّفُوهُمْ مَا يَغْلِبُهُمْ فَإِنْ كَلَّفْتُمُوهُمْ فَأَعِينُوهُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Al Ma'rur bin Suwaid] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saudara-saudara kalian Allah jadikan berada di bawah tangan kalian, maka berilah mereka makan seperti apa yang telah kalian makan, berilah mereka pakaian seperti apa yang telah kalian pakai, dan janganlah kalian membebani mereka dengan sesuatu yang dapat memberatkan mereka. Jika kalian membebankan sesuatu kepada mereka, maka bantulah mereka.\""},"3646":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ عَنْ مُغِيرَةَ بْنِ مُسْلِمٍ عَنْ فَرْقَدٍ السَّبَخِيِّ عَنْ مُرَّةَ الطَّيِّبِ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ الْجَنَّةَ سَيِّئُ الْمَلَكَةِ قَالُوا يَا رَسُولَ اللَّهِ أَلَيْسَ أَخْبَرْتَنَا أَنَّ هَذِهِ الْأُمَّةَ أَكْثَرُ الْأُمَمِ مَمْلُوكِينَ وَيَتَامَى قَالَ نَعَمْ فَأَكْرِمُوهُمْ كَكَرَ��مَةِ أَوْلَادِكُمْ وَأَطْعِمُوهُمْ مِمَّا تَأْكُلُونَ قَالُوا فَمَا يَنْفَعُنَا فِي الدُّنْيَا قَالَ فَرَسٌ تَرْتَبِطُهُ تُقَاتِلُ عَلَيْهِ فِي سَبِيلِ اللَّهِ مَمْلُوكُكَ يَكْفِيكَ فَإِذَا صَلَّى فَهُوَ أَخُوكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata, telah menceritakan kepada kami [Ishaq bin Sulaiman] dari [Mughirah bin Muslim] dari [Farqad As Sabakhi] dari [Murrah At Thayyib] dari [Abu Bakar Ash Shiddiq] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk surga orang yang jelek perangainya.\" Para sahabat lalu bertanya, \"Wahai Rasulullah, bukankah anda telah memberitahukan kepada kami bahwa Ummat ini adalah ummat yang paling banyak budak dan anak yatimnya?\" Rasulullah menjawab: \"Benar, maka itu muliakanlah mereka seperti kalian memuliakan anak-anak kalian, berilah mereka makan dari makanan yang kalian makan.\" Para sahabat bertanya lagi, \"Wahai Rasulullah, apakah yang dapat bermanfaat bagi kami di dunia?\" beliau menjawab: \"Kendaraan yang kalian tambatkan untuk jihad di jalan Allah dan budak yang mencukupimu, jika dia shalat maka dia adalah saudaramu.\""},"3647":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَابْنُ نُمَيْرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تَدْخُلُوا الْجَنَّةَ حَتَّى تُؤْمِنُوا وَلَا تُؤْمِنُوا حَتَّى تَحَابُّوا أَوَلَا أَدُلُّكُمْ عَلَى شَيْءٍ إِذَا فَعَلْتُمُوهُ تَحَابَبْتُمْ أَفْشُوا السَّلَامَ بَيْنَكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Ibnu Numair] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi dzat yang jiwaku berada di tangan-Nya, tidaklah kalian akan masuk surga sehingga kalian beriman, dan tidaklah kalian beriman sampai kalian saling mencintai. Maukah aku tunjukkan kepada kalian suatu amalan jika kalian mengerjakannya, niscaya kalian akan saling mencintai? Tebarkanlah salam di antara kalian.\""},"3648":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي أُمَامَةَ قَالَأَمَرَنَا نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُفْشِيَ السَّلَامَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Muhammad bin Ziyad] dari [Abu Umamah] dia berkata, \"Nabi kita shallallahu 'alaihi wasallam menyuruh kita supaya menebar salam.\""},"3649":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْبُدُوا الرَّحْمَنَ وَأَفْشُوا السَّلَامَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Atha bin As Sa`ib] dari [Ayahnya] dari [Abdullah bin 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sembahlah Ar Rahman (Allah) dan tebarkanlah salam.\""},"3650":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فِي نَاحِيَةِ الْمَسْجِدِ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ فَقَالَ وَعَلَيْكَ السَّلَامُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami ['Ubaidullah bin Umar] telah menceritakan kepada kami [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah], bahwa seorang laki-laki memasuki masjid sedangkan Rasulullah shallallahu 'alaihi wasallam duduk-duduk di sisi masjid, laki-laki itu pun langsung shalat kemudian datang dan memberi shalat. Maka beliau menjawab; \"Wa'alaikas salam.\""},"3651":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ زَكَرِيَّا عَنْ الشَّعْبِيِّ عَنْ أَبِي سَلَمَةَ أَنَّ عَائِشَةَ حَدَّثَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا إِنَّ جِبْرَائِيلَ يَقْرَأُ عَلَيْكِ السَّلَامَ قَالَتْ وَعَلَيْهِ السَّلَامُ وَرَحْمَةُ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Zakaria] dari [Asy Sya'bi] dari [Abu Salamah] bahwa [Aisyah] telah menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Sesungguhnya Jibril menyampaikan salam kepadamu.\" Aisyah menjawab, \"Wa 'alaihis salaam wa Rahmatullah.\""},"3652":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَمُحَمَّدُ بْنُ بِشْرٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ عَلَيْكُمْ أَحَدٌ مِنْ أَهْلِ الْكِتَابِ فَقُولُوا وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami ['Abdah bin Sulaiman] dan [Muhammad bin Bisyr] dari [Sa'id] dari [Qatadah] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian di salami oleh ahli kitab, maka jawablah dengan, 'Wa 'alaikum'.\""},"3653":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاسٌ مِنْ الْيَهُودِ فَقَالُوا السَّامُ عَلَيْكَ يَا أَبَا الْقَاسِمِ فَقَالَ وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Aisyah], bahwa sekelompok orang Yahudi datang kepada Nabi shallallahu 'alaihi wasallam, lalu mereka berkata, \"AS SAAMU ALAIKA YAA ABAL QASIM (Kematian atasmu wahai Abu Qasim).\" Maka beliau menjawab: \"Wa 'alaikum.\""},"3654":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ الْيَزَنِيِّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي رَاكِبٌ غَدًا إِلَى الْيَهُودِ فَلَا تَبْدَءُوهُمْ بِالسَّلَامِ فَإِذَا سَلَّمُوا عَلَيْكُمْ فَقُولُوا وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Ibnu Numair] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Martsad bin Abdullah Al Yazani] dari [Abu Abdurrahman Al Juhani] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya besok aku akan datang menemui orang-orang Yahudi, maka janganlah kalian mendahului mereka dengan salam, dan apabila mereka mengucapkan salam kepada kalian, maka ucapkanlah, 'Wa 'alaikum'.\""},"3655":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ صِبْيَانٌ فَسَلَّمَ عَلَيْنَا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Humaid] dari [Anas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemui kami yang saat itu masih kanak-kanak, beliau kemudian memberi salam kepada kami.\""},"3656":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي حُسَيْنٍ قَالَ سَمِعَهُ مِنْ شَهْرِ بْنِ حَوْشَبٍ يَقُولُ أَخْبَرَتْهُ أَسْمَاءُ بِنْتُ يَزِيدَ قَالَتْمَرَّ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ فَسَلَّمَ عَلَيْنَا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibnu Abu Husain] dia berkata; dia mendengar dari [Syahr bin Hausyab] berkata; [Asma binti Yazid] mengabarkan kepadanya, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati kami yaitu dalam sekumpulan wanita, lalu beliau memberi salam kepada kami.\""},"3657":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ جَرِيرِ بْنِ حَازِمٍ عَنْ حَنْظَلَةَ بْنِ عَبْدِ الرَّحْمَنِ السَّدُوسِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقُلْنَا يَا رَسُولَ اللَّهِ أَيَنْحَنِي بَعْضُنَا لِبَعْضٍ قَالَ لَا قُلْنَا أَيُعَانِقُ بَعْضُنَا بَعْضًا قَالَ لَا وَلَكِنْ تَصَافَحُوا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Jarir bin Hazim] dari [Hanzhalah bin Abdurrahman As Sadusi] dari [Anas bin Malik] dia berkata, \"Kami berkata, \"Wahai Rasulullah, apakah sebagian kami harus membungkuk kepada sebagian yang lain?\" Beliau menjawab: \"Tidak.\" Kami bertanya lagi, \"Apakah sebagian kami boleh memeluk sebagian yang lain?\" Beliau menjawab: \"Tidak, akan tetapi saling berjabat tanganlah kalian.\""},"3658":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَجْلَحِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمَيْنِ يَلْتَقِيَانِ فَيَتَصَافَحَانِ إِلَّا غُفِرَ لَهُمَا قَبْلَ أَنْ يَتَفَرَّقَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dan [Abdullah bin Numair] dari [Al Ajlah] dari [Abu Ishaq] dari [Al Barra bin 'Azib] dia berkata, \"Bersabda Rasulullah shallallahu 'alaihi wasallam: \"Tidaklah dua orang muslim yang saling bertemu, kemudian saling berjabat tangan kecuali keduanya akan di ampuni sebelum mereka berpisah.\""},"3659":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ ابْنِ عُمَرَ قَالَقَبَّلْنَا يَدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Yazid bin Abu Ziyad] dari [Abdurrahman bin Abu Laila] dari [Ibnu Umar] dia berkata, \"Kami mencium tangan Nabi shallallahu 'alaihi wasallam.\""},"3660":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَغُنْدَرٌ وَأَبُو أُسَامَةَ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ عَنْ صَفْوَانَ بْنِ عَسَّالٍأَنَّ قَوْمًا مِنْ الْيَهُودِ قَبَّلُوا يَدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرِجْلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Idris] dan [Ghundar] dan [Abu Usamah] dari [Syu'bah] dari ['Amru bin Murrah] dari [Abdullah bin Salamah] dari [Shafwan bin 'Assal], bahwa sekelompok orang Yahudi mencium tangan dan kedua kakinya Nabi shallallahu 'alaihi wasallam.\""},"3661":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ أَبَا مُوسَى اسْتَأْذَنَ عَلَى عُمَرَ ثَلَاثًا فَلَمْ يُؤْذَنْ لَهُ فَانْصَرَفَ فَأَرْسَلَ إِلَيْهِ عُمَرُ مَا رَدَّكَ قَالَ اسْتَأْذَنْتُ الِاسْتِئْذَانَ الَّذِي أَمَرَنَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا فَإِنْ أُذِنَ لَنَا دَخَلْنَا وَإِنْ لَمْ يُؤْذَنْ لَنَا رَجَعْنَا قَالَ فَقَالَ لَتَأْتِيَنِّي عَلَى هَذَا بِبَيِّنَةٍ أَوْ لَأَفْعَلَنَّ فَأَتَى مَجْلِسَ قَوْمِهِ فَنَاشَدَهُمْ فَشَهِدُوا لَهُ فَخَلَّى سَبِيلَهُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Daud bin Abu Hind] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] bahwa Abu Musa meminta izin (masuk) kepada Umar hingga tiga kali, namun ia tidak juga di beri izin, lantas Abu Musa beranjak untuk pulang. Setelah itu Umar mengutus (utusan kepadanya dan bertanya), \"Apa yang menyebabkanmu pergi?\" Abu Musa menjawab, \"Aku telah meminta izin hingga tiga kali sebagaimana Rasulullah shallallahu 'alaihi wasallam memerintahkan kami. Jika kami di izinkan, maka kami akan masuk dan jika tidak di izinkan maka kami akan pergi.\" Abu Sa'id berkata, \"Umar berkata, \"Berikanlah kepadaku bukti atas hal tersebut atau aku akan (menghukummu).\" Maka Abu Musa mendatangi majelis kaumnya lalu mengungkapkan kepada mereka (buktinya) dan mereka pun menyaksikan (perkataannya Abu Musa). Lantas Umar pun melepaskannya.\""},"3662":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ وَاصِلِ بْنِ السَّائِبِ عَنْ أَبِي سَوْرَةَ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَذَا السَّلَامُ فَمَا الِاسْتِئْذَانُ قَالَ يَتَكَلَّمُ الرَّجُلُ تَسْبِيحَةً وَتَكْبِيرَةً وَتَحْمِيدَةً وَيَتَنَحْنَحُ وَيُؤْذِنُ أَهْلَ الْبَيْتِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Washil bin As Sa`ib] dari [Abu Saurah] dari [Abu Ayyub Al Anshari] dia berkata, \"Kami bertanya, \"Wahai Rasulullah, kami telah mengetahui tentang salam, lalu bagaimana perihal meminta izin?\" Beliau menjawab: \"Hendaknya seseorang mengucapkan tasbih, takbir dan tahmid, kemudian berdehem dan minta izin kepada pemilik rumah.\""},"3663":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ مُغِيرَةَ عَنْ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ نُجَيٍّ عَنْ عَلِيٍّ قَالَكَانَ لِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُدْخَلَانِ مُدْخَلٌ بِاللَّيْلِ وَمُدْخَلٌ بِالنَّهَارِ فَكُنْتُ إِذَا أَتَيْتُهُ وَهُوَ يُصَلِّي يَتَنَحْنَحُ لِي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Mughirah] dari [Al Harits] dari [Abdullah bin Nujja] dari [Ali] dia berkata, \"Aku memiliki dua waktu untuk menemui Rasulullah shallallahu 'alaihi wasallam, malam hari dan di siang hari, dan apabila saya menemui beliau saat beliau sedang melaksanakan shalat, maka beliau akan berdehem kepadaku.\""},"3664":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَاسْتَأْذَنْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ هَذَا فَقُلْتُ أَنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا أَنَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Muhammad bin Al Munkadir] dari [Jabir] dia berkata, \"Saya meminta izin kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Siapakah ini.\" Aku menjawab, \"Ini adalah aku.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Saya, saya (seakan-akan beliau tidak suka dengan jawaban tersebut)!.\""},"3665":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَابِطٍ عَنْ جَابِرٍ قَالَقُلْتُ كَيْفَ أَصْبَحْتَ يَا رَسُولَ اللَّهِ قَالَ بِخَيْرٍ مِنْ رَجُلٍ لَمْ يُصْبِحْ صَائِمًا وَلَمْ يَعُدْ سَقِيمًا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Isa bin Yunus] dari [Abdullah bin Muslim] dari [Abdurrahman bin Sabith] dari [Jabir] dia berkata, \"Bagaimana keadaanmu menjelang pagi ini wahai Rasulullah?\" Beliau menjawab: \"Lebih baik dari orang yang paginya tidak berpuasa dan tidak pula menjenguk orang sakit.\""},"3666":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الْهَرَوِيُّ إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حَاتِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ إِسْحَقَ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ حَدَّثَنِي جَدِّي أَبُو أُمِّي مَالِكُ بْنُ حَمْزَةَ بْنِ أَبِي أُسَيْدٍ السَّاعِدِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ أَبِي أُسَيْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ وَدَخَلَ عَلَيْهِمْ فَقَالَ السَّلَامُ عَلَيْكُمْ قَالُوا وَعَلَيْكَ السَّلَامُ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ قَالَ كَيْفَ أَصْبَحْتُمْ قَالُوا بِخَيْرٍ نَحْمَدُ اللَّهَ فَكَيْفَ أَصْبَحْتَ بِأَبِينَا وَأُمِّنَا يَا رَسُولَ اللَّهِ قَالَ أَصْبَحْتُ بِخَيْرٍ أَحْمَدُ اللَّهَ","id":"Telah menceritakan kepada kami [Abu Ishaq Al Harwi Ibrahim bin Abdullah bin Hatim] telah menceritakan kepada kami [Abdullah bin Utsman bin Ishaq bin Sa'd bin Abu Waqash] telah menceritakan kepadaku [Kakekku yaitu ayahnya ibuku Malik bin Hamzah bin Abu Usaid As Sa'idi] dari [ayahnya] dari [kakeknya Abu Usaid As Sa'idii] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada 'Abbas Bin Abdul Muththalib, dan beliau menemui para sahabat sambil mengucapkan; \"Assalamu'alaikum\". Mereka menjawab; \"Wa'alaikumussalam warahmatullah wabarakatuh (dan kepadamu pula semoga tercurah keselamatan, rahmat Allah dan barakah-Nya) \". Beliau bertanya: \"Bagaimana keadaan kalian di pagi ini?\", mereka menjawab; \" Baik kami bersyukur kepada Allah, dan bagaimana keadaan anda di pagi ini?, demi ayahku dan ibuku wahai Rasulullah?\". Beliau menjawab: \"Baik, Saya bersyukur kepada Allah.\""},"3667":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سَعِيدُ بْنُ مَسْلَمَةَ عَنْ ابْنِ عَجْلَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاكُمْ كَرِيمُ قَوْمٍ فَأَكْرِمُوهُ","id":"Telah menceritakan kepada kami [Muhammad bin Shabah] telah memberitakan kepada kami [Sa'id bin Maslamah] dari [Ibnu 'Ajlan] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila pemuka kaum datang kepada kalian, maka muliakanlah ia\""},"3668":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَعَطَسَ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَمَّتَ أَحَدَهُمَا أَوْ سَمَّتَ وَلَمْ يُشَمِّتْ الْآخَرَ فَقِيلَ يَا رَسُولَ اللَّهِ عَطَسَ عِنْدَكَ رَجُلَانِ فَشَمَّتَّ أَحَدَهُمَا وَلَمْ تُشَمِّتْ الْآخَرَ فَقَالَ إِنَّ هَذَا حَمِدَ اللَّهَ وَإِنَّ هَذَا لَمْ يَحْمَدْ اللَّهَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Sulaiman At Taimi] dari [Anas bin Malik] dia berkata; \"Ada dua orang laki-laki yang sedang bersin di samping Nabi shallallahu 'alaihi wasallam, lantas salah satu darinya mendo'akannya namun yang satunya lagi tidak membalas do'anya, maka beliau di tanya; \"Wahai Rasulullah, ada dua orang laki-laki yang bersin, lantas salah satu darinya mendo'akannya, namun yang satunya lagi tidak membalas do'anya.\" Maka beliau menjawab: \"Sesungguhnya yang satu (yaitu yang mendo'akan) telah memuji Allah, namun yang satunya lagi (yang tidak membalas do'anya) tidak memuji Allah.\""},"3669":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشَمَّتُ الْعَاطِسُ ثَلَاثًا فَمَا زَادَ فَهُوَ مَزْكُومٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari ['Ikrimah bin 'Ammar] dari [Iyyas bin Salamah bin Al Akwa'] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang bersin di do'akan tiga kali, jika dia bersin lebih dari tiga kali berarti dia tengah terserang flu.\""},"3670":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عِيسَى بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا عَطَسَ أَحَدُكُمْ فَلْيَقُلْ الْحَمْدُ لِلَّهِ وَلْيَرُدَّ عَلَيْهِ مَنْ حَوْلَهُ يَرْحَمُكَ اللَّهُ وَلْيَرُدَّ عَلَيْهِمْ يَهْدِيكُمُ اللَّهُ وَيُصْلِحُ بَالَكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Ibnu Abu Lalila] dari [Isa bin Abdurrahman] dari [Abdurrahman bin Abu Laila] dari [Ali] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian bersin, maka ucapkanlah; \"Alhamdulillah\", Dan hendaklah orang yang ada disekitarnya menjawab; \"Yarhamukallah\", (semoga Allah merahmatimu). Dan hendaklah orang yang bersin menjawab; \"Yahdikumullah wa yushlih baalakum\" (semoga Allah memberimu hidayah dan memperbaiki kondisi kalian).\""},"3671":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ أَبِي يَحْيَى الطَّوِيلِ رَجُلٌ مِنْ أَهْلُ الْكُوفَةِ عَنْ زَيْدٍ الْعَمِّيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَقِيَ الرَّجُلَ فَكَلَّمَهُ لَمْ يَصْرِفْ وَجْهَهُ عَنْهُ حَتَّى يَكُونَ هُوَ الَّذِي يَنْصَرِفُ وَإِذَا صَافَحَهُ لَمْ يَنْزِعْ يَدَهُ مِنْ يَدِهِ حَتَّى يَكُونَ هُوَ الَّذِي يَنْزِعُهَا وَلَمْ يُرَ مُتَقَدِّمًا بِرُكْبَتَيْهِ جَلِيسًا لَهُ قَطُّ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Abu Yahya At Thawil] seorang laki-laki dari penduduk Kufah, dari [Zaid bin Al 'Ammi] dari [Anas Bin Malik] dia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam berjumpa dengan seseorang dan beliau mengajaknya bicara, maka beliau tidak memalingkan mukanya dari orang tersebut sehingga orang itu sendiri yang berpaling, dan apabila menjabatnya, beliau tidak melepas tangannya sehingga ia sendiri yang melepaskannya, beliau juga tidak pernah terlihat mendahului teman duduknya dengan kedua lututnya.\""},"3672":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَامَ أَحَدُكُمْ عَنْ مَجْلِسِهِ ثُمَّ رَجَعَ فَهُوَ أَحَقُّ بِهِ","id":"Telah menceritakan kepada kami ['Amru bin rafi'] telah menceritakan kepada kami [Jarir] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jika salah seorang dari kalian bangkit dari Majlis, kemudian dia kembali lagi, maka ia lebih berhak dengan tempat duduknya.\""},"3673":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ مِينَاءَ عَنْ جُودَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اعْتَذَرَ إِلَى أَخِيهِ بِمَعْذِرَةٍ فَلَمْ يَقْبَلْهَا كَانَ عَلَيْهِ مِثْلُ خَطِيئَةِ صَاحِبِ مَكْسٍحَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ ابْنِ جُرَيْجٍ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ مِينَاءَ عَنْ جُودَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Ibnu Mina`] dari [Judan] dia berkata; Rasulullah shallallahu 'alaihi wasallam: \"Barang siapa yang mengajukan permintaan maaf kepada saudaranya, tetapi dia tidak menerimanya, maka baginya adalah seperti kesalahan pemungut bea cukai (yang memungut sesuatu tanpa hak).\" Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ibnu Juraij] dari [Al Abbas bin Abdurrahman yaitu Ibnu Mina`] dari [Judan] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"3674":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا وَكِيعٌ عَنْ زَمْعَةَ بْنِ صَالِحٍ عَنْ الزُّهْرِيِّ عَنْ وَهْبِ بْنِ عَبْدِ بْنِ زَمْعَةَ عَنْ أُمِّ سَلَمَةَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ وَهْبِ بْنِ زَمْعَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْخَرَجَ أَبُو بَكْرٍ فِي تِجَارَةٍ إِلَى بُصْرَى قَبْلَ مَوْتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَامٍ وَمَعَهُ نُعَيْمَانُ وَسُوَيْبِطُ بْنُ حَرْمَلَةَ وَكَانَا شَهِدَا بَدْرًا وَكَانَ نُعَيْمَانُ عَلَى الزَّادِ وَكَانَ سُوَيْبِطُ رَجُلًا مَزَّاحًا فَقَالَ لِنُعَيْمَانَ أَطْعِمْنِي قَالَ حَتَّى يَجِيءَ أَبُو بَكْرٍ قَالَ فَلَأُغِيظَنَّكَ قَالَ فَمَرُّوا بِقَوْمٍ فَقَالَ لَهُمْ سُوَيْبِطٌ تَشْتَرُونَ مِنِّي عَبْدًا لِي قَالُوا نَعَمْ قَالَ إِنَّهُ عَبْدٌ لَهُ كَلَامٌ وَهُوَ قَائِلٌ لَكُمْ إِنِّي حُرٌّ فَإِنْ كُنْتُمْ إِذَا قَالَ لَكُمْ هَذِهِ الْمَقَالَةَ تَرَكْتُمُوهُ فَلَا تُفْسِدُوا عَلَيَّ عَبْدِي قَالُوا لَا بَلْ نَشْتَرِيهِ مِنْكَ فَاشْتَرَوْهُ مِنْهُ بِعَشْرِ قَلَائِصَ ثُمَّ أَتَوْهُ فَوَضَعُوا فِي عُنُقِهِ عِمَامَةً أَوْ حَبْلًا فَقَالَ نُعَيْمَانُ إِنَّ هَذَا يَسْتَهْزِئُ بِكُمْ وَإِنِّي حُرٌّ لَسْتُ بِعَبْدٍ فَقَالُوا قَدْ أَخْبَرَنَا خَبَرَكَ فَانْطَلَقُوا بِهِ فَجَاءَ أَبُو بَكْرٍ فَأَخْبَرُوهُ بِذَلِكَ قَالَ فَاتَّبَعَ الْقَوْمَ وَرَدَّ عَلَيْهِمْ الْقَلَائِصَ وَأَخَذَ نُعَيْمَانَ قَالَ فَلَمَّا قَدِمُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْبَرُوهُ قَالَ فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ مِنْهُ حَوْلًا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Waki'] dari [Zam'ah bin Shalih] dari [Az Zuhri] dari [Wahb bin Abd bin Zam'ah] dari [Ummu Salamah]. Dan di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Zam'ah bin Shalih] dari [Az Zuhri] dari [Abdullah bin Wahb bin Zam'ah] dari [Ummu Salamah] dia berkata; \"Setahun sebelum wafatnya Nabi shallallahu 'alaihi wasallam Abu Bakar pernah keluar berdagang ke negeri Bushra bersama Nu'aiman dan Suwaibith bin Harmalah, -keduanya pernah mengikut perang Badr- ketika itu Nu'aimanlah yang membawa perbekalan, sedangkan Suwaibit adalah orang yang lucu, lalu dia berkata kepada Nu'aiman; \"Berilah saya makanan.\" Nu'aiman menjawab; \"Tidak hingga Abu Bakar datang.\" Oleh karena itu Suwaibith berkata: \"Awas, saya akan memberimu pelajaran.\" Abdullah berkata; \"Kemudian mereka melewati perkumpulan orang banyak. Maka Suwaibith berkata; \"Wahai orang-orang, belailah dariku seorang budak!.\" Mereka menjawab; \"Ya, saya akan membelinya.\" Suwaibith berkata; \"Dia adalah seorang pemuda yang memiliki lidah berkelit, ia akan mengatakan kepada kalian \"saya adalah orang bebas\", apabila kalian meninggalkannya karena hal itu, maka biarkanlah dan janganlah kalian mencelakakan budakku.\" mereka menjawab: \"Tidak, bahkan kami akan membelinya darimu.\" Kemudian mereka membelinya seharga sepuluh Qalais (yaitu; seharga unta muda betina). Setelah itu mereka mendatangi Nu'aiman sambil menaruh surban di lehernya atau seikat tali.\" Maka Nu'aiman berkata; \"Sesungguhnya ia telah mengibuli kalian, sesugguhnya saya adalah orang bebas, bukan seorang budak.\" Mereka berkata; \"Dia telah memberitahu apa yang kamu katakan.\" lalu mereka membawanya pergi, tidak lama kemudian, datanglah Abu Bakar dan dia diberitahu akan hal itu.\" Abdullah berkata; \"Lalu Abu Bakar segera pergi menemui mereka dan menukar Qala`is milik mereka, dan membawa kembali Nu'aiman. Abdullah berkata; \"Ketika mereka tiba, mereka lalu memberitahukan hal itu kepada Nabi shallallahu 'alaihi wasallam.\" Abdullah berkata; \"Maka Nabi shallallahu 'alaihi wasallam tertawa, begitu juga dengan para sahabatnya.\""},"3675":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَالِطُنَا حَتَّى يَقُولَ لِأَخٍ لِي صَغِيرٍ يَا أَبَا عُمَيْرٍ مَا فَعَلَ النُّغَيْرُقَالَ وَكِيعٌ يَعْنِي طَيْرًا كَانَ يَلْعَبُ بِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Abu At Tayyah] dia berkata; saya mendengar [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam duduk bersamaku sampai beliau bersabda kepadaku: \"Wahai Abu 'Umair Apa yang di perbuat Nughair (burung kecil)?\" Waki berkata; \"Yang di maksud adalah seekor burung yang biasa bermain dengannya.\""},"3676":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَتْفِ الشَّيْبِ وَقَالَ هُوَ نُورُ الْمُؤْمِنِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Muhammad bin Ishaq] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang mencabut uban, dan beliau bersabda: \"Dia adalah cahaya bagi orang-orang beriman.\""},"3677":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ أَبِي الْمُنِيبِ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُقْعَدَ بَيْنَ الظِّلِّ وَالشَّمْسِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Zaid bin Al Habbab] dari [Abu Al Munib] dari [Ibnu Buraidah] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam melarang untuk duduk diantara bayang-bayang dan matahari."},"3678":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ قَيْسِ بْنِ طِخْفَةَ الْغِفَارِيِّ عَنْ أَبِيهِ قَالَأَصَابَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَائِمًا فِي الْمَسْجِدِ عَلَى بَطْنِي فَرَكَضَنِي بِرِجْلِهِ وَقَالَ مَا لَكَ وَلِهَذَا النَّوْمِ هَذِهِ نَوْمَةٌ يَكْرَهُهَا اللَّهُ أَوْ يُبْغِضُهَا اللَّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Shabah] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Qais bin Thihfah Al Ghifari] dari [ayahnya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mendapatiku tidur di atas perutku (telungkup) di Masjid, maka beliau membangunkaku dengan kedua kakinya sambil bersabda: \"Kenapa kamu seperti ini? Ini adalah cara tidur yang di benci Allah atau tidak di sukai Allah.\""},"3679":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ أَبِيهِ عَنْ ابْنِ طِخْفَةَ الْغِفَارِيِّ عَنْ أَبِي ذَرٍّ قَالَمَرَّ بِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مُضْطَجِعٌ عَلَى بَطْنِي فَرَكَضَنِي بِرِجْلِهِ وَقَالَ يَا جُنَيْدِبُ إِنَّمَا هَذِهِ ضِجْعَةُ أَهْلِ النَّارِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Isma'il bin Abdullah] telah menceritakan kepada kami [Muhammad bin Nu'aim bin Abdullah Al Mujmir] dari [ayahnya] dari [Ibnu Thihfah Al Ghifari] dari [Abu Dzar] dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah melewatiku yang sedang berbaring diatas perutku (tidur telungkup), maka beliau mendorongku dengan kakinya sambil bersabda: \"Wahai Junaidib, ini adalah cara berbaringnya penghuni neraka.\""},"3680":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا سَلَمَةُ بْنُ رَجَاءٍ عَنْ الْوَلِيدِ بْنِ جَمِيلٍ الدِّمَشْقِيِّ أَنَّهُ سَمِعَ الْقَاسِمَ بْنَ عَبْدِ الرَّحْمَنِ يُحَدِّثُ عَنْ أَبِي أُمَامَةَ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ نَائِمٍ فِي الْمَسْجِدِ مُنْبَطِحٍ عَلَى وَجْهِهِ فَضَرَبَهُ بِرِجْلِهِ وَقَالَ قُمْ وَاقْعُدْ فَإِنَّهَا نَوْمَةٌ جَهَنَّمِيَّةٌ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Salamah bin Raja`] dari [Al Walid bin Jumail Ad Dimasyqi] bahwa dia mendengar [Al Qasim bin Abdurrahman] telah bercerita dari [Abu Umamah] dia berkata; Nabi shallallahu 'alaihi wasallam pernah melewati seseorang yang sedang tidur dengan menelungkupkan wajahnya di masjid, maka beliau mendorong dengan kakinya sambil bersabda: \"Bangun dan duduklah, sesungguhnya itu adalah cara tidurnya penghuni Jahannam\"."},"3681":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ الْوَلِيدِ بْنِ عَبْدِ اللَّهِ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَبَسَ عِلْمًا مِنْ النُّجُومِ اقْتَبَسَ شُعْبَةً مِنْ السِّحْرِ زَادَ مَا زَادَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah bin Al Akhnas] dari [Al Walid bin Abdullah] dari [Yusuf bin Mahak] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa mengambil ilmu perbintangan, berarti ia telah mengambil satu cabang dari ilmu sihir, (yang) selalu bertambah selagi dia menambah.\""},"3682":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ حَدَّثَنَا ثَابِتٌ الزُّرَقِيُّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُسُبُّوا الرِّيحَ فَإِنَّهَا مِنْ رَوْحِ اللَّهِ تَأْتِي بِالرَّحْمَةِ وَالْعَذَابِ وَلَكِنْ سَلُوا اللَّهَ مِنْ خَيْرِهَا وَتَعَوَّذُوا بِاللَّهِ مِنْ شَرِّهَا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Al Auza'i] dari [Az Zuhri] telah menceritakan kepada kami [Tsabit Az Zuraqi] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencela angin, sebab ia merupakan hembusan Allah yang dapat mendatangkan rahmat dan juga azab, akan tetapi mohonlah kepada Allah dari kebaikannya dan berlindunglah kepada Allah dari kejahatannya.\""},"3683":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا الْعُمَرِيُّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحَبُّ الْأَسْمَاءِ إِلَى اللَّهِ عَزَّ وَجَلَّ عَبْدُ اللَّهِ وَعَبْدُ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Al 'Umari] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Nama yang paling di cintai oleh Allah Azza Wa Jalla ialah Abdullah dan Abdurrahman.\""},"3684":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَئِنْ عِشْتُ إِنْ شَاءَ اللَّهُ لَأَنْهَيَنَّ أَنْ يُسَمَّى رَبَاحٌ وَنَجِيحٌ وَأَفْلَحُ وَنَافِعٌ وَيَسَارٌ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Abu Zubair] dari [Jabir] dari [Umar Bin Al Khatthab] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya Allah masih mengizinkan saya hidup, pasti saya akan melarang seseorang di beri nama Rabaah, najiih, aflah, naafi' dan yasaar.\""},"3685":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ الرُّكَيْنِ عَنْ أَبِيهِ عَنْ سَمُرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُسَمِّيَ رَقِيقَنَا أَرْبَعَةَ أَسْمَاءٍ أَفْلَحُ وَنَافِعٌ وَرَبَاحٌ وَيَسَارٌ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Ar Rukkaini] dari [ayahnya] dari [Samurah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang kami menamakan budak-budak kami dengan empat nama yaitu; Aflah, Nafi', Rabah dan Yasar.\""},"3686":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا أَبُو عَقِيلٍ حَدَّثَنَا مُجَالِدُ بْنُ سَعِيدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَلَقِيتُ عُمَرَ بْنَ الْخَطَّابِ فَقَالَ مَنْ أَنْتَ فَقُلْتُ مَسْرُوقُ بْنُ الْأَجْدَعِ فَقَالَ عُمَرُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْأَجْدَعُ شَيْطَانٌ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Abu 'Aqil] telah menceritakan kepada kami [Mujalid bin Sa'id] dari [As Sya'bi] dari [Masruq] dia berkata; saya pernah bertemu Umar bin Khatthab, lantas dia bertanya; \"Siapakah namamu?\" Jawabku; \"Masruq bin Al Ajda', maka [Umar] berkata; Saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Ajda' termasuk dari (nama) Syaithan.\""},"3687":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ قَالَ سَمِعْتُ أَبَا رَافِعٍ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَأَنَّ زَيْنَبَ كَانَ اسْمُهَا بَرَّةَ فَقِيلَ لَهَا تُزَكِّي نَفْسَهَا فَسَمَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْنَبَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari ['Atha` bin Abu Maimunah] dia berkata; saya mendengar [Abu Rafi'] bercerita dari [Abu Hurairah] bahwa Zainab dulunya bernama Barrah, maka di katakan kepadanya supaya dia menyucikan diri, setelah itu Rasulullah shallallahu 'alaihi wasallam menamainya dengan Zainab.\""},"3688":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ ابْنَةً لِعُمَرَ كَانَ يُقَالُ لَهَا عَاصِيَةُ فَسَمَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمِيلَةَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa putrinya Umar dulu bernama 'Ashiyah, maka Rasulullah shallallahu 'alaihi wasallam menamakannya Jamilah."},"3689":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى أَبُو الْمُحَيَّاةِ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ حَدَّثَنِي ابْنُ أَخِي عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ اسْمِي عَبْدَ اللَّهِ بْنَ سَلَامٍ فَسَمَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ سَلَامٍ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yahya bin Ya'la Abu Al Muhayyah] dari [Abdul Malik bin 'Umair] telah menceritakan kepadaku [anak saudaraku Abdullah bin Salam] dari [Abdullah bin Salam] dia berkata; \"Saya datang kepada Rasulullah shallallahu 'alaihi wasallam dengan menyandang nama selain Abdullah bin Salam, maka Rasulullah shallallahu 'alaihi wasallam menamaiku dengan Abdullah bin Salam."},"3690":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَمَّوْا بِاسْمِي وَلَا تَكَنَّوْا بِكُنْيَتِي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ayyub] dari [Muhammad] dia berkata; saya mendengar [Abu Hurairah] berkata; Abu Al Qasim yaitu Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Hendaklah kalian menamai (diri kalian) dengan namaku, dan janganlah kalian memberi julukan dengan julukanku.\""},"3691":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَمَّوْا بِاسْمِي وَلَا تَكَنَّوْا بِكُنْيَتِي","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian menamai (diri kalian) dengan namaku, dan janganlah kalian memberi julukan dengan julukanku.\""},"3692":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَقِيعِ فَنَادَى رَجُلٌ رَجُلًا يَا أَبَا الْقَاسِمِ فَالْتَفَتَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي لَمْ أَعْنِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَمَّوْا بِاسْمِي وَلَا تَكَنَّوْا بِكُنْيَتِي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdul Wahab At Tsaqafi] dari [Humaid] dari [Anas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam berada di Baqi', ada seorang laki-laki memanggil laki-laki lain; \"Wahai Abu Qasim!.\" Maka Rasulullah shallallahu 'alaihi wasallam menoleh kepadanya, laki-laki yang memanggil berkata; \"Saya tidak memanggil anda (wahai Nabi).\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian menamai (diri kalian) dengan namaku, dan janganlah kalian memberi julukan dengan julukanku.\""},"3693":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ حَمْزَةَ بْنِ صُهَيْبٍأَنَّ عُمَرَ قَالَ لِصُهَيْبٍ مَا لَكَ تَكْتَنِي بِأَبِي يَحْيَى وَلَيْسَ لَكَ وَلَدٌ قَالَ كَنَّانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَبِي يَحْيَى","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Abu Bukair] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah bin Muhammad bin 'Aqil] dari [Hamzah bin Shuhaib] bahwa Umar berkata kepada [Shuhaib]; \"Mengapa kamu di juluki dengan Abu Yahya? Sedangkan kamu tidak memiliki anak?\" dia menjawab; \"Rasulullah shallallahu 'alaihi wasallam memberi julukan kepadaku dengan Abu Yahya.\""},"3694":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ مَوْلًى لِلزُّبَيْرِ عَنْ عَائِشَةَأَنَّهَا قَالَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ أَزْوَاجِكَ كَنَّيْتَهُ غَيْرِي قَالَ فَأَنْتِ أُمُّ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Waki'] dari [Hisyam bin 'Urwah] dari [bekas budak Az Zubair] dari ['Aisyah] dia berkata kepada Nabi shallallahu 'alaihi wasallam: \"Semua istri-istrimu telah anda beri kunyah (julukan) semuanya kecuali saya.\" Beliau bersabda: \"Maka kamu (Saya juluki) dengan Ummu 'Abdillah.\""},"3695":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِينَا فَيَقُولُ لِأَخٍ لِي وَكَانَ صَغِيرًا يَا أَبَا عُمَيْرٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Abu At Tayyah] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mendatangi kami, lalu beliau bersabda kepada adikku yang paling kecil: \"Wahai Abu 'Umair.\""},"3696":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ أَبِي جَبِيرَةَ بْنِ الضَّحَّاكِ قَالَفِينَا نَزَلَتْ مَعْشَرَ الْأَنْصَارِ وَلَا تَنَابَزُوا بِالْأَلْقَابِ قَدِمَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالرَّجُلُ مِنَّا لَهُ الِاسْمَانِ وَالثَّلَاثَةُ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُبَّمَا دَعَاهُمْ بِبَعْضِ تِلْكَ الْأَسْمَاءِ فَيُقَالُ يَا رَسُولَ اللَّهِ إِنَّهُ يَغْضَبُ مِنْ هَذَا فَنَزَلَتْ وَلَا تَنَابَزُوا بِالْأَلْقَابِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Idris] dari [Daud] dari [As Sya'bi] dari [Abu Jabirah bin Adl Dlahak] dia berkata; \"Telah di turunkan kepada kami -yaitu kalangan orang-orang Anshar- suatu ayat, yaitu Dan janganlah kalian saling memanggil dengan gelar-gelar yang buruk(Qs Al Hujurat; 11 Nabi shallallahu 'alaihi wasallam datang kepada kami, dan lelaki dari kalangan kami biasanya memiliki dua atau tiga nama, terkadang Nabi shallallahu 'alaihi wasallam memanggil mereka dengan nama-nama itu, tetapi dikatakan kepada beliau; \"wahai Rasulullah, sesungguhnya dia marah jika di panggil dengan nama itu.\" Maka turunlah ayat: Dan janganlah kalian saling memanggil dengan gelar-gelar yang burukQs Al Hujurat; 11.\""},"3697":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ الْمِقْدَادِ بْنِ عَمْرٍو قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَحْثُوَ فِي وُجُوهِ الْمَدَّاحِينَ التُّرَابَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Mujahid] dari [Abu Ma'mar] dari [Al Miqdad bin 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami supaya menaburkan ke wajah orang-orang yang suka memuji.\""},"3698":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ مَعْبَدٍ الْجُهَنِيِّ عَنْ مُعَاوِيَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِيَّاكُمْ وَالتَّمَادُحَ فَإِنَّهُ الذَّبْحُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sa'd bin Ibrahim bin Abdurrahman bin 'Auf] dari [Ma'bad bin Al Juhani] dari [Mu'awiyah] dia berkata; \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhilah oleh kalian saling memuji, sesungguhnya itu adalah sembelihan.\""},"3699":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَمَدَحَ رَجُلٌ رَجُلًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْحَكَ قَطَعْتَ عُنُقَ صَاحِبِكَ مِرَارًا ثُمَّ قَالَ إِنْ كَانَ أَحَدُكُمْ مَادِحًا أَخَاهُ فَلْيَقُلْ أَحْسِبُهُ وَلَا أُزَكِّي عَلَى اللَّهِ أَحَدًا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] dari [Khalid bin Al Khaddza`] dari [Abdurrahman bin Abu Bakrah] dari [ayahnya] dia berkata; \"Ada seorang laki-laki yang sedang memuji laki-laki di samping Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celaka kamu, kamu telah memotong leher temanmu.\" -beliau mengatakannya sampai berkali-kali-, kemudian beliau bersabda: \"Apabila salah seorang dari kalian memuji saudaranya, maka katakanlah; \"Aku rasa…\" dan tidaklah saya mensucikan seorang pun melebihi kesucian Allah.\""},"3700":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ عَنْ شَيْبَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْتَشَارُ مُؤْتَمَنٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Abu Bukair] dari [Syaiban] dari [Abdul Malik bin 'Umair] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya penasehat adalah orang yang dapat di percaya (amanah).\""},"3701":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ عَنْ شَرِيكٍ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْتَشَارُ مُؤْتَمَنٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Aswad bin 'Amir] dari [Syarik] dari [Al A'masy] dari [Abu 'Amru As Syaibani] dari [Abu Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya penasehat adalah orang yang dapat di percaya (amanah).\""},"3702":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ وَعَلِيُّ بْنُ هَاشِمٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَشَارَ أَحَدُكُمْ أَخَاهُ فَلْيُشِرْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yahya bin Zakariya` bin Abu Za`idah] dan [Ali bin Hasyim] dari [Ibnu Abu Laila] dari [Abu Az Zubair] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian meminta nasehat kepada saudaranya, hendaklah ia menunjukkan jalan yang benar.\""},"3703":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا خَالِي يَعْلَى وَجَعْفَرُ بْنُ عَوْنٍ جَمِيعًا عَنْ عَبْدِ الرَّحْمَنِ بْنِ زِيَادِ بْنِ أَنْعُمٍ الْإِفْرِيقِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُفْتَحُ لَكُمْ أَرْضُ الْأَعَاجِمِ وَسَتَجِدُونَ فِيهَا بُيُوتًا يُقَالُ لَهَا الْحَمَّامَاتُ فَلَا يَدْخُلْهَا الرِّجَالُ إِلَّا بِإِزَارٍ وَامْنَعُوا النِّسَاءَ أَنْ يَدْخُلْنَهَا إِلَّا مَرِيضَةً أَوْ نُفَسَاءَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami ['Abdah bin Sulaiman]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami ['Ali bin Muhammad] telah menceritakan kepada kami [pamanku yaitu Ya'la] dan [Ja'far bin 'Aun] semuanya dari [Abdurrahman bin Ziyad bin Al An'um Al Ifriqi] dari [Abdurrahman bin Rafi'] dari [Abdullah bin 'Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ditaklukkan bagi kalian bumi-bumi orang-orang asing, dan kalian akan mendapati disana rumah-rumah yang disebut dengan hamamaat (kamar mandi atau pemandian), Maka kaum lelaki tidak boleh memasukinya kecuali mengenakan sarung, dan cegahlah kaum wanita untuk memasukinya kecuali yang sakit atau yang sedang nifas.\""},"3704":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ شَدَّادٍ عَنْ أَبِي عُذْرَةَ قَالَ وَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى الرِّجَالَ وَالنِّسَاءَ عَنْ الْحَمَّامَاتِ ثُمَّ رَخَّصَ لِلرِّجَالِ أَنْ يَدْخُلُوهَا فِي الْمَيَازِرِ وَلَمْ يُرَخِّصْ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki']. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] telah memberitakan kepada kami [Abdullah bin Syaddad] dari [Abu 'Udzrah] dia berkata; -sedangkan dia adalah seseorang yang telah berjumpa dengan Nabi shallallahu 'alaihi wasallam-, dari ['Aisyah]; \"Bahwa Nabi shallallahu 'alaihi wasallam melarang kaum lelaki dan kaum wanita untuk memasuki hamamat (pemandian umum), kemudian beliau memberi keringanan kepada lelaki untuk memasukinya dengan mengenakan kain sarung dan tidak memberi keringanan kepada kaum wanita.\""},"3705":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِي الْمَلِيحِ الْهُذَلِيِّأَنَّ نِسْوَةً مِنْ أَهَلْ حِمْصَ اسْتَأْذَنَّ عَلَى عَائِشَةَ فَقَالَتْ لَعَلَّكُنَّ مِنْ اللَّوَاتِي يَدْخُلْنَ الْحَمَّامَاتِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا امْرَأَةٍ وَضَعَتْ ثِيَابَهَا فِي غَيْرِ بَيْتِ زَوْجِهَا فَقَدْ هَتَكَتْ سِتْرَ مَا بَيْنَهَا وَبَيْنَ اللَّهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Abu Al Malih Al Hudzali] bahwa para wanita dari penduduk Himsha pernah meminta izin untuk menemui ['Asiyah], maka dia berkata; \"Mungkin kalian adalah para wanita yang suka masuk ke pemandian umum, saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita manapun yang meletakkan pakaiannya di selain rumah suaminya, maka ia telah menghancurkan tirai antara dia dan Allah.\""},"3706":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي هَاشِمٍ الرُّمَّانِيِّ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اطَّلَى بَدَأَ بِعَوْرَتِهِ فَطَلَاهَا بِالنُّورَةِ وَسَائِرَ جَسَدِهِ أَهْلُهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abdurrahman bin Abdullah] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Hasyim Ar Rumani] dari [Habib bin Abu Tsabit] dari [Ummu Salamah] bahwa apabila Nabi shallallahu 'alaihi wasallam melumuri badannya, maka beliau memulai dengan auratnya terlebih dahulu, kemudian istrinya yang melumuri seluruh badannya dengan kapur wangi.\""},"3707":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ عَنْ كَامِلٍ أَبِي الْعَلَاءِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطَّلَى وَوَلِيَ عَانَتَهُ بِيَدِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepadaku [Ishaq bin Manshur] dari [Kamil Abu Al 'Ala`] dari [Habib bin Abu tsabit] dari [Ummu Salamah] bahwa Nabi shallallahu 'alaihi wasallam pernah mengolesi (melumuri) daerah sekitar kemaluan beliau dengan tangannya.\""},"3708":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْهِقْلُ بْنُ زِيَادٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَبْدِ اللَّهِ ب��نِ عَامِرٍ الْأَسْلَمِيِّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقُصُّ عَلَى النَّاسِ إِلَّا أَمِيرٌ أَوْ مَأْمُورٌ أَوْ مُرَاءٍ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Hifl bin Ziyad] telah menceritakan kepada kami [Al Auza'i] dari [Abdulah bin 'Amir Al Aslami] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah (berhak) memberikan kisah kepada suatu kaum kecuali pemerintah (amir) atau yang di perintah (utusan amir) atau perawi.\""},"3709":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْعُمَرِيِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَمْ يَكُنْ الْقَصَصُ فِي زَمَنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا زَمَنِ أَبِي بَكْرٍ وَلَا زَمَنِ عُمَرَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Al 'Umari] dari [nafi'] dari [Ibnu Umar] dia berkata; \"Tidak ada para tukang cerita di zaman Rasulullah shallallahu 'alaihi wasallam, juga di zaman Abu Bakar dan Umar.\""},"3710":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشِّعْرِ لَحِكْمَةً","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Mubarrak] dari [Yunus] dari [Az Zuhri] telah menceritakan kepada kami [Abu Bakar bin Abdurrahman bin Al Harits] dari [Marwan bin Al Hakam] dari [Abdurrahman bin Al Aswad bin Abd Yaghuts] dari [Ubay bin Ka'ab] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dalam sya'ir itu mengandung hikmah.\""},"3711":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ زَائِدَةَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِنَّ مِنْ الشِّعْرِ حِكَمًا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abu Usamah] dari [Za`idah] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dalam sya'ir mengandung hikmah.\""},"3712":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَصْدَقُ كَلِمَةٍ قَالَهَا الشَّاعِرُ كَلِمَةُ لَبِيدٍ أَلَا كُلُّ شَيْءٍ مَا خَلَا اللَّهَ بَاطِلُوَكَادَ أُمَيَّةُ بْنُ أَبِي الصَّلْتِ أَنْ يُسْلِمَ","id":"Telah menceritakan kepada kami [Muhammad bin Shabah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdul Malik bin 'Umair] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalimat yang paling jujur yang pernah di katakan oleh penyair adalah perkataan Labid, yaitu; 'Ingatlah segala sesuatu selain Allah adalah bathil, dan Umayyah bin Abu Shalth nyaris masuk Islam.\""},"3713":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْلَى عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِ قَالَأَنْشَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِائَةَ قَافِيَةٍ مِنْ شِعْرِ أُمَيَّةَ بْنِ أَبِي الصَّلْتِ يَقُولُ بَيْنَ كُلِّ قَافِيَةٍ هِيهْ وَقَالَ كَادَ أَنْ يُسْلِمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isa bin Yunus] dari [Abdullah bin Abdurrahman bin Ya'la] dari ['Amru bin Syarid] dari [ayahnya] dia berkata; \"Saya menyenandungkan bait-bait sya`ir untuk Rasulullah shallallahu 'alaihi wasallam seratus qafiyah (ujung sya`ir) dari sya`ir Umayyah bin Abu Shalth, ia mengatakan di setiap qafiyah (pemberhentian); \"Teruskanlah.\" Dan beliau bersabda: \"Dan ia (Abu As Shalth) hampir masuk Islam.\""},"3714":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا حَفْصٌ وَأَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَمْتَلِئَ جَوْفُ الرَّجُلِ قَيْحًا حَتَّى يَرِيَهُ خَيْرٌ لَهُ مِنْ أَنْ يَمْتَلِئَ شِعْرًا إِلَّا أَنَّ حَفْصًا لَمْ يَقُلْ يَرِيَهُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Hafsh], [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di penuhinya hati (perut) seseorang dengan nanah hingga rusak, lebih baik baginya daripada di penuhi oleh sya'ir.\" Namun Hafsh tidak menyebutkan; \"Hingga rusak.\""},"3715":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ حَدَّثَنِي قَتَادَةُ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ يَمْتَلِئَ جَوْفُ أَحَدِكُمْ قَيْحًا حَتَّى يَرِيَهُ خَيْرٌ لَهُ مِنْ أَنْ يَمْتَلِئَ شِعْرًا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Qatadah] dari [Yunus bin Jubair] dari [Muhammad bin Sa'd bin Abu Waqash] dari [Sa'd bin Abu Waqash] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Di penuhinya hati (perut) seseorang dengan nanah hingga rusak, lebih baik baginya daripada di penuhi oleh sya'ir.\""},"3716":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ شَيْبَانَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَعْظَمَ النَّاسِ فِرْيَةً لَرَجُلٌ هَاجَى رَجُلًا فَهَجَا الْقَبِيلَةَ بِأَسْرِهَا وَرَجُلٌ انْتَفَى مِنْ أَبِيهِ وَزَنَّى أُمَّهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ubaidullah] dari [Syaiban] dari [Al A'masy] dari ['Amru bin Murrah] dari [Yusuf bin Mahak] dari [Ubaidullah 'Umair] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya manusia yang paling besar fitnahnya adalah orang yang mencaci seseorang, kemudian dia membalas mencacinya hingga kabilah semuanya ikut mencaci, dan seorang lelaki yang menyingkirkan ayahnya dan menzinahi ibunya.\""},"3717":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَعِبَ بِالنَّرْدِ فَقَدْ عَصَى اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dan [Abu Usamah] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Sa'id bin Abu Hind] dari [Abu Musa] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa bermain dadu, maka dia telah bermaksiat kepada Allah dan Rasul-Nya.\""},"3718":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَعِبَ بِالنَّرْدَشِيرِ فَكَأَنَّمَا غَمَسَ يَدَهُ فِي لَحْمِ خِنْزِيرٍ وَدَمِهِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa bermain dadu, maka seakan-akan ia merendam tangannya di dalam daging dan darah babi.\""},"3719":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا شَرِيكٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَظَرَ إِلَى إِنْسَانٍ يَتْبَعُ طَائِرًا فَقَالَ شَيْطَانٌ يَتْبَعُ شَيْطَانًا","id":"Telah menceritakan kepada kami [Abdullah bin 'Amir bin Zurarah] telah menceritakan kepada kami [Syarik] dari [Muhammad bin 'Amru] dari [Abu Salamah bin Abdurrahman] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam melihat seseorang yang mengikuti burung, maka beliau bersabda: \"Ada setan yang mengikuti setan.\""},"3720":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَتْبَعُ حَمَامَةً فَقَالَ شَيْطَانٌ يَتْبَعُ شَيْطَانَةً","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Al Aswad bin 'Amir] dari [Hammad bin Salamah] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam melihat seseorang yang mengikuti burung merpati, maka beliau bersabda: \"Ada setan yang mengikuti setan.\""},"3721":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ الْحَسَنِ بْنِ أَبِي الْحَسَنِ عَنْ عُثْمَانَ بْنِ عَفَّانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا وَرَاءَ حَمَامَةٍ فَقَالَ شَيْطَانٌ يَتْبَعُ شَيْطَانَةً","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya bin Sulaim At Tha`ifi] telah menceritakan kepada kami [Ibnu Juraij] dari [Al Hasan bin Abu Al Hasan] dari ['Utsman bin 'Affan] bahwa Rasulullah shallallahu 'alaihi wasallam melihat seseorang berlari mengikuti burung merpati, maka beliau bersabda: \"Ada setan yang mengikuti setan.\""},"3722":{"ar":"حَدَّثَنَا أَبُو نَصْرٍ مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا رَوَّادُ بْنُ الْجَرَّاحِ حَدَّثَنَا أَبُو سَعْدٍ السَّاعِدِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَتْبَعُ حَمَامًا فَقَالَ شَيْطَانٌ يَتْبَعُ شَيْطَانًا","id":"Telah menceritakan kepada kami [Abu Nashr Muhammad bin Khalaf Al 'Asqalani] telah menceritakan kepada kami [Rawwad bin Al Jarrah] telah menceritakan kepada kami [Abu Sa'd As Sa'idi] dari [Anas bin Malik] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melihat seorang lelaki yang mengikuti seekor burung merpati, maka beliau bersabda: \"Ada setan yang mengikuti setan.\""},"3723":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ عَاصِمِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ أَحَدُكُمْ مَا فِي الْوَحْدَةِ مَا سَارَ أَحَدٌ بِلَيْلٍ وَحْدَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari ['Ashim bin Muhammad] dari [ayahnya] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya seseorang di antara kalian (mengetahui apa yang terjadi saat ia) sedang sendirian, tentu tidak mungkin ia akan berani berjalan (sendirian) di malam hari.\""},"3724":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتْرُكُوا النَّارَ فِي بُيُوتِكُمْ حِينَ تَنَامُونَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Salim] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: Janganlah kalian membiarkan api (menyala) di rumah kalian ketika kalian tidur.\""},"3725":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَاحْتَرَقَ بَيْتٌ بِالْمَدِينَةِ عَلَى أَهْلِهِ فَحُدِّثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَأْنِهِمْ فَقَالَ إِنَّمَا هَذِهِ النَّارُ عَدُوٌّ لَكُمْ فَإِذَا نِمْتُمْ فَأَطْفِئُوهَا عَنْكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] dia berkata; \"Di Madinah ada suatu rumah yang terbakar hingga (membunuh) para penghuninya, maka di ceritakan kepada Nabi shallallahu 'alaihi wasallam tentang keadaan mereka tersebut, beliaupun bersabda: \"Api itu adalah musuh bagi kalian, jika kalian hendak tidur, maka matikanlah api tersebut dari sisi kalian.\""},"3726":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عَبْدِ الْمَلِكِ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَهَانَا فَأَمَرَنَا أَنْ نُطْفِئَ سِرَاجَنَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dari [Abdul Malik] dari [Abu Az Zubair] dari [jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan dan melarang kami, maka beliau memerintahkan kami untuk mematikan lampu kami.\""},"3727":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا هِشَامٌ عَنْ الْحَسَنِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنْزِلُوا عَلَى جَوَادِّ الطَّرِيقِ وَلَا تَقْضُوا عَلَيْهَا الْحَاجَاتِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syabah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Hisyam] dari [Al Hasan] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian singgah di pinggir (sisi) jalan, dan jangan pula membuang hajat disana.\"."},"3728":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ عَاصِمٍ حَدَّثَنَا مُوَرِّقٌ الْعِجْلِيُّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ جَعْفَرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَدِمَ مِنْ سَفَرٍ تُلُقِّيَ بِنَا قَالَ فَتُلُقِّيَ بِي وَبِالْحَسَنِ أَوْ بِالْحُسَيْنِ قَالَ فَحَمَلَ أَحَدَنَا بَيْنَ يَدَيْهِ وَالْآخَرَ خَلْفَهُ حَتَّى قَدِمْنَا الْمَدِينَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari ['Ashim] telah menceritakan kepada kami [Muwariq Al 'Ijli] telah menceritakan kepadaku [Abdullah bin Ja'far] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam datang dari bepergian, biasanya beliau menjumpai kami.\" Abdullah berkata; \"Maka beliau menjumpaiku, Hasan atau Husain.\" Abdullah melanjutkan; \"Maka beliau menggendong salah satu dari kami di depan dan yang lainnya di belakang tubuh beliau, hingga kami tiba di Madinah.\""},"3729":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا بَقِيَّةُ أَنْبَأَنَا أَبُو أَحْمَدَ الدِّمَشْقِيُّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَرِّبُوا صُحُفَكُمْ أَنْجَحُ لَهَا إِنَّ التُّرَابَ مُبَارَكٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Baqiyyah] telah memberitakan kepada kami [Abu Ahmad Ad Dimisqi] dari [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pakailah debu untuk membersihkan piring-piring kalian mungkin ia akan lebih berhasil, sebab debu itu diberkahi.\""},"3730":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كُنْتُمْ ثَلَاثَةً فَلَا يَتَنَاجَى اثْنَانِ دُونَ صَاحِبِهِمَا فَإِنَّ ذَلِكَ يَحْزُنُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy] dari [Syaqiq] dari [Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian bertiga, maka janganlah dua orang dari kalian berbisik tanpa menyertakan orang ketiga, sebab hal itu akan membuatnya sedih.\""},"3731":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَنَاجَى اثْنَانِ دُونَ الثَّالِثِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang dua orang berbisik-bisik tanpa menyertakan orang ketiga (yang bersamanya).\""},"3732":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ قُلْتُ لِعَمْرِو بْنِ دِينَارٍ أَسَمِعْتَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرَّ رَجُلٌ بِسِهَامٍ فِي الْمَسْجِدِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ بِنِصَالِهَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dia berkata; saya pernah bertanya kepada kepada ['Amru bin Dinar]; \"Apakah kamu pernah mendengar [Jabir bin Abdullah] berkata; \"Seorang laki-laki melintas di dalam masjid sambil membawa anak panah, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Peganglah mata anak panahmu!.\" Amru menjawab; \"Ya, pernah.\""},"3733":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَرَّ أَحَدُكُمْ فِي مَسْجِدِنَا أَوْ فِي سُوقِنَا وَمَعَهُ نَبْلٌ فَلْيُمْسِكْ عَلَى نِصَالِهَا بِكَفِّهِ أَنْ تُصِيبَ أَحَدًا مِنْ الْمُسْلِمِينَ بِشَيْءٍ أَوْ فَلْيَقْبِضْ عَلَى نِصَالِهَا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Kakeknya yaitu Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jika salah seorang dari kalian berjalan melewati masjid atau pasar kami sambil membawa anak panah, hendaknya ia memegang mata anak panahnya dengan tangannya, karena di khawatirkan akan mengenai seseorang dari kaum Muslimin, atau hendaknya ia menggenggam mata anak panahnya erat-erat.\""},"3734":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَاهِرُ بِالْقُرْآنِ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ وَالَّذِي يَقْرَؤُهُ يَتَتَعْتَعُ فِيهِ وَهُوَ عَلَيْهِ شَاقٌّ لَهُ أَجْرَانِ اثْنَانِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang pandai dalam membaca Al Qur'an, maka ia akan beserta para Malaikat yang mulia. Sedangkan orang yang membacanya dengan terbata-bata dan merasa kesulitan, maka ia akan memperoleh dua pahala.\""},"3735":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا شَيْبَانُ عَنْ فِرَاسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لِصَاحِبِ الْقُرْآنِ إِذَا دَخَلَ الْجَنَّةَ اقْرَأْ وَاصْعَدْ فَيَقْرَأُ وَيَصْعَدُ بِكُلِّ آيَةٍ دَرَجَةً حَتَّى يَقْرَأَ آخِرَ شَيْءٍ مَعَهُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami ['Ubaidullah bin Musa] telah memberitakan kepada kami [Syaiban] dari [Firas] dari ['Athiyah] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di perintahkan kepada orang yang ahli dalam Al Qur'an ketika ia masuk ke dalam surga; \"Bacalah dan naiklah.\" Maka ia pun membacanya dan dirinya pun naik (derajatnya) dengan ayat yang ia baca hingga ayat terakhir.\""},"3736":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ بَشِيرِ بْنِ مُهَاجِرٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجِيءُ الْقُرْآنُ يَوْمَ الْقِيَامَةِ كَالرَّجُلِ الشَّاحِبِ فَيَقُولُ أَنَا الَّذِي أَسْهَرْتُ لَيْلَكَ وَأَظْمَأْتُ نَهَارَكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Basyir bin Muhajir] dari [Ibnu Buraidah] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Al Qur`an akan datang pada hari kiamat seperti orang yang bermuka pucat, maka dia berkata; \"Akulah yang telah membuat kamu tidak tidur di malam harimu dan membuatmu haus pada siang harimu.\""},"3737":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُحِبُّ أَحَدُكُمْ إِذَا رَجَعَ إِلَى أَهْلِهِ أَنْ يَجِدَ فِيهِ ثَلَاثَ خَلِفَاتٍ عِظَامٍ سِمَانٍ قُلْنَا نَعَمْ قَالَ فَثَلَاثُ آيَاتٍ يَقْرَؤُهُنَّ أَحَدُكُمْ فِي صَلَاتِهِ خَيْرٌ لَهُ مِنْ ثَلَاثِ خَلِفَاتٍ سِمَانٍ عِظَامٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak sukakah jika salah seorang dari kalian kembali kepada keluarganya ingin mendapatkan tiga ekor unta betina yang hamil lagi kuat dan gemuk di rumahnya?\" Kami menjawab; \"Ya, tentu.\" Beliau bersabda: \"Tiga ayat yang dibaca seseorang dari kalian dalam shalatnya, itu lebih baik baginya dari tiga ekor unta betina yang hamil, gemuk dan bertuang (kuat).\""},"3738":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْقُرْآنِ مَثَلُ الْإِبِلِ الْمُعَقَّلَةِ إِنْ تَعَاهَدَهَا صَاحِبُهَا بِعُقُلِهَا أَمْسَكَهَا عَلَيْهِ وَإِنْ أَطْلَقَ عُقُلَهَا ذَهَبَتْ","id":"Telah menceritakan kepada kami [Ahmad bin Al Azhar] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan Al Qur'an Bagaikan seekor unta yang diikat, jika pemiliknya mengikat dengan erat berarti ia telah menjaganya. Akan tetapi jika ia melepas ikatannya, niscaya unta itu akan lepas.\""},"3739":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ عَزَّ وَجَلَّ قَسَمْتُ الصَّلَاةَ بَيْنِي وَبَيْنَ عَبْدِي شَطْرَيْنِ فَنِصْفُهَا لِي وَنِصْفُهَا لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا يَقُولُ الْعَبْدُ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ حَمِدَنِي عَبْدِي وَلِعَبْدِي مَا سَأَلَ فَيَقُولُ{ الرَّحْمَنِ الرَّحِيمِ }فَيَقُولُ أَثْنَى عَلَيَّ عَبْدِي وَلِعَبْدِي مَا سَأَلَ يَقُولُ{ مَالِكِ يَوْمِ الدِّينِ }فَيَقُولُ اللَّهُ مَجَّدَنِي عَبْدِي فَهَذَا لِي وَهَذِهِ الْآيَةُ بَيْنِي وَبَيْنَ عَبْدِي نِصْفَيْنِ يَقُولُ الْعَبْدُ{ إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ }يَعْنِي فَهَذِهِ بَيْنِي وَبَيْنَ عَبْدِي وَلِعَبْدِي مَا سَأَلَ وَآخِرُ السُّورَةِ لِعَبْدِي يَقُولُ الْعَبْدُ{ اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَهَذَا لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al 'Utsmani] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: Allah Azza Wa Jalla berfirman: \"Aku telah membagi shalat antara Diri-Ku dan hamba-Ku menjadi dua bagian, sebagiannya adalah untuk-Ku dan sebagian yang lain untuk hamba-Ku, dan bagi hamba-Ku segala yang dimohonkannya.\" Abu Hurairah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah, jika seorang hamba membaca \"Al hamdulillahi rabbil 'alamin (segala puji bagi Allah, Rabb semesta alam), maka Allah akan menjawab; \"Hamba-Ku telah memuji-Ku dan bagi hamba-Ku segala yang dimohonkannya.\" Ketika hamba membaca; \"Arrahmanir rahiim (yang Maha pengasih lagi Maha penyayang), \" Maka Allah menjawab; \"Hamba-Ku telah memuliakan-Ku dan bagi hamba-Ku segala yang di mohonkannya.\" Lalu ketika hamba itu membaca; \"Maaliki yaumiddin (Yang menguasai hari pembalasan).\" Maka Allah akan menjawab; \"Hamba-Ku telah mengagungkan-Ku, dan sesungguhnya sifat ini adalah milik-Ku. Dan ayat ini di bagi menjadi dua bagian, antara Aku dan hamba-Ku.\" Jika seorang hamba membaca; \"Iyyaka na'budu wa iyyaka nasta'iin (hanya kepada-Mu lah kami menyembah dan hanya kepada-Mu lah kami meminta pertolongan).\" Itu berarti perkara ini adalah perkara antara Aku dan hamba-Ku, dan bagi hamba-Ku segala yang di mohonkannya. Adapun akhir surat ini adalah untuk hamba-Ku.\" Jika seorang hamba membaca; \"Shirathalladziina 'an'amta 'alaihim ghairil maghdzuubi 'alaihim walad dzzaallin (yaitu jalan orang-orang yang telah Engkau anugerahkan nikmat kepada mereka, bukan (jalan) mereka yang di murkai dan bukan pula jalan mereka yang sesat.\" Maka bacaan ini adalah untuk hamba-Ku dan bagi hamba-Ku segala yang di mohonkannya.\""},"3740":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُعَلِّمُكَ أَعْظَمَ سُورَةٍ فِي الْقُرْآنِ قَبْلَ أَنْ أَخْرُجَ مِنْ الْمَسْجِدِ قَالَ فَذَهَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَخْرُجَ فَأَذْكَرْتُهُ فَقَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ وَهِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُوتِيتُهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Khubaib bbin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Sa'id Al Mu'alli] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Maukah kamu saya ajarkan tentang suatu surat di dalam Al Qur'an sebelum saya keluar dari Masjid?\" Abu Sa'id berkata; \"Ketika Nabi shallallahu 'alaihi wasallam hendak meninggalkan masjid, maka saya mengingatkan pesan beliau, lantas beliau bersabda: \"Segala puji bagi Allah Rabb semesta alam, dia adalah Sab'ul Matsani (tujuh ayat yang utama) dan Al Qur'an yang agung yang telah di turunkan kepadaku.\""},"3741":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ عَبَّاسٍ الْجُشَمِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ سُورَةً فِي الْقُرْآنِ ثَلَاثُونَ آيَةً شَفَعَتْ لِصَاحِبِهَا حَتَّى غُفِرَ لَهُ تَبَارَكَ الَّذِي بِيَدِهِ الْمُلْكُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Syu'bah] dari [Qatadah] dari ['Aabbas Al Jusyami] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya satu surat didalam Al Qur`an memiliki tiga puluh ayat yang dapat memberi syafa'at kepada pembacanya hingga ia diampuni. yaitu; tabaarakalladzii biyadihil mulku (? surat Al Mulk).\""},"3742":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ هُوَ اللَّهُ أَحَدٌ تَعْدِلُ ثُلُثَ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Khalid bin Mukhlad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepadaku [Suhail] dari [ayahnya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Qul huwallahu ahad sama sepertiga Al Qur`an.\""},"3743":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي قَيْسٍ الْأَوْدِيِّ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَحَدٌ الْوَاحِدُ الصَّمَدُ تَعْدِلُ ثُلُثَ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [waki'] dari [Sufyan] dari [Abu Qais Al Audi] dari ['Amru bin Maimun] dari [Abu Mas'ud Al Anshari] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allahu ahad alwaahidush shamad, sama sepertiga Al Qur`an.\""},"3744":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ زِيَادِ بْنِ أَبِي زِيَادٍ مَوْلَى ابْنِ عَيَّاشٍ عَنْ أَبِي بَحْرِيَّةَ عَنْ أَبِي الدَّرْدَاءِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُنَبِّئُكُمْ بِخَيْرِ أَعْمَالِكُمْ وَأَرْضَاهَا عِنْدَ مَلِيكِكُمْ وَأَرْفَعِهَا فِي دَرَجَاتِكُمْ وَخَيْرٍ لَكُمْ مِنْ إِعْطَاءِ الذَّهَبِ وَالْوَرِقِ وَمِنْ أَنْ تَلْقَوْا عَدُوَّكُمْ فَتَضْرِبُوا أَعْنَاقَهُمْ وَيَضْرِبُوا أَعْنَاقَكُمْ قَالُوا وَمَا ذَاكَ يَا رَسُولَ اللَّهِ قَالَ ذِكْرُ اللَّهِو قَالَ مُعَاذُ بْنُ جَبَلٍ مَا عَمِلَ امْرُؤٌ بِعَمَلٍ أَنْجَى لَهُ مِنْ عَذَابِ اللَّهِ عَزَّ وَجَلَّ مِنْ ذِكْرِ اللَّهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Abdullah bin Sa'id bin Abu Hind] dari [Ziyad bin Abu Ziyad bekas budak Ibnu Abbas] dari [Abu Bahriyah] dari [Abu Darda`] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Maukah kalian saya beritahukan tentang sebaik-baik amalan kalian dan yang lebih dicintai oleh Rabb kalian, lebih mulia bagi kalian dari bersedekah dengan emas dan perak serta dari berperang dengan musuh-musuh kalian kemudian kalian tebas batang leher mereka dan (atau) mereka menebas batang leher kalian?\" para sahabat bertanya; \"Apakah amalan itu wahai Rasulullah?\" beliau menjawab: \"Berdzikir kepada Allah.\" Mu'adz bin Jabal berkata; \"Tidaklah suatu amalan yang di kerjakan oleh seseorang lebih dapat melindungi dirinya dari adzab Allah Azza Wa Jalla selain berdzikir kepada Allah.\""},"3745":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ عَمَّارِ بْنِ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ عَنْ الْأَغَرِّ أَبِي مُسْلِمٍ عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍيَشْهَدَانِ بِهِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا جَلَسَ قَوْمٌ مَجْلِسًا يَذْكُرُونَ اللَّهَ فِيهِ إِلَّا حَفَّتْهُمْ الْمَلَائِكَةُ وَتَغَشَّتْهُمْ الرَّحْمَةُ وَتَنَزَّلَتْ عَلَيْهِمْ السَّكِينَةُ وَذَكَرَهُمْ اللَّهُ فِيمَنْ عِنْدَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] dari ['Ammar bin Ruzaiq] dari [Abu Ishaq] dari [Al Aghar Abu Muslim] dari [Abu Hurairah] dan [Abu Sa'id] bahwa keduanya pernah menyaksikan Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah ada suatu kaum duduk sambil berdzikir kepada Allah, kecuali para Malaikat akan mengelilingi mereka, dan akan diselubungi rahmat, akan turun kepada mereka sakinah (ketenangan), dan Allah akan menyebut-nyebut orang-orang yang ada disisi-Nya.\""},"3746":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ عَنْ الْأَوْزَاعِيِّ عَنْ إِسْمَعِيلَ بْنِ عُبَيْدِ اللَّهِ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَقُولُ أَنَا مَعَ عَبْدِي إِذَا هُوَ ذَكَرَنِي وَتَحَرَّكَتْ بِي شَفَتَاهُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Muhammad bin Mush'ab] dari [Al Auza'i] dari [Isma'il bin 'Ubaidillah] dari [Ummu Darda`] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah Azza Wa Jalla berfirman: \"Aku bersama hamba-Ku apabila dia berdzikir kepada-Ku, dan selama kedua bibirnya bergerak menyebut nama-Ku.\""},"3747":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ أَخْبَرَنِي مُعَاوِيَةُ بْنُ صَالِحٍ أَخْبَرَنِي عَمْرُو بْنُ قَيْسٍ الْكِنْدِيُّ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍأَنَّ أَعْرَابِيًّا قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ شَرَائِعَ الْإِسْلَامِ قَدْ كَثُرَتْ عَلَيَّ فَأَنْبِئْنِي مِنْهَا بِشَيْءٍ أَتَشَبَّثُ بِهِ قَالَ لَا يَزَالُ لِسَانُكَ رَطْبًا مِنْ ذِكْرِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Zaid bin Al Hubab] telah mengabarkan kepadaku [Mu'awiyah bin Shalih] telah mengabarkan kepadaku ['Amru bin Qais Al Kindi] dari ['Abdullah bin Busr] bahwa seorang badui bertanya kepada Nabi shallallahu 'alaihi wasallam, katanya; \"Sesungguhnya ajaran-jaran Islam telah benyak di ketahui, maka beritahukanlah kepadaku sesuatu darinya yang dapat saya ucapkan berulang-ulang.\" Nabi shallallahu 'alaihi wasallam menjawab: \"Selama lidahmu terus bergerak dengan berdzikir kepada Allah Azza Wa Jalla.\""},"3748":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ حَمْزَةَ الزَّيَّاتِ عَنْ أَبِي إِسْحَقَ عَنْ الْأَغَرِّ أَبِي مُسْلِمٍ أَنَّهُ شَهِدَ عَلَى أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍأَنَّهُمَا شَهِدَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْعَبْدُ لَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ قَالَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ صَدَقَ عَبْدِي لَا إِلَهَ إِلَّا أَنَا وَأَنَا أَكْبَرُ وَإِذَا قَالَ الْعَبْدُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ قَالَ صَدَقَ عَبْدِي لَا إِلَهَ إِلَّا أَنَا وَحْدِي وَإِذَا قَالَ لَا إِلَهَ إِلَّا اللَّهُ لَا شَرِيكَ لَهُ قَالَ صَدَقَ عَبْدِي لَا إِلَهَ إِلَّا أَنَا وَلَا شَرِيكَ لِي وَإِذَا قَالَ لَا إِلَهَ إِلَّا اللَّهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ قَالَ صَدَقَ عَبْدِي لَا إِلَهَ إِلَّا أَنَا لِي الْمُلْكُ وَلِيَ الْحَمْدُ وَإِذَا قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ قَالَ صَدَقَ عَبْدِي لَا إِلَهَ إِلَّا أَنَا وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِيقَالَ أَبُو إِسْحَقَ ثُمَّ قَالَ الْأَغَرُّ شَيْئًا لَمْ أَفْهَمْهُ قَالَ فَقُلْتُ لِأَبِي جَعْفَرٍ مَا قَالَ فَقَالَ مَنْ رُزِقَهُنَّ عِنْدَ مَوْتِهِ لَمْ تَمَسَّهُ النَّارُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Al Husain bin Ali] dari [Hamzah Az Za yyat] dari [Abu Ishaq] dari [Al Aghar Abu Muslim] bahwa dia menyaksikan [Abu Hurairah] dan [Abu Sa'id] bahwa keduanya menyaksikan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang hamba mengucapkan; \"Tidak ada ilah yang berhaq disembah kecuali Allah dan Allah Maha Besar\". Beliau bersabda: Maka Allah 'azza wajalla menjawab: \"hamba-Ku benar, tidak ada ilah yang berhak disembah kecuali Aku, dan Aku Maha Besar\". Dan apabila seorang hamba mengucapkan; \"Tidak ada ilah yang berhak disembah kecuali Allah satu-satunya.\" Maka Allah menjawab: \"Hamba-Ku benar, tidak ada ilah yang berhak disembah kecuali Aku satu-satunya.\" Dan apabila seorang hamba mengucapkan; \"Tidak ada ilah yang berhak disembah kecuali Allah yang tidak ada sekutu bagi-Nya.\" Maka Allah menjawab: \"Hamba-Ku benar, tidak ada ilah yang berhak disembah kecuali Aku yang tidak ada sekutu bagi-Ku.\" Dan apabila seorang hamba mengucapkan; \"Tidak ada ilah yang berhak disembah kecuali Allah yang milik-Nya seluruh kerajaan dan bagi-Nya segala pujian.\" Maka Allah menjawab: \"Hambaku benar, tidak ada ilah yang berhak disembah kecuali Aku yang milik-Ku segala kerajaan dan bagi-Ku segala pujian.\" Dan apabila seorang hamba mengucapkan; \"Tidak ada ilah yang berhak disembah kecuali Allah dan tidak ada daya dan upaya kecuali dengan kehendak Allah.\" Maka Allah berfirman: \"Hamba-Ku benar, tidak ada ilah yang berhak disembah kecuali Aku dan tidak ada daya dan upaya kecuali dengan kehendak-Ku.\" Abu Ishaq berkata; \"Kemudian al Agharru berkata; \"Ada sesuatu yang belum saya fahami.\" Dia berkata; \"Lantas saya bertanya kepada Abu Ja'far; apa yang dikatakannya?\". Dia menjawab; \"Barang siapa yang di berikan rizki dengan semua itu ketika meninggalnya, maka dia tidak akan mencium bau neraka.\""},"3749":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْوَهَّابِ عَنْ مِسْعَرٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ يَحْيَى بْنِ طَلْحَةَ عَنْ أُمِّهِ سُعْدَى الْمُرِّيَّةِ قَالَتْمَرَّ عُمَرُ بِطَلْحَةَ بَعْدَ وَفَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا لَكَ كَئِيبًا أَسَاءَتْكَ إِمْرَةُ ابْنِ عَمِّكَ قَالَ لَا وَلَكِنْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنِّي لَأَعْلَمُ كَلِمَةً لَا يَقُولُهَا أَحَدٌ عِنْدَ مَوْتِهِ إِلَّا كَانَتْ نُورًا لِصَحِيفَتِهِ وَإِنَّ جَسَدَهُ وَرُوحَهُ لَيَجِدَانِ لَهَا رَوْحًا عِنْدَ الْمَوْتِ فَلَمْ أَسْأَلْهُ حَتَّى تُوُفِّيَ قَالَ أَنَا أَعْلَمُهَا هِيَ الَّتِي أَرَادَ عَمَّهُ عَلَيْهَا وَلَوْ عَلِمَ أَنَّ شَيْئًا أَنْجَى لَهُ مِنْهَا لَأَمَرَهُ","id":"Telah menceritakan kepada kami [Harun bin Ishaq Al Hamdani] telah menceritakan kepada kami [Muhammad bin Abdul Wahab] dari [Mis'ar] dari [Isma'il bin Abu khalid] dari [As Sya'bi] dari [Yahya bin Thalhah] dari [ibunya yaitu Su'da Al Murriyah] dia berkata; Umar lewati di samping Thalhah setelah wafatnya Rasulullah shallallahu 'alaihi wasallam, kemudian dia berkata; \"Kenapa kamu termenung?, apakah istrimu -sepupumu- menyakitimu?\" [Thalhah] menjawab; \"Tidak, tetap saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya akan memberitahukan suatu kalimat jika diucapkan oleh seseorang ketika ajalnya tiba, maka akan menjadi cahaya untuk catatan amalnya. Dan sesungguhnya jasad dan ruhnya akan mendapatkan ketenangan ketika maut menjemputnya.\" Namun (sayangnya) tidak sempat saya tanyakan kalimat itu sampai beliau meninggal.\" Umar berkata; \"Saya mengetahui kalimat itu, yaitu kalimat yang sangat di inginkan agar pamannya mengucapkan kalimat tersebut. Dan sekiranya beliau mengetahui ada kalimat lain yang lebih baik darinya, tentu beliau akan memerintahkannya.\""},"3750":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَيَانٍ الْوَاسِطِيُّ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ يُونُسَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ هِصَّانَ بْنِ الْكَاهِلِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ نَفْسٍ تَمُوتُ تَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْجِعُ ذَلِكَ إِلَى قَلْبِ مُوقِنٍ إِلَّا غَفَرَ اللَّهُ لَهَا","id":"Telah menceritakan kepada kami [Abdul Hamid bin Bayan Al Wasithi] telah menceritakan kepada kami [Khalid bin Abdullah] dari [Yunus] dari [Humaid bin Hilal] dari [Hishan bin Kahil] dari [Abdurrahman bin Samurah] dari [Mu'adz bin Jabal] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah jiwa yang meninggal dunia dengan bersaksi bahwa tidak ada ilah selain Allah dan saya adalah utusan Allah, serta ucapannya itu muncul dari hati yang yakin, melainkan Allah akan mengampuninya.\""},"3751":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا زَكَرِيَّا بْنُ مَنْظُورٍ حَدَّثَنِي مُحَمَّدُ بْنُ عُقْبَةَ عَنْ أُمِّ هَانِئٍ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا إِلَهَ إِلَّا اللَّهُ لَا يَسْبِقُهَا عَمَلٌ وَلَا تَتْرُكُ ذَنْبًا","id":"Telah menceritakan kepada kami [Ibrahim Al Mundzir Al Hizami] telah menceritakan kepada kami [Zakariya bin Mandzur] telah menceritakan kepadaku [Muhammad bin 'Uqbah] dari [Ummu Hani`] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalimat La ilaaha illallahu, tidak didahului oleh amalan dan tidak meninggalkan dosa\""},"3752":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مَالِكِ بْنِ أَنَسٍ أَخْبَرَنِي سُمَيٌّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ فِي يَوْمٍ مِائَةَ مَرَّةٍ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ كَانَ لَهُ عَدْلُ عَشْرِ رِقَابٍ وَكُتِبَتْ لَهُ مِائَةُ حَسَنَةٍ وَمُحِيَ عَنْهُ مِائَةُ سَيِّئَةٍ وَكُنَّ لَهُ حِرْزًا مِنْ الشَّيْطَانِ سَائِرَ يَوْمِهِ إِلَى اللَّيْلِ وَلَمْ يَأْتِ أَحَدٌ بِأَفْضَلَ مِمَّا أَتَى بِهِ إِلَّا مَنْ قَالَ أَكْثَرَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Zaid bin Hubab] dari [Malik bin Anas] telah mengabarkan kepadaku [Sumayy bekas budak Abu Bakr] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa setiap harinya membaca Tidak ada ilah selain Allah yang Maha Esa, yang tidak ada sekutu bagi-Nya, milik-Nya kerajaan dan bagi-Nya segala pujian, dan Dia atas segala sesuatu berkuasa, \" sebanyak seratus kali, maka pahalanya seperti memerdekakan sepuluh orang budak, akan di tulis baginya seratus kebaikan, dan dihapuskan darinya seratus kesalahan, dan kalimat tersebut akan menjadi pelindung baginya dari setan di sepanjang hari sampai malamnya. Dan tidaklah seorangpun yang akan (datang mengalahkannya) dengan membawa amalan yang lebih utama dari amalan yang dibacanya kecuali jika ia membaca kalimat tersebut lebih banyak lagi.\""},"3753":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا بَكْرُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عِيسَى بْنُ الْمُخْتَارِ عَنْ مُحَمَّدِ بْنِ أَبِي لَيْلَى عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ فِي دُبُرِ صَلَاةِ الْغَدَاةِ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ كَانَ كَعَتَاقِ رَقَبَةٍ مِنْ وَلَدِ إِسْمَعِيلَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Bakr bin Abdurrahman] telah menceritakan kepada kami [Isa bin Al Mukhtar] dari [Muhammad bin Abu Laila] dari ['Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa mengucapkan di akhir shalat subuh; \"Laa ilaaha illallah wahdahu laa syariikalah lahul mulku walahul hamdu biyadihil khair wahuwa 'ala kulli syai`in qadiir (Tidak ada ilah yang berhak disembah kecuali Allah satu-satuNya, tidak ada sekutu bagiNya, milikNya seluruh kerajaan dan bagiNya segala puji, ditanganNya seluruh kebaikan dan Dia atas segala sesuatu menguasai).\" Maka dia seperti orang yang membebaskan seorang budak dari keturunan Isma'il.\""},"3754":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا مُوسَى بْنُ إِبْرَاهِيمَ بْنِ كَثِيرِ بْنِ بَشِيرِ بْنِ الْفَاكِهِ قَالَ سَمِعْتُ طَلْحَةَ بْنَ خِرَاشٍ ابْنَ عَمِّ جَابِرٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَفْضَلُ الذِّكْرِ لَا إِلَهَ إِلَّا اللَّهُ وَأَفْضَلُ الدُّعَاءِ الْحَمْدُ لِلَّهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Musa bin Ibrahim bin Katsir bin Basyir bin Al fakih] dia berkata; saya mendengar [Thalhah bin Khirasy anak pamannya Jabir] dia berkata; saya mendengar [Jabir bin Abdillah] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dzikir yang paling utama adalah Laa ilaaha illallah (Tidak ada ilah yang berhak disembah kecuali Allah). Dan do'a yang paling utama adalah Al Hamdulillah (segala puji bagi Allah).\""},"3755":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا صَدَقَةُ بْنُ بَشِيرٍ مَوْلَى الْعُمَرِيِّينَ قَالَ سَمِعْتُ قُدَامَةَ بْنَ إِبْرَاهِيمَ الْجُمَحِيَّ يُحَدِّثُ أَنَّهُ كَانَ يَخْتَلِفُ إِلَى عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ وَهُوَ غُلَامٌ وَعَلَيْهِ ثَوْبَانِ مُعَصْفَرَانِ قَالَ فَحَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُمْ أَنَّ عَبْدًا مِنْ عِبَادِ اللَّهِ قَالَ يَا رَبِّ لَكَ الْحَمْدُ كَمَا يَنْبَغِي لِجَلَالِ وَجْهِكَ وَلِعَظِيمِ سُلْطَانِكَ فَعَضَّلَتْ بِالْمَلَكَيْنِ فَلَمْ يَدْرِيَا كَيْفَ يَكْتُبَانِهَا فَصَعِدَا إِلَى السَّمَاءِ وَقَالَا يَا رَبَّنَا إِنَّ عَبْدَكَ قَدْ قَالَ مَقَالَةً لَا نَدْرِي كَيْفَ نَكْتُبُهَا قَالَ اللَّهُ عَزَّ وَجَلَّ وَهُوَ أَعْلَمُ بِمَا قَالَ عَبْدُهُ مَاذَا قَالَ عَبْدِي قَالَا يَا رَبِّ إِنَّهُ قَالَ يَا رَبِّ لَكَ الْحَمْدُ كَمَا يَنْبَغِي لِجَلَالِ وَجْهِكَ وَعَظِيمِ سُلْطَانِكَ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لَهُمَا اكْتُبَاهَا كَمَا قَالَ عَبْدِي حَتَّى يَلْقَانِي فَأَجْزِيَهُ بِهَا","id":"Telah menceritakan kepada kami [ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Shadaqah bin Basyir bekas budak Al 'Umariyyin] dia berkata; saya mendengar [Qudamah bin Ibrahim Al Jumahi] bercerita bahwa dia bolak-balik datang ke Abdullah bin 'Umar Bin Al Khatthab, -Pada saat itu dia masih anak-anak yang mengenakan dua baju yang diberi 'Ushfuran- dia berkata; telah menceritakan kepada kami [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam menceritakan kepada mereka: \"Sesungguhnya salah seorang dari hamba-hamba Allah berkata; \"Ya Rabb, bagi-Mu segala puji sebagaimana yang selayaknya bagi kebesaran wajah-Mu dan keagungan kekuasaan-Mu\". Maka ucapan itu membuat dua malaikat bingung dan tidak mengerti bagaimana menulisnya, kemudian mereka berdua naik kelangit dan berkata: \"wahai Rabb kami, sesungguhnya hamba-Mu mengucapkan satu perkataan yang kami tidak tahu bagaimana menulisnya.\" Allah 'azza wajalla yang lebih mengetahui dengan apa yang diucapkan oleh hamba-Nya bertanya: \"Apa yang di ucapkan hamba-Ku?.\" Keduanya menjawab: \"Wahai Rabb, sesungguhnya ia mengucapkan; \"Wahai Rabb, bagi-Mu segala puji sebagaimana yang selayaknya bagi kebesaran Wajah-Mu dan keagungan kekuasaan-Mu.\" Maka Allah 'azza wajalla berfirman kepada keduanya: \"Tulislah sebagaimana yang di ucapkan hamba-Ku, hingga ketika dia bertemu dengan-Ku, Aku akan memberinya balasan.\""},"3756":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ذَا الَّذِي قَالَ هَذَا قَالَ الرَّجُلُ أَنَا وَمَا أَرَدْتُ إِلَّا الْخَيْرَ فَقَالَ لَقَدْ فُتِحَتْ لَهَا أَبْوَابُ السَّمَاءِ فَمَا نَهْنَهَهَا شَيْءٌ دُونَ الْعَرْشِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Abdul Jabbar bin Wa`il] dari [ayahnya] dia berkata; Saya pernah shalat bersama Nabi shallallahu 'alaihi wasallam, maka seorang laki-laki berucap; \"ALHAMDULILLAHI HAMDAN THAYYIBAN MUBAARAKAN FIHI (Segala puji bagi Allah dengan pujian yang penuh kebaikan dan keberkahan) tatkala Nabi shallalahu 'alaihi wa sallam selesai shalat beliau mengatakan siapa yang mengucapkan hal itu? Saya wahai Rasulullah, saya tidak menginginkan kecuali hanya kebaikan, Rasulullah bersabda: Sungguh telah terbuka pintu-pintu langit (dengan do'a tersebut) tidak ada yang menghalanginya kecuali arsy."},"3757":{"ar":"حَدَّثَنَا هِشَامُ بْنُ خَالِدٍ الْأَزْرَقُ أَبُو مَرْوَانَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ مَنْصُورِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَى مَا يُحِبُّ قَالَ الْحَمْدُ لِلَّهِ الَّذِي بِنِعْمَتِهِ تَتِمُّ الصَّالِحَاتُ وَإِذَا رَأَى مَا يَكْرَهُ قَالَ الْحَمْدُ لِلَّهِ عَلَى كُلِّ حَالٍ","id":"Telah menceritaan: kepada kami [Hisyam bin Khalid Al Azraq Abu Marwan] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Manshur bin Abdurrahman] dari [ibunya yaitu Shafiyah binti Syaibah] dari ['Aisyah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam melihat sesuatu yang ia senangi, beliau mengucapkan: \"Segala puji bagi Allah yang dengan nikmat-Nya semua kebaikan menjadi sempurna.\" dan apabila melihat sesuatu yang dibenci, beliau mengucapkan: \"Segala puji bagi Allah atas setiap keadaan.\""},"3758":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مُوسَى بْنِ عُبَيْدَةَ عَنْ مُحَمَّدِ بْنِ ثَابِتٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ الْحَمْدُ لِلَّهِ عَلَى كُلِّ حَالٍ رَبِّ أَعُوذُ بِكَ مِنْ حَالِ أَهْلِ النَّارِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Musa bin 'Ubaidah] dari [Muhammad bin Tsabit] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Segala puji bagi Allah atas setiap keadaan, Wahai Rabbku, aku berlindung kepada-Mu dari keadaan penghuni neraka.\""},"3759":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ شَبِيبِ بْنِ بِشْرٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَنْعَمَ اللَّهُ عَلَى عَبْدٍ نِعْمَةً فَقَالَ الْحَمْدُ لِلَّهِ إِلَّا كَانَ الَّذِي أَعْطَاهُ أَفْضَلَ مِمَّا أَخَذَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Abu 'Ashim] dari [Syabib bin Bisyr] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah Allah memberikan kenikmatan kepada seorang hamba, kemudian ia mengucapkan; \"Segala puji bagi Allah\", kecuali apa yang dia berikan itu lebih utama dari apa yang telah ia terima.\""},"3760":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَتَانِ خَفِيفَتَانِ عَلَى اللِّسَانِ ثَقِيلَتَانِ فِي الْمِيزَانِ حَبِيبَتَانِ إِلَى الرَّحْمَنِ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ سُبْحَانَ اللَّهِ الْعَظِيمِ","id":"Telah menceritakan kepada kami [Abu Bakar] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Amarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua kalimat yang ringan di ucapkan dengan lisan, berat dalam timbangan dan sangat di cintai oleh Dzat yang Maha pengasih adalah Subhanallah wa bihamdihi subhanallahil 'adzim (Maha suci Allah dan segala puji bagi-Nya, Maha suci Allah dan Maha Agung).\""},"3761":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي سِنَانٍ عَنْ عُثْمَانَ بْنِ أَبِي سَوْدَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يَغْرِسُ غَرْسًا فَقَالَ يَا أَبَا هُرَيْرَةَ مَا الَّذِي تَغْرِسُ قُلْتُ غِرَاسًا لِي قَالَ أَلَا أَدُلُّكَ عَلَى غِرَاسٍ خَيْرٍ لَكَ مِنْ هَذَا قَالَ بَلَى يَا رَسُولَ اللَّهِ قَالَ قُلْ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ يُغْرَسْ لَكَ بِكُلِّ وَاحِدَةٍ شَجَرَةٌ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Sinan] dari [Utsman bin Abu Saudah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah melawitnya saat ia sedang menanam tanaman, maka beliau bersabda: \"Wahai Abu Hurairah, tanaman apa yang kamu tanam?\" dia menjawab; \"Tanaman milikku.\" Beliau bersabda: \"Apakah kamu mau kuberitahukan tentang tanaman yang bagimu akan lebih baik dari tanaman ini?\" Abu Hurairah menjawab; \"Tentu wahai Rasulullah!.\" Beliau bersabda: \"Ucapkanlah olehmu Subhanallah (Maha suci Allah), Al Hamdulillah (Segala puji bagi Allah), Laa ilaaha illallah (tidak ada ilah selain Allah) dan Allahu akbar (Allah Maha besar). Maka setiap bacaan tersebut akan menumbuhkan satu pohon di surga bagimu.\""},"3762":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مِسْعَرٌ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي رِشْدِينَ عَنْ ابْنِ عَبَّاسٍ عَنْ جُوَيْرِيَةَ قَالَتْمَرَّ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ صَلَّى الْغَدَاةَ أَوْ بَعْدَ مَا صَلَّى الْغَدَاةَ وَهِيَ تَذْكُرُ اللَّهَ فَرَجَعَ حِينَ ارْتَفَعَ النَّهَارُ أَوْ قَالَ انْتَصَفَ وَهِيَ كَذَلِكَ فَقَالَ لَقَدْ قُلْتُ مُنْذُ قُمْتُ عَنْكِ أَرْبَعَ كَلِمَاتٍ ثَلَاثَ مَرَّاتٍ وَهِيَ أَكْثَرُ وَأَرْجَحُ أَوْ أَوْزَنُ مِمَّا قُلْتِ سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Mis'ar] telah menceritakan kepadaku [Muhammad bin Abdurrahman] dari [Abu Risydin] dari [Ibnu Abbas] dari [Juwairiyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah lewat di dekatnya ketika shalat subuh atau sesudah shalat subuh, saat ia tengah berdzikir kepada Allah. Kemudian beliau kembali ketika siang mulai meninggi -atau perawi berkata; \"Ketika pertengahan siang.\"- sementara dirinya masih tetap seperti semula. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Saya telah mengucapkan empat kalimat sebanyak tiga kali sejal saya meninggalkanmu. Dan kalimat tersebut lebih banyak (pahalanya) dan lebih baik -atau berat timbangannya- dari apa yang kamu ucapkan. Yaitu; Subhanallah 'adada khalqih (Maha suci Allah sebanyak makhluq-Nya), Subhanallah ridla nfsih (Maha suci Allah sebanyak keridlaan diri-Nya), Subhanallah zinata 'arsyih (Maha suci Allah sebanyak hiasan 'Arsy-Nya) dan Subhanallah midada kalimatih (Maha suci Allah sebanyak kelaimat-kalimat-Nya).\""},"3763":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ مُوسَى بْنِ أَبِي عِيسَى الطَّحَّانِ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ أَوْ عَنْ أَخِيهِ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِمَّا تَذْكُرُونَ مِنْ جَلَالِ اللَّهِ التَّسْبِيحَ وَالتَّهْلِيلَ وَالتَّحْمِيدَ يَنْعَطِفْنَ حَوْلَ الْعَرْشِ لَهُنَّ دَوِيٌّ كَدَوِيِّ النَّحْلِ تُذَكِّرُ بِصَاحِبِهَا أَمَا يُحِبُّ أَحَدُكُمْ أَنْ يَكُونَ لَهُ أَوْ لَا يَزَالَ لَهُ مَنْ يُذَكِّرُ بِهِ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepadaku [Yahya bin Sa'id] dari [Musa bin Abu Isa At Thahan] dari ['Aun bin Abdullah] dari [ayahnya] atau dari [saudaranya] dari [An Nu'man bin Basyir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara kalimat yang kalian ucapkan tentang keagungan Allah dari tasbih, tahlil dan tahmid, maka ucapan itu akan selalu berputar di sekeliling 'Arsy. Bagi tia-tiap kalimat tersebut suaranya mendengung bagaikan dengungan lebah yang menyebutkan orang yang membacanya. Bukankah seseorang dari kalian menginginkan -atau, selalu ingin akan sesuatu- yang dapat mengingatkan dirinya?.\""},"3764":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا أَبُو يَحْيَى زَكَرِيَّا بْنُ مَنْظُورٍ حَدَّثَنِي مُحَمَّدُ بْنُ عُقْبَةَ بْنِ أَبِي مَالِكٍ عَنْ أُمِّ هَانِئٍ قَالَتْأَتَيْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ دُلَّنِي عَلَى عَمَلٍ فَإِنِّي قَدْ كَبِرْتُ وَضَعُفْتُ وَبَدُنْتُ فَقَالَ كَبِّرِي اللَّهَ مِائَةَ مَرَّةٍ وَاحْمَدِي اللَّهَ مِائَةَ مَرَّةٍ وَسَبِّحِي اللَّهَ مِائَةَ مَرَّةٍ خَيْرٌ مِنْ مِائَةِ فَرَسٍ مُلْجَمٍ مُسْرَجٍ فِي سَبِيلِ اللَّهِ وَخَيْرٌ مِنْ مِائَةِ بَدَنَةٍ وَخَيْرٌ مِنْ مِائَةِ رَقَبَةٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Abu Yahya Zakariya bin Mandzur] telah menceritakan kepadaku [Muhammad bin 'Uqbah bin Abu Malik] dari [Ummu Hani`] dia berkata; \"Saya mengunjungi Rasulullah shallallahu 'alaihi wasallam dan bertanya; \"Wahai Rasulullah, beritahukanlah kepadaku tentang suatu amalan, karena sesungguhnya usiaku telah lanjut dan saya telah melemah serta badanku pun telah menggemuk.\" Beliau bersabda: \"Bertakbirlah kepada Allah seratus kali, dan bertahmidlah kepada Allah sebanyak seratus kali, dan bertasbihlah kepada Allah seratus sekali, maka semua itu lebih baik dari seratus kuda yang bertali kekang serta berpelana yang di infakkan untuk berperang di jalan Allah. Dan lebih baik dari seratus unta yang gemuk, serta lebih baik dari membebaskan seratus hamba sahaya.\""},"3765":{"ar":"حَدَّثَنَا أَبُو عُمَرَ حَفْصُ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَمُرَةَ بْنِ جُنْدَبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعٌ أَفْضَلُ الْكَلَامِ لَا يَضُرُّكَ بِأَيِّهِنَّ بَدَأْتَ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Abu Umar Hafsh bin 'Amru] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Hilal bin Yasaf] dari [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ucapan yang paling utama itu ada empat, tidak akan membahayakan bagimu dengan mana saja kamu memulainya, yaitu; Subhanallah (Maha suci Allah), Al Hamdulillah (segala puji bagi Allah), Laa ilaaha illallah (tidak ada ilah yang berhak disembah kecuali Allah), dan Allahu akbar (Allah Maha besar).\""},"3766":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَبْدِ الرَّحْمَنِ الْوَشَّاءُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ مِائَةَ مَرَّةٍ غُفِرَتْ لَهُ ذُنُوبُهُ وَلَوْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ","id":"Telah menceritakan kepada kami [Nashr bin Abdurrahman Al Wassya`] telah menceritakan kepada kami [Abdurrahman Al Muharibi] dari [Malik bin Anas] dari [Sumayy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengucapkan Subhanallah wa bihamdihi sebanyak seratus kali, maka dosa-dosanya akan diampuni walau seperti buih di lautan.\""},"3767":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عُمَرَ بْنِ رَاشِدٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَ��َمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكَ بِسُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ فَإِنَّهَا يَعْنِي يَحْطُطْنَ الْخَطَايَا كَمَا تَحُطُّ الشَّجَرَةُ وَرَقَهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Umar bin Rasyid] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Abu Darda`] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Hendaknya kamu selalu mengucapkan Subhanallah wal hamdulillah wa laailaaha illallah wallahu akbar (Maha suci Allah, dan segala pujian bagi Allah, dan tidak ada ilah kecuali Allah dan Allah Maha besar), maka kalimat tersebut akan menggugurkan kesalahan-kesalahan sebagaimana pohon menjatuhkan dedaunannya.\""},"3768":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ وَالْمُحَارِبِيُّ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَإِنْ كُنَّا لَنَعُدُّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَجْلِسِ يَقُولُ رَبِّ اغْفِرْ لِي وَتُبْ عَلَيَّ إِنَّكَ أَنْتَ التَّوَّابُ الرَّحِيمُ مِائَةَ مَرَّةٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abu Usamah] dan [Al Muharibi] dari [Malik bin Mighwal] dari [Muhammad bin Suqah] dari [Nafi'] dari [Ibnu Umar] dia berkata; \"Apabila kami menghitung ucapan Rasulullah shallallahu 'alaihi wasallam dalam suatu majlis: \"Rabbighfirli watub 'alayya innaka anta tawwabur rahim (Ya Rabbku ampunilah aku dan terimalah taubatku, sesungguhnya Engkaulah Maha penerima taubat dan maha penyayang\" beliau mengucapkannya sebanyak seratus kali.\""},"3769":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ فِي الْيَوْمِ مِائَةَ مَرَّةٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya memohon ampunan kepada Allah dan bertaubat kepada-Nya sehari seratus kali.\""},"3770":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مُغِيرَةَ بْنِ أَبِي الْحُرِّ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ فِي الْيَوْمِ سَبْعِينَ مَرَّةً","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Mughirah bin Abu Al Hurr] dari [Sa'id bin Abu Burdah bin Abu Musa] dari [ayahnya] dari [kakeknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya memohon ampunan kepada Allah dan bertaubat kepada-Nya sehari tujuh puluh kali.\""},"3771":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْمُغِيرَةِ عَنْ حُذَيْفَةَ قَالَكَانَ فِي لِسَانِي ذَرَبٌ عَلَى أَهْلِي وَكَانَ لَا يَعْدُوهُمْ إِلَى غَيْرِهِمْ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْنَ أَنْتَ مِنْ الِاسْتِغْفَارِ تَسْتَغْفِرُ اللَّهَ فِي الْيَوْمِ سَبْعِينَ مَرَّةً","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Abu Ishaq] dari [Abu Al Mughirah] dari [Hudzaifah] dia berkata; \"Dilidahku ada kata-kata kotor terhadap keluargaku, dan itu tidak menularkan mereka pada yang lain, lalu saya melaporkan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kemana kamu dari istighfar hai Hudzaifah? Sesungguhnya aku beristighfar kepada Allah tujuh puluh kali dalam sehari.\""},"3772":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عِرْقٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ بُسْرٍ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طُوبَى لِمَنْ وَجَدَ فِي صَحِيفَتِهِ اسْتِغْفَارًا كَثِيرًا","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himsha] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Muhammad bin Abdurrahman bin 'Irq] saya mendengar [Abdullah bin Busr] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beruntunglah bagi orang yang mendapatkan didalam catatan amalnya istighfar yang banyak.\""},"3773":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْحَكَمُ بْنُ مُصْعَبٍ عَنْ مُحَمَّدِ بْنِ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّهُ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَزِمَ الِاسْتِغْفَارَ جَعَلَ اللَّهُ لَهُ مِنْ كُلِّ هَمٍّ فَرَجًا وَمِنْ كُلِّ ضِيقٍ مَخْرَجًا وَرَزَقَهُ مِنْ حَيْثُ لَا يَحْتَسِبُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Hakam bin Mush'ab] dari [Muhammad bin Ali bin Abdullah bin Abbas] bahwa dia menceritakan kepadanya dari [Abdullah bin 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang menekuni istighfar, Allah akan menjadikan dari setiap kesedihan kelonggaran, dan dari setiap kesempitan jalan keluar dan memberi rizki kepadanya dari arah yang tidak disangka-sangka.\""},"3774":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَبِي عُثْمَانَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ اجْعَلْنِي مِنْ الَّذِينَ إِذَا أَحْسَنُوا اسْتَبْشَرُوا وَإِذَا أَسَاءُوا اسْتَغْفَرُوا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Hammad bin Salamah] dari [Ali bin Zaid] dari [Abu Utsman] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam mengucapkan do'a: \"Ya Allah, jadikanlah aku di antara orang-orang yang apabila berbuat baik mereka meminta kabar gembira dan apabila berbuat jelek mereka meminta ampun.\""},"3775":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ تَبَارَكَ وَتَعَالَى مَنْ جَاءَ بِالْحَسَنَةِ فَلَهُ عَشْرُ أَمْثَالِهَا وَأَزِيدُ وَمَنْ جَاءَ بِالسَّيِّئَةِ فَجَزَاءُ سَيِّئَةٍ مِثْلُهَا أَوْ أَغْفِرُ وَمَنْ تَقَرَّبَ مِنِّي شِبْرًا تَقَرَّبْتُ مِنْهُ ذِرَاعًا وَمَنْ تَقَرَّبَ مِنِّي ذِرَاعًا تَقَرَّبْتُ مِنْهُ بَاعًا وَمَنْ أَتَانِي يَمْشِي أَتَيْتُهُ هَرْوَلَةً وَمَنْ لَقِيَنِي بِقِرَابِ الْأَرْضِ خَطِيئَةً ثُمَّ لَا يُشْرِكُ بِي شَيْئًا لَقِيتُهُ بِمِثْلِهَا مَغْفِرَةً","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Al Ma'rur bin Suwaid] dari [Abu Dzar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Tabaraka wa ta'ala berfirman: Barangsiapa mengerjakan satu kebaikan, maka baginya sepuluh kebaikan serupa, dan barangsiapa berbuat satu keburukan, maka baginya satu keburukan yang setimpal atau Aku akan mengampuninya. Dan barangsiapa mendekatkan diri kepada-Ku satu jengkal, niscaya Aku akan mendekatkan Diri kepadanya satu hasta. Barangsiapa mendekatkan diri kepada-Ku satu harta, maka Aku akan mendekatkan Diri kepadanya satu depa. Dan barangsiapa mendekatkan dirinya kepada-Ku dengan berjalan, niscaya Aku akan datang kepadanya dengan berlari kecil. Dan barangsiapa menjumpai-Ku dengan sebanyak bilangan debu bumi dari kesalahan namun dia tidak menyukutukan-Ku dengan sesuatu apapun, maka Aku akan datang kepadanya dengan ampunan yang sama banyaknya.\""},"3776":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ سُبْحَانَهُ أَنَا عِنْدَ ظَنِّ عَبْدِي بِي وَأَنَا مَعَهُ حِينَ يَذْكُرُنِي فَإِنْ ذَكَرَنِي فِي نَفْسِهِ ذَكَرْتُهُ فِي نَفْسِي وَإِنْ ذَكَرَنِي فِي مَلَإٍ ذَكَرْتُهُ فِي مَلَإٍ خَيْرٍ مِنْهُمْ وَإِنْ اقْتَرَبَ إِلَيَّ شِبْرًا اقْتَرَبْتُ إِلَيْهِ ذِرَاعًا وَإِنْ أَتَانِي يَمْشِي أَتَيْتُهُ هَرْوَلَةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Subahanahu berfirman: \"Aku seperti prasangka hamba-Ku, dan Aku bersamanya ketika ia mengingat-Ku. Jika ia mengingat-Ku di dalam dirinya, niscaya Aku akan mengingatnya di dalam Diri-Ku. Dan jika ia mengingat-Ku di suatu kelompok, maka Aku akan mengingatnya dalam suatu kelompok yang lebih mulia dari mereka. jika ia mendekatkan diri kepada-Ku sejengkal, niscaya Aku akan mendekatkan Diri kepadanya satu hasta. Dan jika ia datang kepada-Ku sambil berjalan, niscaya Aku datang kepadanya dengan berlari kecil.\""},"3777":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ عَمَلِ ابْنِ آدَمَ يُضَاعَفُ لَهُ الْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا إِلَى سَبْعِ مِائَةِ ضِعْفٍ قَالَ اللَّهُ سُبْحَانَهُ إِلَّا الصَّوْمَ فَإِنَّهُ لِي وَأَنَا أَجْزِي بِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap perbuatan (pahala) anak Adam akan digandakan baginya, satu kebaikan di balas dengan sepuluh kebaikan serupa sampai tujuh ratus kali lipat. Allah Subhanahu berfirman; \"Kecuali puasa, sesungguhnya puasa itu milik-Ku dan Akulah yang akan membalasnya.\""},"3778":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا جَرِيرٌ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى قَالَسَمِعَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَقُولُ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ قَالَ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ أَلَا أَدُلُّكَ عَلَى كَلِمَةٍ مِنْ كُنُوزِ الْجَنَّةِ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ قُلْ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah memberitakan kepada kami [Jarir] dari ['Ashim Al Ahwal] dari [Abu Utsman] dari [Abu Musa] dia berkata; Nabi shallallahu 'alaihi wasallam pernah mendengarku ketika saya mengucapkan; \"Laa haula walaa quwwata illa billah (tiada daya dan tiada upaya kecuali kehendak Allah).\" Maka beliau bersabda: \"Wahai Abdullah bin Qais, maukah kamu kuberitahukan tentang kalimat dari perbendaharaan surga?\" Jawabku; \"Tentu, wahai Rasulullah.\" Beliau bersabda: \"Katakanlah olehmu; \"Laa haula walaa quwwata illa billah (tiada daya dan tiada upaya kecuali dengan kehendak Allah).\""},"3779":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أَدُلُّكَ عَلَى كَنْزٍ مِنْ كُنُوزِ الْجَنَّةِ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Abu Dzar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Maukah aku tunjukkan kepadamu perbendaharaan dari perbendaharaan surga?\" jawabku; \"Tentu, ya Rasulullah.\" Beliau bersabda: \"Laa haula walaa quwwata illa billah (tiada daya dan tiada upaya kecuali dengan kehendak Allah).\""},"3780":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدٍ الْمَدَنِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ مَعْنٍ حَدَّثَنَا خَالِدُ بْنُ سَعِيدٍ عَنْ أَبِي زَيْنَبَ مَوْلَى حَازِمِ بْنِ حَرْمَلَةَ عَنْ حَازِمِ بْنِ حَرْمَلَةَ قَالَمَرَرْتُ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي يَا حَازِمُ أَكْثِرْ مِنْ قَوْلِ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَإِنَّهَا مِنْ كُنُوزِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid Al Madani] telah menceritakan kepada kami [Muhammad bin Ma'nin] telah menceritakan kepada kami [Khalid bin Sa'id] dari [Abu Zainab bekas budak Hazim bin Harmalah] dari [Hazim bin Harmalah] dia berkata; \"Saya berpapasan dengan Nabi shallallahu 'alaihi wasallam, kemudian beliau bersabda kepadaku: \"Wahai Hazim, perbanyaklah ucapan; \" Laa haula walaa quwwata illa billah (tidak ada daya dan upaya kecuali dengan kehendak Allah), sesungguhnya ia merupakan perbendaharaan surga\"."},"3781":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو الْمَلِيحِ الْمَدَنِيُّ قَالَ سَمِعْتُ أَبَا صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَدْعُ اللَّهَ سُبْحَانَهُ غَضِبَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abu Al Malih Al Madani] dia berkata; saya mendengar [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang tidak berdo`a kepada Allah subhaanahu, maka Allah akan murka kepadanya.\""},"3782":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ ذَرِّ بْنِ عَبْدِ اللَّهِ الْهَمْدَانِيِّ عَنْ يُسَيْعٍ الْكِنْدِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الدُّعَاءَ هُوَ الْعِبَادَةُ ثُمَّ قَرَأَ{ وَقَالَ رَبُّكُمْ ادْعُونِي أَسْتَجِبْ لَكُمْ }","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Dzar bin Abdullah Al Hamdani] dari [Yusai' Al Kindi] dari [Nu'man bin Basyir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya do'a adalah ibadah.\" Kemudian beliau membaca: \"Berdo'alah kepada-Ku, niscaya akan Kuperkenankan bagimu.\" (QS Al Ghafir; 60) "},"3783":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا عِمْرَانُ الْقَطَّانُ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ أَبِي الْحَسَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ شَيْءٌ أَكْرَمَ عَلَى اللَّهِ سُبْحَانَهُ مِنْ الدُّعَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin yahya] telah menceritakan kepada kami [Abu daud] telah menceritakan kepada kami ['Imran Al Qatthan] dari [Qatadah] dari [Sa'id bin Abu Al Hasan] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada sesuatu yang lebih mulia bagi Allah subhaanahu dari do`a.\""},"3784":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ سَنَةَ إِحْدَى وَثَلَاثِينَ وَمِائَتَيْنِ حَدَّثَنَا وَكِيعٌ فِي سَنَةِ خَمْسٍ وَتِسْعِينَ وَمِائَةٍ قَالَ حَدَّثَنَا سُفْيَانُ فِي مَجْلِسِ الْأَعْمَشِ مُنْذُ خَمْسِينَ سَنَةً حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ الْجَمَلِيُّ فِي زَمَنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ الْمُكَتِّبِ عَنْ قَيْسِ بْنِ طَلْقٍ الْحَنَفِيِّ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي دُعَائِهِ رَبِّ أَعِنِّي وَلَا تُعِنْ عَلَيَّ وَانْصُرْنِي وَلَا تَنْصُرْ عَلَيَّ وَامْكُرْ لِي وَلَا تَمْكُرْ عَلَيَّ وَاهْدِنِي وَيَسِّرْ الْهُدَى لِي وَانْصُرْنِي عَلَى مَنْ بَغَى عَلَيَّ رَبِّ اجْعَلْنِي لَكَ شَكَّارًا لَكَ ذَكَّارًا لَكَ رَهَّابًا لَكَ مُطِيعًا إِلَيْكَ مُخْبِتًا إِلَيْكَ أَوَّاهًا مُنِيبًا رَبِّ تَقَبَّلْ تَوْبَتِي وَاغْسِلْ حَوْبَتِي وَأَجِبْ دَعْوَتِي وَاهْدِ قَلْبِي وَسَدِّدْ لِسَانِي وَثَبِّتْ حُجَّتِي وَاسْلُلْ سَخِيمَةَ قَلْبِيقَالَ أَبُو الْحَسَنِ الطَّنَافِسِيُّ قُلْتُ لِوَكِيعٍ أَقُولُهُ فِي قُنُوتِ الْوِتْرِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] -(wafat) tahun dua ratus tiga puluh satu- telah menceritakan kepada kami [Waki'] -tahun seratus sembilan puluh lima- dia berkata; telah menceritakan kepada kami [Sufyan] ketika dia di Majlisnya Al A'masy semenjak lima puluh tahun yang lalu, telah menceritakan kepada kami ['Amru bin Murrah Al Jamali] di zamannya Khalid, dari [Abdullah bin Al Harits Al Mukattib] dari [Qais bin Thalq Al Hanafi] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam dalam do'anya beliau mengucapkan: \"Wahai Rabbku, tolonglah diriku dan janganlah Engkau sia-siakan aku. Belalah daku dan jangan Engkau biarkan daku. Semalatkanlah daku dari tipu daya dan janganlah Engkau perdayai aku. Berilah kepadaku hidayah dan mudahkanlah bagiku hidayah itu. Menangkanlah aku atas orang-orang yang berbuat aniaya terhadap diriku. Ya Rabbku, jadikanlah diriku sebagai orang yang bersyukur kepada-Mu, orang yang selalu mengingat-Mu, orang yang takut kepada-Mu, orang yang taat kepada-Mu. Kepada-Mu aku bersimpuh, kepada-Mu aku merintih dan bertaubat. Wahai Rabbku, terimalah taubatku, hapuskanlah kesalahanku, terimalah do'aku, berilah hatiku petunjuk, kuatkanlah lisanku, tetapkanlah pendirianku dan hilangkanlah rasa dengki dari hatiku.\" Abu Hasan Ath Thanafisi berkata; \"Aku bertanya kepada Waki'; \"Apakah aku dapat membacanya ketika memboca do'a qunut dalam shalat witir?\" dia menjawab; \"Ya, boleh.\""},"3785":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُبَيْدَةَ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَأَتَتْ فَاطِمَةُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْأَلُهُ خَادِمًا فَقَالَ لَهَا مَا عِنْدِي مَا أُعْطِيكِ فَرَجَعَتْ فَأَتَاهَا بَعْدَ ذَلِكَ فَقَالَ الَّذِي سَأَلْتِ أَحَبُّ إِلَيْكِ أَوْ مَا هُوَ خَيْرٌ مِنْهُ فَقَالَ لَهَا عَلِيٌّ قُولِي لَا بَلْ مَا هُوَ خَيْرٌ مِنْهُ فَقَالَتْ فَقَالَ قُولِي اللَّهُمَّ رَبَّ السَّمَاوَاتِ السَّبْعِ وَرَبَّ الْعَرْشِ الْعَظِيمِ رَبَّنَا وَرَبَّ كُلِّ شَيْءٍ مُنْزِلَ التَّوْرَاةِ وَالْإِنْجِيلِ وَالْقُرْآنِ الْعَظِيمِ أَنْتَ الْأَوَّلُ فَلَيْسَ قَبْلَكَ شَيْءٌ وَأَنْتَ الْآخِرُ فَلَيْسَ بَعْدَكَ شَيْءٌ وَأَنْتَ الظَّاهِرُ فَلَيْسَ فَوْقَكَ شَيْءٌ وَأَنْتَ الْبَاطِنُ فَلَيْسَ دُونَكَ شَيْءٌ اقْضِ عَنَّا الدَّيْنَ وَأَغْنِنَا مِنْ الْفَقْرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Abu 'Ubaidah] telah menceritakan kepada kami [ayahku] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; \"Fathimah datang menemui Nabi shallallahu 'alaihi wasallam dan meminta kepada beliau seorang pembantu. Maka beliau bersabda kepadanya: \"Saya tidak memiliki apa yang akan kuberikan kepadamu.\" Maka Fathimah pulang, lantas Nabi shallallahu 'alaihi wasallam mendatanginya dan bersabda: \"Apakah yang kamu meminta sesuatu yang kamu cintai itu atau yang lebih baik lagi?\" Ali berkata kepada Fathimah; \"Katakan tidak, namun yang lebih baik dari hal itu.\" Maka Fathimah mengatakannya, dan beliau bersabda: \"Ucapkanlah olehmu; \"Ya Allah, Rabb pemilik langit yang tujuh dan Rabb pemilik 'Arsy yang agung, Rabb kami dan Rabb segala sesuatu. Dzat yang menurunkan Taurat, Injil dan Al Qur`an yang agung. Engkau yang Maha terdahulu dan tidak ada sesuatu sebelum Engkau, Engkau Maha penghabisan dan tidak ada sesuatu setelah-Mu, Engkau dzat yang Maha nyata dan tidak ada sesuatu yang lebih nyata dari-Mu, Engkau yang Maha tersembunyi dan tidak ada sesuatu yang lebih tersembunyi dari-Mu. Lunasilah hutang kami dan lindungilah kami dari kefakiran.\""},"3786":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْهُدَى وَالتُّقَى وَالْعَفَافَ وَالْغِنَى","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad dauraqi] dan [Muhammad bin Basyar] keduanya berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau membaca do'a: \"Ya Allah, aku memohon kepada-Mu petunjuk, ketakwaan, kelembutan dan kejayaan.\""},"3787":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ مُوسَى بْنِ عُبَيْدَةَ عَنْ مُحَمَّدِ بْنِ ثَابِتٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ انْفَعْنِي بِمَا عَلَّمْتَنِي وَعَلِّمْنِي مَا يَنْفَعُنِي وَزِدْنِي عِلْمًا وَالْحَمْدُ لِلَّهِ عَلَى كُلِّ حَالٍ وَأَعُوذُ بِاللَّهِ مِنْ عَذَابِ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dari [Musa bin 'Ubaidah] dari [Muhammad bin Tsabit] dari [Abu Hurairah] dia berkata; \"Ya Allah, berikanlah kemanfa'atan atas apa yang telah Engkau ajarkan kepadaku, dan ajarkanlah aku apa-apa yang bermanfa'at untuk diriku, tambahkanlah kepadaku ilmu. Dan segala puji bagi Allah atas semua keadaan, aku pun berlindung kepada Allah dari siksa api neraka.\""},"3788":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ أَنْ يَقُولَ اللَّهُمَّ ثَبِّتْ قَلْبِي عَلَى دِينِكَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ تَخَافُ عَلَيْنَا وَقَدْ آمَنَّا بِكَ وَصَدَّقْنَاكَ بِمَا جِئْتَ بِهِ فَقَالَ إِنَّ الْقُلُوبَ بَيْنَ إِصْبَعَيْنِ مِنْ أَصَابِعِ الرَّحْمَنِ عَزَّ وَجَلَّ يُقَلِّبُهَا وَأَشَارَ الْأَعْمَشُ بِإِصْبَعَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] dari [Yazid Ar raqasyi] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam memperbanyak mengucapkan: \"Ya Allah, teguhkan hatiku diatas dien-Mu\", maka seorang sahabat berkata: \"Wahai Rasulullah, mengapa anda mengkhawatirkan kami, sedang kami telah beriman kepadamu dan membenarkanmu terhadap apa yang anda bawa.\" Beliau bersabda: \"Sesungguhnya hati-hati itu berada diantara dua jari dari jari-jari Ar Rahman 'azza wajalla, Dia membolak-balikkannya.\" Dan Al A'masy mengisyaratkan dengan dua jarinya."},"3789":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ أَنَّهُقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمْنِي دُعَاءً أَدْعُو بِهِ فِي صَلَاتِي قَالَ قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا وَلَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ وَارْحَمْنِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Abdullah bin 'Amru bin 'Ash] dari [Abu Bakar As Shidiq] bahwa dia berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"Ajarkanlah kepadaku do'a yang saya baca di dalam shalatku.\" Beliau menjawab: \"Ucapkanlah; \"Ya Allah, sesungguhnya aku telah menganiaya diriku dengan kedzaliman, dan tiada yang mengampuni dosa selain Engkau, maka ampunilah daku dengan pengampunan dari sisi-Mu serta kasihanilah diriku, sesungguhnya Engkau Maha pengampun lagi Maha penyayang.\""},"3790":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ عَنْ أَبِي مَرْزُوقٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُتَّكِئٌ عَلَى عَصًا فَلَمَّا رَأَيْنَاهُ قُمْنَا فَقَالَ لَا تَفْعَلُوا كَمَا يَفْعَلُ أَهْلُ فَارِسَ بِعُظَمَائِهَا قُلْنَا يَا رَسُولَ اللَّهِ لَوْ دَعَوْتَ اللَّهَ لَنَا قَالَ اللَّهُمَّ اغْفِرْ لَنَا وَارْحَمْنَا وَارْضَ عَنَّا وَتَقَبَّلْ مِنَّا وَأَدْخِلْنَا الْجَنَّةَ وَنَجِّنَا مِنْ النَّارِ وَأَصْلِحْ لَنَا شَأْنَنَا كُلَّهُ قَالَ فَكَأَنَّمَا أَحْبَبْنَا أَنْ يَزِيدَنَا فَقَالَ أَوَلَيْسَ قَدْ جَمَعْتُ لَكُمْ الْأَمْرَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Mis'ar] dari [Abu Marzuq] dari [Abu Wa`il] dari [Abu Umamah Al Bahili] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar menemui kami sambil berpegangan pada tongkat, lalu kami berdiri ketika melihat beliau, beliau bersabda: \"Janganlah kalian melakukan perbuatan seperti perbuatan orang-orang Persia terhadap para pembesar kerajaan.\" Kami bertanya; \"Wahai Rasulullah, sekiranya anda berkenan mendo'akan kami semua!.\" Beliau bersabda: \"Ya Allah! Ampuni kami, rahmati kami, ridlai kami, terimalah (amalan) kami, masukkanlah kami ke surga, dan selamatkanlah kami dari neraka serta perbaikilah kondisi kami seluruhnya.\" Abu Umamah berkata; \"Sepertinya kami menginginkan beliau menambahi do`a untuk kami, lalu beliau bersabda; \"Tidakkah saya telah menyatukan urusan kalian menjadi satu?.\""},"3791":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَخِيهِ عَبَّادِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْأَرْبَعِ مِنْ عِلْمٍ لَا يَنْفَعُ وَمِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ نَفْسٍ لَا تَشْبَعُ وَمِنْ دُعَاءٍ لَا يُسْمَعُ","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [saudaranya yaitu 'Abbad bin Abu Sa'id] bahwa dia mendengar [Abu Hurairah] berkata; \"Rasulullah shallallahu 'alaihi wasallam berdo'a: \"Ya Allah, sesungguhnya aku berlindung kepada-Mu dari empat perkara; dari ilmu yang tidak bermanfa'at, dari hati yang tidak khusyu' dari jiwa yang tidak puas dan dari do'a yang tidak di dengar.\""},"3792":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ جَمِيعًا عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَؤُلَاءِ الْكَلِمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ النَّارِ وَعَذَابِ النَّارِ وَمِنْ فِتْنَةِ الْقَبْرِ وَعَذَابِ الْقَبْرِ وَمِنْ شَرِّ فِتْنَةِ الْغِنَى وَشَرِّ فِتْنَةِ الْفَقْرِ وَمِنْ شَرِّ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ اللَّهُمَّ اغْسِلْ خَطَايَايَ بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَنَقِّ قَلْبِي مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ وَبَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْمَأْثَمِ وَالْمَغْرَمِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] semuanya dari [Hisyam bin 'Urwah] dari [ayahnya] da ri ['aisyah] bawa Nabi shallallahu 'alaihi wasallam berdo'a dengan kalimat-kalimat ini, yaitu; \"Ya Allah, aku berlindung kepada-Mu dari fitnah neraka dan dari siksa api neraka, dari fitnah kubur dan dari siksa kubur, dari buruknya fitnah kekayaan dan dari buruknya kekafiran serta dari fitnah Al Masih Ad Dajjal. Ya Allah, bersihkanlah kesalahan-kesalahanku dengan air sajju dan air embun, sucikanlah hatiku dari kotoran-kotoran sebagaimana Engkau menyucikan baju yang putih dari kotoran. Dan jauhkanlah antara diriku dan kesalahan-kesalahanku sebagaimana Engkau jauhkan antara timur dan barat. Ya Allah, aku berlindung kepada-Mu dari rasa malas, kepikunan, kesalahan dan kerugian.\""},"3793":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ حُصَيْنٍ عَنْ هِلَالٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ قَالَسَأَلْتُ عَائِشَةَ عَنْ دُعَاءٍ كَانَ يَدْعُو بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari [Hushain] dari [Hilal] dari [Farwah bin Naufal] dia berkata; saya bertanya kepada ['Aisyah] mengenai do'a yang sering di baca Rasulullah shallallahu 'alaihi wasallam, maka ia menjawab; \"Bahwa beliau mengucapkan: \"Ya Allah, aku berlindung kepada-Mu dari keburukan yang telah aku lakukan dan dari keburukan yang belum lakukan.\""},"3794":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا بَكْرُ بْنُ سُلَيْمٍ حَدَّثَنِي حُمَيْدٌ الْخَرَّاطُ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا هَذَا الدُّعَاءَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ جَهَنَّمَ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Bakr bin Sulaim] telah menceritakan kepadaku [Humaid Al Kharrath] dari [Kuraib bekas budak Ibnu Abbas] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam mengajarkan kami do`a ini sebagaimana beliau mengajari kami surat dari Al Qur`an, yaitu; \"Ya Allah, aku berlindung kepada-Mu dari siksa Jahannam, dan aku berlindung kepada-Mu dari siksa kubur. Aku berlindung kepada-Mu dari fitnah Al Masih Ad Dajjal dan aku berlindung kepada-Mu dari fitnah kematian dan kehidupan.\""},"3795":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ عَائِشَةَ قَالَتْفَقَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ مِنْ فِرَاشِهِ فَالْتَمَسْتُهُ فَوَقَعَتْ يَدِي عَلَى بَطْنِ قَدَمَيْهِ وَهُوَ فِي الْمَسْجِدِ وَهُمَا مَنْصُوبَتَانِ وَهُوَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِرِضَاكَ مِنْ سَخَطِكَ وَبِمُعَافَاتِكَ مِنْ عُقُوبَتِكَ وَأَعُوذُ بِكَ مِنْكَ لَا أُحْصِي ثَنَاءً عَلَيْكَ أَنْتَ كَمَا أَثْنَيْتَ عَلَى نَفْسِكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami ['Ubaidullah bin Umar] dari Telah memberitakan kepada kami [Muhammad bin Yahya bin Habban] dari [Al A'raj] dari [Abu Hurairah] dari ['Aisyah] dia berkata; \"Pada suatu malam, saya pernah kehilangan Rasulullah shallallahu 'alaihi wasallam dari tempat tidurnya, maka saya pun mencarinya, kemudian tanganku menyentuh kedua telapak kaki belaiu saat beliau tengah berada di dalam Masjid. dan kedua telapak kaki beliau berdiri tegak. Beliau tengah mengucapkan: \"Ya Allah, sesungguhnya aku berlindung dengan keridlaan-Mu dari kemarahan-Mu, dengan ke'afiyatan-Mu dari siksaan-Mu. Dan aku berlindung kepada-Mu dari murka-Mu, aku tidak mampu menghitung pujian atas diri-Mu sebagaimana Engkau telah memuji diri-Mu sendiri.\""},"3796":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ عَنْ الْأَوْزَاعِيِّ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ عَنْ جَعْفَرِ بْنِ عِيَاضٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَوَّذُوا بِاللَّهِ مِنْ الْفَقْرِ وَالْقِلَّةِ وَالذِّلَّةِ وَأَنْ تَظْلِمَ أَوْ تُظْلَمَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Muhammad bin Mush'ab] dari [Al Auza'i] dari [Ishaq bin Abdullah] dari [Ja'far bin 'Iyadl] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam: \"Berlindunglah kalian kepada Allah dari kefakiran dan kekurangan dan kehinaan dan berbuat dzalim dan di dzalimi.\""},"3797":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلُوا اللَّهَ عِلْمًا نَافِعًا وَتَعَوَّذُوا بِاللَّهِ مِنْ عِلْمٍ لَا يَنْفَعُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Usamah bin Zaid] dari [Muhammad bin Al Munkadir] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Memintalah kalian kepada Allah ilmu yang bermanfa'at, dan berlindunglah kalian kepada Allah dari ilmu yang tidak bermanfa'at.\""},"3798":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ مِنْ الْجُبْنِ وَالْبُخْلِ وَأَرْذَلِ الْعُمُرِ وَعَذَابِ الْقَبْرِ وَفِتْنَةِ الصَّدْرِقَالَ وَكِيعٌ يَعْنِي الرَّجُلَ يَمُوتُ عَلَى فِتْنَةٍ لَا يَسْتَغْفِرُ اللَّهَ مِنْهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari ['Amru bin Maimun] dari [Umar] bahwa Nabi shallallahu 'alaihi wasallam selalu berlindung diri dari sifat pengecut dan bakhil, kepikunan, siksa kubur, dan dari fitnah dada. Waki’ menerangkan; yaitu seseorang meninggal diatas fitnah dan dia tidak beristighfar kepada kepada Allah dari fitnah tersebut."},"3799":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا أَبُو مَالِكٍ سَعْدُ بْنُ طَارِقٍ عَنْ أَبِيهِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ أَقُولُ حِينَ أَسْأَلُ رَبِّي قَالَ قُلْ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَعَافِنِي وَارْزُقْنِي وَجَمَعَ أَصَابِعَهُ الْأَرْبَعَ إِلَّا الْإِبْهَامَ فَإِنَّ هَؤُلَاءِ يَجْمَعْنَ لَكَ دِينَكَ وَدُنْيَاكَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yazid bin harun] telah memberitakan kepada kami [Abu Malik Sa'd bin Thariq] dari [ayahnya] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam telah di kunjungi oleh seseorang laki-laki sambil bertanya; \"Wahai Rasulullah, apa yang harus saya ucapkan ketika aku memohon kepada Rabbku?\" beliau menjawab: \"Ucapkanlah; Ya Allah, ampunilah daku, kasihanilah daku, berikanlah daku ke'afiyatan dan berilah daku riziki.\" Kemudian beliau merapatkan keempat jari tangannya selain ibu jari: \"Sesungguhnya kalimat-kalimat tersebut akan mencukup bagimu agamamu dan duniamu.\""},"3800":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنِي جَبْرُ بْنُ حَبِيبٍ عَنْ أُمِّ كُلْثُومٍ بِنْتِ أَبِي بَكْرٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَهَا هَذَا الدُّعَاءَ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ الْخَيْرِ كُلِّهِ عَاجِلِهِ وَآجِلِهِ مَا عَلِمْتُ مِنْهُ وَمَا لَمْ أَعْلَمْ وَأَعُوذُ بِكَ مِنْ الشَّرِّ كُلِّهِ عَاجِلِهِ وَآجِلِهِ مَا عَلِمْتُ مِنْهُ وَمَا لَمْ أَعْلَمْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ خَيْرِ مَا سَأَلَكَ عَبْدُكَ وَنَبِيُّكَ وَأَعُوذُ بِكَ مِنْ شَرِّ مَا عَاذَ بِهِ عَبْدُكَ وَنَبِيُّكَ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَمَا قَرَّبَ إِلَيْهَا مِنْ قَوْلٍ أَوْ عَمَلٍ وَأَعُوذُ بِكَ مِنْ النَّارِ وَمَا قَرَّبَ إِلَيْهَا مِنْ قَوْلٍ أَوْ عَمَلٍ وَأَسْأَلُكَ أَنْ تَجْعَلَ كُلَّ قَضَاءٍ قَضَيْتَهُ لِي خَيْرًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepadaku [Jabr bin Habib] dari [Ummu Kultsum binti Abu Bakar] dari ['Aisyah] bawha Rasulullah shallallahu 'alaihi wasallam pernah mengajarinya do'a ini, yaitu; \"Ya Allah, aku memohon kepada-Mu semua kebaikan, baik yang cepat (di dunia) maupun yang di tangguhkan (di akhirat), yang aku ketahui maupun yang tidak aku ketahui. Dan aku berlindung kepada-Mu dari semua keburukan, baik yang cepat (di dunia) maupun yang di tangguhkan (di akhirat), yang aku ketahui maupun yang tidak aku ketahui. Ya Allah, aku memohon kepada-Mu kebaikan yang di mohonkan hamba-Mu dan Nabi-Mu kepada-Mu, dan aku berlindung kepada-Mu dari keburukan yang hamba-Mu dan Nabi-Mu berlindung darinya kepada-Mu. Ya Allah, sungguh aku memohon surga memohon surga kepada-Mu dan semua yang mendekatkan diriku kepadanya dari perkataan atau perbuatan. Dan aku berlindung kepada-Mu dari neraka dan semua yang mendekatkan diriku kepadanya dari perkataan dan perbuatan. Serta aku memohon kepada-Mu agar Engkau menjadikan semua ketentuan yang Engkau tentukan kepadaku sebagai kebaikan.\""},"3801":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى الْقَطَّانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مَا تَقُولُ فِي الصَّلَاةِ قَالَ أَتَشَهَّدُ ثُمَّ أَسْأَلُ اللَّهَ الْجَنَّةَ وَأَعُوذُ بِهِ مِنْ النَّارِ أَمَا وَاللَّهِ مَا أُحْسِنُ دَنْدَنَتَكَ وَلَا دَنْدَنَةَ مُعَاذٍ قَالَ حَوْلَهَا نُدَنْدِنُ","id":"Telah menceritakan kepada kami [Yusuf bin Musa Al Qatthan] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada seorang lelaki: \"Apa yang kamu ucapkan didalam shalat?.\" Dia menjawab; \"Aku membaca tasyahhud, kemudian meminta surga kepada Allah, dan berlindung kepada-Nya dari neraka. Demi Allah, sesungguhnya ucapan-ucapan pujianmu sangat baik dan bukan ucapan pujiam-pujian dari Mu'adz.\" Beliau bersabda: \"Semua dalam shalat kita mengucapkan pujian.\""},"3802":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنِي سَلَمَةُ بْنُ وَرْدَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ الدُّعَاءِ أَفْضَلُ قَالَ سَلْ رَبَّكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ ثُمَّ أَتَاهُ فِي الْيَوْمِ الثَّانِي فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ الدُّعَاءِ أَفْضَلُ قَالَ سَلْ رَبَّكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ ثُمَّ أَتَاهُ فِي الْيَوْمِ الثَّالِثِ فَقَالَ يَا نَبِيَّ اللَّهِ أَيُّ الدُّعَاءِ أَفْضَلُ قَالَ سَلْ رَبَّكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ فَإِذَا أُعْطِيتَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ فَقَدْ أَفْلَحْتَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Ibnu Abu Fudaik] telah mengabarkan kepada kami [Salamah bin Wardan] dari [Anas bin Malik] dia berkata; \"Seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam seraya bertanya; \"Wahai Rasulullah, do`a apa yang paling utama?.\" Beliau menjawab: \"Mintalah ampunan dan kesehatan kepada Rabbmu di dunia dan akhirat.\" Kemudian datang lagi di hari yang kedua, dan bertanya; \"Wahai Rosulullah, do`a apa yang paling utama?.\" Beliau menjawab: \"Mintalah ampunan dan kesehatan kepada Robbmu di dunia dan akhirat.\" Kemuduian datang lagi di hari yang ketiga, dan bertanya; \"Wahai Nabi Allah, do`a apa yang paling utama?.\" Beliau menjnawab: \"Mintalah ampunan dan kesehatan kepada Rabbmu di dunia dan akhirat, dan jika kamu telah di beri ma'af dan kesehatan di dunia dan akhirat, maka kamu telah beruntung.\""},"3803":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا عُبَيْدُ بْنُ سَعِيدٍ قَالَ سَمِعْتُ شُعْبَةَ عَنْ يَزِيدَ بْنِ خُمَيْرٍ قَالَ سَمِعْتُ سُلَيْمَ بْنَ عَامِرٍ يُحَدِّثُ عَنْ أَوْسَطَ بْنِ إِسْمَعِيلَ الْبَجَلِيِّ أَنَّهُ سَمِعَ أَبَا بَكْرٍ حِينَ قُبِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَقَامِي هَذَا عَامَ الْأَوَّلِ ثُمَّ بَكَى أَبُو بَكْرٍ ثُمَّ قَالَ عَلَيْكُمْ بِالصِّدْقِ فَإِنَّهُ مَعَ الْبِرِّ وَهُمَا فِي الْجَنَّةِ وَإِيَّاكُمْ وَالْكَذِبَ فَإِنَّهُ مَعَ الْفُجُورِ وَهُمَا فِي النَّارِ وَسَلُوا اللَّهَ الْمُعَافَاةَ فَإِنَّهُ لَمْ يُؤْتَ أَحَدٌ بَعْدَ الْيَقِينِ خَيْرًا مِنْ الْمُعَافَاةِ وَلَا تَحَاسَدُوا وَلَا تَبَاغَضُوا وَلَا تَقَاطَعُوا وَلَا تَدَابَرُوا وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا","id":"Telah menceritakan kepada kami [Abu Bakar] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami ['Ubaid bin Sa'id] dia berkata; saya mendengar [Syu'bah] dari [Yazid bin Khumair] dia berkata; saya mendengar [Sulaim bin 'Amir] bercerita dari [Ausath bin Isma'il Al Bajali] bahwa dia mendengar [Abu Bakar] ketika Nabi shallallahu 'alaihi wasallam meninggal dunia, katanya; \"Rasulullah shallallahu 'alaihi wasallam telah berdiri di tempat berdiriku ini pada tahun pertama.\" -kemudian dia menangis- dia melanjutkan; \"Kalian harus berlaku jujur, karena sesungguhnya kejujuran bersama dengan kebaikan, dan keduanya berada di surga. Janganlah kalian berdusta, karena sesungguhnya kedustaan bersama dengan kejahatan, dan kedua-duanya berada di neraka. Memintalah kalian kepada Allah ampunan, sesungguhnya ia tidak di berikan kepada seseorang setelah keyakinan yang lebih baik daripada pengampunan, dan janganlah kalian saling hasad, jangan saling membenci, jangan saling memutus hubungan dan jangan saling bermusuhan, dan jadilah kalian hamba-hamba Allah yang bersaudara.\""},"3804":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ كَهْمَسِ بْنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ وَافَقْتُ لَيْلَةَ الْقَدْرِ مَا أَدْعُو قَالَ تَقُولِينَ اللَّهُمَّ إِنَّكَ عَفُوٌّ تُحِبُّ الْعَفْوَ فَاعْفُ عَنِّي","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Kahmas bin Al Hasan] dari [Abdullah bin Buraidah] dari ['Aisyah] bahwa dia berkata; \"Wahai Rasulullah, apa pendapatmu jika aku ketepatan mendapatkan malam lailatul Qodar, apa yang harus aku ucapkan?\", beliau menjawab: \"Ucapkanlah; ya Allah, sesungguhnya Engkau maha pema'af mencintai kema'afan, maka ma'afkanlah daku.\""},"3805":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ صَاحِبِ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ الْعَلَاءِ بْنِ زِيَادٍ الْعَدَوِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ دَعْوَةٍ يَدْعُو بِهَا الْعَبْدُ أَفْضَلَ مِنْ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْمُعَافَاةَ فِي الدُّنْيَا وَالْآخِرَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Hisyam pemilik Ad Dastuwa`i] dari [Qatadah] dari [Al 'Ala` bin Ziyad Al 'Adawi] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada do`a yang di ucapkan seorang hamba ketika berdo`a lebih utama dari; Ya Allah, sesungguhnya aku meminta kepada-Mu ampunan didunia dan akhirat.\""},"3806":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُنَا اللَّهُ وَأَخَا عَادٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] telah menceritakan kepada kami [Zaid bin Al Khubab] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah merahmati kita dan saudara 'Aad (Nabi Hud).\""},"3807":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسْتَجَابُ لِأَحَدِكُمْ مَا لَمْ يَعْجَلْ قِيلَ وَكَيْفَ يَعْجَلُ يَا رَسُولَ اللَّهِ قَالَ يَقُولُ قَدْ دَعَوْتُ اللَّهَ فَلَمْ يَسْتَجِبْ اللَّهُ لِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Ishaq bin Sulaiman] dari [Malik bin Anas] dari [Az Zuhri] dari [Abu 'Ubaid bekas budak Abdurrahman bin 'Auf] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Do`a salah seorang dari kalian akan di kabulkan selagi ia tidak tergesa-gesa.\" Di tanyakan; \"Bagaimana maksud dari tergesa-gesa?\" beliau menjawab: \"Ia berkata; \"aku telah berdo'a kepada Allah, namun sampai saat ini Allah tidak juga mengabulkan do'aku.\""},"3808":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقُولَنَّ أَحَدُكُمْ اللَّهُمَّ اغْفِرْ لِي إِنْ شِئْتَ وَلْيَعْزِمْ فِي الْمَسْأَلَةِ فَإِنَّ اللَّهَ لَا مُكْرِهَ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Idris] dari [Ibnu 'Ajlan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mengucapkan; \"Ya Allah, ampunilah daku jika Engkau menghendaki.\" Namun hendaknya ia bersungguh-sungguh dalam memohon, karena sesungguhnya Allah tidak memiliki kebencian.\""},"3809":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ سُورَةِ آلِ عِمْرَانَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidillah bin Abu Ziyad] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Nama Allah yang Agung terdapat di dalam dua ayat ini; Dan Rabbmu adalah Rabb yang Maha Esa, tidak ada ilah (yang berhak di sembah) selain Dia, yang Maha pemurah lagi Maha penyayang.\" Qs Al Baqarah; 163, dan pembukaan surat Ali Imran.\""},"3810":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْعَلَاءِ عَنْ الْقَاسِمِ قَالَاسْمُ اللَّهِ الْأَعْظَمُ الَّذِي إِذَا دُعِيَ بِهِ أَجَابَ فِي سُوَرٍ ثَلَاثٍ الْبَقَرَةِ وَآلِ عِمْرَانَ وَطهحَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ قَالَ ذَكَرْتُ ذَلِكَ لِعِيسَى بْنِ مُوسَى فَحَدَّثَنِي أَنَّهُ سَمِعَ غَيْلَانَ بْنَ أَنَسٍ يُحَدِّثُ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami ['Amru bin Abu Salamah] dari [Abdullah bin Al 'Ala`] dari [Al Qasim] dia berkata; \"Nama Allah yang Agung yang apabila berdo`a dengan-Nya akan di kabulkan, yaitu didalam tiga surat; Al Baqarah, Ali 'Imran dan Thahaa.\" Telah menceritakan kepadaku [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami ['Amru bin Abu Salamah] dia berkata; aku menyebutkan hal itu kepada ['Isa bin Musa] lantas dia menceritakannya kepadaku, bahwa dia pernah mendengar [Ghailan bin Anas] menceritakan dari [Al Qasim] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam seperti di atas.\""},"3811":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مَالِكِ بْنِ مِغْوَلٍ أَنَّهُ سَمِعَهُ مِنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ بِأَنَّكَ أَنْتَ اللَّهُ الْأَحَدُ الصَّمَدُ الَّذِي لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ سَأَلَ اللَّهَ بِاسْمِهِ الْأَعْظَمِ الَّذِي إِذَا سُئِلَ بِهِ أَعْطَى وَإِذَا دُعِيَ بِهِ أَجَابَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Malik bin Mighwal] bahwa dia mendengar dari [Abdullah bin Buraidah] dari [ayahnya] dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah mendengar seseorang mengucapkan; \"Ya Allah, sesungguhnya aku meminta kepada-Mu, bahwasanya Engkau adalah Allah Yang Maha Esa, Yang Bergantung pada-Nya segala sesuatu, yang tidak beranak dan tidak diperanakkan, dan tidak ada seorang pun yang setara dengan-Nya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh dia telah meminta kepada Allah dengan nama-Nya yang Agung, yang apabila diminta dengan menyebut-Nya, pasti akan di beri dan apabila berdo'a dengan menyebut-Nya pasti akan di kabulkan.\""},"3812":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو خُزَيْمَةَ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ بِأَنَّ لَكَ الْحَمْدَ لَا إِلَهَ إِلَّا أَنْتَ وَحْدَكَ لَا شَرِيكَ لَكَ الْمَنَّانُ بَدِيعُ السَّمَوَاتِ وَالْأَرْضِ ذُو الْجَلَالِ وَالْإِكْرَامِ فَقَالَ لَقَدْ سَأَلَ اللَّهَ بِاسْمِهِ الْأَعْظَمِ الَّذِي إِذَا سُئِلَ بِهِ أَعْطَى وَإِذَا دُعِيَ بِهِ أَجَابَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abu Khaizamah] dari [Anas bin Sirin] dari [Anas bin Malik] dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah mendengar seseorang mengucapkan; \"Ya Allah, sesungguhnya aku memohon kepada-Mu bahwa bagi-Mu segala pujian, tiada ilah melainkan Engkau yang tidak ada sekutu bagi-Mu, yang Maha memberi, pencipta langit dan bumi, Yang Maha memiliki keluruhan dan Kemurahan.\" Maka beliau bersabda: \"Ia telah memohon kepada Allah dengan nama-Nya yang Agung, yang jika ia meminta sesutu dengan menyebutnya pasti akan di beri, dan jika berdo'a dengannya pasti akan di kabulkan.\""},"3813":{"ar":"حَدَّثَنَا أَبُو يُوسُفَ الصَّيْدَلَانِيُّ مُحَمَّدُ بْنُ أَحْمَدَ الرَّقِّيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ الْفَزَارِيِّ عَنْ أَبِي شَيْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ الْجُهَنِيِّ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ بِاسْمِكَ الطَّاهِرِ الطَّيِّبِ الْمُبَارَكِ الْأَحَبِّ إِلَيْكَ الَّذِي إِذَا دُعِيتَ بِهِ أَجَبْتَ وَإِذَا سُئِلْتَ بِهِ أَعْطَيْتَ وَإِذَا اسْتُرْحِمْتَ بِهِ رَحِمْتَ وَإِذَا اسْتُفْرِجَتَ بِهِ فَرَّجْتَ قَالَتْ وَقَالَ ذَاتَ يَوْمٍ يَا عَائِشَةُ هَلْ عَلِمْتِ أَنَّ اللَّهَ قَدْ دَلَّنِي عَلَى الِاسْمِ الَّذِي إِذَا دُعِيَ بِهِ أَجَابَ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي فَعَلِّمْنِيهِ قَالَ إِنَّهُ لَا يَنْبَغِي لَكِ يَا عَائِشَةُ قَالَتْ فَتَنَحَّيْتُ وَجَلَسْتُ سَاعَةً ثُمَّ قُمْتُ فَقَبَّلْتُ رَأْسَهُ ثُمَّ قُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِيهِ قَالَ إِنَّهُ لَا يَنْبَغِي لَكِ يَا عَائِشَةُ أَنْ أُعَلِّمَكِ إِنَّهُ لَا يَنْبَغِي لَكِ أَنْ تَسْأَلِينَ بِهِ شَيْئًا مِنْ الدُّنْيَا قَالَتْ فَقُمْتُ فَتَوَضَّأْتُ ثُمَّ صَلَّيْتُ رَكْعَتَيْنِ ثُمَّ قُلْتُ اللَّهُمَّ إِنِّي أَدْعُوكَ اللَّهَ وَأَدْعُوكَ الرَّحْمَنَ وَأَدْعُوكَ الْبَرَّ الرَّحِيمَ وَأَدْعُوكَ بِأَسْمَائِكَ الْحُسْنَى كُلِّهَا مَا عَلِمْتُ مِنْهَا وَمَا لَمْ أَعْلَمْ أَنْ تَغْفِرَ لِي وَتَرْحَمَنِي قَالَتْ فَاسْتَضْحَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ إِنَّهُ لَفِي الْأَسْمَاءِ الَّتِي دَعَوْتِ بِهَا","id":"Telah menceritakan kepada kami [Abu Yusuf As Shaidalani Muhammad bin Ahmad Ar raqqi] telah menceritakan kepada kami [Muhammad bin Salamah] da ri [Al Fazari] dari [Abu Syaibah] dari [Abdullah bin 'Ukaim Al Juhani] dari ['Aisyah] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam mengucapkan: \"Ya Allah, sesungguhnya aku meminta kepada-Mu dengan nama-Mu Yang Suci, yang Indah, diberkahi serta lebih Engkau cintai, yang apabila Engkau diseru dengan-Nya, Engkau akan mengabulkan, dan apabila Engkau diminta dengan-Nya Engkau akan memberi, dan apabila Engkau dimintai rahmat dengan-Nya Engkau akan merahmati dan apabila Engkau dimintai jalan keluar dengan-Nya Engkau akan memberi jalan keluar.\" 'Aisyah berkata; Suatu hari beliau bersabda: \"Wahai 'Aisyah, apakah kamu tahu bahwa Allah telah menunjukkan kepadaku satu nama yang apabila diseru dengannya Dia akan mengabulkan?\" 'Aisyah berkata; Jawabku; \"Wahai Rasulullah, demi ayahku, anda dan ibuku, maka ajarkanlah ia kepadaku.\" Beliau bersabda: \"Sesungguhnya ia tidak layak bagimu wahai 'Aisyah.\" 'Aisyah berkata; maka aku menyingkir dan duduk sejenak kemudian aku bangun dan membalik kepalanya, kemudian aku berkata; \"Wahai Rosulullah, ajarkanlah kepadaku.\" Beliau bersabda: \"Sesungguhnya ia tidak layak bagimu wahai 'Aisyah yaitu untuk mengajarkan kepadamu, sesungguhnya ia tidak layak bagimu jika dengannya kamu meminta sesuatu dari dunia.\" 'Aisyah berkata; \"Maka aku bangun dan berwudlu` kemudian shalat dua raka'at dan berdo'a; \"Ya Allah, sesungguhnya aku berdo'a kepada-Mu ya Allah, aku berdo'a kepada-Mu ya Rahman, aku berdo'a kepada-Mu wahai yang Maha Baik lagi Maha Penyayang, dan aku berdo'a kepada-Mu dengan nama-nama-Mu yang indah semuanya, baik yang aku ketahui dan yang tidak aku ketahui agar Engkau mengampuniku dan merahmatiku.\" 'Aisyah berkata; Maka Rasulullah shallallahu 'alaihi wasallam mentertawakanku dan bersabda: \"Sesungguhnya itu terdapat di dalam asma'-asma' yang Engkau berdo'a dengannya tadi.\""},"3814":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلَّهِ تِسْعَةً وَتِسْعِينَ اسْمًا مِائَةً إِلَّا وَاحِدًا مَنْ أَحْصَاهَا دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Abdah bin Sulaiman] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam: \"Sesungguhnya Allah memiliki sembilan puluh sembilan nama, seratus kurang satu, maka barangsiapa menghitungnya (menghafalnya) akan masuk surga.\""},"3815":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مُحَمَّدٍ الصَّنْعَانِيُّ حَدَّثَنَا أَبُو الْمُنْذِرِ زُهَيْرُ بْنُ مُحَمَّدٍ التَّمِيمِيُّ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ الْأَعْرَجُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِلَّهِ تِسْعَةً وَتِسْعِينَ اسْمًا مِائَةً إِلَّا وَاحِدًا إِنَّهُ وِتْرٌ يُحِبُّ الْوِتْرَ مَنْ حَفِظَهَا دَخَلَ الْجَنَّةَ وَهِيَ اللَّهُ الْوَاحِدُ الصَّمَدُ الْأَوَّلُ الْآخِرُ الظَّاهِرُ الْبَاطِنُ الْخَالِقُ الْبَارِئُ الْمُصَوِّرُ الْمَلِكُ الْحَقُّ السَّلَامُ الْمُؤْمِنُ الْمُهَيْمِنُ الْعَزِيزُ الْجَبَّارُ الْمُتَكَبِّرُ الرَّحْمَنُ الرَّحِيمُ اللَّطِيفُ الْخَبِيرُ السَّمِيعُ الْبَصِيرُ الْعَلِيمُ الْعَظِيمُ الْبَارُّ الْمُتْعَالِ الْجَلِيلُ الْجَمِيلُ الْحَيُّ الْقَيُّومُ الْقَادِرُ الْقَاهِرُ الْعَلِيُّ الْحَكِيمُ الْقَرِيبُ الْمُجِيبُ الْغَنِيُّ الْوَهَّابُ الْوَدُودُ الشَّكُورُ الْمَاجِدُ الْوَاجِدُ الْوَالِي الرَّاشِدُ الْعَفُوُّ الْغَفُورُ الْحَلِيمُ الْكَرِيمُ التَّوَّابُ الرَّبُّ الْمَجِيدُ الْوَلِيُّ الشَّهِيدُ الْمُبِينُ الْبُرْهَانُ الرَّءُوفُ الرَّحِيمُ الْمُبْدِئُ الْمُعِيدُ الْبَاعِثُ الْوَارِثُ الْقَوِيُّ الشَّدِيدُ الضَّارُّ النَّافِعُ الْبَاقِي الْوَاقِي الْخَافِضُ الرَّافِعُ الْقَابِضُ الْبَاسِطُ الْمُعِزُّ الْمُذِلُّ الْمُقْسِطُ الرَّزَّاقُ ذُو الْقُوَّةِ الْمَتِينُ الْقَائِمُ الدَّائِمُ الْحَافِظُ الْوَكِيلُ الْفَاطِرُ السَّامِعُ الْمُعْطِي الْمُحْيِي الْمُمِيتُ الْمَانِعُ الْجَامِعُ الْهَادِي الْكَافِي الْأَبَدُ الْعَالِمُ الصَّادِقُ النُّورُ الْمُنِيرُ التَّامُّ الْقَدِيمُ الْوِتْرُ الْأَحَدُ الصَّمَدُ الَّذِي لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌقَالَ زُهَيْرٌ فَبَلَغَنَا مِنْ غَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ أَنَّ أَوَّلَهَا يُفْتَحُ بِقَوْلِ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ بِيَدِهِ الْخَيْرُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ لَا إِلَهَ إِلَّا اللَّهُ لَهُ الْأَسْمَاءُ الْحُسْنَى","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Abdul Malik bin Muhammad As Shan'ani] telah menceritakan kepada kami [Abu Al Mundzir Zuhair bin Muhammad At Taimi] telah menceritakan kepada kami [Musa bin 'Uqbah] telah menceritakan kepadaku [Abdurrahman Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah memiliki sembilan puluh sembilan nama, seratus kurang satu. Sesungguhnya Dia Maha ganjil serta mencintai sesuantu yang genjil. Barangsiapa menghafalnya, maka ia akan masuk surga. Yaitu; Allah, Al Ahad, As Shamad, Al Awwal. Al Akhir, Ad Dlahir, Al bathin, Al Khaliq, AL Bari`, Al Mushawir, Al Malik, Al Haq, As Salam, Al Mu`min, Al Muhaimin, Al Aziz, Al Jabbar, Al Mutakabbir, Ar Rahman, Ar Rahim, Al Lathif, Al Khabir, As Sami', Al Bashir, Al 'Alim, Al 'Adzim, Al Baar, Al Muta'al, Al Jalil, Al Jamil, Al Hayyu, Al Qayyum, Al Qadir, Al Qahir, Al 'Ali, Al Hakim, Al Qarib, Al Mujib, Al Ghaniy, Al Wahhab, Al Wadud, As Syakur, Al Majid, AL Wajid, Al Wali, Ar Rasyid, Al 'Afwu, Al ghafur, Al Halim, Al Karim, At Tawwab, Ar Rabb, Al Majid, Al Wali, As Syahid, Al Mubin, Al Burhan, Ar Ra`uf Ar Rahim, Al mubdi`, Al Mu'id, Al Ba'its, Al Warits, Al Qawi, As Syadid, Adl Dlar, An Nafi', Al Baqi, Al Waqi, Al Khafidl, Ar Rafi', Al Qabidl, Al Basith, Al Mu'iz, Al Mudzil, Al Muqsith, Ar Razaq, Dzu Al Quwwatil Matin, Al Qa`im, Ad da`im, Al Hafidz, Al Wakil, Al Fathir, As Sami', Al Mu'thi, Al Muhyi, Al Mumit, Al Mani', Al Jami', Al Haadi, Al Kaafi, Al Abad, Al 'Alim, As Shadiq, An Nuur, Al Munir, At Taam, Al Qadim, Al Witru, Al Ahad, As Shamad alladzi lam yalid walam yuulad walam yakul lahu kufuwan ahad.\" Zuhair berkata; \"telah menyampaikan kepadaku tidak cuma satu orang dari ahli ilmu, bahwa pertama-tama di awali dengan kalimat; Tidak ada ilah selain Allah, dzat satu-satunya yang tidak ada sekutu bagi-Nya, dzat yang memiliki kerajaan, dan bagi-Nya segala pujian, di tangan-Nya lah kebaikan dan Dia adalah dzat yang terhadap segala sesuatu berkuasa, tidak ada ilah (yang berhak di sembah) kecuali Allah, Dialah dzat yang memiliki nama-nama yang bagus.\""},"3816":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي جَعْفَرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثُ دَعَوَاتٍ يُسْتَجَابُ لَهُنَّ لَا شَكَّ فِيهِنَّ دَعْوَةُ الْمَظْلُومِ وَدَعْوَةُ الْمُسَافِرِ وَدَعْوَةُ الْوَالِدِ لِوَلَدِهِ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Bakr As Sahmi] dari [Hisyam Ad Dastuwa`i] dari [Yahya bin Abu Katsir] dari [Abu Ja'far] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga macam do`a yang akan di kabulkan dan tidak ada keraguan pada ketiganya, yaitu; do'a orang yang di dzalimi, do'anya orang musafir dan do'a orang tua kepada anaknya.\""},"3817":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو سَلَمَةَ حَدَّثَتْنَا حُبَابَةُ ابْنَةُ عَجْلَانَ عَنْ أُمِّهَا أُمِّ حَفْصٍ عَنْ صَفِيَّةَ بِنْتِ جَرِيرٍ عَنْ أُمِّ حَكِيمٍ بِنْتِ وَدَّاعٍ الْخُزَاعِيَّةِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ دُعَاءُ الْوَالِدِ يُفْضِي إِلَى الْحِجَابِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abu Salamah] telah menceritakan kepada kami [Hubabah putrinya 'Ajlan] dari [ibunya yaitu Ummu Hafsh] dari [Shafiyah binti Jarir] dari [Ummu Hakim binti Wadda' al Khuza'iyyah] dia berkata; \"Aku mendengar Rosulullah shallallahu 'alaihi wasallam bersabda: \"Do'a orang tua itu membuka hijab.\""},"3818":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَنْبَأَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي نَعَامَةَ أَنَّ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍسَمِعَ ابْنَهُ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْقَصْرَ الْأَبْيَضَ عَنْ يَمِينِ الْجَنَّةِ إِذَا دَخَلْتُهَا فَقَالَ أَيْ بُنَيَّ سَلْ اللَّهَ الْجَنَّةَ وَعُذْ بِهِ مِنْ النَّارِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَيَكُونُ قَوْمٌ يَعْتَدُونَ فِي الدُّعَاءِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah memberitakan kepada kami [Sa'id Al Jurairi] dari [Abu Na'amah] bahwa [Abdullah bin Mughaffal] mendengar anaknya mengatakan; \"Ya Allah, aku memohon kepada-Mu istana putih yang berada di sisi kanan surga jika saya masuk ke dalamnya.\" Maka Abdullah bin Mughffal berkata; \"Wahai anakku, mohonlah kepada Allah surga, dan berlindunglah kepada-Nya dari api neraka. Karena sesungguhnya aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada suatu kaum yang berdo'a secara berlebih-lebihan.\""},"3819":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ جَعْفَرِ بْنِ مَيْمُونٍ عَنْ أَبِي عُثْمَانَ عَنْ سَلْمَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ رَبَّكُمْ حَيِيٌّ كَرِيمٌ يَسْتَحْيِي مِنْ عَبْدِهِ أَنْ يَرْفَعَ إِلَيْهِ يَدَيْهِ فَيَرُدَّهُمَا صِفْرًا أَوْ قَالَ خَائِبَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Ja'far bin Maimun] dari [Abu Utsman] dari [Salman] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Rabb kalian Maha Hidup lagi Maha Pemurah, Malu dari hamba-Nya yang mengangkat kedua tangannya kepada-Nya kemudian mengembalikannya dengan tangan hampa, atau bersabda;...kedua tangannya yang tidak mendapatkan apa-apa.\""},"3820":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَائِذُ بْنُ حَبِيبٍ عَنْ صَالِحِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَعَوْتَ اللَّهَ فَادْعُ بِبُطُونِ كَفَّيْكَ وَلَا تَدْعُ بِظُهُورِهِمَا فَإِذَا فَرَغْتَ فَامْسَحْ بِهِمَا وَجْهَكَ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah menceritakan kepada kami ['Aidz bin Habib] dari [Shalih bin Hasan] dari [Muhammad bin Ka'ab Al Qurtzi] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu berdo'a kepada Allah, maka berdo'alah dengan kedua telapak tanganmu, jangan berdo'a dengan punggung telapak tangan, jika kamu telah selesai, maka basuhlah wajahmu dengan kedua telapak tangan tersebut.\""},"3821":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي عَيَّاشٍ الزُّرَقِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ حِينَ يُصْبِحُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ كَانَ لَهُ عَدْلَ رَقَبَةٍ مِنْ وَلَدِ إِسْمَعِيلَ وَحُطَّ عَنْهُ عَشْرُ خَطِيئَاتٍ وَرُفِعَ لَهُ عَشْرُ دَرَجَاتٍ وَكَانَ فِي حِرْزٍ مِنْ الشَّيْطَانِ حَتَّى يُمْسِيَ وَإِذَا أَمْسَى فَمِثْلُ ذَلِكَ حَتَّى يُصْبِحَ قَالَ فَرَأَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا يَرَى النَّائِمُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أَبَا عَيَّاشٍ يَرْوِي عَنْكَ كَذَا وَكَذَا فَقَالَ صَدَقَ أَبُو عَيَّاشٍ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Hammad bin Salamah] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu 'Ayyasy Az Zuraqi] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ketika pagi hari mengucapkan; \"Laa ilaaha illallah wahdahu laa syariikalah lahul mulku walahul hamdu wahuwa 'alaa kulli syai`in qadiir (Tiada ilah selain Allah yang Maha Esa, yang tiada sekutu bagi-Nya, milik-Nya kerajaan dan bagi-Nya segala pujian, serta Dia berkuasa atas segala sesuatu). Maka ia akan mendapatkan pahala seperti memerdekakan seorang budak dari keturunan Isma'il, di hapuskan darinya sepuluh kesalahan, di angkat baginya sepuluh derajat, dan ia tetap terjaga dari syaitan hingga sore hari. Jika dia berada di sore hari, maka ia akan tetap demikian sampai pagi hari menjelang.\" Perawi berkata; \"Seorang laki-laki bermimpi bertemu dengan Rasulullah shallallahu 'alaihi wasallam sebagaimana mimpinya orang-orang yang tidur, dan dia berkata; \"Wahai Rasulullah, Abu 'Ayyasy telah meriwayatkan darimu begini dan begini.\" Beliau menjawab: \"Abu 'Ayyasy benar.\""},"3822":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصْبَحْتُمْ فَقُولُوا اللَّهُمَّ بِكَ أَصْبَحْنَا وَبِكَ أَمْسَيْنَا وَبِكَ نَحْيَا وَبِكَ نَمُوتُ وَإِذَا أَمْسَيْتُمْ فَقُولُوا اللَّهُمَّ بِكَ أَمْسَيْنَا وَبِكَ أَصْبَحْنَا وَبِكَ نَحْيَا وَبِكَ نَمُوتُ وَإِلَيْكَ الْمَصِيرُ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian berada di pagi hari, maka ucapkanlah; \"Allahumma bika ashbahna wabika amsaina wabika nahya wabika namut (Ya Allah, dengan-Mu kami di pagi hari, dan dengan-Mu kami di sore hari, dengan-Mu kami hidup dan dengan-Mu kami mati).\" Dan jika berada di sore hari, maka ucapkanlah \"Allahumma bika amsaina wabika ashbahnya wabika nahya wabika namut wa ilaikal mashir (Ya Allah, dengan-Mu kami di sore hari, dan dengan-Mu kami di pagi hari, dengan-Mu kami hidup dan dengan-Mu kami mati).\""},"3823":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ أَبَانَ بْنِ عُثْمَانَ قَالَ سَمِعْتُ عُثْمَانَ بْنَ عَفَّانَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَقُولُ فِي صَبَاحِ كُلِّ يَوْمٍ وَمَسَاءِ كُلِّ لَيْلَةٍ بِسْمِ اللَّهِ الَّذِي لَا يَضُرُّ مَعَ اسْمِهِ شَيْءٌ فِي الْأَرْضِ وَلَا فِي السَّمَاءِ وَهُوَ السَّمِيعُ الْعَلِيمُ ثَلَاثَ مَرَّاتٍ فَيَضُرَّهُ شَيْءٌقَالَ وَكَانَ أَبَانُ قَدْ أَصَابَهُ طَرَفٌ مِنْ الْفَالِجِ فَجَعَلَ الرَّجُلُ يَنْظُرُ إِلَيْهِ فَقَالَ لَهُ أَبَانُ مَا تَنْظُرُ إِلَيَّ أَمَا إِنَّ الْحَدِيثَ كَمَا قَدْ حَدَّثْتُكَ وَلَكِنِّي لَمْ أَقُلْهُ يَوْمَئِذٍ لِيُمْضِيَ اللَّهُ عَلَيَّ قَدَرَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Ibnu Abu Az Zinnad] dari [ayahnya] dari [Aban bin Utsman] dia berkata; saya mendengar ['Utsman bin 'Affan] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba yang membaca pada pagi dan sore hari di setiap malamnya; Bismillahilladzii laa yadzurru ma'asmihi syai`un fil alrdli walaa fis samaa` wahuwas samii'ul 'aliim (Dengan menyebut nama Allah yang tidaklah sesuatu yang ada di bumi dan di langit akan celaka dengan nama-Nya, dan Dia Maha mendengar lagi Maha mengetahui).\" Sebanyak tiga kali, niscaya tidak akan di celakakan oleh sesuatu.\" Abu Zinnad berkata; \"Sementara itu, Abban terkena penyakit lumpuh, sedangkan ada seorang laki-laki yang memandanginya. Maka Abban berkata kepadanya; \"Mengapa kamu memandangiku?\" adapun mengenai hadits tersebut telah kuriwayatkan sebagaimana yang aku riwayatkan kepadamu. Namun saat (kejadian) itu aku tidak membacanya, sehingga Allah menakdirkanku dengan takdir-Nya.\""},"3824":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مِسْعَرٌ حَدَّثَنَا أَبُو عَقِيلٍ عَنْ سَابِقٍ عَنْ أَبِي سَلَّامٍ خَادِمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُسْلِمٍ أَوْ إِنْسَانٍ أَوْ عَبْدٍ يَقُولُ حِينَ يُمْسِي وَحِينَ يُصْبِحُ رَضِيتُ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا إِلَّا كَانَ حَقًّا عَلَى اللَّهِ أَنْ يُرْضِيَهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Mis'ar] telah menceritakan kepada kami [Abu 'Aqil] dari [Sabiq] dari [Abu Sallam] [pembantu Nabi] shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seorang muslim atau manusia atau seorang hamba berkata ketika menjelang sore dan pagi hari; \"Radliitu billahi rabba wabil islaami diina wabimuhammadi nabiyya (aku ridla kepada Allah sebagai Robbku, Islam sebagai agamaku dan Muhammad sebagai Nabi), kecuali Allah berhak untuk meridlainya pada hari kiamat.\""},"3825":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ الطَّنَافِسِيُّ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عُبَادَةُ بْنُ مُسْلِمٍ حَدَّثَنَا جُبَيْرُ بْنُ أَبِي سُلَيْمَانَ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَعُ هَؤُلَاءِ الدَّعَوَاتِ حِينَ يُمْسِي وَحِينَ يُصْبِحُ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَفْوَ وَالْعَافِيَةَ فِي دِينِي وَدُنْيَايَ وَأَهْلِي وَمَالِي اللَّهُمَّ اسْتُرْ عَوْرَاتِي وَآمِنْ رَوْعَاتِي وَاحْفَظْنِي مِنْ بَيْنِ يَدَيَّ وَمِنْ خَلْفِي وَعَنْ يَمِينِي وَعَنْ شِمَالِي وَمِنْ فَوْقِي وَأَعُوذُ بِكَ أَنْ أُغْتَالَ مِنْ تَحْتِيقَالَ وَكِيعٌ يَعْنِي الْخَسْفَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad At Thanafisi] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami ['Ubadah bin Muslim] telah menceritakan kepada kami [Jubair bin Abu Sulaiman bin Jubair bin Muth'im] dia berkata; saya mendengar [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam tidak pernah meninggalkan do'a-do'a tersebut ketika menjelang pagi dan sore, yaitu; \"Ya Allah, sesungguhnya aku meminta kepada-Mu ampunan dan keselamatan dunia dan akhirat. Ya Allah, sesungguhnya aku meminta kepada-Mu ampunan dan keselamatan di dalam menjalankan dienku, duniaku, keluargaku dan hartaku. Ya Allah, tutupilah auratku, amankanlah apa-apa yang menjadi pemeliharaanku, lindumgilah kami dari bahaya yang datang dari hadapanku, dari belakangku, dari samping kananku, dari sampaing kiriku dan dari atasku dan aku berlindung kepada-Mu dari bahaya yang datang tak disangka dari bawahku.\""},"3826":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُيَيْنَةَ حَدَّثَنَا الْوَلِيدُ بْنُ ثَعْلَبَةَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ خَلَقْتَنِي وَأَنَا عَبْدُكَ وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ أَبُوءُ بِنِعْمَتِكَ وَأَبُوءُ بِذَنْبِي فَاغْفِرْ لِي فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَهَا فِي يَوْمِهِ وَلَيْلَتِهِ فَمَاتَ فِي ذَلِكَ الْيَوْمِ أَوْ تِلْكَ اللَّيْلَةِ دَخَلَ الْجَنَّةَ إِنْ شَاءَ اللَّهُ تَعَالَى","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Ibrahim bin 'Uyainah] telah menceritakan kepada kami [Al Walid bin tsa'labah] dari [Abdullah bin Buraidah] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam berdo'a: \"Ya Allah, Engkaulah Rabbku, tiada ilah yang berhak di sembah selain Engkau, Engkau telah menciptakanku, dan aku adalah hamba-Mu. Aku berada dalam ketentuan dan janji-Mu semampuku. Aku berlindung kepada-Mu dari keburukan yang telah aku perbuat. Kuakui akan nikmat-nikmat-Mu dan kuakui akan dosa-dosaku, maka ampunilah aku, karena sesugguhnya tidak ada yang mampu mengampuni dosa selain Engkau.\" Buraidah berkata; \"Rasulullah shallallahu 'alaihi wasallam berabda: \"Barangsiapa membacanya pada siang dan malam hari, kemudian dia mati pada hari itu atau pada malam itu, niscaya ia akan masuk surga, jika Allah Ta'ala menghendaki.\""},"3827":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ إِذَا أَوَى إِلَى فِرَاشِهِ اللَّهُمَّ رَبَّ السَّمَوَاتِ وَالْأَرْضِ وَرَبَّ كُلِّ شَيْءٍ فَالِقَ الْحَبِّ وَالنَّوَى مُنْزِلَ التَّوْرَاةِ وَالْإِنْجِيلِ وَالْقُرْآنِ الْعَظِيمِ أَعُوذُ بِكَ مِنْ شَرِّ كُلِّ دَابَّةٍ أَنْتَ آخِذٌ بِنَاصِيَتِهَا أَنْتَ الْأَوَّلُ فَلَيْسَ قَبْلَكَ شَيْءٌ وَأَنْتَ الْآخِرُ فَلَيْسَ بَعْدَكَ شَيْءٌ وَأَنْتَ الظَّاهِرُ فَلَيْسَ فَوْقَكَ شَيْءٌ وَأَنْتَ الْبَاطِنُ فَلَيْسَ دُونَكَ شَيْءٌ اقْضِ عَنِّي الدَّيْنَ وَأَغْنِنِي مِنْ الْفَقْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Abdul Aziz bin Muhtar] telah menceritakan kepada kami [Suhail] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bahwa apabila beliau hendak berbaring ke tempat tidurnya, maka beliau membaca: \"Ya Allah, Rabb langit dan bumi, Rabb segala sesuatu, yang Maha menumbuhkan butir tumbuh-tumbuhan dan biji buah-buahan, dzat yang telah menurunkan Taurat, Injil dan Al Qur`an yang agung. Aku berlindung kepada-Mu dari kejahatan semua binatang merayap yang Engkau pegang ubun-ubunnya. Engkau Maha terdahulu yang tidak ada sesuatu sebelum-Mu. Engkau Maha terakhir yang tiada sesuatu setelah-Mu. Engkau Maha nyata yang tidak ada sesuatu yang lebih nyata dari-Mu. Dan Engkau Maha tersembunyi yang tidak ada sesuatu yang lebih tersembunyi dari-Mu. Lunasilah dariku segala hutang-hutangku dan cukupkanlah aku dari kefakiran.\""},"3828":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَرَادَ أَحَدُكُمْ أَنْ يَضْطَجِعَ عَلَى فِرَاشِهِ فَلْيَنْزِعْ دَاخِلَةَ إِزَارِهِ ثُمَّ لِيَنْفُضْ بِهَا فِرَاشَهُ فَإِنَّهُ لَا يَدْرِي مَا خَلَفَهُ عَلَيْهِ ثُمَّ لِيَضْطَجِعْ عَلَى شِقِّهِ الْأَيْمَنِ ثُمَّ لِيَقُلْ رَبِّ بِكَ وَضَعْتُ جَنْبِي وَبِكَ أَرْفَعُهُ فَإِنْ أَمْسَكْتَ نَفْسِي فَارْحَمْهَا وَإِنْ أَرْسَلْتَهَا فَاحْفَظْهَا بِمَا حَفِظْتَ بِهِ عِبَادَكَ الصَّالِحِينَ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abdullah bin Numair] dari ['Ubaidullah] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian hendak berbaring di atas tempat tidurnya, maka hendaknya ia membuka bagian dari selimutnya lalu membersihkan kasurnya, karena dirinya tidak mengetahui terhadap apa yang akan membahayakan dirinya. Kemudian hendaknya ia berbaring dengan meletakkan sisi kanan badannya sambil berdo'a; \"Wahai Rabbku, dengan nama-Mu aku membaringkan sisi badanku, dan juga dengan nama-Mu aku mengangkatnya. Jika Engkau mengambil jiwaku, maka kasihanilah ia. Dan jika Engkau melepaskannya, maka lindungilah ia, sebagaimana Engkau melindungi pada hamba-Mu yang shalih.\""},"3829":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ وَسَعِيدُ بْنُ شُرَحْبِيلَ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ أَخْبَرَهُ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَخَذَ مَضْجَعَهُ نَفَثَ فِي يَدَيْهِ وَقَرَأَ بِالْمُعَوِّذَتَيْنِ وَمَسَحَ بِهِمَا جَسَدَهُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Yunus bin Muhammad] dan [Sa'id bin Syurahbil] telah memberitakan kepada kami [Al Laits bin Sa'd] dari ['Uqail] dari [Ibnu Syihab] bahwa ['Urwah bin Az Zubair] telah mengabarkan kepadanya dari ['Aisyah] bahwa Apabila Rasulullah shallallahu 'alaihi wasallam mendatangi tempat pembaringannya, beliau meniup di kedua tangannya dan membaca surat mu'awwidatain lalu mengusapkan ke badannya dengan kedua telapak tangannya tersebut."},"3830":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ إِذَا أَخَذْتَ مَضْجَعَكَ أَوْ أَوَيْتَ إِلَى فِرَاشِكَ فَقُلْ اللَّهُمَّ أَسْلَمْتُ وَجْهِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ رَغْبَةً وَرَهْبَةً إِلَيْكَ لَا مَلْجَأَ وَلَا مَنْجَأَ مِنْكَ إِلَّا إِلَيْكَ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَنَبِيِّكَ الَّذِي أَرْسَلْتَ فَإِنْ مِتَّ مِنْ لَيْلَتِكَ مِتَّ عَلَى الْفِطْرَةِ وَإِنْ أَصْبَحْتَ أَصْبَحْتَ وَقَدْ أَصَبْتَ خَيْرًا كَثِيرًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Barra` bin 'Azib] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada seorang laki-laki: \"Jika kamu hendak pergi ke tempat pembaringanmu atau kamu hendak pergi tidur ke tempat tidurmu, maka ucapkanlah; \"Ya Allah, aku hadapkan wajahku kepada-Mu dan aku serahkan punggungku kepada-Mu. Aku titipkan kepada-Mu dalam keadaan suka dan senag terhadap-Mu, tiada tempat bergantung dan berlindung melainkan hanya kepada-Mu. Aku beriman kepada kitab-Mu yang telah Engkau turunkan kepada Nabi-Mu yang telah Engkau utus.\" Maka jika kamu meninggal dunia pada malam itu, kamu akan meninggal dalam keadaan suci. Dan jika kamu bangun di pagi hari, maka kamu akan hidup di pagi hari dengan mendapatkan kebaikan yang berlimpah.\""},"3831":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَوَى إِلَى فِرَاشِهِ وَضَعَ يَدَهُ يَعْنِي الْيُمْنَى تَحْتَ خَدِّهِ ثُمَّ قَالَ اللَّهُمَّ قِنِي عَذَابَكَ يَوْمَ تَبْعَثُ أَوْ تَجْمَعُ عِبَادَكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu 'Ubaidah] dari [Abdullah] bahwa apabila Nabi shallallahu 'alaihi wasallam hendak pergi ke tempat tidurnya, beliau meletakkan tangannya -yaitu yang kanan- di bawah pipinya, lalu beliau mengucapkan: \"Allahumma qinii 'adzaabaka yauma tab'ats au tajma' 'ibadaka (Ya Allah, lindungilah aku dari adzab-Mu pada hari saat Engkau bangkitkan -atau kumpulkan- para hamba-Mu.\""},"3832":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي عُمَيْرُ بْنُ هَانِئٍ حَدَّثَنِي جُنَادَةُ بْنُ أَبِي أُمَيَّةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَعَارَّ مِنْ اللَّيْلِ فَقَالَ حِينَ يَسْتَيْقِظُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ الْعَلِيِّ الْعَظِيمِ ثُمَّ دَعَا رَبِّ اغْفِرْ لِي غُفِرَ لَهُ قَالَ الْوَلِيدُ أَوْ قَالَ دَعَا اسْتُجِيبَ لَهُ فَإِنْ قَامَ فَتَوَضَّأَ ثُمَّ صَلَّى قُبِلَتْ صَلَاتُهُ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku ['Umair bin Hani`] telah menceritakan kepadaku [Junadah bin Abu Umayyah] dari ['Ubadah bin Shamit] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa terbangun di malam hari, dan ketika terbangun ia mengucapkan; \"Tidak ada ilah selain Allah yang Maha Esa, yang tidak ada sekutu bagi-Nya. Milik-Nya kerajaan dan bagi-Nya segala pujian, dan Dia Maha Kuasa atas segala sesuatu. Maha Suci Allah, d an segala puji bagi Allah serta tidak ada ilah selain Allah dan Allah Maha Besar. Tiada daya dan upaya melainkan Allah yang Maha Agung.\" Kemudian dia berdo'a; \"Ya Allah, ampunilah aku.\" Niscaya ia akan di ampuni.\" Al Walid berkata; \"atau beliau bersabda: \"Jika ia berdo'a, niscaya do'anya akan di kabulkan. Dan jika ia bangun untuk berwudlu' lalu shalat, maka shalatnya pasti di terima.\""},"3833":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ أَنْبَأَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ رَبِيعَةَ بْنَ كَعْبٍ الْأَسْلَمِيَّ أَخْبَرَهُأَنَّهُ كَانَ يَبِيتُ عِنْدَ بَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ يَسْمَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِنْ اللَّيْلِ سُبْحَانَ اللَّهِ رَبِّ الْعَالَمِينَ الْهَوِيَّ ثُمَّ يَقُولُ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah memberitakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] bahwa [Rabi'ah bin Ka'b Al Aslami] telah mengabarkan bahwa dirinya pernah bermalam di depan pintu rumah Rasulullah shallallahu 'alaihi wasallam, dan dia mendengar Rasulullah shallallahu 'alaihi wasallam membaca do'a di malam hari: \"Al Hamdulillahi rabbil 'alamin (Segala puji bagi Allah Rabb semesta alam.\" Suatu waktu di malam hari beliau mengucapkan: \"Subhanallah wa bihamdih (Maha Suci Allah dan segala puji bagi-Nya).\""},"3834":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا انْتَبَهَ مِنْ اللَّيْلِ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin 'Umair] dari [Rib'i bin Hirasy] dari [Hudzaifah] dia berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam terbangum di malam hari, beliau mengucapkan: \"Al Hamdulillahilladzii ahyaana ba'da maa amatana wailaihi nusyur (Segala puji bagi Allah yang telah menghidupkan kami setelah mematikan kami, dan kepada-Nya lah tempat kembali.\""},"3835":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو الْحُسَيْنِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَاصِمِ بْنِ أَبِي النُّجُودِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي ظَبْيَةَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ عَبْدٍ بَاتَ عَلَى طُهُورٍ ثُمَّ تَعَارَّ مِنْ اللَّيْلِ فَسَأَلَ اللَّهَ شَيْئًا مِنْ أَمْرِ الدُّنْيَا أَوْ مِنْ أَمْرِ الْآخِرَةِ إِلَّا أَعْطَاهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Al Husain] dari [Hammad bin Salamah] dari ['Ashim bin Abu An Nujud] dari [Syahr bin Hausyab] dari [Abu Dzabyah] dari [Mu'adz bin Jabal] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba tidur di malam hari dalam keadaan suci, kemudian ia terbangun di tengah malam, lalu ia memohon sesuatu kepada Allah dari perkara dunia atau perkara akhirat, niscaya akan di berikan kepadanya.\""},"3836":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ جَمِيعًا عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ حَدَّثَنِي هِلَالٌ مَوْلَى عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ أُمِّهِ أَسْمَاءَ ابْنَةِ عُمَيْسٍ قَالَتْعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهُنَّ عِنْدَ الْكَرْبِ اللَّهُ اللَّهُ رَبِّي لَا أُشْرِكُ بِهِ شَيْئًا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Muhammad bin Bisyr]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] semuanya dari [Abdul Aziz bin Umar bin Abdul Aziz] telah menceritakan kepadaku [Hilal bekas budak Umar bin Abdul Aziz] dari [Umar bin Abdul Aziz] dari [Abdullah bin Ja'far] dari [ibunya Asma' binti 'Umais] dia berkata; Rasulullah shallallahu 'alaihi wasallam mengajariku beberapa kalimat yang aku baca ketika sedang susah, yaitu; \"Allah, Allah Rabbi, laa usyrik bihi syai`a. (Allah, Allah, Robbku, aku tidak menyekutukan-Nya dengan sesuatu apapun).\""},"3837":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ صَاحِبِ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ عِنْدَ الْكَرْبِ لَا إِلَهَ إِلَّا اللَّهُ الْحَلِيمُ الْكَرِيمُ سُبْحَانَ اللَّهِ رَبِّ الْعَرْشِ الْعَظِيمِ سُبْحَانَ اللَّهِ رَبِّ السَّمَوَاتِ السَّبْعِ وَرَبِّ الْعَرْشِ الْكَرِيمِ قَالَ وَكِيعٌ مَرَّةً لَا إِلَهَ إِلَّا اللَّهُ فِيهَا كُلِّهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Hisyam pemilik Ad Dastuwa`i] dari [Qatadah] dari [Abu 'Aliyah] dari [Ibnu 'Abbas] bahwa ketika Nabi shallallahu 'alaihi wasallam dalam kesulitan, beliau akan mengucapkan: \"Tidak ada ilah selain Allah, yang Maha Lembut lagi Maha Mulia. Maha suci Allah, Rabb pemilik 'Arsy yang agung, Maha suci Allah, Rabb langit yang tujuh dan Rabb 'Arsy yang mulia.\" Waki' berkata; \"Suatu kali (beliau mengucapkan): \"Laa ilaaha illallah (Tidak ada ilah yang berhak di sembah selain Allah), \" sebab di dalamnya terkandung segalanya.\""},"3838":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ مِنْ مَنْزِلِهِ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ أَنْ أَضِلَّ أَوْ أَزِلَّ أَوْ أَظْلِمَ أَوْ أُظْلَمَ أَوْ أَجْهَلَ أَوْ يُجْهَلَ عَلَيَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Abidah bin Humaid] dari [Manshur] dari [As Sya'bi] dari [Ummu Salamah] bahwa apabila Nabi shallallahu 'alaihi wasallam keluar dari rumahnya, beliau mengucapkan: \"Allahumma inni a'uudzubika an adzilla au azilla, au adzlima au udzlama, au ajhala au yujhala 'alaya (Ya Allah, aku berlindung kepada-Mu dari ketersesatan atau ketergelinciran, atau dari berbuat kedzaliman maupun di dzalimi atau berbuat kebodohan maupun di bodohi.\""},"3839":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ عَبْدِ اللَّهِ بْنِ حُسَيْنِ بْنِ عَطَاءِ بْنِ يَسَارٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ مِنْ بَيْتِهِ قَالَ بِسْمِ اللَّهِ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ التُّكْلَانُ عَلَى اللَّهِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Abdullah bin Husain bin 'Atha` bin Yasar] dari [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] bahwa apabila Rasulullah shallallahu 'alaihi wasallam apabila keluar dari rumahnya beliau mengucapkan: \"Bismillah laa haula walaa quwwata illa billahi at tuklanu 'alallah (Dengan nama Allah, tidak ada daya dan upaya kecuali dengan kehendak Allah, dan bersandar kepada Allah).\""},"3840":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي هَارُونُ بْنُ هَارُونَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا خَرَجَ الرَّجُلُ مِنْ بَابِ بَيْتِهِ أَوْ مِنْ بَابِ دَارِهِ كَانَ مَعَهُ مَلَكَانِ مُوَكَّلَانِ بِهِ فَإِذَا قَالَ بِسْمِ اللَّهِ قَالَا هُدِيتَ وَإِذَا قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ قَالَا وُقِيتَ وَإِذَا قَالَ تَوَكَّلْتُ عَلَى اللَّهِ قَالَا كُفِيتَ قَالَ فَيَلْقَاهُ قَرِينَاهُ فَيَقُولَانِ مَاذَا تُرِيدَانِ مِنْ رَجُلٍ قَدْ هُدِيَ وَكُفِيَ وَوُقِيَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Ibnu Abu fudaik] telah menceritakan kepadaku [Harun bin Harun] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seseorang keluar dari pintu rumahnya atau dari pintu tempat tinggalnya, maka dia akan di sertai oleh dua Malaikat yang diwakilkan dengannya, jika ia mengatakan; \"Bismillah (dengan menyebut nama Allah), \" maka dua malaikat tersebut akan menjawab; \"Kamu telah di beri petunjuk.\" Jika ia mengucapkan; \"Laa haula walaa quwwata illa billah (Tidak ada daya dan upaya kecuali dengan kehendak Allah), \" maka kedua Malaikat tersebut akan berkata; \"Kamu telah di lindungi.\" Jika ia mengucapkan; \"Tawakaltu 'alallah (saya bertawakal kepada Allah).\" Maka kedua Malaikat tersebut akan berkata; \"Kamu telah di cukupi).\" Beliau bersabda: \"Kemudian jika dua qarinnya menemuinya, maka kedua Malaikat tersebut akan mengatakan; \"Apa yang akan hendak kalian perbuat dari seseorang yang telah di beri petunjuk, dan di cukupi serta di lindungi ini?.\""},"3841":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا دَخَلَ الرَّجُلُ بَيْتَهُ فَذَكَرَ اللَّهَ عِنْدَ دُخُولِهِ وَعِنْدَ طَعَامِهِ قَالَ الشَّيْطَانُ لَا مَبِيتَ لَكُمْ وَلَا عَشَاءَ وَإِذَا دَخَلَ وَلَمْ يَذْكُرْ اللَّهَ عِنْدَ دُخُولِهِ قَالَ الشَّيْطَانُ أَدْرَكْتُمْ الْمَبِيتَ فَإِذَا لَمْ يَذْكُرْ اللَّهَ عِنْدَ طَعَامِهِ قَالَ أَدْرَكْتُمْ الْمَبِيتَ وَالْعَشَاءَ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] telah mengabarkan kepadaku [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seseorang memasuki rumahnya kemudian dia berdzikir kepada Allah ketika masuk dan ketika makan, maka setan akan berkata (kepada kawannya); \"Tidak ada tempat menginap bagi kalian dan tidak ada makan malam.\" Jika ia masuk (rumahnya) tanpa berdzikir kepada Allah ketika memasukinya, maka setan akan berkata (kepada kawannya); \"Kalian telah mendapatkan tempat menginap.\" Dan jika ia tidak berdzikir kepada Allah ketika makan, setan pun akan berkata (kepada kawannya); \"Kalian telah mendapatkan tempat menginap dan makan malam.\""},"3842":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ وَأَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَقَالَ عَبْدُ الرَّحِيمِ يَتَعَوَّذُ إِذَا سَافَرَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ وَزَادَ أَبُو مُعَاوِيَةَ فَإِذَا رَجَعَ قَالَ مِثْلَهَا","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Abndurrahim bin Sulaiman] dan [Abu Mu'awiyah] dari ['Ashim] dari [Abdullah bin Sarjis] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda -Abdurrahim bin Sulaiman mengatakan; berta'awudz- jika hendak bepergian: \"Ya Allah, aku berlindung kepada-Mu dari kesusahan dalam kesusahan dan kesedihan, kekurangan setelah penambahan, do'a orang yang terdzalimi serta keburukan akan penilaian terhadap harta benda dan keluarga.\" Abu Mu'awiyah menambahkan; \"Dan jika beliau hendak kembali, beliau juga membaca seperti itu."},"3843":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ الْمِقْدَامِ عَنْ أَبِيهِ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَأَى سَحَابًا مُقْبِلًا مِنْ أُفُقٍ مِنْ الْآفَاقِ تَرَكَ مَا هُوَ فِيهِ وَإِنْ كَانَ فِي صَلَاتِهِ حَتَّى يَسْتَقْبِلَهُ فَيَقُولُ اللَّهُمَّ إِنَّا نَعُوذُ بِكَ مِنْ شَرِّ مَا أُرْسِلَ بِهِ فَإِنْ أَمْطَرَ قَالَ اللَّهُمَّ سَيْبًا نَافِعًا مَرَّتَيْنِ أَوْ ثَلَاثَةً وَإِنْ كَشَفَهُ اللَّهُ عَزَّ وَجَلَّ وَلَمْ يُمْطِرْ حَمِدَ اللَّهَ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Al Miqdam bin Syuraih] dari [ayahnya Al Miqdam] dari [ayahnya] bahwa ['Aisyah] telah mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam apabila beliau melihat awan gelap yang begerak di ufuk di antara ufuk yang tinggi, maka beliau meninggalkan semua kegiatannya meski dalam shalat, sampai menatapnya dan berdo'a: \"Ya Allah, kami berlindung kepada-Mu dari keburukan yang Engkau datangkan bersamanya.\" Jika turun hujan, maka beliau berdo'a: \"Allahumma shaiban naafi'a (Ya Allah jadikanlah curahan yang penuh keberkahan).\" (beliau membacanya) dua kali atau tiga kali. Dan jika Allah Azza Wa Jalla menghilangkannya dan tidak jadi turun hujan, maka beliau (bersyukur) memuji Allah atas semua itu.\""},"3844":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبِ بْنِ أَبِي الْعِشْرِينَ حَدَّثَنَا الْأَوْزَاعِيُّ أَخْبَرَنِي نَافِعٌ أَنَّ الْقَاسِمَ بْنَ مُحَمَّدٍ أَخْبَرَهُ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَأَى الْمَطَرَ قَالَ اللَّهُمَّ اجْعَلْهُ صَيِّبًا هَنِيئًا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Abdul Hamid bin Habib bin Abu Al 'Isyrin] telah menceritakan kepada kami [Al Auza'i] telah mengabarkan kepadaku [Nafi'] bahwa [Al Qasim bin Muhammad] telah mengabarkan dari ['Aisyah] bahwa apabila Rasulullah shallallahu 'alaihi wasallam melihat hujan turun, beliau berdo'a: \"Allahummaj'alhu shaiyyiban hani`an (Ya Allah, jadikanlah curahan hujan yang menyejukkan.\""},"3845":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَى مَخِيلَةً تَلَوَّنَ وَجْهُهُ وَتَغَيَّرَ وَدَخَلَ وَخَرَجَ وَأَقْبَلَ وَأَدْبَرَ فَإِذَا أَمْطَرَتْ سُرِّيَ عَنْهُ قَالَ فَذَكَرَتْ لَهُ عَائِشَةُ بَعْضَ مَا رَأَتْ مِنْهُ فَقَالَ وَمَا يُدْرِيكِ لَعَلَّهُ كَمَا قَالَ قَوْمُ هُودٍ{ فَلَمَّا رَأَوْهُ عَارِضًا مُسْتَقْبِلَ أَوْدِيَتِهِمْ قَالُوا هَذَا عَارِضٌ مُمْطِرُنَا بَلْ هُوَ مَا اسْتَعْجَلْتُمْ بِهِ }الْآيَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Ibnu Juraij] dari ['Atha`] dari ['Asiyah] dia berkata; Apabila Rasulullah shallallahu 'alaihi wasallam melihat mendung yang akan menurunkan hujan, maka raut wajah beliau berubah, beliau akan keluar-masuk, berjalan ke depan dan ke belakang. Dan apabila hujan telah turun, maka beliau sangat bergembira dengannya.\" Ibnu Juraij berkata; Kemudian 'Aisyah menanyakan apa yang di lihatnya dari sikap beliau!.\" Maka beliau menjawab: \"Apa yang mungkin kamu tahu (tentang apa yang akan terjadi)? Mungkin saja mendung itu sebagaimana yang di katakan oleh kaumnya Hud, yaitu; \"Maka tatkala mereka melihat adzab itu berupa awan yang menuju ke lembah-lembah mereka, berkatalah mereka; \"inilah awan yang akan menurunkan hujan kepada kami. (Bukan), bahkan itulah adzab yang kamu minta supaya datang dengan segera.\" QS Al Ahqaf; 24."},"3846":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ خَارِجَةَ بْنِ مُصْعَبٍ عَنْ أَبِي يَحْيَى عَمْرِو بْنِ دِينَارٍ وَلَيْسَ بِصَاحِبِ ابْنِ عُيَيْنَةَ مَوْلَى آلِ الزُّبَيْرِ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَجِئَهُ صَاحِبُ بَلَاءٍ فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي عَافَانِي مِمَّا ابْتَلَاكَ بِهِ وَفَضَّلَنِي عَلَى كَثِيرٍ مِمَّنْ خَلَقَ تَفْضِيلًا عُوفِيَ مِنْ ذَلِكَ الْبَلَاءِ كَائِنًا مَا كَانَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Kharijah bin Mush'ab] dari [Abu Yahya 'Amru bin Dinar] -tidak termasuk dari teman Ibnu 'Uyainah- yaitu bekas budak Az Zubair, dari [Salim] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dikejutkan oleh orang yang tertimpa musibah, kemudian dia mengucapkan; \"Segala puji bagi Allah yang telah menyelamatkanku dari musibah yang menimpamu, dan memberi kelebihan kepadaku atas semua yang di ciptakan-Nya dengan kelebihan yang sempurna.\" Maka dia akan diselamatkan dari musibah itu bagaimanapun juga.\""},"3847":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنِي إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا الْحَسَنَةُ مِنْ الرَّجُلِ الصَّالِحِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Malik bin Anas] telah menceritakan kepadaku [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi yang baik dari seorang yang shalih adalah satu bagian dari empat puluh enam bagian kenabian.\""},"3848":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Mimpi seorang mukmin adalah satu bagian dari empat puluh enam bagian kenabian.\""},"3849":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَنْبَأَنَا شَيْبَانُ عَنْ فِرَاسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُؤْيَا الرَّجُلِ الْمُسْلِمِ الصَّالِحِ جُزْءٌ مِنْ سَبْعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] telah memberitakan kepada kami [Syaiban] dari [Firas] dari ['Athiyah] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Mimpi seorang muslim yang shalih merupakan bagian dari tujuh puluh bagian kenabian.\""},"3850":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍ الْكَعْبِيَّةِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَهَبَتْ النُّبُوَّةُ وَبَقِيَتْ الْمُبَشِّرَاتُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah Al Hammal] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ubaidullah bin Abu Yazid] dari [ayahnya] dari [Siba' bin Tsabit] dari [Ummu Kurz Al Ka'biyah] dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kenabian telah tiada, dan yang tersisa adalah (para Malaikat) pemberi kabar gembira.\""},"3851":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ وَعَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا الصَّالِحَةُ جُزْءٌ مِنْ سَبْعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abu Usamah] dan [Abdullah bin Numair] dari ['Ubaidillah bin Umar] dari [Nafi] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi yang benar adalah bagian dari tujuh puluh bagian kenabian.\""},"3852":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ عَلِيِّ بْنِ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِ اللَّهِ سُبْحَانَهُ{ لَهُمْ الْبُشْرَى فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ هِيَ الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Ali bin Mubarak] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari ['Ubadah bin Shamit] dia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai firman Allah Subhanah; \"Bagi mereka berita gembira di dalam kehidupan dunia dan akhirat.\" QS Yunus; 64. Beliau menjawab: \"ia adalah mimpi yang baik yang di mimpikan oleh seorang muslim atau di perlihatkan kepada dirinya.\""},"3853":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ الْأَيْلِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ بْنِ سُحَيْمٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ مَعْبَدِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَشَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السِّتَارَةَ فِي مَرَضِهِ وَالصُّفُوفُ خَلْفَ أَبِي بَكْرٍ فَقَالَ أَيُّهَا النَّاسُ إِنَّهُ لَمْ يَبْقَ مِنْ مُبَشِّرَاتِ النُّبُوَّةِ إِلَّا الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Aili] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Sulaiman bin Suhaim] dari [Ibrahim bin Abdullah bin Ma'bad bin 'Abbas] dari [ayahnya] dari [Ibnu Abbas] dia berkata; \"Ketika sakit, Rasulullah shallallahu 'alaihi wasallam membuka tirai jendelanya, sementara barisan orang-orang berada di belakang Abu Bakar, lalu beliau bersabda: \"Wahai sekalian manusia, sesungguhnya kabar kenabian telah tiada, kecuali mimpi yang baik yang di mimpikan oleh seorang muslim atau mimpi yang di perlihatkan kepadanya.\""},"3854":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فِي الْيَقَظَةِ فَإِنَّ الشَّيْطَانَ لَا يَتَمَثَّلُ عَلَى صُورَتِي","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa bermimpi melihatku, sungguh dia telah melihatku sebagaimana ketika terjaga, karena sesungguhnya syaitan tidak akan menyerupai bentuk diriku.\""},"3855":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَتَمَثَّلُ بِي","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani] dia berkata; telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bermimpi melihatku, sungguh dia telah melihatku, karena sesungguhnya syaitan tidak akan menyerupai bentuk diriku.\""},"3856":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي إِنَّهُ لَا يَنْبَغِي لِلشَّيْطَانِ أَنْ يَتَمَثَّلَ فِي صُورَتِي","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepadaku [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"\"Barangsiapa bermimpi melihatku, sungguh dia telah melihatku, karena sesungguhnya syetan tidak di perkenankan untuk menyerupai bentuk diriku.\""},"3857":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا بَكْرُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عِيسَى بْنُ الْمُخْتَارِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَتَمَثَّلُ بِي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Bakr bin Abdurrahman] telah menceritakan kepada kami [Isa bin Al Muhtar] dari [Ibnu Abu Laila] dari ['Athiyah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa bermimpi melihatku, sungguh dia telah melihatku, karena sesungguhnya syaitan tidak dapat menyerupai diriku.\""},"3858":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيُّ حَدَّثَنَا سَعْدَانُ بْنُ يَحْيَى بْنِ صَالِحٍ اللَّخْمِيُّ حَدَّثَنَا صَدَقَةُ بْنُ أَبِي عِمْرَانَ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَآنِي فِي الْمَنَامِ فَكَأَنَّمَا رَآنِي فِي الْيَقَظَةِ إِنَّ الشَّيْطَانَ لَا يَسْتَطِيعُ أَنْ يَتَمَثَّلَ بِي","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Sulaiman bin Abdurrahman Ad Dimasyqi] telah menceritakan kepada kami [Sa'dan bin Yahya bin Shalih Al Lakhmi] telah menceritakan kepada kami [Shadaqah bin Abu 'Imran] dari ['Aun bin Abu Juhaifah] dari [ayahnya] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa melihatku didalam mimpi, maka seakan-akan dia telah melihatku dalam keadaan sadar (terjaga), sesungguhnya syetan tidak dapat menyerupai diriku.\""},"3859":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو الْوَلِيدِ قَالَ أَبُو عَوَانَةَ حَدَّثَنَا عَنْ جَابِرٍ عَنْ عَمَّارٍ هُوَ الدُّهْنِيُّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَتَمَثَّلُ بِي","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abu Al Walid], [Abu 'Awanah] mengatakan; telah menceritakan kepada kami, dari [Jabir] dari ['Ammar yaitu Ad Duhni] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam berabda: \"Barangsiapa bermimpi melihatku, sungguh dia telah melihatku, karena sesungguhnya syaitan tidak dapat menyerupai diriku.\""},"3860":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هَوْذَةُ بْنُ خَلِيفَةَ حَدَّثَنَا عَوْفٌ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرُّؤْيَا ثَلَاثٌ فَبُشْرَى مِنْ اللَّهِ وَحَدِيثُ النَّفْسِ وَ��َخْوِيفٌ مِنْ الشَّيْطَانِ فَإِنْ رَأَى أَحَدُكُمْ رُؤْيَا تُعْجِبُهُ فَلْيَقُصَّ إِنْ شَاءَ وَإِنْ رَأَى شَيْئًا يَكْرَهُهُ فَلَا يَقُصَّهُ عَلَى أَحَدٍ وَلْيَقُمْ يُصَلِّي","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Haudzah bin Khalifah] telah menceritakan kepada kami ['Auf] dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Mimpi ada tiga macam, yaitu; kabar gembira dari Allah, (mimpi yang di sebabkan) dari kondisi kejiwaan, dan rasa takut yang di timbulkan oleh syetan untuk menakut-nakuti. Jika salah seorang dari kalian bermimpi dengan mimpi yang menyenangkan dirinya, maka hendaknya ia menceritakannya jika dirinya mau, dan jika ia bermimpi tentang sesuatu yang di bencinya, maka hendaknya ia tidak menceritakan kepada siapapun, dan hendaknya ia segera bangkit untuk mengerjakan shalat.\""},"3861":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا يَزِيدُ بْنُ عَبِيدَةَ حَدَّثَنِي أَبُو عُبَيْدِ اللَّهِ مُسْلِمُ بْنُ مِشْكَمٍ عَنْ عَوْفِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرُّؤْيَا ثَلَاثٌ مِنْهَا أَهَاوِيلُ مِنْ الشَّيْطَانِ لِيَحْزُنَ بِهَا ابْنَ آدَمَ وَمِنْهَا مَا يَهُمُّ بِهِ الرَّجُلُ فِي يَقَظَتِهِ فَيَرَاهُ فِي مَنَامِهِ وَمِنْهَا جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ قَالَ قُلْتُ لَهُ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ أَنَا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [Yazid bin 'Abidah] telah menceritakan kepadaku [Abu 'Ubaidillah Muslim bin Misykam] dari ['Auf bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya mimpi itu ada tiga macam, diantaranya mimpi-mimpi buruk yang menakutkan yang datang dari setan untuk membuat sedih anak Adam, diantaranya pula perkara yang menggelisahkan seseorang ketika terjaga kemudian terbawa dalam mimpinya, dan diantaranya pula satu bagian dari empat puluh enam bagian kenabian.\" Abu 'Ubaidillah berkata; aku bertanya; \"Apakah kamu mendengar ini dari Rasulullah shallallahu 'alaihi wasallam?\", dia menjawab; \"Ya, aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},"3862":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا رَأَى أَحَدُكُمْ الرُّؤْيَا يَكْرَهُهَا فَلْيَبْصُقْ عَنْ يَسَارِهِ ثَلَاثًا وَلْيَسْتَعِذْ بِاللَّهِ مِنْ الشَّيْطَانِ ثَلَاثًا وَلْيَتَحَوَّلْ عَنْ جَنْبِهِ الَّذِي كَانَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir bin Abdullah] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Jika salah seorang dari kalian bermimpi sesuatu yang di bencinya, maka hendaknya ia meludah ke sisi kiri (tubuhnya) tiga kali dan membaca ta'awudz (memohon perlindungan) kepada Allah dari godaan syetan tiga kali, serta merubah posisi badannya (dari posisi tidurnya semula) saat itu.\""},"3863":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرُّؤْيَا مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ فَإِذَا رَأَى أَحَدُكُمْ شَيْئًا يَكْرَهُهُ فَلْيَبْصُقْ عَنْ يَسَارِهِ ثَلَاثًا وَلْيَسْتَعِذْ بِاللَّهِ مِنْ الشَّيْطَانِ الرَّجِيمِ ثَلَاثًا وَلْيَتَحَوَّلْ عَنْ جَنْبِهِ الَّذِي كَانَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Yahya bin Sa'id] dari [Abu Salamah bin Abdurrahman bin 'Auf] dari [Abu Qatadah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi itu dari Allah, dan ihtilam (mimpi basah) itu dari syetan. Maka jika seseorang dari kalian bermimpi sesuatu yang di bencinya, hendaknya ia meludah ke sisi kirinya tiga kali, dan berlindung kepada Allah dari godaan syetan (membaca ta'awudz) tiga kali, serta merubah posisi badanya (dari posisi semula tidurnya) saat itu.\""},"3864":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْعُمَرِيِّ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَى أَحَدُكُمْ رُؤْيَا يَكْرَهُهَا فَلْيَتَحَوَّلْ وَلْيَتْفُلْ عَنْ يَسَارِهِ ثَلَاثًا وَلْيَسْأَلْ اللَّهَ مِنْ خَيْرِهَا وَلْيَتَعَوَّذْ مِنْ شَرِّهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Al 'Umari] dari [Sa'id Al Maqburi] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian bermimpi dengan sesuatu yang di bencinya, maka hendaknya ia merubah posisi tidurnya dan meludah ke sebelah kirinya tiga kali, dan meminta kepada Allah dari kebaikannya dan berlindung dari keburukannya.\""},"3865":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عُمَرَ بْنِ سَعِيدِ بْنِ أَبِي حُسَيْنٍ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي رَأَيْتُ رَأْسِي ضُرِبَ فَرَأَيْتُهُ يَتَدَهْدَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْمِدُ الشَّيْطَانُ إِلَى أَحَدِكُمْ فَيَتَهَوَّلُ لَهُ ثُمَّ يَغْدُو يُخْبِرُ النَّاسَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Abdullah bin Az Zubair] dari [Umar bin Sa'id bin Abu Husain] telah menceritakan kepadaku ['Atha bin Abu Rabah] dari [Abu Hurairah] dia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Saya pernah mimpi bahwa kepalaku di pukul sehingga terputus, Nabi shallallahu 'alaihi wasallam lantas bersabda: \"Setan sengaja berbuat demikian kepada salah seorang dari kalian, sehingga membuatnya takut dan kemudian di pagi harinya menceritakan kepada orang-orang.\""},"3866":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ وَهُوَ يَخْطُبُ فَقَالَ يَا رَسُولَ اللَّهِ رَأَيْتُ الْبَارِحَةَ فِيمَا يَرَى النَّائِمُ كَأَنَّ عُنُقِي ضُرِبَتْ وَسَقَطَ رَأْسِي فَاتَّبَعْتُهُ فَأَخَذْتُهُ فَأَعَدْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَعِبَ الشَّيْطَانُ بِأَحَدِكُمْ فِي مَنَامِهِ فَلَا يُحَدِّثَنَّ بِهِ النَّاسَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata, \"Seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang berkhutbah, laki-laki itu berkata, \"Wahai Rasulullah, tadi malam aku bermimpi leherku dipeneggal sehingga kepalaku pun terlepas, lalu aku mencarinya, ketika kudapatkan kepala tersebut aku pasang kembali ke tempatnya semula.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Apabila setan mempermainkan seseorang di antara kalian dalam tidurnya, maka hendaknya ia tidak menceritakannya kepada orang-orang.\""},"3867":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَلَمَ أَحَدُكُمْ فَلَا يُخْبِرْ النَّاسَ بِتَلَعُّبِ الشَّيْطَانِ بِهِ فِي الْمَنَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian bermimpi, hendaklah ia tidak menceritakan kepada orang lain tentang dirinya yang sedang dipermainkan oleh setan dalam mimpinya.\""},"3868":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا هُشَيْمٌ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ عُدُسٍ الْعُقَيْلِيِّ عَنْ عَمِّهِ أَبِي رَزِينٍأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرُّؤْيَا عَلَى رِجْلِ طَائِرٍ مَا لَمْ تُعْبَرْ فَإِذَا عُبِرَتْ وَقَعَتْ قَالَ وَالرُّؤْيَا جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ قَالَ وَأَحْسِبُهُ قَالَ لَا يَقُصُّهَا إِلَّا عَلَى وَادٍّ أَوْ ذِي رَأْيٍ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Husyaim] dari [Ya'la bin 'Atha] dari [Waki' bin 'Udus Al 'Uqaili] dari pamannya [Abu Razin], bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Mimpi itu berada di kaki burung selama tidak di ta'birkan, jika dita'birkan bisa jadi mimpi itu akan terjadi.\" Beliau menambahkan: \"Mimpi adalah satu bagian dari empat puluh enam bagian kenabian.\" Abu Razin berkata, \"Menurutku beliau juga mengatakan: \"Janganlah seseorang menceritakannya kecuali kepada orang yang dicintainya atau orang yang mengerti.\""},"3869":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَبِرُوهَا بِأَسْمَائِهَا وَكَنُّوهَا بِكُنَاهَا وَالرُّؤْيَا لِأَوَّلِ عَابِرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dari [Yazid Ar Raqasy] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah pelajaran dengan nama-namanya dan pakailah kunyah dengan menggunakan kunyahnya, dan mimpi adalah ta'bir yang pertama.\""},"3870":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَحَلَّمَ حُلُمًا كَاذِبًا كُلِّفَ أَنْ يَعْقِدَ بَيْنَ شَعِيرَتَيْنِ وَيُعَذَّبُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal As Shawwaf] telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bermimpi dengan (disertai) kedustaan, maka akan dibebankan kepadanya untuk mengikat antara dua gandum dan dia akan di siksa akan perkara itu.\""},"3871":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا بِشْرُ بْنُ بَكْرٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَرُبَ الزَّمَانُ لَمْ تَكَدْ رُؤْيَا الْمُؤْمِنِ تَكْذِبُ وَأَصْدَقُهُمْ رُؤْيَا أَصْدَقُهُمْ حَدِيثًا وَرُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh Al Mishri] telah menceritakan kepada kami [Bisyr bin Bakr] telah menceritakan kepada kami [Al Auza'i] dari [Ibnu Sirin] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila zaman telah mendekati (hari Kiamat), hampir-hampir mimpinya seorang mukmin tidak bohong, maka orang yang paling benar mimpinya adalah orang yang paling jujur pembicaraannya. Dan mimpi seorang mukmin merupakan satu bagian dari empat puluh enam bagian kenabian.\""},"3872":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ الْمَدَنِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ مُنْصَرَفَهُ مِنْ أُحُدٍ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي رَأَيْتُ فِي الْمَنَامِ ظُلَّةً تَنْطُفُ سَمْنًا وَعَسَلًا وَرَأَيْتُ النَّاسَ يَتَكَفَّفُونَ مِنْهَا فَالْمُسْتَكْثِرُ وَالْمُسْتَقِلُّ وَرَأَيْتُ سَبَبًا وَاصِلًا إِلَى السَّمَاءِ رَأَيْتُكَ أَخَذْتَ بِهِ فَعَلَوْتَ بِهِ ثُمَّ أَخَذَ بِهِ رَجُلٌ بَعْدَكَ فَعَلَا بِهِ ثُمَّ أَخَذَ بِهِ رَجُلٌ بَعْدَهُ فَعَلَا بِهِ ثُمَّ أَخَذَ بِهِ رَجُلٌ بَعْدَهُ فَانْقَطَعَ بِهِ ثُمَّ وُصِلَ لَهُ فَعَلَا بِهِ فَقَالَ أَبُو بَكْرٍ دَعْنِي أَعْبُرُهَا يَا رَسُولَ اللَّهِ قَالَ اعْبُرْهَا قَالَ أَمَّا الظُّلَّةُ فَالْإِسْلَامُ وَأَمَّا مَا يَنْطُفُ مِنْهَا مِنْ الْعَسَلِ وَالسَّمْنِ فَهُوَ الْقُرْآنُ حَلَاوَتُهُ وَلِينُهُ وَأَمَّا مَا يَتَكَفَّفُ مِنْهُ النَّاسُ فَالْآخِذُ مِنْ الْقُرْآنِ كَثِيرًا وَقَلِيلًا وَأَمَّا السَّبَبُ الْوَاصِلُ إِلَى السَّمَاءِ فَمَا أَنْتَ عَلَيْهِ مِنْ الْحَقِّ أَخَذْتَ بِهِ فَعَلَا بِكَ ثُمَّ يَأْخُذُهُ رَجُلٌ مِنْ بَعْدِكَ فَيَعْلُو بِهِ ثُمَّ آخَرُ فَيَعْلُو بِهِ ثُمَّ آخَرُ فَيَنْقَطِعُ بِهِ ثُمَّ يُوَصَّلُ لَهُ فَيَعْلُو بِهِ قَالَ أَصَبْتَ بَعْضًا وَأَخْطَأْتَ بَعْضًا قَالَ أَبُو بَكْرٍ أَقْسَمْتُ عَلَيْكَ يَا رَسُولَ اللَّهِ لَتُخْبِرَنِّي بِالَّذِي أَصَبْتُ مِنْ الَّذِي أَخْطَأْتُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْسِمْ يَا أَبَا بَكْرٍحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ أَبُو هُرَيْرَةَ يُحَدِّثُ أَنَّ رَجُلًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ رَأَيْتُ ظُلَّةً بَيْنَ السَّمَاءِ وَالْأَرْضِ تَنْطِفُ سَمْنًا وَعَسَلًا فَذَكَرَ الْحَدِيثَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib Al Madani] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam ketika beliau kembali dari perang Uhud, laki-laki itu berkata, \"Wahai Rasulullah, aku bermimpi melihat awan menaungi dan menurunkan hujan minyak samin dan madu. Aku juga melihat orang-orang menadahinya dengan kedua telapak tangan mereka, maka ada yang mendapat banyak dan ada pula yang mendapat sedikit. Aku juga melihat tangga yang menghubungkan ke langit, kulihat anda menaikinya sampai ke atas. Kemudian ada seorang laki-laki menaikinya setelah anda, sehingga ia sampai ke atas. Lalu seorang laki-laki setelahnya pun turut menaikinya namun terputus dan diperbaiki untuknya sehingga ia pun sampai ka atas.\" Abu Bakar berkata, \"Izinkanlah aku untuk menta'birkannya, wahai Rasulullah.\" Beliau menjawab: \"Ta'birkanlah.\" Abu Bakar berkata, \"Adapun awan itu adalah Islam, sedangkan hujan minyak samin dan madu yang turun darinya adalah Al Quran dengan kenikmatan dan kelembutannya. Adapun yang ditadahi oleh orang-orang dengan kedua telapak tangan mereka adalah orang-orang yang mengambil Al Quran, ada yang mendapat banyak dan ada pula yang mendapat sedikit. Sedangkan tangga yang sampai ke langit adalah kebenaran yang ada pada dirimu, dan kamu mempertahankannya sehingga kamu dapat mencapai kemualiaan. Setelah itu seorang laki-laki setelahmu juga mempertahankannya dan membuat dirinya juga mulia. Setelah itu datang laki-laki lain dan ia juga mendapatkan kemuliaan dengannya, dan yang lain ada yang terputus, namun disambungkan lagi untuknya sehingga dengannya ia juga mendapatkan kemuliaan.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Apa yang kamu ta'birkan itu sebagiannya benar, dan sebagiannya lagi ada yang keliru.\" Abu Bakar berkata, \"Aku bersumpah atas namamu wahai Rasulullah, sekiranya anda berkenan untuk memberitahukan sebagian yang benar dan sebagian yang keliru kepadaku.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Bakar, janganlah kamu bersumpah dengan urusan seperti ini.\" Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah] dari [Ibnu Abbas] dia berkata; [Abu Hurairah] pernah bercerita bahwa seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, saya pernah bermimpi melihat naungan awan yang berada antara langit dan bumi, ia menurunkan minyak samin dan madu…kemudian dia menyebutkan hadits seperti di atas.\""},"3873":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاذٍ الصَّنْعَانِيُّ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَكُنْتُ غُلَامًا شَابًّا عَزَبًا فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ أَبِيتُ فِي الْمَسْجِدِ فَكَانَ مَنْ رَأَى مِنَّا رُؤْيَا يَقُصُّهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ اللَّهُمَّ إِنْ كَانَ لِي عِنْدَكَ خَيْرٌ فَأَرِنِي رُؤْيَا يُعَبِّرُهَا لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنِمْتُ فَرَأَيْتُ مَلَكَيْنِ أَتَيَانِي فَانْطَلَقَا بِي فَلَقِيَهُمَا مَلَكٌ آخَرُ فَقَالَ لَمْ تُرَعْ فَانْطَلَقَا بِي إِلَى النَّارِ فَإِذَا هِيَ مَطْوِيَّةٌ كَطَيِّ الْبِئْرِ وَإِذَا فِيهَا نَاسٌ قَدْ عَرَفْتُ بَعْضَهُمْ فَأَخَذُوا بِي ذَاتَ الْيَمِينِ فَلَمَّا أَصْبَحْتُ ذَكَرْتُ ذَلِكَ لِحَفْصَةَ فَزَعَمَتْ حَفْصَةُ أَنَّهَا قَصَّتْهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ عَبْدَ اللَّهِ رَجُلٌ صَالِحٌ لَوْ كَانَ يُكْثِرُ الصَّلَاةَ مِنْ اللَّيْلِقَالَ فَكَانَ عَبْدُ اللَّهِ يُكْثِرُ الصَّلَاةَ مِنْ اللَّيْلِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] telah menceritakan kepada kami [Abdullah bin Mu'adz Ash Shan'ani] dari [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] dia berkata, \"Di masa Rasulullah shallallahu 'alaihi wasallam aku adalah seorang remaja yang tumbuh dengan gagah, aku biasa bermalam di masjid, ketika ada yang bermimpi maka pastilah mimpi tersebut diceritakan kepada Rasulullah shallallahu 'alaihi wasallam. Dalam hati aku berkata, \"Ya Allah, seandainya aku memiliki kebaikan pada-Mu, maka perlihatkan kepadaku suatu mimpi yang akan dita'birkan oleh Rasulullah shallallahu 'alaihi wasallam untukku.\" Setelah itu aku tidur, tiba-tiba aku bermimpi melihat dua malaikat yang datang menghampiriku. Keduanya membawaku dan bertemu dengan malaikat yang lain. Malaikat itu berkata, 'Jangan diteruskan.' Akhirnya keduanya membawaku ke neraka, ternyata neraka itu dipasangi dengan bebatuan bagaikan sumur di tembok batu. Dan ternyata di dalamnya terdapat orang-orang yang sebagiannya telah aku kenal, dan mereka mengambil beberapa sumpah dariku. Ketika aku bangun di pagi harinya, aku langsung memberitahukannya kepada [Hafshah], maka Hafshah mengaku telah menceritakannya kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Abdullah itu seorang yang shalih sekiranya mau memperbanyak shalat malam.\" Perawi berkata, \"Maka sejak saat itu Abdullah menjadi seorang yang banyak mengerjakan shalat malam.\""},"3874":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى الْأَشْيَبُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ قَالَقَدِمْتُ الْمَدِينَةَ فَجَلَسْتُ إِلَى شِيَخَةٍ فِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ شَيْخٌ يَتَوَكَّأُ عَلَى عَصًا لَهُ فَقَالَ الْقَوْمُ مَنْ سَرَّهُ أَنْ يَنْظُرَ إِلَى رَجُلٍ مِنْ أَهْلِ الْجَنَّةِ فَلْيَنْظُرْ إِلَى هَذَا فَقَامَ خَلْفَ سَارِيَةٍ فَصَلَّى رَكْعَتَيْنِ فَقُمْتُ إِلَيْهِ فَقُلْتُ لَهُ قَالَ بَعْضُ الْقَوْمِ كَذَا وَكَذَا قَالَ الْحَمْدُ لِلَّهِ الْجَنَّةُ لِلَّهِ يُدْخِلُهَا مَنْ يَشَاءُ وَإِنِّي رَأَيْتُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُؤْيَا رَأَيْتُ كَأَنَّ رَجُلًا أَتَانِي فَقَالَ لِي انْطَلِقْ فَذَهَبْتُ مَعَهُ فَسَلَكَ بِي فِي نَهْجٍ عَظِيمٍ فَعُرِضَتْ عَلَيَّ طَرِيقٌ عَلَى يَسَارِي فَأَرَدْتُ أَنْ أَسْلُكَهَا فَقَالَ إِنَّكَ لَسْتَ مِنْ أَهْلِهَا ثُمَّ عُرِضَتْ عَلَيَّ طَرِيقٌ عَنْ يَمِينِي فَسَلَكْتُهَا حَتَّى إِذَا انْتَهَيْتُ إِلَى جَبَلٍ زَلَقٍ فَأَخَذَ بِيَدِي فَزَجَّلَ بِي فَإِذَا أَنَا عَلَى ذُرْوَتِهِ فَلَمْ أَتَقَارَّ وَلَمْ أَتَمَاسَكْ وَإِذَا عَمُودٌ مِنْ حَدِيدٍ فِي ذُرْوَتِهِ حَلْقَةٌ مِنْ ذَهَبٍ فَأَخَذَ بِيَدِي فَزَجَّلَ بِي حَتَّى أَخَذْتُ بِالْعُرْوَةِ فَقَالَ اسْتَمْسَكْتَ قُلْتُ نَعَمْ فَضَرَبَ الْعَمُودَ بِرِجْلِهِ فَاسْتَمْسَكْتُ بِالْعُرْوَةِ فَقَالَ قَصَصْتُهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتَ خَيْرًا أَمَّا الْمَنْهَجُ الْعَظِيمُ فَالْمَحْشَرُ وَأَمَّا الطَّرِيقُ الَّتِي عُرِضَتْ عَنْ يَسَارِكَ فَطَرِيقُ أَهْلِ النَّارِ وَلَسْتَ مِنْ أَهْلِهَا وَأَمَّا الطَّرِيقُ الَّتِي عُرِضَتْ عَنْ يَمِينِكَ فَطَرِيقُ أَهْلِ الْجَنَّةِ وَأَمَّا الْجَبَلُ الزَّلَقُ فَمَنْزِلُ الشُّهَدَاءِ وَأَمَّا الْعُرْوَةُ الَّتِي اسْتَمْسَكْتَ بِهَا فَعُرْوَةُ الْإِسْلَامِ فَاسْتَمْسِكْ بِهَا حَتَّى تَمُوتَ فَأَنَا أَرْجُو أَنْ أَكُونَ مِنْ أَهْلِ الْجَنَّةِ فَإِذَا هُوَ عَبْدُ اللَّهِ بْنُ سَلَامٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Al Hasan bin Musa Al Asyaib] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim bin Bahdalah] dari [Al Musayyab bin Rafi'] dari [Kharasyah bin Al Hur] dia berkata, \"Saya tiba di Madinah, lalu duduk-duduk bersama dengan beberapa orang tua di masjid Nabi shallallahu 'alaihi wasallam. Tiba-tiba seorang yang telah lanjut usia datang dengan bersandar pada tongkatnya, lalu orang-orang berkata, \"Barangsiapa ingin melihat seorang penghuni surga maka lihatlah orang ini! \" Orang itu kemudian berdiri dan shalat dua rakaat di belakang tiang masjid. Aku lalu mendekat dan berkata kepadanya, \"Sebagian orang telah menceritakan tentang dirimu begini dan begini.\" Orang itu menjawab, \"Segala puji bagi Allah, surga adalah milik Allah dan Dia memasukkan ke dalamnya siapa saja yang di kehendaki-Nya. Ketahuilah, bahwa pada zaman Rasulullah shallallahu 'alaihi wasallam aku telah bermimpi, kulihat seakan-akan seorang laki-laki telah menjumpaiku dan berkata kepadaku, 'Berangkatlah! ' Lalu aku berangkat bersamanya dan ia membawaku menelusuri tempat yang terang dan besar, lantas ditampakkan kepadaku jalan yang berada di sisi kiriku, dan aku ingin berjalan mengikuti jalan tersebut. Maka laki-laki yang bersamaku berkata, 'Sesungguhnya kamu bukan termasuk dari golongan mereka.\" Kemudian di tampakkan kepadaku jalan yang berada di sebelah kananku, maka aku berjalan mengikuti jalan tersebut hingga sampailah ke suatu gunung yang tidak dapat ditapaki kaki. Tiba-tiba lelaki itu memegang tanganku lantas mendorongku, dan tak disangka ternyata aku telah berada di puncaknya hingga aku tidak dapat bersandar dan berpegangan. Ternyata ada suatu tiang dari besi di atas puncak tersebut yang terbuat dari emas, maka ia pegang tanganku dan melemparkanku sehingga aku berpegangan pada seutas tali. Lalu dia bertanya, 'Sudahkah kamu berpegangan? ' Aku menjawab, 'Sudah.' Kemudian dia menghempaskan tiang tersebut dan aku pun berpegangan pada tali tersebut.' Orang itu berkata, 'Kemudian aku menceritakannya kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: 'Kamu telah bermimpi dengan mimpi yang baik. Adapun tempat yang terang dan besar itu adalah padang Mahsyar. Sedangkan jalan yang di perlihatkan di sisi kirimu adalah jalan penghuni neraka, dan kamu bukan termasuk dari penghuninya. Sedangkan jalan yang di perlihatkan di sisi kananmu adalah jalan kananmu adalah jalan penghuni surga. Adapun gunung yang tidak dapat ditapaki kaki itu adalah kediaman para syuhada, dan tali yang kamu berpegang padanya adalah Islam. Maka berpeganglah kamu erat-erat sampai ajal menjemputmu.' Oleh sebab itu, aku berharap menjadi penghuni surga.\" Ternyata orang tua itu adalah [Abdullah bin Salam].\""},"3875":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا بُرَيْدَةُ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَال�� رَأَيْتُ فِي الْمَنَامِ أَنِّي أُهَاجِرُ مِنْ مَكَّةَ إِلَى أَرْضٍ بِهَا نَخْلٌ فَذَهَبَ وَهَلِي إِلَى أَنَّهَا يَمَامَةُ أَوْ هَجَرٌ فَإِذَا هِيَ الْمَدِينَةُ يَثْرِبُ وَرَأَيْتُ فِي رُؤْيَايَ هَذِهِ أَنِّي هَزَزْتُ سَيْفًا فَانْقَطَعَ صَدْرُهُ فَإِذَا هُوَ مَا أُصِيبَ مِنْ الْمُؤْمِنِينَ يَوْمَ أُحُدٍ ثُمَّ هَزَزْتُهُ فَعَادَ أَحْسَنَ مَا كَانَ فَإِذَا هُوَ مَا جَاءَ اللَّهُ بِهِ مِنْ الْفَتْحِ وَاجْتِمَاعِ الْمُؤْمِنِينَ وَرَأَيْتُ فِيهَا أَيْضًا بَقَرًا وَاللَّهُ خَيْرٌ فَإِذَا هُمْ النَّفَرُ مِنْ الْمُؤْمِنِينَ يَوْمَ أُحُدٍ وَإِذَا الْخَيْرُ مَا جَاءَ اللَّهُ بِهِ مِنْ الْخَيْرِ بَعْدُ وَثَوَابِ الصِّدْقِ الَّذِي آتَانَا اللَّهُ بِهِ يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Buraidah] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku bermimpi bahwa aku berhijrah dari Makkah ke bumi yang banyak terdapat pohon kurma, maka aku mengira bahwa itu adalah Yamamah atau Hajar, ternyata daerah itu adalah Madinah, Yatsrib. Dan di dalam mimpiku itu, kulihat aku menebaskan pedang namun tengah-tengahnya patah, ternyata itu pertanda musibah yang menimpa kaum mukminin di perang Uhud. Kemudian aku memukulkannya kembali dan dia kembali lebih bagus dari sebelumnya, dan ternyata itu pertanda sesuatu kemenangan yang diberikan oleh Allah dan bersatunya kaum mukminin. Demi Allah, dalam mimpiku tersebut aku juga melihat seekor lembu dan kebaikan yang diberikan Allah, dan ternyata itu pertanda sekelompok orang dari kaum mukminin pada perang Uhud, dan ternyata kebaikan itu adalah semua yang telah dianugerahkan oleh Allah dari kebaikan yang datang setelahnya, sebagai balasan atas kesungguhan yang di anugerahkan oleh Allah pada perang badar.\""},"3876":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ فِي يَدِي سِوَارَيْنِ مِنْ ذَهَبٍ فَنَفَخْتُهُمَا فَأَوَّلْتُهُمَا هَذَيْنِ الْكَذَّابَيْنِ مُسَيْلِمَةَ وَالْعَنْسِيَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya bermimpi bahwa di tanganku terdapat dua gelang dari emas kemudian keduanya aku tiup, aku lalu takwilkan keduanya sebagai dua orang pembohong, yaitu Musailamah dan Al 'Ansi.\""},"3877":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا عَلِيُّ بْنُ صَالِحٍ عَنْ سِمَاكٍ عَنْ قَابُوسَ قَالَ قَالَتْ أُمُّ الْفَضْلِيَا رَسُولَ اللَّهِ رَأَيْتُ كَأَنَّ فِي بَيْتِي عُضْوًا مِنْ أَعْضَائِكَ قَالَ خَيْرًا رَأَيْتِ تَلِدُ فَاطِمَةُ غُلَامًا فَتُرْضِعِيهِ فَوَلَدَتْ حُسَيْنًا أَوْ حَسَنًا فَأَرْضَعَتْهُ بِلَبَنِ قُثَمٍ قَالَتْ فَجِئْتُ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْتُهُ فِي حَجْرِهِ فَبَالَ فَضَرَبْتُ كَتِفَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْجَعْتِ ابْنِي رَحِمَكِ اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Ali bin Shalih] dari [Simak] dari [Qabus] dia berkata; [Ummul Fadll] berkata, \"Wahai Rasulullah, aku bermimpi seakan-akan di dalam rumahku ada anggota tubuh dari tubuhmu.\" Beliau menjawab: \"Itu pertanda baik, kamu akan menyaksikan Fatimah melahirkan seorang anak laki-laki, kemudian kamu yang akan menyusuinya.\" Maka Fatimah melahirkan Husain atau Hasan, dan Ummu Fadll menyusuinya. Dia berkata, \"Maka aku datang membawanya kepada Rasulullah shallallahu 'alaihi wasallam, kemudian aku letakkan di pangkuan beliau, ternyata dia kencing hingga aku pun menepuk pundaknya, Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Kamu telah menyakiti anakku, semoga Allah merahmatimu.\""},"3878":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنِي ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رُؤْيَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ امْرَأَةً سَوْدَاءَ ثَائِرَةَ الرَّأْسِ خَرَجَتْ مِنْ الْمَدِينَةِ حَتَّى قَامَتْ بِالْمَهْيَعَةِ وَهِيَ الْجُحْفَةُ فَأَوَّلْتُهَا وَبَاءً بِالْمَدِينَةِ فَنُقِلَ إِلَى الْجُحْفَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu 'Ashim] telah mengabarkan kepadaku [Ibnu Juraij] telah mengabarkan kepadaku [Musa bin 'Uqbah] telah mengabarkan kepadaku [Salim bin Abdullah] dari [Abdullah bin Umar] mengenai mimpi Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku pernah mimpi melihat seorang perempuan hitam yang tidak memakai penutup kepala keluar dari kota Madinah dan singgah di Al Mahya'ah (daerah dekat Juhfah). Maka aku ta'wilkan bahwa wabah penyakit di Kota Madinah telah dipindahkan ke daerah Juhfah.\""},"3879":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِأَنَّ رَجُلَيْنِ مِنْ بَلِيٍّ قَدِمَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ إِسْلَامُهُمَا جَمِيعًا فَكَانَ أَحَدُهُمَا أَشَدَّ اجْتِهَادًا مِنْ الْآخَرِ فَغَزَا الْمُجْتَهِدُ مِنْهُمَا فَاسْتُشْهِدَ ثُمَّ مَكَثَ الْآخَرُ بَعْدَهُ سَنَةً ثُمَّ تُوُفِّيَ قَالَ طَلْحَةُ فَرَأَيْتُ فِي الْمَنَامِ بَيْنَا أَنَا عِنْدَ بَابِ الْجَنَّةِ إِذَا أَنَا بِهِمَا فَخَرَجَ خَارِجٌ مِنْ الْجَنَّةِ فَأَذِنَ لِلَّذِي تُوُفِّيَ الْآخِرَ مِنْهُمَا ثُمَّ خَرَجَ فَأَذِنَ لِلَّذِي اسْتُشْهِدَ ثُمَّ رَجَعَ إِلَيَّ فَقَالَ ارْجِعْ فَإِنَّكَ لَمْ يَأْنِ لَكَ بَعْدُ فَأَصْبَحَ طَلْحَةُ يُحَدِّثُ بِهِ النَّاسَ فَعَجِبُوا لِذَلِكَ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدَّثُوهُ الْحَدِيثَ فَقَالَ مِنْ أَيِّ ذَلِكَ تَعْجَبُونَ فَقَالُوا يَا رَسُولَ اللَّهِ هَذَا كَانَ أَشَدَّ الرَّجُلَيْنِ اجْتِهَادًا ثُمَّ اسْتُشْهِدَ وَدَخَلَ هَذَا الْآخِرُ الْجَنَّةَ قَبْلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ قَدْ مَكَثَ هَذَا بَعْدَهُ سَنَةً قَالُوا بَلَى قَالَ وَأَدْرَكَ رَمَضَانَ فَصَامَ وَصَلَّى كَذَا وَكَذَا مِنْ سَجْدَةٍ فِي السَّنَةِ قَالُوا بَلَى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا بَيْنَهُمَا أَبْعَدُ مِمَّا بَيْنَ السَّمَاءِ وَالْأَرْضِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim At Taimi] dari [Abu Salamah bin Abdurrahman] dari [Thalhah bin 'Ubaidullah] bahwa dua orang laki-laki dari Baliy datang menemui Rasulullah shallallahu 'alaihi wasallam dan masuk Islam. Salah seorang dari keduanya lebih semangat berjihad dari yang lainnya, kemudian dia pergi berperang sehingga ia menemui syahid. Sedangkan yang satunya lagi masih hidup hingga setahun setelahnya, lalu dia meninggal dunia.\" Thalhah berkata, \"Kemudian aku bermimpi seakan-akan aku berada di pintu surga. Tiba-tiba aku berada di sisi kedua laki-laki tersebut, setelah itu Malaikat keluar dari surga. Malaikat itu kemudian mengizinkan laki-laki yang meninggal dunia belakangan dari keduanya untuk memasukinya, kemudian ia keluar lagi dan mempersilahkan kepada laki-laki yang mati syahid. Lalu malaikat itu kembali kepadaku dan berkata, 'Kembalilah kamu, sebab belum saatnya kamu memperoleh hal ini.' Keesokan harinya Thalhah menceritakannya kepada orang-orang, mereka pun heran. Mereka lalu memberitahukannya kepada Rasulullah shallallahu 'alaihi wasallam dan menceritakan kejadian tersebut. Maka beliau bersabda: \"Perkara yang mana yang membuat kalian heran?\" mereka menjawab, \"Wahai Rasulullah, laki-laki (yang pertama meninggal) adalah orang yang paling bersemangat dalam berjihad dari yang lain, lalu dia mati syahid. Tapi mengapa orang yang lain (laki-laki yang meninggal belakangan) justru masuk surga terlebih dahulu darinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Bukankah orang ini hidup setahun setelahnya?\" mereka menjawab, \"Ya.\" Beliau bersabda: \"Bukankah ia mendapatkan bulan Ramadan dan berpuasa? Ia juga telah mengerjakan shalat ini dan itu dengan beberapa sujud dalam setahun?\" mereka menjawab, \"Ya.\" Rasulullah shallallahu 'alaihi wasallam kembali bersabda: \"Sungguh, sangat jauh perbedaan antara keduanya (dalam kebajikan) bagaikan antara langit dan bumi.\""},"3880":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو بَكْرٍ الْهُذَلِيُّ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْرَهُ الْغِلَّ وَأُحِبُّ الْقَيْدَ الْقَيْدُ ثَبَاتٌ فِي الدِّينِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abu Bakr Al Hudzaili] dari [Ibnu Sirin] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak menyukai Al Ghil (mimpi dengan tangan terikat di tengkuk) dan menyukai Al Qayid (mimpi dengan kedua kaki terikat), karena Qayid adalah keteguhan dalam agama.\""},"3881":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَحَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا عَصَمُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Hafsh bin Ghiiyats] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diperintahkan untuk memerangi manusia sampai mereka mengucapkan 'LAA ILAAHA ILLALLAH'. Jika mereka telah mengucapkannya, maka telah terjaga dariku darah dan harta mereka, kecuali dengan haknya. Dan hisap mereka hanya di tentukan oleh Allah 'azza wajalla.\""},"3882":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوا لَا إِلَهَ إِلَّا اللَّهُ عَصَمُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diperintahkan untuk memerangi manusia sehingga mereka mengucapkan 'LAA ILAAHA ILLALLAH'. Jika mereka telah mengucapkan 'LAA ILAAHA ILLALLAH' maka telah terjaga dariku darah dan harta mereka kecuali haknya, dan hisap mereka atas Allah.\""},"3883":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا حَاتِمُ بْنُ أَبِي صَغِيرَةَ عَنْ النُّعْمَانِ بْنِ سَالِمٍ أَنَّ عَمْرَو بْنَ أَوْسٍ أَخْبَرَهُ أَنَّ أَبَاهُ أَوْسًا أَخْبَرَهُ قَالَإِنَّا لَقُعُودٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُصُّ عَلَيْنَا وَيُذَكِّرُنَا إِذْ أَتَاهُ رَجُلٌ فَسَارَّهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبُوا بِهِ فَاقْتُلُوهُ فَلَمَّا وَلَّى الرَّجُلُ دَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ تَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ نَعَمْ قَالَ اذْهَبُوا فَخَلُّوا سَبِيلَهُ فَإِ��َّمَا أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا فَعَلُوا ذَلِكَ حَرُمَ عَلَيَّ دِمَاؤُهُمْ وَأَمْوَالُهُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Bakr As Sahmi] telah menceritakan kepada kami [Hatim bin Abu Shaghirah] dari [An Nu'man bin Salim] dari ['Amru bin Aus] telah mengabarkan kepadanya ayahnya [Aus], bahwa dia mengabarkan kepadanya, dia berkata, \"Kami pernah duduk-duduk di sisi Nabi shallallahu 'alaihi wasallam, beliau bercerita kepada kami dan memberikan pelajaran kepada kami. Tiba-tiba datanglah seorang laki-laki yang mengintainya, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Tangkaplah ia dan bunuhlah.\" Ketika orang tersebut hendak melarikan diri, Rasulullah shallallahu 'alaihi wasallam memanggilnya dan bertanya: \"Apakah kamu telah bersaksi tidak ada tuhan yang berhak disembah selain Allah?\" dia menjawab, \"Ya.\" Beliau bersabda: \"Pergilah kalian dan lepaskanlah ia, sebab aku telah diperintahkan untuk memerangi manusia sampai mereka mengucapkan 'LAA ILAAHA ILLALLAH'. Jika mereka telah mengucapkannya, maka telah di haramkan bagiku darah dan hartanya mereka.\""},"3884":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَاصِمٍ عَنْ السُّمَيْطِ بْنِ السَّمِيرِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَأَتَى نَافِعُ بْنُ الْأَزْرَقِ وَأَصْحَابُهُ فَقَالُوا هَلَكْتَ يَا عِمْرَانُ قَالَ مَا هَلَكْتُ قَالُوا بَلَى قَالَ مَا الَّذِي أَهْلَكَنِي قَالُوا قَالَ اللَّهُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ وَيَكُونَ الدِّينُ كُلُّهُ لِلَّهِ }قَالَ قَدْ قَاتَلْنَاهُمْ حَتَّى نَفَيْنَاهُمْ فَكَانَ الدِّينُ كُلُّهُ لِلَّهِ إِنْ شِئْتُمْ حَدَّثْتُكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَأَنْتَ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ بَعَثَ جَيْشًا مِنْ الْمُسْلِمِينَ إِلَى الْمُشْرِكِينَ فَلَمَّا لَقُوهُمْ قَاتَلُوهُمْ قِتَالًا شَدِيدًا فَمَنَحُوهُمْ أَكْتَافَهُمْ فَحَمَلَ رَجُلٌ مِنْ لُحْمَتِي عَلَى رَجُلٍ مِنْ الْمُشْرِكِينَ بِالرُّمْحِ فَلَمَّا غَشِيَهُ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ إِنِّي مُسْلِمٌ فَطَعَنَهُ فَقَتَلَهُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكْتُ قَالَ وَمَا الَّذِي صَنَعْتَ مَرَّةً أَوْ مَرَّتَيْنِ فَأَخْبَرَهُ بِالَّذِي صَنَعَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا شَقَقْتَ عَنْ بَطْنِهِ فَعَلِمْتَ مَا فِي قَلْبِهِ قَالَ يَا رَسُولَ اللَّهِ لَوْ شَقَقْتُ بَطْنَهُ لَكُنْتُ أَعْلَمُ مَا فِي قَلْبِهِ قَالَ فَلَا أَنْتَ قَبِلْتَ مَا تَكَلَّمَ بِهِ وَلَا أَنْتَ تَعْلَمُ مَا فِي قَلْبِهِ قَالَ فَسَكَتَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَلْبَثْ إِلَّا يَسِيرًا حَتَّى مَاتَ فَدَفَنَّاهُ فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَقَالُوا لَعَلَّ عَدُوًّا نَبَشَهُ فَدَفَنَّاهُ ثُمَّ أَمَرْنَا غِلْمَانَنَا يَحْرُسُونَهُ فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَقُلْنَا لَعَلَّ الْغِلْمَانَ نَعَسُوا فَدَفَنَّاهُ ثُمَّ حَرَسْنَاهُ بِأَنْفُسِنَا فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَأَلْقَيْنَاهُ فِي بَعْضِ تِلْكَ الشِّعَابِحَدَّثَنَا إِسْمَعِيلُ بْنُ حَفْصٍ الْأَيْلِيُّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَاصِمٍ عَنْ السُّمَيْطِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَ بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَحَمَلَ رَجُلٌ مِنْ الْمُسْلِمِينَ عَلَى رَجُلٍ مِنْ الْمُشْرِكِينَ فَذَكَرَ الْحَدِيثَ وَزَادَ فِيهِ فَنَبَذَتْهُ الْأَرْضُ فَأُخْبِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّ الْأَرْضَ لَتَقْبَلُ مَنْ هُوَ شَرٌّ مِنْهُ وَلَكِنَّ اللَّهَ أَحَبَّ أَنْ يُرِيَكُمْ تَعْظِيمَ حُرْمَةِ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari ['Ashim] dari [As Sumaith bin As Samir] dari ['Imran bin Al Hushin] dia berkata, \"Nafi' bin Al Azraq bersama para sahabatnya, mereka berkata, \"Celaka kamu wahai 'Imran! \" Imran pun bertanya, \"Aku celaka! \" mereka menjawab, \"Ya.\" Imran bertanya lagi, \"Apa yang mencelakakanku?\" mereka menjawab, \"Allah telah berfirman '(dan perangilah mereka sehingga tidak ada fitnah dan yang ada hanya agama milik Allah saja) ' (Qs. Al Anfal: 39). Imran berkata, \"Kami telah memerangi mereka dan memberangusnya, sehingga din ini hanya milik Allah saja. Kalau kalian kehendaki, aku akan ceritakan kepada kalian suatu hadits yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam.\" Mereka berkata, \"Dan kamu (benar-benar) mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?.\" Imran menjawab, \"Ya. Aku menyaksikan Rasulullah shallallahu 'alaihi wasallam mengutus pasukan kaum muslimin untuk menyerang kaum musyrikin, tatkala mereka bertemu musuh, mereka pun memeranginya dengan pertempuran sengit hingga berhasil mengalahkan musuh. Lalu salah seorang dari familiku dapat menodong seorang dari kaum musyrikin dengan tombak, ketika saudaraku mendatanginya ia berkata, \"Aku bersaksi bahwa tidak ada tuhan yang berhak disembah selain Allah, aku adalah seorang muslim.\" Tetapi familiku itu tetap menikamnya sehingga ia mati. Kemudian saudaraku datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Celaka aku wahai Rasulullah! \" Beliau bertanya sekali atau dua kali: \"Apa yang telah kamu lakukan?\" Dia memberitahukan kepada beliau apa yang dia perbuat. Rasulullah shallallahu 'alaihi wasallam pun bersabda kepadanya: \"Apakah kamu harus membelah perutnya sehingga kamu dapat mengetahui apa yang ada di dalam hatinya?\" Dia menjawab, \"Ya Rasulullah, kalau seandainya aku (memang harus) membelah perutnya niscaya aku mengetahui apa yang ada di dalam hatinya.\" Beliau bertanya: \"Lalu kenapa kamu tidak terima apa yang dia ucapkan sedang kamu tidak mengetahui apa yang ada dalam hatinya?\" 'Imran berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam mendiamkannya. Dan tidak lama kemudian, orang itu pun meninggal dunia. Maka kami menguburkannya. Di pagi harinya (jenazahnya) telah berada di atas permukaan tanah. Mereka berkata, \"Jangan-jangan ada musuh yang sengaja mengeluarkannya.\" Maka kami menguburnya kemudian memerintahkan kepada budak-budak kami untuk menjaganya, tetapi (jenazahnya) kembali berada di atas permukaan tanah. Maka kami berkata, \"Jangan-jangan budak-budak itu telah ngantuk.\" Kemudian kami menjaganya sendiri tetapi (jenazahnya) tetap berada di atas permukaan tanah sehingga kami melemparkannya di celah yang terletak di antara dua bukit.\" Telah menceritakan kepada kami [Isma'il bin Hafsh Al Aili] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari ['Ashim] dari [As Sumaith] dari ['Imran bin AL Hushain] dia berkata, 'Rasulullah shallallahu 'alaihi wasallam mengutus kami di suatu ekspedisi. Kemudian ada seorang dari kaum muslimin menyerang seseorang dari kaum musyrikin…. Kemudian perawi menyebutkan hadits seperti yang di atas, dan dia menambahkan di dalam haditsnya, \"Tetapi bumi membuangnya (mengeluarkannya), kemudian kejadian itu diberitahukan kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Sesungguhnya bumi menerima orang yang lebih buruk dari dia, tetapi Allah ingin memperlihatkan kepada kalian pengagungan terhadap kehormatan kalimat Laa Ilaaha Illallah.\""},"3885":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ أَلَا إِنَّ أَحْرَمَ الْأَيَّامِ يَوْمُكُمْ هَذَا أَلَا وَإِنَّ أَحْرَمَ الشُّهُورِ شَهْرُكُمْ هَذَا أَلَا وَإِنَّ أَحْرَمَ الْبَلَدِ بَلَدُكُمْ هَذَا أَلَا وَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا هَلْ بَلَّغْتُ قَالُوا نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] dia berkata, \"Ketika haji Wada' Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Ketahuilah, sebaik-baik (dihormati) hari adalah hari kalian ini. Ketahuilah, sebaik-baik (dihormati) bulan adalah bulan kalian ini. Ketahuilah, bahwa negeri yang paling dihormati dari negeri-negeri adalah negeri kalian ini. Ketahuilah, bahwa darah dan harta kalian adalah haram bagi kalian sebagaimana kehormatan hari kalian ini, dibulan kalian ini dan di negeri kalian ini. Ketahuilah, apakah aku telah menyampaikan?\" Mereka menjawab, \"Ya.\" Beliau bersabda: \"Ya Allah, saksikanlah.\""},"3886":{"ar":"حَدَّثَنَا أَبُو الْقَاسِمِ بْنُ أَبِي ضَمْرَةَ نَصْرُ بْنُ مُحَمَّدِ بْنِ سُلَيْمَانَ الْحِمْصِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي قَيْسٍ النَّصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَطُوفُ بِالْكَعْبَةِ وَيَقُولُ مَا أَطْيَبَكِ وَأَطْيَبَ رِيحَكِ مَا أَعْظَمَكِ وَأَعْظَمَ حُرْمَتَكِ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَحُرْمَةُ الْمُؤْمِنِ أَعْظَمُ عِنْدَ اللَّهِ حُرْمَةً مِنْكِ مَالِهِ وَدَمِهِ وَأَنْ نَظُنَّ بِهِ إِلَّا خَيْرًا","id":"Telah menceritakan kepada kami [Abu Al Qasim bin Abu Dlamrah Nashr bin Muhammad bin Sulaiman Al Himshi] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Abdullah bin Abu Qais An Nashr] telah menceritakan kepada kami [Abbdullah bin Umar] dia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam thawaf di Ka'bah sambil mengucapkan: \"Alangkah indahnya kamu, alangkah harumnya baumu, alangkah agungnya dirimu dan alangkah agungnya kehormatanmu. Demi Dzat yang jiwa Muhammad berada di tangan-Nya, sungguh kehormatan seorang mukmin, hartanya, darahnya itu lebih agung di sisi Allah darimu, dan kami tidak berprasangka kepadanya kecuali dengan baik.\""},"3887":{"ar":"حَدَّثَنَا بَكْرُ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ وَيُونُسُ بْنُ يَحْيَى جَمِيعًا عَنْ دَاوُدَ بْنِ قَيْسٍ عَنْ أَبِي سَعِيدٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ كُرَيْزٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ الْمُسْلِمِ عَلَى الْمُسْلِمِ حَرَامٌ دَمُهُ وَمَالُهُ وَعِرْضُهُ","id":"Telah menceritakan kepada kami [Bakr bin Abdul Wahhab] telah menceritakan kepada kami [Abdullah bin Nafi'] dan [Yunus bin Yahya] semuanya dari [Daud bin Qais] dari [Abu Sa'id] bekas budak Abdullah bin 'Amir bin Kuraiz dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap muslim atas muslim yang lain haram darahnya, hartanya dan kehormatannya.\""},"3888":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ أَبِي هَانِئٍ عَنْ عَمْرِو بْنِ مَالِكٍ الْجَنْبِيِّ أَنَّ فَضَالَةَ بْنَ عُبَيْدٍ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ مَنْ أَمِنَهُ النَّاسُ عَلَى أَمْوَالِهِمْ وَأَنْفُسِهِمْ وَالْمُهَاجِرُ مَنْ هَجَرَ الْخَطَايَا وَالذُّنُوبَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Amru bin As Sarh Al Mishri] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Abu Hani`] dari ['Amru bin Malik Al Janbi] bahwa [Fadlalah bin 'Ubaid] telah menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin adalah orang yang membuat orang lain merasa aman atas harta dan jiwa mereka. Dan seorang yang berhijrah adalah orang yang meninggalkan kesalahan dan perbuatan dosa.\""},"3889":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ انْتَهَبَ نُهْبَةً مَشْهُورَةً فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Abu Ashim] telah menceritakan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir bin Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa merampas harta orang lain dengan cara paksa, maka dia bukan dari golongan kami.\""},"3890":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَنْتَهِبُ نُهْبَةً يَرْفَعُ النَّاسُ إِلَيْهِ أَبْصَارَهُمْ حِينَ يَنْتَهِبُهَا وَهُوَ مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Isa bin Hammad] telah memberitakan kepada kami [Al Laits bin Sa'd] dari ['Uqail] dari [Ibnu Syihab] dari [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak disebut beriman orang yang berzina saat melakukannya, tidak disebut mukmin orang yang minum khamer saat melakukannya, tidak disebut mukmin orang yang mencuri saat melakukannya. Dan tidaklah orang yang merampas harta orang lain hingga membuat pandangan orang tertuju padanya disebut sebagai mukmin saat melakukannya.\""},"3891":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حُمَيْدٌ حَدَّثَنَا الْحَسَنُ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ انْتَهَبَ نُهْبَةً فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Humaid] telah menceritakan kepada kami [Al Hasan] dari ['Imran bin Al Hushain], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa merampas (harta orang lain) bukanlah dari golongan kami.\""},"3892":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ ثَعْلَبَةَ بْنِ الْحَكَمِ قَالَأَصَبْنَا غَنَمًا لِلْعَدُوِّ فَانْتَهَبْنَاهَا فَنَصَبْنَا قُدُورَنَا فَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقُدُورِ فَأَمَرَ بِهَا فَأُكْفِئَتْ ثُمَّ قَالَ إِنَّ النُّهْبَةَ لَا تَحِلُّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari [Tsa'labah bin Al Hakam] dia berkata, \"Kami mendapati kambing milik musuh lalu merampasnya, kemudian kami meletakkannya di periuk-periuk kami. Ketika Rasulullah shallallahu 'alaihi wasallam melewati periuk-periuk itu, beliau memerintahkan untuk menumpahkannya, maka seluruh isinya ditumpahkan. Beliau kemudian bersabda: \"Sesungguhnya barang rampasan itu tidak halal.\""},"3893":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ ابْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Ibnu Mas'ud] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mencela orang muslim adalah kefasikan, dan membunuhnya adalah kekufuran.\""},"3894":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْحَسَنِ الْأَسْدِيُّ حَدَّثَنَا أَبُو هِلَالٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Al Hasan Al Asdi] telah menceritakan kepada kami [Abu Hilal] dari [Ibnu Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Mencaci orang muslim adalah kefasikan dan memeranginya adalah kekufuran.\""},"3895":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ أَبِي إِسْحَقَ عَنْ مُحَمَّدِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Abu Ishaq] dari [Muhammad bin Sa'd] dari [Sa'ad], dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mencaci orang muslim adalah kefasikan dan memeranginya adalah kekufuran.\""},"3896":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَعْبَدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ قَالَ سَمِعْتُ أَبَا زُرْعَةَ بْنَ عَمْرِو بْنِ جَرِيرٍ يُحَدِّثُ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي حَجَّةِ الْوَدَاعِ اسْتَنْصِتْ النَّاسَ فَقَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Ali bin Mudrik] dia berkata; saya mendengar [Abu Zur'ah bin 'Amru bin Jarir] menceritakan dari [Jarir bin Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda ketika haji Wada': \"Dengarkanlah wahai manusia.\" Kemudian beliau bersabda: \"Janganlah kalian kembali kepada kekafiran sepeninggalku dengan saling memerangi antara sesama kalian.\""},"3897":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ أَخْبَرَنِي عُمَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيْحَكُمْ أَوْ وَيْلَكُمْ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Al Walid bin Muslim] telah mengabarkan kepadaku [Umar bin Muhammad] dari [Ayahnya] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celakalah kalian -atau binasalah kalian-, janganlah kalian kembali kepada kekufuran sepeninggalku, yaitu dengan saling berperang di antara kalian.\""},"3898":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَمُحَمَّدُ بْنُ بِشْرٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ عَنْ قَيْسٍ عَنْ الصُّنَابِحِ الْأَحْمَسِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا إِنِّي فَرَطُكُمْ عَلَى الْحَوْضِ وَإِنِّي مُكَاثِرٌ بِكُمْ الْأُمَمَ فَلَا تَقَتِّلُنَّ بَعْدِي","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ayahku] dan [Muhammad bin Bisyr] keduanya berkata; telah menceritakan kepada kami [Isma'il] dair [Qais] dari [As Shunabih Al Ahmas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, sesungguhnya aku menunggu kalian di telaga surga, dan di jadikan untukku pengikut yang sangat banyak dari kalian, maka janganlah kalian saling memerangi sepeninggalku.\""},"3899":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ الْوَهْبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ الْمَاجِشُونُ عَنْ عَبْدِ الْوَاحِدِ بْنِ أَبِي عَوْنٍ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ حَابِسٍ الْيَمَانِيِّ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى الصُّبْحَ فَهُوَ فِي ذِمَّةِ اللَّهِ فَلَا تُخْفِرُوا اللَّهَ فِي عَهْدِهِ فَمَنْ قَتَلَهُ طَلَبَهُ اللَّهُ حَتَّى يَكُبَّهُ فِي النَّارِ عَلَى وَجْهِهِ","id":"Telah menceritakan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] telah menceritakan kepada kami [Ahmad bin Khalid Al Wahbi] telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah Al Majisyun] dari [Abdul Wahid bin Abu 'Aun] dari [Sa'd bin Ibrahim] dari [Habis Al Yamani] dari [Abu Bakr As Shidiq] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menunaikan shalat shubuh maka dia berada di bawah perlindungan Allah, oleh karena itu janganlah kalian melanggar perjanjian Allah. Barangsiapa membunuhnya, maka Allah akan menuntutnya sehingga melemparkan wajahnya ke dalam neraka.\""},"3900":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا أَشْعَثُ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى الصُّبْحَ فَهُوَ فِي ذِمَّةِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Asy'ats] dari [Al Hasan] dari [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa melaksanakan shalat subuh, maka ia berada dalam tanggungan Allah 'azza wajalla.\" "},"3901":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو الْمُهَزِّمِ يَزِيدُ بْنُ سُفْيَانَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ أَكْرَمُ عَلَى اللَّهِ عَزَّ وَجَلَّ مِنْ بَعْضِ مَلَائِكَتِهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Abu Al Muhazzam Yazid bin Sufyan] saya mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin itu lebih mulia bagi Allah daripada sebagian dari malaikat.\""},"3902":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا أَيُّوبُ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ زِيَادِ بْنِ رِيَاحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَاتَلَ تَحْتَ رَايَةٍ عِمِّيَّةٍ يَدْعُو إِلَى عَصَبِيَّةٍ أَوْ يَغْضَبُ لِعَصَبِيَّةٍ فَقِتْلَتُهُ جَاهِلِيَّةٌ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal As Shawaf] telah menceritakan kepada kami [Abdul Warits bin Sa'id] telah menceritakan kepada kami [Ayyub] dari [Ghailan bin Jarir] dari [Ziyad bin Riyyah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berperang di bawah bendera kefanatikan dan menyeru kepada fanatisme, atau marah karena fanatisme, maka matinya menyerupai mati jahiliyyah.\""},"3903":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زِيَادُ بْنُ الرَّبِيعِ الْيُحْمِدِيُّ عَنْ عَبَّادِ بْنِ كَثِيرٍ الشَّامِيِّ عَنْ امْرَأَةٍ مِنْهُمْ يُقَالُ لَهَا فُسَيْلَةُ قَالَتْ سَمِعْتُ أَبِي يَقُولُسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَمِنَ الْعَصَبِيَّةِ أَنْ يُحِبَّ الرَّجُلُ قَوْمَهُ قَالَ لَا وَلَكِنْ مِنْ الْعَصَبِيَّةِ أَنْ يُعِينَ الرَّجُلُ قَوْمَهُ عَلَى الظُّلْمِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ziyad bin Ar Rabi' Al Yuhmidi] dari ['Abbad bin Katsir As Syami] dari seorang wanita yang disebut dengan [Fusailah] ia berkata, \"Aku mendengar [Ayahku] berkata, \"Aku bertanya kepada Nabi shallallahu 'alaihi wasallam, 'Wahai Rasulullah, apakah termasuk dari ashabiyah (fanatik golongan) apabila ada seseorang yang mencintai kaumnya? ' Beliau menjawab: \"Bukan, akan tetapi yang termasuk ashabiyah adalah seseorang menolong kaumnya atas dasar kezhaliman.\""},"3904":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مُعَانُ بْنُ رِفَاعَةَ السَّلَامِيُّ حَدَّثَنِي أَبُو خَلَفٍ الْأَعْمَى قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أُمَّتِي لَا تَجْتَمِعُ عَلَى ضَلَالَةٍ فَإِذَا رَأَيْتُمْ اخْتِلَافًا فَعَلَيْكُمْ بِالسَّوَادِ الْأَعْظَمِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin 'Utsman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ma'an bin Rifa'ah As Salami] telah menceritakan kepadaku [Abu Khalaf Al A'ma] dia berkata; aku mendengar [Anas bin Malik] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya umatku tidak akan bersatu di atas kesesatan, apabila kalian melihat perselisihan maka kalian harus berada di sawadul a'dzam (kelompok yang terbanyak; maksudnya yang sesuai sunnah).\""},"3905":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ رَجَاءٍ الْأَنْصَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادِ بْنِ الْهَادِ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا صَلَاةً فَأَطَالَ فِيهَا فَلَمَّا انْصَرَفَ قُلْنَا أَوْ قَالُوا يَا رَسُولَ اللَّهِ أَطَلْتَ الْيَوْمَ الصَّلَاةَ قَالَ إِنِّي صَلَّيْتُ صَلَاةَ رَغْبَةٍ وَرَهْبَةٍ سَأَلْتُ اللَّهَ عَزَّ وَجَلَّ لِأُمَّتِي ثَلَاثًا فَأَعْطَانِي اثْنَتَيْنِ وَرَدَّ عَلَيَّ وَاحِدَةً سَأَلْتُهُ أَنْ لَا يُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ غَيْرِهِمْ فَأَعْطَانِيهَا وَسَأَلْتُهُ أَنْ لَا يُهْلِكَهُمْ غَرَقًا فَأَعْطَانِيهَا وَسَأَلْتُهُ أَنْ لَا يَجْعَلَ بَأْسَهُمْ بَيْنَهُمْ فَرَدَّهَا عَلَيَّ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Raja` Al Anshari] dari [Abdullah bin Syaddad bin Al Hadi] dari [Mu'adz bin Jabal] dia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan shalat dengan memanjangkan do'anya, setelah selesai shalat kami bertanya -atau mereka berkata-, \"Wahai Rasulullah, (mengapa) hari ini anda memanjangkan shalat?\" beliau menjawab: \"Sesungguhnya aku telah berdo'a dengan penuh rasa harap dan kekhawatir, saya memohon kepada Allah 'azza wajalla untuk ummatku tiga perkara, namun Dia hanya mengabulkan dua perkara untukku dan menolak satu perkara. Aku memohon kepada-Nya agar mereka tidak dibinasakan musuh dan Dia mengabulkannya. Kemudian aku meminta agar Allah tidak mencelakan mereka dengan ditenggelamkan dan Dia juga mengabulkan permintaanku. Dan aku juga memohon kepada-Nya supaya tidak menjadikan mereka saling bermusuhan sesama mereka, namun Allah mengembalikannya kepadaku (menolaknya).\""},"3906":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبِ بْنِ شَابُورَ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ أَنَّهُ حَدَّثَهُمْ عَنْ أَبِي قِلَابَةَ الْجَرْمِيِّ عَبْدِ اللَّهِ بْنِ زَيْدٍ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ زُوِيَتْ لِي الْأَرْضُ حَتَّى رَأَيْتُ مَشَارِقَهَا وَمَغَارِبَهَا وَأُعْطِيتُ الْكَنْزَيْنِ الْأَصْفَرَ أَوْ الْأَحْمَرَ وَالْأَبْيَضَ يَعْنِي الذَّهَبَ وَالْفِضَّةَ وَقِيلَ لِي إِنَّ مُلْكَكَ إِلَى حَيْثُ زُوِيَ لَكَ وَإِنِّي سَأَلْتُ اللَّهَ عَزَّ وَجَلَّ ثَلَاثًا أَنْ لَا يُسَلِّطَ عَلَى أُمَّتِي جُوعًا فَيُهْلِكَهُمْ بِهِ عَامَّةً وَأَنْ لَا يَلْبِسَهُمْ شِيَعًا وَيُذِيقَ بَعْضَهُمْ بَأْسَ بَعْضٍ وَإِنَّهُ قِيلَ لِي إِذَا قَضَيْتُ قَضَاءً فَلَا مَرَدَّ لَهُ وَإِنِّي لَنْ أُسَلِّطَ عَلَى أُمَّتِكَ جُوعًا فَيُهْلِكَهُمْ فِيهِ وَلَنْ أَجْمَعَ عَلَيْهِمْ مِنْ بَيْنَ أَقْطَارِهَا حَتَّى يُفْنِيَ بَعْضُهُمْ بَعْضًا وَيَقْتُلَ بَعْضُهُمْ بَعْضًا وَإِذَا وُضِعَ السَّيْفُ فِي أُمَّتِي فَلَنْ يُرْفَعَ عَنْهُمْ إِلَى يَوْمِ الْقِيَامَةِ وَإِنَّ مِمَّا أَتَخَوَّفُ عَلَى أُمَّتِي أَئِمَّةً مُضِلِّينَ وَسَتَعْبُدُ قَبَائِلُ مِنْ أُمَّتِي الْأَوْثَانَ وَسَتَلْحَقُ قَبَائِلُ مِنْ أُمَّتِي بِالْمُشْرِكِينَ وَإِنَّ بَيْنَ يَدَيْ السَّاعَةِ دَجَّالِينَ كَذَّابِينَ قَرِيبًا مِنْ ثَلَاثِينَ كُلُّهُمْ يَزْعُمُ أَنَّهُ نَبِيٌّ وَلَنْ تَزَالَ طَائِفَةٌ مِنْ أُمَّتِي عَلَى الْحَقِّ مَنْصُورِينَ لَا يَضُرُّهُمْ مَنْ خَالَفَهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ عَزَّ وَجَلَّقَالَ أَبُو الْحَسَنِ لَمَّا فَرَغَ أَبُو عَبْدِ اللَّهِ مِنْ هَذَا الْحَدِيثِ قَالَ مَا أَهْوَلَهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Muhammad bin Syu'aib bin Syabur] telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] dia menceritakan kepada mereka dari [Abu Qilabah Al Jarmi Abdullah bin Zaid] dari [Abu Asma Ar Rahabi] dari [Tsauban] mantan budak Rasulullah shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bumi disatukan bagiku sehingga saya dapat melihat sisi timur dan baratnya. Dan aku telah diberi dua perbendaharaan yang sangat berharga; yang kuning -atau merah- dan putih, yaitu emas dan perak. Kemudian dikatakan kepadaku, 'Sesungguhnya kerajaanmu seperti yang telah di satukan untukmu'. Dan aku memohon kepada Allah 'azza wajalla tiga perkara; supaya tidak menimpakan atas ummatku kelaparan sehingga akan membinasakan mereka, tidak mencampurkan mereka dalam golongan yang saling bertentangan dan merasakan keganasan antara yang satu dengan goliongan yang lain. Sesungguhnya telah difirmankan kepadaku: \"Jika Aku telah menentukan sesuatu, niscaya tidak akan ada yang dapat menolaknya, dan sesungguhnya Aku tidak akan menimpakan atas ummatmu kelaparan yang menyebabkan mereka binasa, dan tidak akan Aku campurkan mereka dari segala penjuru, sehingga sebagian dari mereka menumpas sebagian lainnya, dan mereka pun akan saling memerangi antara mereka.' Dan jika telah diperintahkan kepada ummatku untuk mengangkat pedang, maka tidak akan dicabut kembali sampai datangnya hari Kiamat. Dan di antara yang saya khawatirkan atas ummatku adalah para pemimpin yang menyesatkan, dan akan ada sebagian dari ummatku kelak yang menyembah berhala. Sebagian dari ummatku akan ada yang bergabung dengan kaum Musyrikin. Sesungguhnya di antara tanda-tanda hari Kiamat adalah munculnya para Dajjal pendusta, jumlah mereka hampir mencapai tiga puluh orang dan mereka semua akan mendakwakan dirinya seorang Nabi. Dan akan senantiasa ada dari umatku sekelompok orang yang berpegang terhadap kebenaran, mereka akan senantiasa mendapatkan pertolongan, dan tidak akan dapat di kalahkan oleh orang-orang yang menentangnya sampai tiba ketentuan Allah 'azza wajalla.\" Abu Al Hasan berkata, \"Ketika Abu Abdullah selesai membacakan hadits ini, ia berkata, 'Sungguh sangat mengerikannya perkara ini'.\""},"3907":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ زَيْنَبَ ابْنَةِ أُمِّ سَلَمَةَ عَنْ حَبِيبَةَ عَنْ أُمِّ حَبِيبَةَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ أَنَّهَا قَالَتْاسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نَوْمِهِ وَهُوَ مُحْمَرٌّ وَجْهُهُ وَهُوَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ وَعَقَدَ بِيَدَيْهِ عَشَرَةً قَالَتْ زَيْنَبُ قُلْتُ يَا رَسُولَ اللَّهِ أَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ إِذَا كَثُرَ الْخَبَثُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Urwah] dari [Zainab] puterinya Ummu Salamah, dari [Habibah] dari [Ummu Habibah] dari [Zainab binti Jahsy] bahwa dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bangun dari tidurnya dengan wajah memerah, lalu beliau bersabda: \"Laa ilaaha illallah, sungguh celaka bangsa Arab dari kehancuran yang akan segera tiba. Hari ini telah dibuka pintu keluarnya Ya'juj dan Ma'juj.\" Beliau mengepalkan kesepuluh jari tangannya.\" Zainab berkata, \"Aku bertanya, \"Apakah kita akan celaka wahai Rasulullah, sedangkan di antara kita masih terdapat orang-orang shalih?\" beliau menjawab: \"Ya, apabila kekejian telah menyebar luas.\""},"3908":{"ar":"حَدَّثَنَا رَاشِدُ بْنُ سَعِيدٍ الرَّمْلِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْوَلِيدِ بْنِ سُلَيْمَانَ بْنِ أَبِي السَّائِبِ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَكُونُ فِتَنٌ يُصْبِحُ الرَّجُلُ فِيهَا مُؤْمِنًا وَيُمْسِي كَافِرًا إِلَّا مَنْ أَحْيَاهُ اللَّهُ بِالْعِلْمِ","id":"Telah menceritakan kepada kami [Rasyid bin Sa'id Ar Ramli] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Walid bin Sulaiman bin Abu As Sa`ib] dari [Ali bin Yazid] dari [Al Qasim Abu Abdurrahman] dari [Abu Umamah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan muncul berbagai fitnah, di pagi hari seseorang dalam keadaan mukmin lalu kafir di sore harinya, kecuali orang yang dihidupkan Allah dengan ilmu.\""},"3909":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَأَبِي عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ حُذَيْفَةَ قَالَكُنَّا جُلُوسًا عِنْدَ عُمَرَ فَقَالَ أَيُّكُمْ يَحْفَظُ حَدِيثَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْفِتْنَةِ قَالَ حُذَيْفَةُ فَقُلْتُ أَنَا قَالَ إِنَّكَ لَجَرِيءٌ قَالَ كَيْفَ قَالَ سَمِعْتُهُ يَقُولُ فِتْنَةُ الرَّجُلِ فِي أَهْلِهِ وَوَلَدِهِ وَجَارِهِ تُكَفِّرُهَا الصَّلَاةُ وَالصِّيَامُ وَالصَّدَقَةُ وَالْأَمْرُ بِالْمَعْرُوفِ وَالنَّهْيُ عَنْ الْمُنْكَرِ فَقَالَ عُمَرُ لَيْسَ هَذَا أُرِيدُ إِنَّمَا أُرِيدُ الَّتِي تَمُوجُ كَمَوْجِ الْبَحْرِ فَقَالَ مَا لَكَ وَلَهَا يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ بَيْنَكَ وَبَيْنَهَا بَابًا مُغْلَقًا قَالَ فَيُكْسَرُ الْبَابُ أَوْ يُفْتَحُ قَالَ لَا بَلْ يُكْسَرُ قَالَ ذَاكَ أَجْدَرُ أَنْ لَا يُغْلَقَقُلْنَا لِحُذَيْفَةَ أَكَانَ عُمَرُ يَعْلَمُ مَنْ الْبَابُ قَالَ نَعَمْ كَمَا يَعْلَمُ أَنَّ دُونَ غَدٍ اللَّيْلَةَ إِنِّي حَدَّثْتُهُ حَدِيثًا لَيْسَ بِالْأَغَالِيطِ فَهِبْنَا أَنْ نَسْأَلَهُ مَنْ الْبَابُ فَقُلْنَا لِمَسْرُوقٍ سَلْهُ فَسَأَلَهُ فَقَالَ عُمَرُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Abu Mu'wiyah] dan [Ayahku] dari [Al A'masy] dari [Syaqiq] dari [Hudzaifah] dia berkata, \"Kami pernah duduk bermajlis di sisi Umar, lalu ia berkata, \"Siapakah di antara kalian yang masih hafal hadits Rasulullah shallallahu 'alaihi wasallam tentang fitnah?\" aku menjawab, \"Aku.\" Lantas Umar berkata, \"Sesungguhnya kamu adalah seorang yang sangat pemberani.\" Umar melanjutkan, \"Bagaimana dengan hadits tersebut?\" Hudzaifah berkata, \"Aku pernah mendengar belaiu bersabda: \"Fitnah seorang laki-laki yang berasal dari isteri, anak dan tetangganya dapat terhapuskan dengan shalat, puasa, sedekah dan Amar Ma'ruf nahi munkar.\" Umar berkata, \"Bukan hadits ini yang kumaksud! tetapi fitnah yang kumaksudkan adalah yang bergemuruh laksana gemuruh ombak di lautan.\" Hudzaifah berkata, \"Apa hubungannya dirimu dengan fitnah tersebut wahai Amirul mukminin? Sepertinya dirimu dengan fitnah tersebut terdapat pintu yang terkunci.\" Umar bertanya, \"Apakah pintu itu dapat di rusak atau di buka?\" Hudzaifah menjawab, \"Tidak, namun harus di rusak.\" Umar berkata, \"Hal itu supaya tidak dapat ditutup kembali.\" Kami lalu bertanya kepada Hudzaifah, \"Apakah Umar tahu siapakah yang di maksud dengan pintu?\" Hudzaifah menjawab, \"Ya, seperti halnya ia mengetaui bahwa setelah esok hari pasti datang malam hari. Sebab aku telah menceritakan kepadanya hadits yang tidak terdapat kesalahan dan kedustaan.\" Kami ingin sekali bertanya siapakah pintuk itu? lalu kami katakan kepada Masruq, \"Tanyakanlah padanya.\" Hudzaifah lalu menjawab, \"Yaitu Umar sendiri.\""},"3910":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَعَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ قَالَانْتَهَيْتُ إِلَى عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ وَهُوَ جَالِسٌ فِي ظِلِّ الْكَعْبَةِ وَالنَّاسُ مُجْتَمِعُونَ عَلَيْهِ فَسَمِعْتُهُ يَقُولُ بَيْنَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ إِذْ نَزَلَ مَنْزِلًا فَمِنَّا مَنْ يَضْرِبُ خِبَاءَهُ وَمِنَّا مَنْ يَنْتَضِلُ وَمِنَّا مَنْ هُوَ فِي جَشَرِهِ إِذْ نَادَى مُنَادِيهِ الصَّلَاةُ جَامِعَةٌ فَاجْتَمَعْنَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَنَا فَقَالَ إِنَّهُ لَمْ يَكُنْ نَبِيٌّ قَبْلِي إِلَّا كَانَ حَقًّا عَلَيْهِ أَنْ يَدُلَّ أُمَّتَهُ عَلَى مَا يَعْلَمُهُ خَيْرًا لَهُمْ وَيُنْذِرَهُمْ مَا يَعْلَمُهُ شَرًّا لَهُمْ وَإِنَّ أُمَّتَكُمْ هَذِهِ جُعِلَتْ عَافِيَتُهَا فِي أَوَّلِهَا وَإِنَّ آخِرَهُمْ يُصِيبُهُمْ بَلَاءٌ وَأُمُورٌ يُنْكِرُونَهَا ثُمَّ تَجِيءُ فِتَنٌ يُرَقِّقُ بَعْضُهَا بَعْضًا فَيَقُولُ الْمُؤْمِنُ هَذِهِ مُهْلِكَتِي ثُمَّ تَنْكَشِفُ ثُمَّ تَجِيءُ فِتْنَةٌ فَيَقُولُ الْمُؤْمِنُ هَذِهِ مُهْلِكَتِي ثُمَّ تَنْكَشِفُ فَمَنْ سَرَّهُ أَنْ يُزَحْزَحَ عَنْ النَّارِ وَيُدْخَلَ الْجَنَّةَ فَلْتُدْرِكْهُ مَوْتَتُهُ وَهُوَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَلْيَأْتِ إِلَى النَّاسِ الَّذِي يُحِبُّ أَنْ يَأْتُوا إِلَيْهِ وَمَنْ بَايَعَ إِمَامًا فَأَعْطَاهُ صَفْقَةَ يَمِينِهِ وَثَمَرَةَ قَلْبِهِ فَلْيُطِعْهُ مَا اسْتَطَاعَ فَإِنْ جَاءَ آخَرُ يُنَازِعُهُ فَاضْرِبُوا عُنُقَ الْآخَرِقَالَ فَأَدْخَلْتُ رَأْسِي مِنْ بَيْنِ النَّاسِ فَقُلْتُ أَنْشُدُكَ اللَّهَ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَشَارَ بِيَدِهِ إِلَى أُذُنَيْهِ فَقَالَ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] dan [Abdurrahman Al Muharibi] serta [Waki'] dari [Al A'masy] dari [Zaid bin Wahb] dari [Abdurahman bin Abd Rabbil Ka'bah] dia berkata, \"Aku melewati [Abdullah bin 'Amru bin Al 'Ash] yang sedang duduk-duduk di bawah naungan Ka'bah, sementara itu orang-orang tengah berkumpul di sekelilingnya. Maka aku mendengar dia berkata, \"Ketika kami sedang bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, tiba-tiba beliau singgah di suatu tempat. Karena itu, di antara kami ada yang mendirikan tenda, dan ada yang melakukan perlombaan serta ada juga yang pergi entah ke mana. Tiba-tiba seorang penyeru berseru, 'Shalat Jama'ah.' Maka kami berkumpul, lalu Rasulullah shallallahu 'alaihi wasallam berdiri berkhutbah di hadapan kami, beliau katakan: \"Sesungguhnya tidak ada Nabi sebelumku kecuali dia berkewajiban untuk menunjuki kaumnya kepada suatu kebaikan yang telah di ketahuinya untuk diri mereka, dan memperingatkan kaumnya dari kejelekan yang telah mereka ketahui. Sesungguhnya ummat kalian ini telah di tetapkan kebaikannya di awal, sedangkan orang-orang yang datang belakangan akan ditimpa bencana dan perkara yang banyak dipungkiri, kemudian menyusul fitnah yang saling memberatkan antara satu dengan yang lain sehingga seorang mukmin berkata, 'Inilah saat kehancuranku'. Setelahitu fitnah tersebut di angkat. Maka barangsiapa ingin dijauhkan dari neraka dan dimasukkan ke dalam surga, hendaknya ia menjumpai kematiannya sedangkan dirinya dalam keadaan beriman kepada Allah dan hari Kiamat. Dan hendaknya ia mendatangi orang yang dicintainya untuk selalu datang berkunjung. Barangsiapa telah berbai'at kepada seorang pemimpin dan memberi kesaksian dan suara hatinya, maka hendaknya ia menta'ati semampunya. Dan jika datang orang lain yang menentangnya, maka bunuhlah ia.\" Abdurrahman bin Abdur Rabbil Ka'bah berkata, \"Kemudian aku julurkan kepalaku di antara kerumunan orang-orang seraya berkata, 'Aku memintamu bersaksi kepada Allah, (apakah) kamu benar-benar telah mendengar dari Rasulullah shallallahu 'alaihi wasallam? ' Abdurrahman berkata, \"Kemudian Abdullah bin 'Amru bin Al 'Ash mengisyaratkan dengan jari tangannya pada kedua telinganya sambil berkata, 'Aku telah mendengar dengan kedua telingaku dan dengan keterbuakaan hatiku'.\""},"3911":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ حَدَّثَنِي أَبِي عَنْ عُمَارَةَ بْنِ حَزْمٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَيْفَ بِكُمْ وَبِزَمَانٍ يُوشِكُ أَنْ يَأْتِيَ يُغَرْبَلُ النَّاسُ فِيهِ غَرْبَلَةً وَتَبْقَى حُثَالَةٌ مِنْ النَّاسِ قَدْ مَرِجَتْ عُهُودُهُمْ وَأَمَانَاتُهُمْ فَاخْتَلَفُوا وَكَانُوا هَكَذَا وَشَبَّكَ بَيْنَ أَصَابِعِهِ قَالُوا كَيْفَ بِنَا يَا رَسُولَ اللَّهِ إِذَا كَانَ ذَلِكَ قَالَ تَأْخُذُونَ بِمَا تَعْرِفُونَ وَتَدَعُونَ مَا تُنْكِرُونَ وَتُقْبِلُونَ عَلَى خَاصَّتِكُمْ وَتَذَرُونَ أَمْرَ عَوَامِّكُمْ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] dan [Muhammad bin As Shabah] keduanya berkata; telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] telah menceritakan kepadaku [Ayahku] dari ['Umarah bin Hazm] dari [Abdullah bin 'Amru], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana keadaan kalian dengan zaman yang hampir tiba, disaat manusia dipisah dan dipilah-pilah, lalu yang tersisa hanyalah orang-orang yang hina di antara manusia? Mereka telah merusak dan mencampur aduk amanat dan perjanjian, yang membuat mereka saling berselisih, dan beginilah keadaan mereka.\" -beliau menjalin jari-jarinya- mereka bertanya, \"Bagaimana keadaan kami wahai Rasulullah jika keadaannya seperti itu?\" beliau menjawab: \"Peganglah dengan erat apa yang kalian ketahui dan tinggalkan apa yang kalian ingkari, terimalah dari orang-orang tertentu kalian dan tinggalkanlah urusan orang awam kalian.\""},"3912":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ الْمُشَعَّثِ بْنِ طَرِيفٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَنْتَ يَا أَبَا ذَرٍّ وَمَوْتًا يُصِيبُ النَّاسَ حَتَّى يُقَوَّمَ الْبَيْتُ بِالْوَصِيفِ يَعْنِي الْقَبْرَ قُلْتُ مَا خَارَ اللَّهُ لِي وَرَسُولُهُ أَوْ قَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ تَصَبَّرْ قَالَ كَيْفَ أَنْتَ وَجُوعًا يُصِيبُ النَّاسَ حَتَّى تَأْتِيَ مَسْجِدَكَ فَلَا تَسْتَطِيعَ أَنْ تَرْجِعَ إِلَى فِرَاشِكَ وَلَا تَسْتَطِيعَ أَنْ تَقُومَ مِنْ فِرَاشِكَ إِلَى مَسْجِدِكَ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ أَوْ مَا خَارَ اللَّهُ لِي وَرَسُولُهُ قَالَ عَلَيْكَ بِالْعِفَّةِ ثُمَّ قَالَ كَيْفَ أَنْتَ وَقَتْلًا يُصِيبُ النَّاسَ حَتَّى تُغْرَقَ حِجَارَةُ الزَّيْتِ بِالدَّمِ قُلْتُ مَا خَارَ اللَّهُ لِي وَرَسُولُهُ قَالَ الْحَقْ بِمَنْ أَنْتَ مِنْهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَفَلَا آخُذُ بِسَيْفِي فَأَضْرِبَ بِهِ مَنْ فَعَلَ ذَلِكَ قَالَ شَارَكْتَ الْقَوْمَ إِذًا وَلَكِنْ ادْخُلْ بَيْتَكَ قُلْتُ يَا رَسُولَ اللَّهِ فَإِنْ دُخِلَ بَيْتِي قَالَ إِنْ خَشِيتَ أَنْ يَبْهَرَكَ شُعَاعُ السَّيْفِ فَأَلْقِ طَرَفَ رِدَائِكَ عَلَى وَجْهِكَ فَيَبُوءَ بِإِثْمِهِ وَإِثْمِكَ فَيَكُونَ مِنْ أَصْحَابِ النَّارِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abddah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu 'Imran Al Jauni] dari [Al Muysa'ats] dari [Abdullah bin As Shamit] dari [Abu Dzar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana keadaanmu wahai Abbu Dzar, disaat kematian menimpa manusia sehingga rumah ditegakkan di kuburan.\" Aku berkata, \"Allah dan Rasul-Nya tidak mengungkapkan untukku.\" Atau, \"Allah dan Rasul-Nya yang lebih tahu.\" Beliau bersabda: \"Bersabarlah.\" Beliau kembali bersabda: \"Apa yang akan kamu lakukan sedangkan orang-orang tengah tertimpa kelaparan, sehingga kamu datang ke masjidmu lalu kamu tidak bisa lagi kembali ke kasurmu, dan kamu juga tidak bisa berdiri dari tempat tidurmu menuju ke masjidmu?\" Abu Dzar berkata, \"Aku berkata, \"Allah dan Rasul-Nya yang lebih tahu.\" Atau, \"Allah dan Rasul-Nya tidak mengabarkan untukku.\" Beliau bersabda: \"Hendaklah kamu menjaga kebersihan dirimu.\" Kemudian beliau bersabda lagi: \"Apa yang akan kamu lakukan sementara pembunuhan telah menimpa manusia sehingga Hijrah Az Zait (nama tempat di Madinah) di banjiri oleh darah.\" Aku menjawab, \"Allah dan Rasul-Nya tidak mengabarkannya untukku.\" Beliau bersabda: \"Bergabunglah kamu dengan orang-orang yang kamu berasal darinya.\" Abu Dzar berkata, \"Aku berkata, \"Wahai Rasulullah, bolehkan kuambil pedangku lalu aku tebas orang-orang yang demikian (memerangi kaum muslimin)? ' Beliau menjawab: \"Kalau begitu, kamu telah ikut serta dengan kaum itu. Tetapi masuklah (diamlah) di rumahmu.\" Aku bertanya, \"Wahai Rasulullah, bagaimana jika rumahku di masuki (mereka)? Beliau menjawab: \"Jika kamu disilaukan oleh sinar pedang, maka lemparlah (tutuplah) ujung selendangmu di mukamu, sehingga ia akan menanggung dosanya dan dosamu, dan ia termasuk dari penghuni Neraka.\""},"3913":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَوْفٌ عَنْ الْحَسَنِ حَدَّثَنَا أَسِيدُ بْنُ الْمُتَشَمِّسِ قَالَ حَدَّثَنَا أَبُو مُوسَىحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ لَهَرْجًا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مَا الْهَرْجُ قَالَ الْقَتْلُ فَقَالَ بَعْضُ الْمُسْلِمِينَ يَا رَسُولَ اللَّهِ إِنَّا نَقْتُلُ الْآنَ فِي الْعَامِ الْوَاحِدِ مِنْ الْمُشْرِكِينَ كَذَا وَكَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ بِقَتْلِ الْمُشْرِكِينَ وَلَكِنْ يَقْتُلُ بَعْضُكُمْ بَعْضًا حَتَّى يَقْتُلَ الرَّجُلُ جَارَهُ وَابْنَ عَمِّهِ وَذَا قَرَابَتِهِ فَقَالَ بَعْضُ الْقَوْمِ يَا رَسُولَ اللَّهِ وَمَعَنَا عُقُولُنَا ذَلِكَ الْيَوْمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُنْزَعُ عُقُولُ أَكْثَرِ ذَلِكَ الزَّمَانِ وَيَخْلُفُ لَهُ هَبَاءٌ مِنْ النَّاسِ لَا عُقُولَ لَهُمْثُمَّ قَالَ الْأَشْعَرِيُّ وَايْمُ اللَّهِ إِنِّي لَأَظُنُّهَا مُدْرِكَتِي وَإِيَّاكُمْ وَايْمُ اللَّهِ مَا لِي وَلَكُمْ مِنْهَا مَخْرَجٌ إِنْ أَدْرَكَتْنَا فِيمَا عَهِدَ إِلَيْنَا نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا أَنْ نَخْرُجَ كَمَا دَخَلْنَا فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami ['Auf] dari [Al Hasan] telah menceritakan kepada kami [Asid bin Al Mutasyammas] dia berkata; telah menceritakan kepada kami [Abu Musa] telah menceritakan kepada kami Rasulullah shallallahu 'alaihi wasallam, beliau bersabda \"Sesungguhnya di antara (tanda-tanda) hari Kiamat adalah terjadinya kekacauan.\" Abu Musa berkata, \"Saya bertanya, \"Wahai Rasulullah, apakah yang di maksudkan kekacauan?\" beliau menjawa: \"Pembunuhan.\" Sebagian kaum Muslimin lalu bertanya, \"Wahai Rasulullah, dalam satu tahun ini kami telah membunuh kaum Musyrikin begini dan begini.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukannya membunuh kaum Musyrikin, akan tetapi kalianlah yang akan saling bunuh sesama kalian, sehingga seseorang membunuh tetangganya, anak pamannya, dan kerabat dekatnya sendiri.\" Sebagian yang lain lalu bertanya, \"Wahai Rasulullah, mekipun saat itu para ulama masih bersama kami?! Rasulullah shallallahu 'alaihi wasallam menjawab: \"Tidak, para ulama akan dimatikan lalu diganti dengan orang-orang hina dan bodoh.\" Kemudian Abu Musa Al Asy'ari berkata, \"Demi Allah, sesungguhnya aku memastikan bahwa perkara itu akan menimpa kita dan kalian. Demi Allah, tidak ada jalan keluar bagiku dan kalian, jika apa yang telah di janjikan Rasulullah shallallahu 'alaihi wasallam itu menimpa kita, kecuali jika kita keluar sebagaimana kita masuk ke dalamnya.\""},"3914":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُبَيْدٍ مُؤَذِّنُ مَسْجِدِ حُرْدَانَ قَالَ حَدَّثَتْنِي عُدَيْسَةُ بِنْتُ أُهْبَانَ قَالَتْلَمَّا جَاءَ عَلِيُّ بْنُ أَبِي طَالِبٍ هَاهُنَا الْبَصْرَةَ دَخَلَ عَلَى أَبِي فَقَالَ يَا أَبَا مُسْلِمٍ أَلَا تُعِينُنِي عَلَى هَؤُلَاءِ الْقَوْمِ قَالَ بَلَى قَالَ فَدَعَا جَارِيَةً لَهُ فَقَالَ يَا جَارِيَةُ أَخْرِجِي سَيْفِي قَالَ فَأَخْرَجَتْهُ فَسَلَّ مِنْهُ قَدْرَ شِبْرٍ فَإِذَا هُوَ خَشَبٌ فَقَالَ إِنَّ خَلِيلِي وَابْنَ عَمِّكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيَّ إِذَا كَانَتْ الْفِتْنَةُ بَيْنَ الْمُسْلِمِينَ فَأَتَّخِذُ سَيْفًا مِنْ خَشَبٍ فَإِنْ شِئْتَ خَرَجْتُ مَعَكَ قَالَ لَا حَاجَةَ لِي فِيكَ وَلَا فِي سَيْفِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Shafwan bin Isa] telah menceritakan kepada kami [Abdullah bin 'Ubaid] seorang Mu'adzin Masjid Hurdan, dia berkata; telah menceritakan kepadaku ['Udaisah binti Uhban] dia berkata, \"Tatkala Ali bin Abu Thalib datang ke sini, yaitu Bashrah, ia mendatangi ayahku dan berkata, \"Wahai Abu Muslim, maukah kamu menolongku melawan mereka itu?\" [dia (ayahku)] menjawab, \"Baiklah.\" Kemudian ayahku memanggil budak perempuannya seraya berkata, \"Wahai budak, keluarkanlah pedangku! \" Udaisah menuturkan, \"Budak itu lalu mengeluarkan pedangnya, kemudian mencabut kira-kira sepanjang satu jengkal, dan ternyata pedang itu terbuat dari kayu. Kemudian ayahku berkata, \"Sesungguhnya kekasihku dan anak pamanmu shallallahu 'alaihi wasallam berjanji kepadaku, jika terjadi fitnah di antara kaum muslimin, maka ambillah pedang dari kayu. Maka jika kamu berkehendak aku akan keluar bersamamu?\" Ali berkata, \"Aku tidak membutuhkanmu dan juga pedangmu.\""},"3915":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ ثَرْوَانَ عَنْ هُزَيْلِ بْنِ شُرَحْبِيلَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ فِتَنًا كَقِطَعِ اللَّيْلِ الْمُظْلِمِ يُصْبِحُ الرَّجُلُ فِيهَا مُؤْمِنًا وَيُمْسِي كَافِرًا وَيُمْسِي مُؤْمِنًا وَيُصْبِحُ كَافِرًا الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ الْمَاشِي وَالْمَاشِي فِيهَا خَيْرٌ مِنْ السَّاعِي فَكَسِّرُوا قِسِيَّكُمْ وَقَطِّعُوا أَوْتَارَكُمْ وَاضْرِبُوا بِسُيُوفِكُمْ الْحِجَارَةَ فَإِنْ دُخِلَ عَلَى أَحَدِكُمْ فَلْيَكُنْ كَخَيْرِ ابْنَيْ آدَمَ","id":"Telah menceritakan kepada kami ['Imran bin Musa Al Laitsi] telah menceritakan kepada kami [Abdul Warits bin Sa'id] telah menceritakan kepada kami [Muhammad bin Juhadah] dari [Abdurrahman bin Tsarwan] dari [Huzail bin Syurahbil] dari [Abu Musa Al Asy'ari] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, ketika mendekati kiamat akan terjadi berbagai fitnah seperti sepenggal malam yang gelap, di pagi hari seseorang beriman lalu di sore hari ia menjadi kafir, dan di sore hari ia beriman lalu di pagi harinya ia kafir. Pada saat itu, orang yang duduk lebih baik dari orang yang berdiri, dan yang berdiri lebih baik dari orang yang berjalan, dan orang yang berjalan lebih baik orang yang berlari, maka hancurkanlah busur kalian dan putuskanlah tali busur kalian. dan tancapkanlah pedang-pedang kalian di bebatuan. Jika salah seorang dari kalian diserang, maka jadilah seperti sebaik-baik dari dua anak Adam.\""},"3916":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ أَوْ عَلِيِّ بْنِ زَيْدِ بْنِ جَدْعَانَ شَكَّ أَبُو بَكْرٍ عَنْ أَبِي بُرْدَةَ قَالَ دَخَلْتُ عَلَى مُحَمَّدِ بْنِ مَسْلَمَةَ فَقَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا سَتَكُونُ فِتْنَةٌ وَفُرْقَةٌ وَاخْتِلَافٌ فَإِذَا كَانَ كَذَلِكَ فَأْتِ بِسَيْفِكَ أُحُدًا فَاضْرِبْهُ حَتَّى يَنْقَطِعَ ثُمَّ اجْلِسْ فِي بَيْتِكَ حَتَّى تَأْتِيَكَ يَدٌ خَاطِئَةٌ أَوْ مَنِيَّةٌ قَاضِيَةٌ فَقَدْ وَقَعَتْ وَفَعَلْتُ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Hammad bin Salamah] dari [Tsabit] atau [Ali binn Zaid bin Jad'an] -Abu Bakr ragu- dari [Abu Burdah] dia berkata, \"Saya menemui [Muhammad bin Maslamah], lalu ia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sungguh, fitnah akan terjadi, perpecahan dan perselisihan. Jika demikian keadaannya, maka datangilah bukit Uhud dengan pedangmu, kemudian tebaslah (bukit Uhud) sampai terbelah, lalu duduklah (tetaaplah) di rumahmu sampai datangnya tangan-tangan yang bersalah (orang yang akan membunuhmu), atau kematian menjemputmu.' Fitnah telah terjadi, dan aku telah mengerjakan apa yang diperintahkan Rasulullah shallallahu 'alaihi wasallam.\""},"3917":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مُبَارَكُ بْنُ سُحَيْمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُسْلِمَيْنِ الْتَقَيَا بِأَسْيَافِهِمَا إِلَّا كَانَ الْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Mubarak bin Suhaim] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah dari dua orang muslim yang saling bertemu dengan menghunus pedangnya, kecuali pembunuh dan yang terbunuh berada di neraka.\""},"3918":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ سُلَيْمَانَ التَّيْمِيِّ وَسَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا الْتَقَى الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ قَالُوا يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ إِنَّهُ أَرَادَ قَتْلَ صَاحِبِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] telah menceritakan kepada kami [Yazid bin Harun] dari [Sulaiman At Taimi] dan [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Al Hasan] dari [Abu Musa] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila dua orang muslim yang berhadapan dengan pedangnya, maka orang yang membunuh dan terbunuh berada di neraka.\" Para sahabat berkata, \"Wahai Rasulullah, (neraka) layak bagi yang membunuh, lalu bagaimana halnya dengan orang yang terbunuh?\" beliau bersabda: \"Karena ia juga berkeinginan membunuh temannya.\""},"3919":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا الْمُسْلِمَانِ حَمَلَ أَحَدُهُمَا عَلَى أَخِيهِ السِّلَاحَ فَهُمَا عَلَى جُرُفِ جَهَنَّمَ فَإِذَا قَتَلَ أَحَدُهُمَا صَاحِبَهُ دَخَلَاهَا جَمِيعًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Rib'I bin Hirasy] dari [Abu Bakrah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika dua orang muslim dan salah seorang dari keduanya menghunuskan pedang kepada saudaranya, maka keduanya berada di tepi neraka Jahannam, apabila salah seorang membunuh temannya maka keduanya akan masuk ke neraka.\""},"3920":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ عَبْدِ الْحَكَمِ السُّدُوسِيِّ حَدَّثَنَا شَهْرُ بْنُ حَوْشَبٍ عَنْ أَبِي أُمَامَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ شَرِّ النَّاسِ مَنْزِلَةً عِنْدَ اللَّهِ يَوْمَ الْقِيَامَةِ عَبْدٌ أَذْهَبَ آخِرَتَهُ بِدُنْيَا غَيْرِهِ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Abdul Hakam As Sudusi] telah menceritakan kepada kami [Syahr bin Hausyab] dari [Abu Umamah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seburuk-buruk kedudukan manusia di sisi Allah pada hari kiamat adalah seorang hamba yang menghancurkan akhiratnya dengan dunia orang lain.\""},"3921":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ لَيْثٍ عَنْ طَاوُسٍ عَنْ زِيَادِ سَيْمِينْ كُوشْ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكُونُ فِتْنَةٌ تَسْتَنْظِفُ الْعَرَبَ قَتْلَاهَا فِي النَّارِ اللِّسَانُ فِيهَا أَشَدُّ مِنْ وَقْعِ السَّيْفِ","id":"Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Laits] dari [Thawus] dari [Ziyad Saimin Kusy] dari [Abdullah 'Amru] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi suatu fitnah yang akan menimpa seluruh orang Arab, orang yang mati dalam fitnah itu akan menjadi penghuni neraka, dan saat itu ucapan lisan lebih tajam daripada tebasan pedang.\""},"3922":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكُمْ وَالْفِتَنَ فَإِنَّ اللِّسَانَ فِيهَا مِثْلُ وَقْعِ السَّيْفِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Al Harits] telah menceritakan kepada kami [Muhammad bin Abdurrahman bin Al Bailamani] dari [Ayahnya] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berhati-hatilah kalian pada saat terjadinya fitnah, sesungguhnya lisan pada saat itu setajam tebasan pedang.\""},"3923":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَلْقَمَةَ بْنِ وَقَّاصٍ قَالَمَرَّ بِهِ رَجُلٌ لَهُ شَرَفٌ فَقَالَ لَهُ عَلْقَمَةُ إِنَّ لَكَ رَحِمًا وَإِنَّ لَكَ حَقًّا وَإِنِّي رَأَيْتُكَ تَدْخُلُ عَلَى هَؤُلَاءِ الْأُمَرَاءِ وَتَتَكَلَّمُ عِنْدَهُمْ بِمَا شَاءَ اللَّهُ أَنْ تَتَكَلَّمَ بِهِ وَإِنِّي سَمِعْتُ بِلَالَ بْنَ الْحَارِثِ الْمُزَنِيَّ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَدَكُمْ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ رِضْوَانِ اللَّهِ مَا يَظُنُّ أَنْ تَبْلُغَ مَا بَلَغَتْ فَيَكْتُبُ اللَّهُ عَزَّ وَجَلَّ لَهُ بِهَا رِضْوَانَهُ إِلَى يَوْمِ الْقِيَامَةِ وَإِنَّ أَحَدَكُمْ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ سُخْطِ اللَّهِ مَا يَظُنُّ أَنْ تَبْلُغَ مَا بَلَغَتْ فَيَكْتُبُ اللَّهُ عَزَّ وَجَلَّ عَلَيْهِ بِهَا سُخْطَهُ إِلَى يَوْمِ يَلْقَاهُقَالَ عَلْقَمَةُ فَانْظُرْ وَيْحَكَ مَاذَا تَقُولُ وَمَاذَا تَكَلَّمُ بِهِ فَرُبَّ كَلَامٍ قَدْ مَنَعَنِي أَنْ أَتَكَلَّمَ بِهِ مَا سَمِعْتُ مِنْ بِلَالِ بْنِ الْحَارِثِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Muhammad bin 'Amru] telah menceritakan kepadaku [Ayahku] dari ayahnya ['Alqamah bin Waqash] dia berkata, \"Seorang laki-laki bangsawan melintas di hadapannya, lalu 'Alqamah berkata kepadanya, 'Sesungguhnya kamu memiliki hubungan silaturrahim dan hak, dan sungguh aku melihatmu mendatangi para pejabat lalu kamu berbicara dengan apa yang telah Allah kehendaki dari pembicaraanmu. Sungguh, aku telah mendengar [Bilal bin Al Harits Al Muzani] -seorang sahabat Rasulullah shallallahu 'alaihi wasallam- berkata, 'Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh salah seorang dari kalian akan mengatakan suatu ucapan yang diridlai oleh dan ia tidak mengira akan balasannya, lalu Allah 'azza wajalla mencatatnya dalam keridlaan-Nya sampai Hari Kiamat. Dan sungguh, salah seorang dari kalian akan mengucapkan suatu perkataan yang dimurkai oleh Allah dan ia tidak mengira akan akibatnya, lalu Allah mencatat dalam kemurkaan-Nya hari ketika bertemu dengan-Nya\" Bilal bin Al Harits Al Muzni berkata, \"'Alqamah berkata, 'Berapa banyak perkataan yang saya tahan karena hadits Bilal bin Al Harits tersebut'.\""},"3924":{"ar":"حَدَّثَنَا أَبُو يُوسُفَ بْنُ الصَّيْدَلَانِيُّ مُحَمَّدُ بْنُ أَحْمَدَ الرَّقِّيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرَّجُلَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ سُخْطِ اللَّهِ لَا يَرَى بِهَا بَأْسًا فَيَهْوِي بِهَا فِي نَارِ جَهَنَّمَ سَبْعِينَ خَرِيفًا","id":"Telah menceritakan kepada kami [Abu Yusuf bin As Shaidalani Muhammad bi Ahmad Ar Raqqi] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, salah seorang dari kalian mengucapkan suatu ucapan yang dimurkai oleh Allah, namun ia tidak menganggapnya sebagai dosa, hingga dengannya ucapan tersebut ia jatuh ke dalam neraka Jahannam selama tujuh puluh tahun.\""},"3925":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَسْكُتْ","id":"Telah menceritakan kepada kami [Abu Bakr] telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Al Hashin] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan hari Akhir, hendaknya berkata baik atau diam.\""},"3926":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَاعِزٍ الْعَامِرِيِّ أَنَّ سُفْيَانَ بْنَ عَبْدِ اللَّهِ الثَّقَفِيَّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ حَدِّثْنِي بِأَمْرٍ أَعْتَصِمُ بِهِ قَالَ قُلْ رَبِّيَ اللَّهُ ثُمَّ اسْتَقِمْ قُلْتُ يَا رَسُولَ اللَّهِ مَا أَكْثَرُ مَا تَخَافُ عَلَيَّ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلِسَانِ نَفْسِهِ ثُمَّ قَالَ هَذَا","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin 'Utsman Al 'Utsmani] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Muhammad bin Abdurrahman bin Ma'iz Al 'Amiri] bahwa [Sufyan bin Abdullah Ats Tsaqafi] berkata, \"Saya bertanya, 'Wahai Rasulullah, katakanlah kepadaku sesuatu yang bisa aku jadikan pegangan.\" Beliau bersabda: \"Katakanlah, 'Rabbku adalah Allah', lalu beristiqamahlah kamu.\" Aku bertanya lagi, \"Wahai Rasulullah, apa yang paling anda khawatirkan terhadap diriku?\" Rasulullah shallallahu 'alaihi wasallam lalu memegang lidahnya sendiri sambil bersabda: \"Ini.\""},"3927":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُمَرَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاذٍ عَنْ مَعْمَرٍ عَنْ عَاصِمِ بْنِ أَبِي النُّجُودِ عَ��ْ أَبِي وَائِلٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَصْبَحْتُ يَوْمًا قَرِيبًا مِنْهُ وَنَحْنُ نَسِيرُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَخْبِرْنِي بِعَمَلٍ يُدْخِلُنِي الْجَنَّةَ وَيُبَاعِدُنِي مِنْ النَّارِ قَالَ لَقَدْ سَأَلْتَ عَظِيمًا وَإِنَّهُ لَيَسِيرٌ عَلَى مَنْ يَسَّرَهُ اللَّهُ عَلَيْهِ تَعْبُدُ اللَّهَ لَا تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ وَتَصُومُ رَمَضَانَ وَتَحُجَّ الْبَيْتَ ثُمَّ قَالَ أَلَا أَدُلُّكَ عَلَى أَبْوَابِ الْخَيْرِ الصَّوْمُ جُنَّةٌ وَالصَّدَقَةُ تُطْفِئُ الْخَطِيئَةَ كَمَا يُطْفِئُ النَّارَ الْمَاءُ وَصَلَاةُ الرَّجُلِ مِنْ جَوْفِ اللَّيْلِ ثُمَّ قَرَأَ{ تَتَجَافَى جُنُوبُهُمْ عَنْ الْمَضَاجِعِ حَتَّى بَلَغَ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }ثُمَّ قَالَ أَلَا أُخْبِرُكَ بِرَأْسِ الْأَمْرِ وَعَمُودِهِ وَذُرْوَةِ سَنَامِهِ الْجِهَادُ ثُمَّ قَالَ أَلَا أُخْبِرُكَ بِمِلَاكِ ذَلِكَ كُلِّهِ قُلْتُ بَلَى فَأَخَذَ بِلِسَانِهِ فَقَالَ تَكُفُّ عَلَيْكَ هَذَا قُلْتُ يَا نَبِيَّ اللَّهِ وَإِنَّا لَمُؤَاخَذُونَ بِمَا نَتَكَلَّمُ بِهِ قَالَ ثَكِلَتْكَ أُمُّكَ يَا مُعَاذُ وَهَلْ يُكِبُّ النَّاسَ عَلَى وُجُوهِهِمْ فِي النَّارِ إِلَّا حَصَائِدُ أَلْسِنَتِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Umar Al 'Adani] telah menceritakan kepada kami [Abdullah bin Mu'adz] dari [Ma'mar] dari ['Ashim bin Abu An Nujud] dari [Abu Wa`il] dari [Mu'adz bin Jabal] dia berkata, \"Aku bersama Nabi shallallahu 'alaihi wasallam di suatu perjalanan, hingga di suatu pagi aku berada di sisi beliau. Saat berjalan aku berkata kepada beliau, \"Wahai Rasulullah, kabarkanlah kepadaku amalan yang dapat memasukkan aku ke dalam surga dan menjauhkan aku dari neraka?\" Beliau menjawab: \"Sungguh, kamu telah menanyakan suatu perkara yang sangat besar (bagus) padahal itu sebenarnya sangat mudah bagi orang yang Allah mudahkan; yaitu kamu menyembah Allah dan jangan menyekutukannya dengan sesuatupun, menegakkan shalat, menunaikan zakat, berpuasa di bulan Ramadan dan menunaikan iabdah haji.\" Kemudian beliau bersabda: \"Maukah aku tunjukkan kepadamu pintu-pintu kebaikan? Puasa adalah perisai dan sedekah dapat memadamkan kesalahan sebagaimana air dapat memadamkan api, dan shalatnya seseorang di tengah malam.\" Lalu beliau membaca: '(Lambung mereka jauh dari tempat tidurny...) ' sampai pada bagian ayat '(sebagai balasan terhadap apa yang telah mereka kerjakan) ' (Qs. As Sajadah: 16-18). Kemudian beliau melanjutkan: \"Maukah aku beritahukan kepadamu pokok perkara, tiang-tiangnya dan puncak tertinggi segala urusan? Itu adalah jihad.\" Kemudian beliau bersabda: \"Maukah aku beritahukan kepadamu tentang orang yang memiliki semua itu?\" aku menjawab, \"Tentu.\" Beliau lalu memegang lidahnya dan bersabda: \"Kamu harus menahan ini dari dirimu.\" Aku berkata, \"Wahai Nabi Allah, apakah kami akan diproses dengan ap yang kami ucapan ini?\" Beliau bersabda: \"Sungguh kebangetan kamu wahai Mu'adz, tidaklah muka-muka manusia disungkurkan ke dalam api neraka melainkan karena hasil perbuatan lidah-lidah mereka! \""},"3928":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ بْنِ خُنَيْسٍ الْمَكِّيُّ قَالَ سَمِعْتُ سَعِيدَ بْنَ حَسَّانَ الْمَخْزُومِيَّ قَالَ حَدَّثَتْنِي أُمُّ صَالِحٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَلَامُ ابْنِ آدَمَ عَلَيْهِ لَا لَهُ إِلَّا الْأَمْرَ بِالْمَعْرُوفِ وَالنَّهْيَ عَنْ الْمُنْكَرِ وَذِكْرَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Yazid bin Khunais Al Makki] dia berkata; saya mendengar [Sa'id bin Al Hasan Al Mahzumi] berkata; telah menceritakan kepadaku [Ummu Shalih] dari [Shafiyah binti Syaibah] dari [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ucapan anak Adam itu akan kembali dengan membawa bencana untuknya dan tidak membawa keberuntungan baginya, kecuali amar ma'ruf dan nahi mungkar, serta berdzikir kepada Allah 'azza wajalla.\""},"3929":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا خَالِي يَعْلَى عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ أَبِي الشَّعْثَاءِ قَالَقِيلَ لِابْنِ عُمَرَ إِنَّا نَدْخُلُ عَلَى أُمَرَائِنَا فَنَقُولُ الْقَوْلَ فَإِذَا خَرَجْنَا قُلْنَا غَيْرَهُ قَالَ كُنَّا نَعُدُّ ذَلِكَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النِّفَاقَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [pamanku Ya'la] dari [Al A'masy] dari [Ibrahim] dari [Abu Asy Sya'tsa`] dia berkata, \"Dikatakan kepada [Ibnu Umar], \"Sesungguhnya kami sering mengunjungi para pejabat-pejabat kami, lalu kami mengatakan suatu perkataan. Jika kami telah selesai dan beranjak pergi, kami pun mengatakan perkataan yang berbeda.\" Ibnu Umar berkata, \"Kami menilai hal itu pada zaman Rasulullah shallallahu 'alaihi wasallam termamsuk dari perbuatan nifak.\""},"3930":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبِ بْنِ شَابُورَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ قُرَّةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ حَيْوَئِيلَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حُسْنِ إِسْلَامِ الْمَرْءِ تَرْكُهُ مَا لَا يَعْنِيهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Muhammad bin Syu'aib bin Syabur] telah menceritakan kepada kami [Al Auza'i] dari [Qurrah bin Abdurrahman bin Haiwa`il] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanda dari baiknya keIslaman seseorang adalah meninggalkan sesuatu yang tidak bermanfaat baginya.\""},"3931":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ أَخْبَرَنِي أَبِي عَنْ بَعَجَةَ بْنِ عَبْدِ اللَّهِ بْنِ بَدْرٍ الْجُهَنِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ مَعَايِشِ النَّاسِ لَهُمْ رَجُلٌ مُمْسِكٌ بِعِنَانِ فَرَسِهِ فِي سَبِيلِ اللَّهِ وَيَطِيرُ عَلَى مَتْنِهِ كُلَّمَا سَمِعَ هَيْعَةً أَوْ فَزْعَةً طَارَ عَلَيْهِ إِلَيْهَا يَبْتَغِي الْمَوْتَ أَوْ الْقَتْلَ مَظَانَّهُ وَرَجُلٌ فِي غُنَيْمَةٍ فِي رَأْسِ شَعَفَةٍ مِنْ هَذِهِ الشِّعَافِ أَوْ بَطْنِ وَادٍ مِنْ هَذِهِ الْأَوْدِيَةِ يُقِيمُ الصَّلَاةَ وَيُؤْتِي الزَّكَاةَ وَيَعْبُدُ رَبَّهُ حَتَّى يَأْتِيَهُ الْيَقِينُ لَيْسَ مِنْ النَّاسِ إِلَّا فِي خَيْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] telah mengabarkan kepadaku [ayahku] dari [Ba'jah bin Abdullah bin Badi Al Juhanni] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kehidupan manusia adalah seseorang yang memegang kendali kudanya dalam perjuangan di jalan Allah. Setiap kali mendengar suara musuh yang menakutkan dan mengerikan, ia pun langsung melompat ke atas punggung kudanya mencari kematian sebagai tempat sangkaannya. Dan seseorang yang memelihara kambing di puncak-puncak gunung atau pedalaman lembah dari lembah-lembah ini sambil mendirikan shalat, menunaikan zakat dan menyembah Rabbnya sampai ajal menjemput, dan tidaklah ia menjadi manusia melainkan dalam kebaikan.\""},"3932":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا الزَّبِيدِيُّ حَدَّثَنِي الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّ النَّاسِ أَفْضَلُ قَالَ رَجُلٌ مُجَاهِدٌ فِي سَبِيلِ اللَّهِ بِنَفْسِهِ وَمَالِهِ قَالَ ثُمَّ مَنْ قَالَ ثُمَّ امْرُؤٌ فِي شِعْبٍ مِنْ الشِّعَابِ يَعْبُدُ اللَّهَ عَزَّ وَجَلَّ وَيَدَعُ النَّاسَ مِنْ شَرِّهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [Az Zubaidi] telah menceritakan kepadaku [Az Zuhri] dari ['Atha bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudri], bahwa seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam, dia bertanya, \"Siapakah manusia yang paling mulia? ' beliau menjawab: \"Seeorang yang berjihad di jalan Allah dengan jiwa dan harta bendanya.\" Dia berkata, \"Kemudian siapa lagi?\" beliau menjawab: \"Kemudian seseorang yang hidup di perbukitan beribadah kepada Allah dan meninggalkan kejahatan manusia.\""},"3933":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنِي بُسْرُ بْنُ عُبَيْدِ اللَّهِ حَدَّثَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ أَنَّهُ سَمِعَ حُذَيْفَةَ بْنَ الْيَمَانِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ دُعَاةٌ عَلَى أَبْوَابِ جَهَنَّمَ مَنْ أَجَابَهُمْ إِلَيْهَا قَذَفُوهُ فِيهَا قُلْتُ يَا رَسُولَ اللَّهِ صِفْهُمْ لَنَا قَالَ هُمْ قَوْمٌ مِنْ جِلْدَتِنَا يَتَكَلَّمُونَ بِأَلْسِنَتِنَا قُلْتُ فَمَا تَأْمُرُنِي إِنْ أَدْرَكَنِي ذَلِكَ قَالَ فَالْزَمْ جَمَاعَةَ الْمُسْلِمِينَ وَإِمَامَهُمْ فَإِنْ لَمْ يَكُنْ لَهُمْ جَمَاعَةٌ وَلَا إِمَامٌ فَاعْتَزِلْ تِلْكَ الْفِرَقَ كُلَّهَا وَلَوْ أَنْ تَعَضَّ بِأَصْلِ شَجَرَةٍ حَتَّى يُدْرِكَكَ الْمَوْتُ وَأَنْتَ كَذَلِكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepadaku [Abdurrahman bin Yazid bin Jabir] telah menceritakan kepadaku [Busr bin 'Ubaidullah] telah menceritakan kepadaku [Abu Idris Al Khaulani] bahwa dia mendengar [Hudzaifah bin Al Yaman] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada para da'i (penyeru) yang menyeru ke pintu neraka Jahannam, barangsiapa memenuhi ajakannya maka ia akan dilemparkan ke dalam neraka.\" Lalu aku bertanya, \"Wahai Rasulullah, sebutkanlah ciri-ciri mereka kepada kami! \" Beliau bersabda: 'Mereka adalah suatu kaum yang warna kulitnya sama dengan kita, dan berbicara dengan bahasa yang sama dengan kita.\" Aku bertanya lagi, \"Apakah yang anda perintahkan kepada kami, seandainya kami menjumpai hal itu?\" Beliau menjawab: \"Berpegang teguhlah kepada Jama'ah kaum muslimin dan imam mereka, jika mereka tidak memiliki Jama'ah kaum Muslimin dan imamnya, maka jauhilah semua golongan tersebut meskipun kamu harus menggigit akar pohon sampai ajal menjemputmu dan kamu masih tetap dalam keadaan seperti itu.\""},"3934":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيِّ عَنْ أَبِيهِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ أَنْ يَكُونَ خَيْرَ مَالِ الْمُسْلِمِ غَنَمٌ يَتْبَعُ بِهَا شَعَفَ الْجِبَالِ وَمَوَاقِعَ الْقَطْرِ يَفِرُّ بِدِينِهِ مِنْ الْفِتَنِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdullah bin Numair] dari [Yahya bin Sa'id] dari [Abdullah bin Abdurrahman Al Anshari] dari [Ayahnya] bahwa dia mendengar [Abu Sa'id Al Khudri] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nyaris harta seorang muslim yang terbaik adalah seekor kambing yang dipelihara di atas pegunungan dan tempat tetesan embun (mata air), lari demi menyelamatkan agamanya dari fitnah.\""},"3935":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيٍّ الْمُقَدِّمِيُّ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ حَدَّثَنَا أَبُو عَامِرٍ الْخَزَّازُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ قُرْطٍ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكُونُ فِتَنٌ عَلَى أَبْوَابِهَا دُعَاةٌ إِلَى النَّارِ فَأَنْ تَمُوتَ وَأَنْتَ عَاضٌّ عَلَى جِذْلِ شَجَرَةٍ خَيْرٌ لَكَ مِنْ أَنْ تَتْبَعَ أَحَدًا مِنْهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Ali Al Muqaddimi] telah menceritakan kepada kami [Sa'id bin 'Amir] telah menceritakan kepada kami [Abu 'Amir Al Khazzaz] dari [Humaid bin Hilal] dari [Abdurrahman bin Qurth] dari [Hudzaifah bin Al Yaman] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan datang berbagai fitnah yang di depannya adalah para penyeru ke neraka, jika kamu mati dalam keadaan menggigit akar suatu pohon itu lebih baik daripada harus mengikuti seseorang dari mereka (para penyeru ke neraka).\""},"3936":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْحَارِثِ الْمِصْرِيُّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُلْدَغُ الْمُؤْمِنُ مِنْ جُحْرٍ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Harits Al Mishri] telah menceritakan kepada kami [Al Laits bin Sa'd] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang muslim terperosok dua kali ke dalam satu lubang.\""},"3937":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ قَالَ حَدَّثَنَا زَمْعَةُ بْنُ صَالِحٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُلْدَغُ الْمُؤْمِنُ مِنْ جُحْرٍ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dia berkata; telah menceritakan kepada kami [Abu Ahmad Az Zubairi] dia berkata; telah menceritakan kepada kami [Zam'ah bin Shalih] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang muslim terperosok dua kali ke dalam satu lubang.\""},"3938":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ الشَّعْبِيِّ قَالَسَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُ عَلَى الْمِنْبَرِ وَأَهْوَى بِإِصْبَعَيْهِ إِلَى أُذُنَيْهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحَلَالُ بَيِّنٌ وَالْحَرَامُ بَيِّنٌ وَبَيْنَهُمَا مُشْتَبِهَاتٌ لَا يَعْلَمُهَا كَثِيرٌ مِنْ النَّاسِ فَمَنْ اتَّقَى الشُّبُهَاتِ اسْتَبْرَأَ لِدِينِهِ وَعِرْضِهِ وَمَنْ وَقَعَ فِي الشُّبُهَاتِ وَقَعَ فِي الْحَرَامِ كَالرَّاعِي حَوْلَ الْحِمَى يُوشِكُ أَنْ يَرْتَعَ فِيهِ أَلَا وَإِنَّ لِكُلِّ مَلِكٍ حِمَى أَلَا وَإِنَّ حِمَى اللَّهِ مَحَارِمُهُ أَلَا وَإِنَّ فِي الْجَسَدِ مُضْغَةً إِذَا صَلُحَتْ صَلُحَ الْجَسَدُ كُلُّهُ وَإِذَا فَسَدَتْ فَسَدَ الْجَسَدُ كُلُّهُ أَلَا وَهِيَ الْقَلْبُ","id":"Telah menceritakan kepada kami ['Amru bin Rafi'] telah menceritakan kepada kami [Abdullah bin Mubarak] dari [Zakaria bin Abu Za`idah] dari [Asy Sya'bi] dia berkata; saya mendengar [An Nu'man bin Basyir] berkata di atas mimbar dan mengisyaratkan dengan jari-jarinya di kedua telinganya, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Sesuatu) yang halal telah jelas dan yangharam juga telah jelas, dan di antara keduanya ada perkara Syubhat (samar-samar) yang kebanyakan orang tidak mengetahuinya. Barangsiapa dapat menjaga diri dari perkara syubhat itu berarti ia telah menjaga agama dan kehormatannya, dan barangsiapa terjatuh ke dalam perkara syubhat berarti ia telah terjatuh dalam keharaman. Seperti penggembala yang menggembala hewan ternaknya di sekitar daerah terlarang, dikhawatirkan hewannya akan masuk ke wilayah yang terlarang itu. Ketahuilah, bahwa setiap raja memiliki larangan, dan larangan Allah adalah sesuatu yang di haramkannya. Ketahuilah, di dalam tubuh terdapat segumpal darah, jika ia baik maka akan baiklah seluruh tubuh. Namun jika ia rusak maka akan rusak pulalah seluruh tubuh, ketahuilah bahwa segumpal darah tersebut adalah hati.\""},"3939":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ الْمُعَلَّى بْنِ زِيَادٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِبَادَةُ فِي الْهَرْجِ كَهِجْرَةٍ إِلَيَّ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Al Mu'alla bin Ziyad] dari [Mu'awiyah bin Qurrah] dari [Ma'qil bin Yasar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ibadah dalam kondisi huru-hara bagiku sama seperti melakukan hijrah.\""},"3940":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ وَسُوَيْدُ بْنُ سَعِيدٍ قَالُوا حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَأَ الْإِسْلَامُ غَرِيبًا وَسَيَعُودُ غَرِيبًا فَطُوبَى لِلْغُرَبَاءِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] dan [Ya'qub bin Humaid bin Kasib] serta [Suwaid bin Sa'id] mereka berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] telah menceritakan kepada kami [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Islam pertama kali muncul dalam keadaan asing dan akan kembali dalam keadaan asing pula, maka beruntunglah bagi orang-orang yang terasing.\""},"3941":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا عَمْرُو بْنُ الْحَارِثِ وَابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سِنَانِ بْنِ سَعْدٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْإِسْلَامَ بَدَأَ غَرِيبًا وَسَيَعُودُ غَرِيبًا فَطُوبَى لِلْغُرَبَاءِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah memberitakan kepada kami ['Amru bin Al Harits] dan [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Sinan bin Sa'd] dari [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Islam muncul pertama kali dalam keadaan asing dan akan kembali dalam keadaan asing, maka beruntunglah bagi orang-orang yang terasing.\""},"3942":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْإِسْلَامَ بَدَأَ غَرِيبًا وَسَيَعُودُ غَرِيبًا فَطُوبَى لِلْغُرَبَاءِ قَالَ قِيلَ وَمَنْ الْغُرَبَاءُ قَالَ النُّزَّاعُ مِنْ الْقَبَائِلِ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Islam muncul pertama kali dalam keadaan asing dan akan kembali dalam keadaan asing pula, maka beruntunglah orang-orang yang terasing.\" Abdullah berkata, \"Dikatakan, \"Siapakah orang-orang yang terasing itu?\" beliau menjawab: \"Orang-orang yang memisahkan diri dari kabilah-kabilah (yang sesat).\""},"3943":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ عِيسَى بْنِ عَبْدِ الرَّحْمَنِ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّهُ خَرَجَ يَوْمًا إِلَى مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ مُعَاذَ بْنَ جَبَلٍ قَاعِدًا عِنْدَ قَبْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْكِي فَقَالَ مَا يُبْكِيكَ قَالَ يُبْكِينِي شَيْءٌ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ يَسِيرَ الرِّيَاءِ شِرْكٌ وَإِنَّ مَنْ عَادَى لِلَّهِ وَلِيًّا فَقَدْ بَارَزَ اللَّهَ بِالْمُحَارَبَةِ إِنَّ اللَّهَ يُحِبُّ الْأَبْرَارَ الْأَتْقِيَاءَ الْأَخْفِيَاءَ الَّذِينَ إِذَا غَابُوا لَمْ يُفْتَقَدُوا وَإِنْ حَضَرُوا لَمْ يُدْعَوْا وَلَمْ يُعْرَفُوا قُلُوبُهُمْ مَصَابِيحُ الْهُدَى يَخْرُجُونَ مِنْ كُلِّ غَبْرَاءَ مُظْلِمَةٍ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Isa bin Abdurrahman] dari [Zaid bin Aslam] dari [Aslam] dari [Umar bin Khattab], bahwa suatu ketika dia keluar menuju masjid Nabi shallallahu 'alaihi wasallam lalu berjumpa dengan Mu'adz bin Jabal yang sedang duduk di sisi Kuburan Nabi shallallahu 'alaihi wasallam sambil menangis. Maka ia pun bertanya, \"Apa yang membuatmu manangis?\" [Mu'adz] menjawab, \"Aku menangis karena sesuatu yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya riya' yang paling ringan pun sudah terhitung syirik, dan sesungguhnya orang yang memusuhi wali Allah maka dia telah menantang bertarung dengan Allah. Sesungguhnya Allah mencintai orang-orang yang baik lagi bertakwa dan tidak dikenal, yaitu orang-orang yang apabila menghilang maka mereka tidak dicari-cari, dan jika mereka hadir maka mereka tidak di kenal, hati mereka ibarat lentera-lentera petunjuk yang muncul dari setiap bumi yang gelap.\""},"3944":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسُ كَإِبِلِ مِائَةٍ لَا تَكَادُ تَجِدُ فِيهَا رَاحِلَةً","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] telah menceritakan kepada kami [Zaid bin Aslam] dari [Abdullah bin Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia ibarat seratus ekor unta yang darinya nyaris tidak didapatkan seekor pun yang layak dijadikan kendaraan.\""},"3945":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحْمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَفَرَّقَتْ الْيَهُودُ عَلَى إِحْدَى وَسَبْعِينَ فِرْقَةً وَتَفْتَرِقُ أُمَّتِي عَلَى ثَلَاثٍ وَسَبْعِينَ فِرْقَةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Yahudi akan terpecah menjadi tujuh puluh satu golongan dan ummatku akan terpecah menajadi tujuh puluh tiga golongan.\""},"3946":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا عَبَّادُ بْنُ يُوسُفَ حَدَّثَنَا صَفْوَانُ بْنُ عَمْرٍو عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَرَقَتْ الْيَهُودُ عَلَى إِحْدَى وَسَبْعِينَ فِرْقَةً فَوَاحِدَةٌ فِي الْجَنَّةِ وَسَبْعُونَ فِي النَّارِ وَافْتَرَقَتْ النَّصَارَى عَلَى ثِنْتَيْنِ وَسَبْعِينَ فِرْقَةً فَإِحْدَى وَسَبْعُونَ فِي النَّارِ وَوَاحِدَةٌ فِي الْجَنَّةِ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَتَفْتَرِقَنَّ أُمَّتِي عَلَى ثَلَاثٍ وَسَبْعِينَ فِرْقَةً وَاحِدَةٌ فِي الْجَنَّةِ وَثِنْتَانِ وَسَبْعُونَ فِي النَّارِ قِيلَ يَا رَسُولَ اللَّهِ مَنْ هُمْ قَالَ الْجَمَاعَةُ","id":"Telah menceritakan kepada kami ['Amru bin 'Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] telah menceritakan kepada kami ['Abbad bin Yusuf] telah menceritakan kepada kami [Shafwan bin 'Amru] dari [Rasyid bin Sa'd] dari ['Auf bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Yahudi akan terpecah menjadi tujuh puluh satu golongan, satu golongan akan masuk surga dan yang tujuh puluh golongan akan masuk neraka. Dan orang-orang Nashrani terpecah menjadi tujuh puluh dua golongan, yang tujuh puluh satu golongan masuk neraka dan yang satu golongan akan masuk surga. Demi Dzat yang jiwa Muhammad ada ditangan-Nya, sungguh ummatku akan terpecah menjadi tujuh puluh tiga golongan, yang satu golongan masuk surga dan yang tujuh puluh dua golongan akan masuk neraka.\" Lalu beliau ditanya, \"Wahai Rasulullah, siapakah mereka (yang masuk surga)?\" beliau mennjawab: \"Yaitu Al Jama'ah.\""},"3947":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو عَمْرٍو حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ افْتَرَقَتْ عَلَى إِحْدَى وَسَبْعِينَ فِرْقَةً وَإِنَّ أُمَّتِي سَتَفْتَرِقُ عَلَى ثِنْتَيْنِ وَسَبْعِينَ فِرْقَةً كُلُّهَا فِي النَّارِ إِلَّا وَاحِدَةً وَهِيَ الْجَمَاعَةُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Abu 'Amru] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bani Israil akan terpecah menjadi tujuh puluh golongan, dan ummatku akan terpecah menjadi tujuh puluh dua golongan, semuanya akan masuk neraka kecuali satu golongan, yaitu Al Jama'ah.\""},"3948":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَتَتَّبِعُنَّ سُنَّةَ مَنْ كَانَ قَبْلَكُمْ بَاعًا بِبَاعٍ وَذِرَاعًا بِذِرَاعٍ وَشِبْرًا بِشِبْرٍ حَتَّى لَوْ دَخَلُوا فِي جُحْرِ ضَبٍّ لَدَخَلْتُمْ فِيهِ قَالُوا يَا رَسُولَ اللَّهِ الْيَهُودُ وَالنَّصَارَى قَالَ فَمَنْ إِذًا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, kalian akan mengikuti jalan (cara hidup) orang-orang sebelum kalian sedepa demi sedepa, sehasta demi sehasta dan sejengkal demi sejengkal, sehingga sekiranya mereka masuk ke lubang biawak, sungguh kalian juga akan mengikuti mereka.\" Para sahabat bertanya, \"Wahai Rasulullah, apakah mereka orang-orang Yahudi dan Nahsrani?\" beliau menjawab: \"Siapa lagi kalau bukan mereka.\""},"3949":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَ النَّاسَ فَقَالَ لَا وَاللَّهِ مَا أَخْشَى عَلَيْكُمْ أَيُّهَا النَّاسُ إِلَّا مَا يُخْرِجُ اللَّهُ لَكُمْ مِنْ زَهْرَةِ الدُّنْيَا فَقَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ أَيَأْتِي الْخَيْرُ بِالشَّرِّ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاعَةً ثُمَّ قَالَ كَيْفَ قُلْتَ قَالَ قُلْتُ وَهَلْ يَأْتِي الْخَيْرُ بِالشَّرِّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْخَيْرَ لَا يَأْتِي إِلَّا بِخَيْرٍ أَوَ خَيْرٌ هُوَ إِنَّ كُلَّ مَا يُنْبِتُ الرَّبِيعُ يَقْتُلُ حَبَطًا أَوْ يُلِمُّ إِلَّا آكِلَةَ الْخَضِرِ أَكَلَتْ حَتَّى إِذَا امْتَلَأَتْ امْتَدَّتْ خَاصِرَتَاهَا اسْتَقْبَلَتْ الشَّمْسَ فَثَلَطَتْ وَبَالَتْ ثُمَّ اجْتَرَّتْ فَعَادَتْ فَأَكَلَتْ فَمَنْ يَأْخُذُ مَالًا بِحَقِّهِ يُبَارَكُ لَهُ وَمَنْ يَأْخُذُ مَالًا بِغَيْرِ حَقِّهِ فَمَثَلُهُ كَمَثَلِ الَّذِي يَأْكُلُ وَلَا يَشْبَعُ","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Sa'id Al Maqburi] dari ['Iyadl bin Abdullah] bahwa dia mendengar [Abu Sa'id Al Khudri] berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah di hadapan orang-orang, sabdanya: \"Tidak! Demi Allah, tidak ada yang aku khawatirkan atas kalian wahai manusia, kecuali gemerlapnya dunia yang Allah keluarkan.\" Maka seseorang bertanya kepada beliau, \"Wahai Rasulullah, apakah mungkin kebaikan akan mendatangkan keburukan?\" Rasulullah shallallahu 'alaihi wasallam diam beberapa saat, kemudian bertanya: \"Apa yang kamu tanyakan?\" Abu Sa'id berkata, \"Aku menanyakan, \"Apakah mungkin kebaikan akan mendatangkan keburukan?\" Beliau bersabda: \"Sesungguhnya kebaikan itu tidak mendatangkan kecuali kebaikan atau kebaikan itu sendiri. Sungguh, setiap sesuatu yang ditumbuhkan musim semi akan mematikan dengan sia-sia, atau mendekati kematian, kecuali pemakan sayuran, ia terus saja makan hingga apabila lambungnya telah melebar, maka ia akan menghadap matahari sambil mengeluarkan kotorannya dan kencing. Setelahitu ia kembali makan lagi. Maka barangsiapa mendapatkan kekayaan dengan cara yang benar akan diberkahi, dan barangsiapa mendapatkan kekayaan dengan cara yang tidak benar maka perumpamaannya ibarat orang yang makan dan tidak pernah merasa kenyang.\""},"3950":{"ar":"حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ الْمِصْرِيُّ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا عَمْرُو بْنُ الْحَارِثِ أَنَّ بَكْرَ بْنَ سَوَادَةَ حَدَّثَهُ أَنَّ يَزِيدَ بْنَ رَبَاحٍ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا فُتِحَتْ عَلَيْكُمْ خَزَائِنُ فَارِسَ وَالرُّومِ أَيُّ قَوْمٍ أَنْتُمْ قَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ نَقُولُ كَمَا أَمَرَنَا اللَّهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ غَيْرَ ذَلِكَ تَتَنَافَسُونَ ثُمَّ تَتَحَاسَدُونَ ثُمَّ تَتَدَابَرُونَ ثُمَّ تَتَبَاغَضُونَ أَوْ نَحْوَ ذَلِكَ ثُمَّ تَنْطَلِقُونَ فِي مَسَاكِينِ الْمُهَاجِرِينَ فَتَجْعَلُونَ بَعْضَهُمْ عَلَى رِقَابِ بَعْضٍ","id":"Telah menceritakan kepada kami ['Amru bin Sawwad Al Mishri] telah mengabarkan kepadaku [Abdullah bin Wahb] telah memberitakan kepada kami ['Amru bin Al Harits] bahwa [Bakr bin Sawadah] telah menceritakan kepadanya, bahwa [Yazid bin Rabah] menceritakan kepadanya dari [Abdullah bin 'Amru bin Al 'Ash] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Apabila dibukakan untuk kalian perbendaharaan Persia dan Romawi, maka kalian akan menjadi kaum seperti apa?\" Abdurrahman bin 'Auf menjawab, \"Kami akan mengatakan sebagaimana yang diperintahkan Allah kepada kami.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ataukah kalian akan menjadi selain itu? Yaitu kalian saling berlomba-lomba, kemudian saling hasad, saling bermusuhan, saling membuat makar atau seperti itulah! kemudian kalian pergi ke tempat tinggal para Muhajirin, maka sebagian kalian memukul leher sebagian yang lain (berperang).\""},"3951":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى الْمِصْرِيُّ أَخْبَرَنِي ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَهُ عَنْ عَمْرِو بْنِ عَوْفٍ وَهُوَ حَلِيفُ بَنِي عَامِرِ بْنِ لُؤَيٍّ وَكَانَ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ إِلَى الْبَحْرَيْنِ يَأْتِي بِجِزْيَتِهَا وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ صَالَحَ أَهْلَ الْبَحْرَيْنِ وَأَمَّرَ عَلَيْهِمْ الْعَلَاءَ بْنَ الْحَضْرَمِيِّ فَقَدِمَ أَبُو عُبَيْدَةَ بِمَالٍ مِنْ الْبَحْرَيْنِ فَسَمِعَتْ الْأَنْصَارُ بِقُدُومِ أَبِي عُبَيْدَةَ فَوَافَوْا صَلَاةَ الْفَجْرِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ فَتَعَرَّضُوا لَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَآهُمْ ثُمَّ قَالَ أَظُنُّكُمْ سَمِعْتُمْ أَنَّ أَبَا عُبَيْدَةَ قَدِمَ بِشَيْءٍ مِنْ الْبَحْرَيْنِ قَالُوا أَجَلْ يَا رَسُولَ اللَّهِ قَالَ أَبْشِرُوا وَأَمِّلُوا مَا يَسُرُّكُمْ فَوَاللَّهِ مَا الْفَقْرَ أَخْشَى عَلَيْكُمْ وَلَكِنِّي أَخْشَى عَلَيْكُمْ أَنْ تُبْسَطَ الدُّنْيَا عَلَيْكُمْ كَمَا بُسِطَتْ عَلَى مَنْ كَانَ قَبْلَكُمْ فَتَنَافَسُوهَا كَمَا تَنَافَسُوهَا فَتُهْلِكَكُمْ كَمَا أَهْلَكَتْهُمْ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la Al Mishri] telah mengabarkan kepadaku [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] bahwa [Al Miswar bin Al Mahramah] mengabarkan kepadanya dari ['Amru bin 'Auf] seorang sekutu Bani 'Amir bin Lu'ay dan termasuk dari salah seorang sahabat yang ikut serta dalam perang Badr bersama Rasulullah shallallahu 'alaihi wasallam, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutus Abu 'Ubaidah bin Jarrah ke negeri Bahrain untuk mengambil upeti ketika Rasulullah shallallahu 'alaihi wasallam telah membuat perdamaian dengan penduduk Bahrain dan mengangkat Al A'la bin Al Hadlrami sebagai penguasanya. Lalu Abu 'Ubaidah pulang dengan membawa harta benda dari Bahrain, ketika kaum Anshar mendengar kembalinya Abu 'Ubaidah mereka tengah mengerjakan shalat shubuh bersama Rasulullah shallallahu 'alaihi wasallam. Ketika beliau selesai shalat, beliau beranjak pergi, mereka pun mencegahnya sehingga beliau tersenyum melihat tingkah laku mereka. Lalu beliau bersabda: \"Aku kira kalian telah mendengar Abu 'Ubaidah telah kembali dengan membawa sesuatu dari Bahrain?\" para sahabat menjawab, \"Benar wahai Rasulullah.\" Beliau lalu bersabda: \"Berilah kabar gembira dan carilah apa yang dapat membuat kalian gembira. Demi Allah, bukanlah kemiskinan yang aku khawatirkan terhadapa diri kalian, akan tetapi yang aku khawatirkan terhadap diri kalian adalah dibentangkannya kemudahan dunia pada diri kalian sebagaimana dibentangkannya kepada orang-orang sebelum kalian, lalu kalian saling berlomba untuk mendapatkannya sebagaimana mereka berlomba, sehingga harta tersebut akan membinasakan kalian sebagaimana keluasan dunia membinasakan mereka.\""},"3952":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ ح و حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَدَعُ بَعْدِي فِتْنَةً أَضَرَّ عَلَى الرِّجَالِ مِنْ النِّسَاءِ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal As Shawaf] telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Sulaiman At Taimi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Amru bin Rafi'] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Sulaiman At Taimi] dari [Abu Utsman An Nahdi] dari [Usamah bin Zaid] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah saya meninggalkan fitnah yang lebih berbahaya bagi kaum laki-laki daripada wanita.\""},"3953":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ خَارِجَةَ بْنِ مُصْعَبٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ صَبَاحٍ إِلَّا وَمَلَكَانِ يُنَادِيَانِ وَيْلٌ لِلرِّجَالِ مِنْ النِّسَاءِ وَوَيْلٌ لِلنِّسَاءِ مِنْ الرِّجَالِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Kharijah bin Mush'ab] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah di pagi hari melainkan akan ada dua Malaikat yang menyeru, 'Celakalah bagi kaum lelaki yang menyerupai kaum wanita, dan celakalah kaum wanita yang menyerupai kaum laki-laki'.\""},"3954":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا عَلِيُّ بْنُ زَيْدِ بْنِ جُدْعَانَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ خَطِيبًا فَكَانَ فِيمَا قَالَ إِنَّ الدُّنْيَا خَضِرَةٌ حُلْوَةٌ وَإِنَّ اللَّهَ مُسْتَخْلِفُكُمْ فِيهَا فَنَاظِرٌ كَيْفَ تَعْمَلُونَ أَلَا فَاتَّقُوا الدُّنْيَا وَاتَّقُوا النِّسَاءَ","id":"Telah menceritakan kepada kami ['Imran bin Musa Al Laitsi] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ali bin Zaid bin Jud'an] dari [Abu Nadlrah] dari [Abu Sa'id], bahwa Rasulullah shallallahu 'alaihi wasallam berkhutbah, dan di antara isi khutbahnya adalah: 'Sesungguhnya dunia adalah lahan yang hijau dan manis, dan Allah menyerahkannya kepada kalian, lalu Allah akan melihat apa yang kalian kerjakan. Ketahuilah, berhati-hatilah kalian dari (keindahan) dunia dan wanita.\""},"3955":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ مُوسَى بْنِ عُبَيْدَةَ عَنْ دَاوُدَ بْنِ مُدْرِكٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فِي الْمَسْجِدِ إِذْ دَخَلَتْ امْرَأَةٌ مِنْ مُزَيْنَةَ تَرْفُلُ فِي زِينَةٍ لَهَا فِي الْمَسْجِدِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ انْهَوْا نِسَاءَكُمْ عَنْ لُبْسِ الزِّينَةِ وَالتَّبَخْتُرِ فِي الْمَسْجِدِ فَإِنَّ بَنِي إِسْرَائِيلَ لَمْ يُلْعَنُوا حَتَّى لَبِسَ نِسَاؤُهُمْ الزِّينَةَ وَتَبَخْتَرْنَ فِي الْمَسَاجِدِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Musa bin 'Ubaidah] dari [Daud bin Mudrik] dari ['Urwah bin Az Zubair] dari ['Aisyah] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam duduk-duduk di masjid, tiba-tiba seorang wanita dari Muzainah masuk dengan menampakkan perhiasannya, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Wahai manusia sekalian, laranglah isteri-isteri kalian mengenakan perhiasan dan memakai minyak wangi di masjid, sesungguhnya Bani Israil tidak dilaknat kecuali karena wanita mereka memakai perhiasan dan mengenakan minyak wangi (ketika melewati) masjid-masjid.\""},"3956":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَاصِمٍ عَنْ مَوْلَى أَبِي رُهْمٍ وَاسْمُهُ عُبَيْدٌأَنَّ أَبَا هُرَيْرَةَ لَقِيَ امْرَأَةً مُتَطَيِّبَةً تُرِيدُ الْمَسْجِدَ فَقَالَ يَا أَمَةَ الْجَبَّارِ أَيْنَ تُرِيدِينَ قَالَتْ الْمَسْجِدَ قَالَ وَلَهُ تَطَيَّبْتِ قَالَتْ نَعَمْ قَالَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا امْرَأَةٍ تَطَيَّبَتْ ثُمَّ خَرَجَتْ إِلَى الْمَسْجِدِ لَمْ تُقْبَلْ لَهَا صَلَاةٌ حَتَّى تَغْتَسِلَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ashim] dari bekas budak Abu Ruhm yang bernama ['Ubaid] bahwa [Abu Hurairah] pernah berpapasan dengan seorang wanita yang memakai minyak wangi dan ingin pergi ke masjid, maka dia pun bertanya, \"Wahai hamba wanita Al Jabbar, kemanakah kamu hendak pergi?\" wanita itu menjawab, \"Ke masjid.\" Abu Hurairah berkata, \"Untuk Allah juga engkau kenakan wewangian?\" wanita itu menjawab, Ya.\" Abu Hurairah berkata, \"Sungguh, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perempuan mana saja yang memakai minyak wangi kemudian keluar ke masjid, maka tidak akan diterima shalatnya sehingga dia mandi terlebih dahulu.\""},"3957":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَا مَعْشَرَ النِّسَاءِ تَصَدَّقْنَ وَأَكْثِرْنَ مِنْ الِاسْتِغْفَارِ فَإِنِّي رَأَيْتُكُنَّ أَكْثَرَ أَهْلِ النَّارِ فَقَالَتْ امْرَأَةٌ مِنْهُنَّ جَزْلَةٌ وَمَا لَنَا يَا رَسُولَ اللَّهِ أَكْثَرَ أَهْلِ النَّارِ قَالَ تُكْثِرْنَ اللَّعْنَ وَتَكْفُرْنَ الْعَشِيرَ مَا رَأَيْتُ مِنْ نَاقِصَاتِ عَقْلٍ وَدِينٍ أَغْلَبَ لِذِي لُبٍّ مِنْكُنَّ قَالَتْ يَا رَسُولَ اللَّهِ وَمَا نُقْصَانُ الْعَقْلِ وَالدِّينِ قَالَ أَمَّا نُقْصَانِ الْعَقْلِ فَشَهَادَةُ امْرَأَتَيْنِ تَعْدِلُ شَهَادَةَ رَجُلٍ فَهَذَا مِنْ نُقْصَانِ الْعَقْلِ وَتَمْكُثُ اللَّيَالِيَ مَا تُصَلِّي وَتُفْطِرُ فِي رَمَضَانَ فَهَذَا مِنْ نُقْصَانِ الدِّينِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Al Had] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Wahai para wanita, perbanyaklah sedekah dan istighfar, sungguh saya melihat kebanyakan kalian adalah penghuni neraka.\" Lalu seorang wanita berbadan gemuk dari mereka bertanya, \"Wahai Rasulullah, kenapa kami yang paling banyak masuk ke dalam neraka?\" Beliau menjawab: \"Kalian banyak melaknat dan mengkhianati perlakuan suami, saya tidak pernah melihat makhluk berakal yang akal dan agamanya kurang selain kalian.\" Wanita tersebut kembali bertanya, \"Wahai Rasulullah, apa yang di maksud dengan kekurangan akal dan agama?\" beliau menjawab: \"Adapun akalnya kurang disebabkan karena kesaksian dua orang wanita sama dengan kesaksian seorang laki-laki, ini termasuk dari kekurangan akal. Kalian berdiam beberapa hati tidak shalat dan berbuka di bulan Ramadan adalah bukti kurangnya agama kalian.\""},"3958":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ عُثْمَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مُرُوا بِالْمَعْرُوفِ وَانْهَوْا عَنْ الْمُنْكَرِ قَبْلَ أَنْ تَدْعُوا فَلَا يُسْتَجَابَ لَكُمْ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Hisyam bin Sa'd] dari ['Amru bin 'Utsman] dari ['Ashim bin Umar bin Utsman] dari ['Urwah] dari ['Aisyah] dia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lakukanlah amar ma'ruf dan nahi munkar sebelum kalian menyeru namun seruan kalian tidak disambut.\""},"3959":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَالَقَامَ أَبُو بَكْرٍ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }وَإِنَّا سَمِعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ إِذَا رَأَوْا الْمُنْكَرَ لَا يُغَيِّرُونَهُ أَوْشَكَ أَنْ يَعُمَّهُمْ اللَّهُ بِعِقَابِهِ قَالَ أَبُو أُسَامَةَ مَرَّةً أُخْرَى فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dia berkata, \" [Abu Bakar] berdiri sambil bersyukur kepada Allah dan memuji-Nya, kemudian dia berkata, \"Wahai sekalian manusia, kalian membaca ayat ini '(Hai orang-orang yang beriman, jagalah dirimu, tiadalah orang yang sesat itu akan memberi mudlarat kepadamu apabila kamu telah mendapat petunjuk) ' (Qs. Al Maidah: 105), dan sesungguhnya kami mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya manusia apabila melihat kemungkaran, kemudian mereka tidak merubahnya di khawatirkan Allah akan meratakan adzab-Nya kepada mereka.\" Sekali waktu Abu Usamah menyebutkan, \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda.\""},"3960":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَنِي إِسْرَائِيلَ لَمَّا وَقَعَ فِيهِمْ النَّقْصُ كَانَ الرَّجُلُ يَرَى أَخَاهُ عَلَى الذَّنْبِ فَيَنْهَاهُ عَنْهُ فَإِذَا كَانَ الْغَدُ لَمْ يَمْنَعْهُ مَا رَأَى مِنْهُ أَنْ يَكُونَ أَكِيلَهُ وَشَرِيبَهُ وَخَلِيطَهُ فَضَرَبَ اللَّهُ قُلُوبَ بَعْضِهِمْ بِبَعْضٍ وَنَزَلَ فِيهِمْ الْقُرْآنُ فَقَالَ{ لُعِنَ الَّذِينَ كَفَرُوا مِنْ بَنِي إِسْرَائِيلَ عَلَى لِسَانِ دَاوُدَ وَعِيسَى ابْنِ مَرْيَمَ حَتَّى بَلَغَ وَلَوْ كَانُوا يُؤْمِنُونَ بِاللَّهِ وَالنَّبِيِّ وَمَا أُنْزِلَ إِلَيْهِ مَا اتَّخَذُوهُمْ أَوْلِيَاءَ وَلَكِنَّ كَثِيرًا مِنْهُمْ فَاسِقُونَ }قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئًا فَجَلَسَ وَقَالَ لَا حَتَّى تَأْخُذُوا عَلَى يَدَيْ الظَّالِمِ فَتَأْطِرُوهُ عَلَى الْحَقِّ أَطْرًاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ أَمْلَاهُ عَلَيَّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْوَضَّاحِ عَنْ عَلِيِّ بْنِ بَذِيمَةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika terjadi krisis moral di tengah-tengah Bani Israil, ada seorang laki-laki melihat saudaranya berbuat dosa, maka dia pun melarangnya. Namun di esok harinya dia tidak mencegahnya dari apa yang dia lihat dari saudaranya supaya dia menjadi teman makan, teman minum dan teman bergaul. Maka Allah menutup hati mereka dengan sebagian yang lain, dan turunlah ayat Al Quran mengenai diri mereka, Allah berfirman: '(Telah dilaknati orang-orang kafir dari Bani Israil dengan lisan Daud dan 'Isa putera Maryam...) ' sampai pada ayat '(Sekiranya mereka beriman kepada Allah, kepada Nabi (Musa) dan kepada apa yang diturunkan kepadanya (Nabi), niscaya mereka tidak akan mengambil orang-orang musyrikin itu menjadi penolong-penolong, tapi kebanyakan dari mereka adalah orang-orang yang fasik) ' (Qs. Al Maidah: 78-81). Abu 'Ubaidah berkata, \"Rasulullah shallallahu 'alaihi wasallam pada saat itu bersandar kemudian duduk seraya bersabda: \"Tidak, sehingga kalian mengambil dari kedua tangan orang yang zhalim, kemudian kalian benar-benar meletakkannya kepada jalan yang benar.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] yang ia diktekan kepadaku, telah menceritakan kepada kami [Muhammad bin Abu Al Waddlah] dari [Ali bin Badzimah] dari [Abu 'Ubaidah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"3961":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا عَلِيُّ بْنُ زَيْدِ بْنِ جَدْعَانَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ خَطِيبًا فَكَانَ فِيمَا قَالَ أَلَا لَا يَمْنَعَنَّ رَجُلًا هَيْبَةُ النَّاسِ أَنْ يَقُولَ بِحَقٍّ إِذَا عَلِمَهُقَالَ فَبَكَى أَبُو سَعِيدٍ وَقَالَ قَدْ وَاللَّهِ رَأَيْنَا أَشْيَاءَ فَهِبْنَا","id":"Telah menceritakan kepada kami [Imran bin Musa] telah memberitakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ali bin Zaid bin Jad'an] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam berdiri menyampaikan khutbah, dan di antara isi khutbah beliau adalah: \"Ketahuilah, jangan sekali-kali seseorang terhalangi untuk menyampaikan kebenaran yang ia lihat karena takut kepada orang.\" Abu Nadlrah berkata, \"Lalu Abu Sa'id menangis dan berkata, \"Sungguh, demi Allah, kami telah melihat kemungkaran tersebut, namun kami takut.\""},"3962":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْقِرْ أَحَدُكُمْ نَفْسَهُ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ يَحْقِرُ أَحَدُنَا نَفْسَهُ قَالَ يَرَى أَمْرًا لِلَّهِ عَلَيْهِ فِيهِ مَقَالٌ ثُمَّ لَا يَقُولُ فِيهِ فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ لَهُ يَوْمَ الْقِيَامَةِ مَا مَنَعَكَ أَنْ تَقُولَ فِي كَذَا وَكَذَا فَيَقُولُ خَشْيَةُ النَّاسِ فَيَقُولُ فَإِيَّايَ كُنْتَ أَحَقَّ أَنْ تَخْشَى","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Mu'awiyah] dari [Al A'masy] dari ['Amru bin Murrah] dari [Abu Al Bahtari] dari [Abu Sa'id] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang mencela dirinya sendiri.\" Mereka bertanya, \"Wahai Rasulullah, bagaimana seseorang mencela dirinya sendiri?\" Beliau menjawab: \"Dia melihat perkara Allah diperbincangkan, lalu dia tidak mengatakan (pembelaan) kepadanya, maka Allah 'azza wajalla akan berkata kepadanya kelak di hari Kiamat; 'Apa yang mencegahmu untuk mengatakan begini dan begini! ' lalu ia menjawab, 'Saya takut terhadap manusia'. Maka Allah pun berfirman: 'Aku lebih berhak untuk kamu takuti'.\""},"3963":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عُبَيْدِ اللَّهِ بْنِ جَرِيرٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ قَوْمٍ يُعْمَلُ فِيهِمْ بِالْمَعَاصِي هُمْ أَعَزُّ مِنْهُمْ وَأَمْنَعُ لَا يُغَيِّرُونَ إِلَّا عَمَّهُمْ اللَّهُ بِعِقَابٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari ['Ubaidullah bin Jarir] dari [Ayahnya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah suatu kaum yang memberlakukan kemaksiatan di antara mereka -padahal ia berkuasa dan berwenang dari kaum itu- melainkan Allah akan meratakan adzab terhadap mereka semua.\""},"3964":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍقَالَ لَمَّا رَجَعَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُهَاجِرَةُ الْبَحْرِ قَالَ أَلَا تُحَدِّثُونِي بِأَعَاجِيبِ مَا رَأَيْتُمْ بِأَرْضِ الْحَبَشَةِ قَالَ فِتْيَةٌ مِنْهُمْ بَلَى يَا رَسُولَ اللَّهِ بَيْنَا نَحْنُ جُلُوسٌ مَرَّتْ بِنَا عَجُوزٌ مِنْ عَجَائِزِ رَهَابِينِهِمْ تَحْمِلُ عَلَى رَأْسِهَا قُلَّةً مِنْ مَاءٍ فَمَرَّتْ بِفَتًى مِنْهُمْ فَجَعَلَ إِحْدَى يَدَيْهِ بَيْنَ كَتِفَيْهَا ثُمَّ دَفَعَهَا فَخَرَّتْ عَلَى رُكْبَتَيْهَا فَانْكَسَرَتْ قُلَّتُهَا فَلَمَّا ارْتَفَعَتْ الْتَفَتَتْ إِلَيْهِ فَقَالَتْ سَوْفَ تَعْلَمُ يَا غُدَرُ إِذَا وَضَعَ اللَّهُ الْكُرْسِيَّ وَجَمَعَ الْأَوَّلِينَ وَالْآخِرِينَ وَتَكَلَّمَتْ الْأَيْدِي وَالْأَرْجُلُ بِمَا كَانُوا يَكْسِبُونَ فَسَوْفَ تَعْلَمُ كَيْفَ أَمْرِي وَأَمْرُكَ عِنْدَهُ غَدًا قَالَ يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَتْ صَدَقَتْ كَيْفَ يُقَدِّسُ اللَّهُ أُمَّةً لَا يُؤْخَذُ لِضَعِيفِهِمْ مِنْ شَدِيدِهِمْ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Yahya bin Sulaim] dari [Abdullah bin Utsman bin Khutsaim] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Tatkala rombongan Muhajirin yang menyeberangi lautan kembali kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Maukah kalian menceritakan kepada kami hal-hal yang mengagumkan yang pernah kalian lihat di bumi Habasyah?\" Sekelompok pemuda dari mereka berkata, \"Baik ya Rasulullah, ketika kami sedang duduk-duduk, lewatlah seorang wanita tua dari biarawati mereka sedang memanggul tempayan air di atas kepala. Kemudian wanita tua itu melewati seorang pemuda dari kaumnya, hingga pemuda itu meletakkan salah satu tangannya di antara pundak wanita tersebut, lalu pemuda itu mendorongnya sehingga nenek itu tersungkur di atas kedua lututnya dan tempayan airnya pecah. Ketika wanita tua itu berdiri, dia menoleh ke pemuda dan berkata, 'Suatu saat kamu akan mengetahui wahai pengkhianat, di saat Allah meletakkan kursi-Nya dan mengumpulkan orang yang terdahulu dan yang terakhir, tangan-tangan dan kaki-kaki akan berbicara bersaksi terhadap apa yang mereka kerjakan. Dan kamu akan mengetahui bagaimana urusanku dan urusanmu di sisi-Nya kelak'.\" Jabir berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita tua itu benar, wanita tua itu benar, bagaimana mungkin Allah akan memberkati suatu kaum dimana yang lemah tidak dibela oleh yang kuat! \""},"3965":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُصْعَبٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عُبَادَةَ الْوَاسِطِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَا حَدَّثَنَا إِسْرَائِيلُ أَنْبَأَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الْجِهَادِ كَلِمَةُ عَدْلٍ عِنْدَ سُلْطَانٍ جَائِرٍ","id":"Telah menceritakan kepada kami [Al Qasim bin Zakaria bin Dinar] telah menceritakan kepada kami [Abdurrahman bin Mush'ab]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin 'Ubadah Al Wasithi] telah menceritakan kepada kami [Yazid bin Harun] keduanya berkata; telah menceritakan kepada kami [Israil] telah memberitakan kepada kami [Muhammad bin Juhadah] dari ['Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jihad yang paling utama adalah (menyampaikan) kalimat (haq) di depan penguasa yang lalim.\""},"3966":{"ar":"حَدَّثَنَا رَاشِدُ بْنُ سَعِيدٍ الرَّمْلِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي غَالِبٍ عَنْ أَبِي أُمَامَةَ قَالَعَرَضَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ عِنْدَ الْجَمْرَةِ الْأُولَى فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ الْجِهَادِ أَفْضَلُ فَسَكَتَ عَنْهُ فَلَمَّا رَأَى الْجَمْرَةَ الثَّانِيَةَ سَأَلَهُ فَسَكَتَ عَنْهُ فَلَمَّا رَمَى جَمْرَةَ الْعَقَبَةِ وَضَعَ رِجْلَهُ فِي الْغَرْزِ لِيَرْكَبَ قَالَ أَيْنَ السَّائِلُ قَالَ أَنَا يَا رَسُولَ اللَّهِ قَالَ كَلِمَةُ حَقٍّ عِنْدَ ذِي سُلْطَانٍ جَائِرٍ","id":"Telah menceritakan kepada kami [Rasyid bin Sa'id Ar Ramli] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Ghalib] dari [Abu Umamah] dia berkata, \"Seorang lelaki mencegat Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang berada di Jamratul Ula sambil bertanya, \"Wahai Rasulullah, jihad apa yang paling utama?\" beliau mendiamkannya, ketika dia melihat beliau berada di Jumratuts Tsaniyah, dia bertanya lagi tetapi beliau tetap mendiamkannya. Setelah beliau selesai dari Jumratul 'Aqabah, beliau meletakkan kakinya di batang kayu untuk naik ke atas kendaraan, beliau lalu bertanya: \"Di mana orang yang bertanya tadi?\" laki-laki tersebut menjawab, \"Saya wahai Rasulullah.\" Beliau bersabda: \"Kalimat haq (kebenaran) yang disampaikan kepada pemimpin yang lalim.\""},"3967":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ و عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأَخْرَجَ مَرْوَانُ الْمِنْبَرَ فِي يَوْمِ عِيدٍ فَبَدَأَ بِالْخُطْبَةِ قَبْلَ الصَّلَاةِ فَقَالَ رَجُلٌ يَا مَرْوَانُ خَالَفْتَ السُّنَّةَ أَخْرَجْتَ الْمِنْبَرَ فِي هَذَا الْيَوْمِ وَلَمْ يَكُنْ يُخْرَجُ وَبَدَأْتَ بِالْخُطْبَةِ قَبْلَ الصَّلَاةِ وَلَمْ يَكُنْ يُبْدَأُ بِهَا فَقَالَ أَبُو سَعِيدٍ أَمَّا هَذَا فَقَدْ قَضَى مَا عَلَيْهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَأَى مِنْكُمْ مُنْكَرًا فَاسْتَطَاعَ أَنْ يُغَيِّرَهُ بِيَدِهِ فَلْيُغَيِّرْهُ بِيَدِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِقَلْبِهِ وَذَلِكَ أَضْعَفُ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Isma'il bin Raja] dari [Ayahnya] dari [Abu Sa'id Al Khudri] dan [Qais bin Muslim] dari [Thariq bin Syihab] dari [Abu Sa'id Al Khudri] dia berkata, \"Marwan pernah mengeluarkan mimbar saat (shalat) Ied, kemudian dia mengawalinya dengan khutbah sebelum shalat sehingga seorang laki-laki berkata kepadanya, \"Wahai Marwan, kamu telah menyalahi sunnah! Kamu telah mengeluarkan mimbar sedangkan (dalam sunnah Nabi) mimbar tidak di keluarkan. Dan kamu juga memulainya dengan khutbah sebelum shalat, padahal (dalam sunnah Nabi) bukan di awali dengan khutbah.\" Kemudian Abu Sa'id berkata, \"Orang ini telah melaksanakan apa yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam: \"Barangsiapa di antara kalian melihat kemungkaran dan ia mampu merubah dengan tangannya, hendaklah ia merubahnya dengan tangannya. Jika ia tidak mampu hendaklah dengan lisan, apabila tidak mampu hendaklah dengan hatinya. Dan itulah selemah-lemah iman.\""},"3968":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنِي عُتْبَةُ بْنُ أَبِي حَكِيمٍ حَدَّثَنِي عَنْ عَمِّهِ عَمْرِو بْنِ جَارِيَةَ عَنْ أَبِي أُمَيَّةَ الشَّعْبَانِيِّ قَالَأَتَيْتُ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ قَالَ قُلْتُ كَيْفَ تَصْنَعُ فِي هَذِهِ الْآيَةِ قَالَ أَيَّةُ آيَةٍ قُلْتُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }قَالَ سَأَلْتَ عَنْهَا خَبِيرًا سَأَلْتُ عَنْهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَلْ ائْتَمِرُوا بِالْمَعْرُوفِ وَتَنَاهَوْا عَنْ الْمُنْكَرِ حَتَّى إِذَا رَأَيْتَ شُحًّا مُطَاعًا وَهَوًى مُتَّبَعًا وَدُنْيَا مُؤْثَرَةً وَإِعْجَابَ كُلِّ ذِي رَأْيٍ بِرَأْيِهِ وَرَأَيْتَ أَمْرًا لَا يَدَانِ لَكَ بِهِ فَعَلَيْكَ خُوَيْصَةَ نَفْسِكَ فَإِنَّ مِنْ وَرَائِكُمْ أَيَّامَ الصَّبْرِ الصَّبْرُ فِيهِنَّ عَلَى مِثْلِ قَبْضٍ عَلَى الْجَمْرِ لِلْعَامِلِ فِيهِنَّ مِثْلُ أَجْرِ خَمْسِينَ رَجُلًا يَعْمَلُونَ بِمِثْلِ عَمَلِهِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Shadaqah bin Khalid] telah menceritakan kepadaku ['Utbah bin Abu Hakim] telah menceritakan kepadaku dari pamannya ['Amru bin Jariyah] dari [Abu Umayyah As Sya'bani] dia berkata; Saya pernah mendatangi [Abu Tsa'labah Al Khusyani] dan bertanya, \"Apa yang kamu perbuat dengan ayat ini?\" Abu Tsa'labah ganti bertanya, \"Ayat yang mana?\" aku lalu membaca: '(Hai orang-orang yang beriman, jagalah dirimu; tiadalah orang yang sesat itu akan memberi mudharat kepadamu apabila kamu telah mendapat petunjuk) ' (Qs. Al Maidah; 105). Abu Tsa'labah lalu berkata, \"Kamu bertanya kepada orang yang tahu, aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang itu, dan beliau menjawab: \"Yaitu mereka saling memerintahkan kepada kebaikan dan saling melarang pada yang mungkar, sehingga jika kamu melihat bakhil ditaati, hawa nafsu diikuti, dunia yang diprioritaskan, setiap orang bangga dengan pendapatnya, dan kamu melihat perkara tidak sesuai denganmu, maka kamu harus kembalikan kepada mata hatimu. Karena sesungguhnya di belakang kalian adalah hari-hari kesabaran, kesabaran saat itu seperti seseorang menggenggam bara api, bagi orang yang beramal pada saat itu seperti pahala lima puluh orang yang mengamalkan seperti amalannya.\""},"3969":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا زَيْدُ بْنُ يَحْيَى بْنِ عُبَيْدٍ الْخُزَاعِيُّ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو مُعَيْدٍ حَفْصُ بْنُ غَيْلَانَ الرُّعَيْنِيُّ عَنْ مَكْحُولٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقِيلَ يَا رَسُولَ اللَّهِ مَتَى نَتْرُكُ الْأَمْرَ بِالْمَعْرُوفِ وَالنَّهْيَ عَنْ الْمُنْكَرِ قَالَ إِذَا ظَهَرَ فِيكُمْ مَا ظَهَرَ فِي الْأُمَمِ قَبْلَكُمْ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا ظَهَرَ فِي الْأُمَمِ قَبْلَنَا قَالَ الْمُلْكُ فِي صِغَارِكُمْ وَالْفَاحِشَةُ فِي كِبَارِكُمْ وَالْعِلْمُ فِي رُذَالَتِكُمْقَالَ زَيْدٌ تَفْسِيرُ مَعْنَى قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْعِلْمُ فِي رُذَالَتِكُمْ إِذَا كَانَ الْعِلْمُ فِي الْفُسَّاقِ","id":"Telah menceritakan kepada kami [Al Abbas bin Al Walid Ad Dimasyqi] telah menceritakan kepada kami [Zaid bin Yahya bin 'Ubaid Al Khuza'i] telah menceritakan kepada kami [Al Haitsam bin Humaid] telah menceritakan kepada kami [Abu Mu'aid Hafsh bin Ghailan Ar Ru'aini] dari [Makhul] dari [Anas bin Malik] dia berkata, \"Dikatakan, \"Wahai Rasulullah, kapan kita meninggalkan amar ma'ruf dan nahi munkar?\" beliau bersabda: \"Jika telah terjadi pada kalian sebagaimana yang terjadi pada bani Israil, yaitu apabila perbuatan keji dilakukan oleh pembesar-pembesar kalian, dan kekuasaan ada pada orang-orang kecil dari kalian sedangkan ilmu berada pada orang-orang yang hina dari kalian.\" Zaid berkata mengenai tafsir sabda Nabi shallallahu 'alaihi wasallam 'Dan ilmu berada di kalangan orang-orang yang hina di antara kalian', yaitu jika ilmu ada dikalangan orang-orang yang fasik.\""},"3970":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ الْحَسَنِ عَنْ جُنْدُبٍ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْبَغِي لِلْمُؤْمِنِ أَنْ يُذِلَّ نَفْسَهُ قَالُوا وَكَيْفَ يُذِلُّ نَفْسَهُ قَالَ يَتَعَرَّضُ مِنْ الْبَلَاءِ لِمَا لَا يُطِيقُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami ['Amru bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dari [Al Hasan] dari [Jundab] dari [Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak patut bagi seorang mukmin merendahkan dirinya sendiri.\" Para sahabat bertanya, \"Bagaimana seseorang merendahkan dirinya sendiri?\" beliau menjawab: \"Menerjunkan diri pada ujian yang dia tidak mampu menanggungnya.\""},"3971":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَبُو طُوَالَةَ حَدَّثَنَا نَهَارٌ الْعَبْدِيُّ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ لَيَسْأَلُ الْعَبْدَ يَوْمَ الْقِيَامَةِ حَتَّى يَقُولَ مَا مَنَعَكَ إِذْ رَأَيْتَ الْمُنْكَرَ أَنْ تُنْكِرَهُ فَإِذَا لَقَّنَ اللَّهُ عَبْدًا حُجَّتَهُ قَالَ يَا رَبِّ رَجَوْتُكَ وَفَرِقْتُ مِنْ النَّاسِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Abdullah bin Abdurrahman Abu Thuwalah] telah menceritakan kepada kami [Nahar Al 'Abdi] bahwa dia mendengar [Abu Sa'id Al Khudri] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah pasti akan menanyakan hamba-Nya pada hari Kiamat kelak, hingga Dia bertanya, 'Apa yang menghalangimu untuk mencegah kemungkaran ketika kamu melihatnya?\" hamba itu akan menjawab, 'Wahai Rabb, aku mengharapkan ridla-Mu dan mengasingkan diri dari manusia'.\""},"3972":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُمْلِي لِلظَّالِمِ فَإِذَا أَخَذَهُ لَمْ يُفْلِتْهُ ثُمَّ قَرَأَ{ وَكَذَلِكَ أَخْذُ رَبِّكَ إِذَا أَخَذَ الْقُرَى وَهِيَ ظَالِمَةٌ }","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Buraid bin Abdullah bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya jika Allah hendak menyiksa orang-orang zhalim, maka Dia akan menyiksanya tanpa ada satupun yang tertinggal.\" Kemudian beliau membaca: '(Dan begitulah azab Rabbmu, apabila Dia mengazab penduduk negeri-negeri yang berbuat zalim) ' (Qs. Huud; 102)."},"3973":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ الدِّمَشْقِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ أَبُو أَيُّوبَ عَنْ ابْنِ أَبِي مَالِكٍ عَنْ أَبِيهِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَأَقْبَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مَعْشَرَ الْمُهَاجِرِينَ خَمْسٌ إِذَا ابْتُلِيتُمْ بِهِنَّ وَأَعُوذُ بِاللَّهِ أَنْ تُدْرِكُوهُنَّ لَمْ تَظْهَرْ الْفَاحِشَةُ فِي قَوْمٍ قَطُّ حَتَّى يُعْلِنُوا بِهَا إِلَّا فَشَا فِيهِمْ الطَّاعُونُ وَالْأَوْجَاعُ الَّتِي لَمْ تَكُنْ مَضَتْ فِي أَسْلَافِهِمْ الَّذِينَ مَضَوْا وَلَمْ يَنْقُصُوا الْمِكْيَالَ وَالْمِيزَانَ إِلَّا أُخِذُوا بِالسِّنِينَ وَشِدَّةِ الْمَئُونَةِ وَجَوْرِ السُّلْطَانِ عَلَيْهِمْ وَلَمْ يَمْنَعُوا زَكَاةَ أَمْوَالِهِمْ إِلَّا مُنِعُوا الْقَطْرَ مِنْ السَّمَاءِ وَلَوْلَا الْبَهَائِمُ لَمْ يُمْطَرُوا وَلَمْ يَنْقُضُوا عَهْدَ اللَّهِ وَعَهْدَ رَسُولِهِ إِلَّا سَلَّطَ اللَّهُ عَلَيْهِمْ عَدُوًّا مِنْ غَيْرِهِمْ فَأَخَذُوا بَعْضَ مَا فِي أَيْدِيهِمْ وَمَا لَمْ تَحْكُمْ أَئِمَّتُهُمْ بِكِتَابِ اللَّهِ وَيَتَخَيَّرُوا مِمَّا أَنْزَلَ اللَّهُ إِلَّا جَعَلَ اللَّهُ بَأْسَهُمْ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid Ad Dimasyqi] telah menceritakan kepada kami [Sulaiman bin Abdurrahman Abu Ayyub] dari [Ibnu Abu Malik] dari [Ayahnya] dari ['Atha bin Abu Rabah] dari [Abdullah bin Umar] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menghadapkan wajah ke kami dan bersabda: \"Wahai golongan Muhajirin, lima perkara apabila kalian mendapat cobaan dengannya, dan aku berlindung kepada Allah semoga kalian tidak mengalaminya; Tidaklah kekejian menyebar di suatu kaum, kemudian mereka melakukannya dengan terang-terangan kecuali akan tersebar di tengah mereka penyakit Tha'un dan kelaparan yang belum pernah terjadi terhadap para pendahulu mereka. Tidaklah mereka mengurangi timbangan dan takaran kecuali mereka akan disiksa dengan kemarau berkepanjangan dan penguasa yang zhalim. Tidaklah mereka enggan membayar zakat harta-harta mereka kecuali langit akan berhenti meneteskan air untuk mereka, kalau bukan karena hewan-hewan ternak niscaya mereka tidak akan beri hujan. Tidaklah mereka melanggar janji Allah dan Rasul-Nya kecuali Allah akan kuasakan atas mereka musuh dari luar mereka dan menguasainya. Dan tidaklah pemimpin-pemimpin mereka enggan menjalankan hukum-hukum Allah dan tidak menganggap lebih baik apa yang diturunkan Allah, kecuali Allah akan menjadikan rasa takut di antara mereka.\""},"3974":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا مَعْنُ بْنُ عِيسَى عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ حَاتِمِ بْنِ حُرَيْثٍ عَنْ مَالِكِ بْنِ أَبِي مَرْيَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ الْأَشْعَرِيِّ عَنْ أَبِي مَالِكٍ الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَشْرَبَنَّ نَاسٌ مِنْ أُمَّتِي الْخَمْرَ يُسَمُّونَهَا بِغَيْرِ اسْمِهَا يُعْزَفُ عَلَى رُءُوسِهِمْ بِالْمَعَازِفِ وَالْمُغَنِّيَاتِ يَخْسِفُ اللَّهُ بِهِمْ الْأَرْضَ وَيَجْعَلُ مِنْهُمْ الْقِرَدَةَ وَالْخَنَازِيرَ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Ma'n bin Isa] dari [Mu'awiyah bin Shalih] dari [Hatim bin Huraits] dari [Malik bin Abu Maryam] dari [Abdurrahman bin Ghanm Al Asy'ari] dari [Abu Malik Al Asy'ari] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, sebagian dari ummatku akan meminum khamer yang mereka namai dengan selain namanya, akan bernyanyi dengan para biduan disertai dengan alat musik. Allah akan menutupi kehidupan mereka dan akan menjadikan sebagian mereka kera dan babi.\""},"3975":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَمَّارُ بْنُ مُحَمَّدٍ عَنْ لَيْثٍ عَنْ الْمِنْهَالِ عَنْ زَاذَانَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْعَنُهُمْ اللَّهُ وَيَلْعَنُهُمْ اللَّاعِنُونَ قَالَ دَوَابُّ الْأَرْضِ","id":"Telah menceritakan kepada kami [Muhammad bin As Shabah] telah menceritakan kepada kami ['Ammar bin Muhammad] dari [Laits] dari [Al Minhal] dari [Zadzan] dari [Al Barra bin 'Azib] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan melaknat mereka dan para pelaknat pun akan melaknat mereka.\" Beliau juga bersabda: \"Begitu juga dengan hewan melata yang ada muka bumi.\""},"3976":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْجَعْدِ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزِيدُ فِي الْعُمْرِ إِلَّا الْبِرُّ وَلَا يَرُدُّ الْقَدَرَ إِلَّا الدُّعَاءُ وَإِنَّ الرَّجُلَ لَيُحْرَمُ الرِّزْقَ بِالذَّنْبِ يُصِيبُهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdullah bin Isa] dari [Abdullah bin Abu Al Ja'd] dari [Tsauban] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah akan bertambah umur (seseorang) kecuali dengan kebaikan, dan tidaklah akan dapat menolak takdir kecuali doa. Sesungguhnya seseorang akan ditahan rizkinya karena dosa yang dia lakukan.\""},"3977":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ حَمَّادٍ الْمَعْنِيُّ وَيَحْيَى بْنُ دُرُسْتَ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ أَشَدُّ بَلَاءً قَالَ الْأَنْبِيَاءُ ثُمَّ الْأَمْثَلُ فَالْأَمْثَلُ يُبْتَلَى الْعَبْدُ عَلَى حَسَبِ دِينِهِ فَإِنْ كَانَ فِي دِينِهِ صُلْبًا اشْتَدَّ بَلَاؤُهُ وَإِنْ كَانَ فِي دِينِهِ رِقَّةٌ ابْتُلِيَ عَلَى حَسَبِ دِينِهِ فَمَا يَبْرَحُ الْبَلَاءُ بِالْعَبْدِ حَتَّى يَتْرُكَهُ يَمْشِي عَلَى الْأَرْضِ وَمَا عَلَيْهِ مِنْ خَطِيئَةٍ","id":"Telah menceritakan kepada kami [Yusuf bin Hammad Al Ma'ni] dan [Yahya bin Durusta] keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim] dari [Mush'ab bin Sa'd] dari [Ayahnya Sa'd bin Abu Waqash] dia berkata, \"Saya bertanya, \"Wahai Rasulullah, siapakah orang yang paling keras cobaannya?\" beliau menjawab: \"Para Nabi, kemudian kalangan selanjutnya (yang lebih utama) dan selanjutnya. Seorang hamba akan diuji sesuai kadar agamanya (keimanannya). Jika keimanannya kuat maka cobaannya pun akan semakin berat. Jika keimanannya lemah maka ia akan diuji sesuai dengan kadarnya imannya. Tidaklah cobaan ini akan diangkat dari seorang hamba hingga Allah membiarkan mereka berjalan di muka bumi dengan tanpa dosa.\""},"3978":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ حَدَّثَنِي هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُوعَكُ فَوَضَعْتُ يَدِي عَلَيْهِ فَوَجَدْتُ حَرَّهُ بَيْنَ يَدَيَّ فَوْقَ اللِّحَافِ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَشَدَّهَا عَلَيْكَ قَالَ إِنَّا كَذَلِكَ يُضَعَّفُ لَنَا الْبَلَاءُ وَيُضَعَّفُ لَنَا الْأَجْرُ قُلْتُ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ أَشَدُّ بَلَاءً قَالَ الْأَنْبِيَاءُ قُلْتُ يَا رَسُولَ اللَّهِ ثُمَّ مَنْ قَالَ ثُمَّ الصَّالِحُونَ إِنْ كَانَ أَحَدُهُمْ لَيُبْتَلَى بِالْفَقْرِ حَتَّى مَا يَجِدُ أَحَدُهُمْ إِلَّا الْعَبَاءَةَ يُحَوِّيهَا وَإِنْ كَانَ أَحَدُهُمْ لَيَفْرَحُ بِالْبَلَاءِ كَمَا يَفْرَحُ أَحَدُكُمْ بِالرَّخَاءِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Ibnu Abu Fudaik] telah menceritakan kepadaku [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Sa'id Al Khudri] dia berkata, \"Aku pernah menjenguk Nabi shallallahu 'alaihi wasallam ketika beliau sedang sakit panas, aku meletakkan tanganku dan aku mendapati panasnya terasa hingga di atas selimut. Aku lalu berkata, \"Wahai Rasulullah, alangkah panasnya sakit yang menimpa dirimu.\" Beliau bersabda: \"Sesungguhnya begitulah kita, ketika dilipat gandakan cobaan bagi kita maka akan dilipat gandakan pula pahalanya.\" Aku bertanya, \"Wahai Rasulullah, siapakah manusia yang paling keras cobaannya?\" beliau menjawab: \"Para nabi.\" Aku bertanya lagi, \"Wahai Rasulullah, kemudian siapa?\" Beliau menjawab: \"Kemudian orang-orang shalih, salah seorang di antara mereka yang dicoba dengan kefakiran sehingga tidak menemukan kecuali mantel untuk dia pakai, dan ada salah seorang dari mereka yang senang dengan cobaan sebagaimana salah seorang dari kalian senang dengan kemewahan.\""},"3979":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَكَأَنِّي أَنْظُرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَحْكِي نَبِيًّا مِنْ الْأَنْبِيَاءِ ضَرَبَهُ قَوْمُهُ وَهُوَ يَمْسَحُ الدَّمَ عَنْ وَجْهِهِ وَيَقُولُ رَبِّ اغْفِرْ لِقَوْمِي فَإِنَّهُمْ لَا يَعْلَمُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah] dia berkata, \"Seakan aku melihat Rasulullah shallallahu 'alaihi wasallam -saat itu beliau menceritakan seorang Nabi dari para Nabi yang pernah di sakiti oleh kaumnya-, beliau mengusap darah dari wajahnya sambil bersabda: 'Wahai Rabbku, ampunilah kaumku karena sesungguhnya mereka tidak mengetahui'.\""},"3980":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى وَيُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ إِذْ قَالَ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوَلَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي وَيَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ طُولَ مَا لَبِثَ يُوسُفُ لَأَجَبْتُ الدَّاعِيَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] dan [Yunus bin Abdul A'la] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman bin 'Auf] dan [Sa'id bin Al Musayyab] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami lebih berhak ragu daripada Ibrahim, ketika dia berkata, '(Dan (Ingatlah) ketika Ibrahim berkata: \"Ya Tuhanku, perlihatkanlah kepadaku bagaimana Engkau menghidupkan orang-orang mati.\" Allah berfirman: \"Belum yakinkah kamu?\" Ibrahim menjawab: \"Aku telah meyakinkannya, akan tetapi agar hatiku tetap mantap (dengan imanku) ' (Qs. Al Baqarah: 260). Dan Allah telah merahmati Nabi Luth karena beliau telah berlindung kepada keluarga yang kuat. Dan sekiranya aku dipenjara selama Nabi Yusuf dipenjara, pastilah aku tetap menunaikan panggilan.\""},"3981":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ كُسِرَتْ رَبَاعِيَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَشُجَّ فَجَعَلَ الدَّمُ يَسِيلُ عَلَى وَجْهِهِ وَجَعَلَ يَمْسَحُ الدَّمَ عَنْ وَجْهِهِ وَيَقُولُ كَيْفَ يُفْلِحُ قَوْمٌ خَضَبُوا وَجْهَ نَبِيِّهِمْ بِالدَّمِ وَهُوَ يَدْعُوهُمْ إِلَى اللَّهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ }","id":"Telah menceritakan kepada kami [Nahsr bin Ali Al Jahdlami] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Abdul Wahb] telah menceritakan kepada kami [Humaid] dari [Anas bin Malik] dia berkata, \"Ketika terjadi perang Uhud, antara gigi geraham Rasulullah shallallahu 'alaihi wasallam pecah sehingga darah mengalir ke wajahnya. Sambil mengusap darah yang mengalir di wajahnya, Rasulullah bersabda: \"Bagaimana suatu kaum akan beruntung sedangkan mereka telah melumuri wajah nabinya darah! Padahal dia menyeru mereka kembali kepada Allah Azza wa Jalla '(Tak ada sedikitpun campur tanganmu dalam urusan…) ' (Qs. Ali Imaran: 128)."},"3982":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْصُوا لِي كُلَّ مَنْ تَلَفَّظَ بِالْإِسْلَامِ قُلْنَا يَا رَسُولَ اللَّهِ أَتَخَافُ عَلَيْنَا وَنَحْنُ مَا بَيْنَ السِّتِّ مِائَةِ إِلَى السَّبْعِ مِائَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ لَا تَدْرُونَ لَعَلَّكُمْ أَنْ تُبْتَلُوا قَالَ فَابْتُلِينَا حَتَّى جَعَلَ الرَّجُلُ مِنَّا مَا يُصَلِّي إِلَّا سِرًّا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Hudzaifah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hitunglah untukku setiap orang yang mengucapkan (pengakuan) Islam.\" Kami bertanya, \"Wahai Rasulullah, apakah anda khawatir kepada kami, sedangkan kami berjumlah antara enam ratus sampai tujuh ratus orang?\" Beliau bersabda: \"Kalian tidak mengetahui ujian yang akan menimpa kalian.\" Hudzaifah berkata, \"Maka kami benar-benar diuji, sehingga salah seorang dari kami tidak melakukan shalat kecuali secara sembunyi-sembunyi.\""},"3983":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَيْلَةَ أُسْرِيَ بِهِ وَجَدَ رِيحًا طَيِّبَةً فَقَالَ يَا جِبْرِيلُ مَا هَذِهِ الرِّيحُ الطَّيِّبَةُ قَالَ هَذِهِ رِيحُ قَبْرِ الْمَاشِطَةِ وَابْنَيْهَا وَزَوْجِهَا قَالَ وَكَانَ بَدْءُ ذَلِكَ أَنَّ الْخَضِرَ كَانَ مِنْ أَشْرَافِ بَنِي إِسْرَائِيلَ وَكَانَ مَمَرُّهُ بِرَاهِبٍ فِي صَوْمَعَتِهِ فَيَطَّلِعُ عَلَيْهِ الرَّاهِبُ فَيُعَلِّمُهُ الْإِسْلَامَ فَلَمَّا بَلَغَ الْخَضِرُ زَوَّجَهُ أَبُوهُ امْرَأَةً فَعَلَّمَهَا الْخَضِرُ وَأَخَذَ عَلَيْهَا أَنْ لَا تُعْلِمَهُ أَحَدًا وَكَانَ لَا يَقْرَبُ النِّسَاءَ فَطَلَّقَهَا ثُمَّ زَوَّجَهُ أَبُوهُ أُخْرَى فَعَلَّمَهَا وَأَخَذَ عَلَيْهَا أَنْ لَا تُعْلِمَهُ أَحَدًا فَكَتَمَتْ إِحْدَاهُمَا وَأَفْشَتْ عَلَيْهِ الْأُخْرَى فَانْطَلَقَ هَارِبًا حَتَّى أَتَى جَزِيرَةً فِي الْبَحْرِ فَأَقْبَلَ رَجُلَانِ يَحْتَطِبَانِ فَرَأَيَاهُ فَكَتَمَ أَحَدُهُمَا وَأَفْشَى الْآخَرُ وَقَالَ قَدْ رَأَيْتُ الْخَضِرَ فَقِيلَ وَمَنْ رَآهُ مَعَكَ قَالَ فُلَانٌ فَسُئِلَ فَكَتَمَ وَكَانَ فِي دِينِهِمْ أَنَّ مَنْ كَذَبَ قُتِلَ قَالَ فَتَزَوَّجَ الْمَرْأَةَ الْكَاتِمَةَ فَبَيْنَمَا هِيَ تَمْشُطُ ابْنَةَ فِرْعَوْنَ إِذْ سَقَطَ الْمُشْطُ فَقَالَتْ تَعِسَ فِرْعَوْنُ فَأَخْبَرَتْ أَبَاهَا وَكَانَ لِلْمَرْأَةِ ابْنَانِ وَزَوْجٌ فَأَرْسَلَ إِلَيْهِمْ فَرَاوَدَ الْمَرْأَةَ وَزَوْجَهَا أَنْ يَرْجِعَا عَنْ دِينِهِمَا فَأَبَيَا فَقَالَ إِنِّي قَاتِلُكُمَا فَقَالَا إِحْسَانًا مِنْكَ إِلَيْنَا إِنْ قَتَلْتَنَا أَنْ تَجْعَلَنَا فِي بَيْتٍ فَفَعَلَ فَلَمَّا أُسْرِيَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ رِيحًا طَيِّبَةً فَسَأَلَ جِبْرِيلَ فَأَخْبَرَهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] dari [Mujahid] dari [Ibnu Abbas] dari [Ubay bin Ka'ab] dari Nabi shallallahu 'alaihi wasallam, bahwa ketika malam diisra`kan, beliau menemukan bau yang sangat harum. Maka beliau pun bertanya: \"Wahai Jibril, apakah bau harum ini?\" Jibril menjawab, \"Ini adalah bau harum kuburanya Masyithah, kedua anaknya beserta suami.\" Jibril melanjutkan, \"Pada awal mulanya, khidlir termasuk dari kalangan orang-orang mulia Bani Israil dan dia sering melewati seorang Rahib yang tinggal di biara. Setiap kali lewat Rahib itu muncul ke hadapannya, lantas dia mengajarkan Islam kepadanya. Tatkala Khidlir telah mencapai aqil baligh, bapaknya menikahkannya dengan seorang perempuan, maka Khidlir pun mengajarkan (Islam) kepada isterinya. Lalu dia minta kepada isterinya agar tidak memberitahukan ajaran tersebut kepada seorangpun. Karena Khidlir tidak pernah mendekati seorang wanita, maka dia mentalaknya, kemudian ayahnya menikahkannya lagi dengan wanita lain, maka Khidlir pun mengajarkan kepada isterinya yang baru dan meminta kepadanya agar tidak memberitahukan ajaran tersebut kepada seorangpun. Ternyata salah seorang dari keduanya menyembunyikannya dan yang lainnya menyebarkannya, Maka dia bergegas pergi sehingga tiba di suatu pulau di tengah laut. Dan di sana dua lelaki yang sedang mencari kayu melihatnya, maka salah seorang darinya menyembunyikan sedang yang lain menyebarkan, Orang yang menyebarkan (berita itu) berkata, \"Aku telah melihat Khidlir.\" Maka dia ditanya, \"Dengan siapa kamu melihatnya.\" Dia menjawab, \"Dengan fulan.\" Laki-laki itu berkata lagi, \"Tetapi dia menyembunyikannya. Dan kebiasaan dalam agama mereka, bahwa siapa berdusta maka akan dibunuh.\" Dia menuturkan kembali, \"Maka laki-laki itu menikahi seorang perempuan yang bisa menjaga rahasia, ketika dia sedang menyisir anak perempuan Fir'aun, tiba-tiba sisirnya terjatuh, sambil berkata, \"Celaka Fir'aun.\" Maka puterinya memberitahukan kepada bapaknya. Sedangkan wanita itu memiliki dua orang anak dan suami. Maka Fir'aun mengutus utusan kepada perempuan itu dan suaminya untuk merayu agar kembali kepada agamanya, tetapi keduanya menolak, maka utusan itu berkata, \"Aku akan membunuh kalian berdua.\" Keduanya berkata, \"Sebagai budi baik darimu kepada kami, apabila kamu membunuh kami hendaknya kamu jadikan kami di satu rumah.\" Maka dia melakukannya.\" Tatkala Nabi shallallahu 'alaihi wasallam di israkan, beliau mendapati bau harum, maka dia bertanya kepada Jibril dan Jibril pun memberitahukan kepada beliau.\""},"3984":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعْدِ بْنِ سِنَانٍ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ عِظَمُ الْجَزَاءِ مَعَ عِظَمِ الْبَلَاءِ وَإِنَّ اللَّهَ إِذَا أَحَبَّ قَوْمًا ابْتَلَاهُمْ فَمَنْ رَضِيَ فَلَهُ الرِّضَا وَمَنْ سَخِطَ فَلَهُ السُّخْطُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepadaku [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Sa'd bin Sinan] dari [Anas bin Malik] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Besarnya pahala sesuai dengan besarnya cobaan, dan sesungguhnya apabila Allah mencintai suatu kaum maka Dia akan menguji mereka. Oleh karena itu, barangsiapa ridla (menerima cobaan tersebut) maka baginya keridlaan, dan barangsiapa murka maka baginya kemurkaan.\""},"3985":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثٌ مَنْ كُنَّ فِيهِ وَجَدَ طَعْمَ الْإِيمَانِ وَقَالَ بُنْدَارٌ حَلَاوَةَ الْإِيمَانِ مَنْ كَانَ يُحِبُّ الْمَرْءَ لَا يُحِبُّهُ إِلَّا لِلَّهِ وَمَنْ كَانَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَمَنْ كَانَ أَنْ يُلْقَى فِي النَّارِ أَحَبَّ إِلَيْهِ مِنْ أَنْ يَرْجِعَ فِي الْكُفْرِ بَعْدَ إِذْ أَنْقَذَهُ اللَّهُ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; saya mendengar [Qatadah] menceritakan dari [Anas bin Malik] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga hal yang siapa terdapat dalam dirinya, maka ia akan merasakan rasanya iman -Bundar menyebutkan; Manisnya iman-, yaitu; barangsiapa mencintai seseorang dan dia tidak mencintainya kecuali karena Allah, barangsiapa menjadikan Allah dan Rasul-Nya lebih ia cintai dari selain keduanya, dan orang yang lebih suka dilempar ke dalam api daripada ia kembali kepada kekafiran setelah Allah menyelamatkan darinya (kekafiran).\""},"3986":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ ح و حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ قَالَا حَدَّثَنَا رَاشِدٌ أَبُو مُحَمَّدٍ الْحِمَّانِيُّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَأَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا تُشْرِكْ بِاللَّهِ شَيْئًا وَإِنْ قُطِّعْتَ وَحُرِّقْتَ وَلَا تَتْرُكْ صَلَاةً مَكْتُوبَةً مُتَعَمِّدًا فَمَنْ تَرَكَهَا مُتَعَمِّدًا فَقَدْ بَرِئَتْ مِنْهُ الذِّمَّةُ وَلَا تَشْرَبْ الْخَمْرَ فَإِنَّهَا مِفْتَاحُ كُلِّ شَرٍّ","id":"Telah menceritakan kepada kami [Al Husain bin Hasan Al Mawarzi] telah menceritakan kepada kami [Ibnu Abu 'Adi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] telah menceritakan kepada kami [Abdul Wahab bin 'Atha] keduanya berkata; telah menceritakan kepada kami [Rasyid Abu Muhammad Al Himmani] dari [Syahr bin Hausyab] dari [Ummu Darda] dari [Abu Darda] dia berkata, \"Kekasihku telah mewasiatkan kepadaku agar tidak menyekutukan Allah dengan sesuatupun, meski kamu harus disembelih dan dibakar, janganlah kamu meninggalkan shalat wajib dengan sengaja, barangsiapa meninggalkannya dengan sengaja maka telah lepas dari tanggungan (Allah). Dan janganlah kamu meminum khamer, sebab khamar itu merupakan kunci semua kejahatan.\""},"3987":{"ar":"حَدَّثَنَا غِيَاثُ بْنُ جَعْفَرٍ الرَّحَبِيُّ أَنْبَأَنَا الْوَلِيدُ بْنُ مُسْلِمٍ سَمِعْتُ ابْنَ جَابِرٍ يَقُولُ قَالَ سَمِعْتُ أَبَا عَبْدِ رَبِّهِ يَقُولُ سَمِعْتُ مُعَاوِيَةَ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَمْ يَبْقَ مِنْ الدُّنْيَا إِلَّا بَلَاءٌ وَفِتْنَةٌ","id":"Telah menceritakan kepada kami [Ghiyats bin Ja'far Ar Rahabi] telah memberitakan kepada kami [Al Walid bin Muslim] saya mendengar [Ibnu Jabir] berkata; katanya; saya mendengar [Abu Abdu Rabbihi] berkata; saya mendengar [Mu'awiyah] berkata, \"Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah akan tersisa dari dunia ini melainkan cobaan dan fitnah.\""},"3988":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ قُدَامَةَ الْجُمَحِيُّ عَنْ إِسْحَقَ بْنِ أَبِي الْفُرَاتِ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيَأْتِي عَلَى النَّاسِ سَنَوَاتٌ خَدَّاعَاتُ يُصَدَّقُ فِيهَا الْكَاذِبُ وَيُكَذَّبُ فِيهَا الصَّادِقُ وَيُؤْتَمَنُ فِيهَا الْخَائِنُ وَيُخَوَّنُ فِيهَا الْأَمِينُ وَيَنْطِقُ فِيهَا الرُّوَيْبِضَةُ قِيلَ وَمَا الرُّوَيْبِضَةُ قَالَ الرَّجُلُ التَّافِهُ فِي أَمْرِ الْعَامَّةِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Abdul Malik bin Qudamah Al Jumahi] dari [Ishaq bin Abu Furat] dari [Al Maqburi] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan datang tahun-tahun penuh dengan kedustaan yang menimpa manusia, pendusta dipercaya, orang yang jujur didustakan, amanat diberikan kepada pengkhianat, orang yang jujur dikhianati, dan Ruwaibidlah turut bicara.\" Lalu beliau ditanya, \"Apakah Ruwaibidlah itu?\" beliau menjawab: \"Orang-orang bodoh yang mengurusi urusan perkara umum.\""},"3989":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِي إِسْمَعِيلَ الْأَسْلَمِيِّ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تَذْهَبُ الدُّنْيَا حَتَّى يَمُرَّ الرَّجُلُ عَلَى الْقَبْرِ فَيَتَمَرَّغَ عَلَيْهِ وَيَقُولَ يَا لَيْتَنِي كُنْتُ مَكَانَ صَاحِبِ هَذَا الْقَبْرِ وَلَيْسَ بِهِ الدِّينُ إِلَّا الْبَلَاءُ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Abu Isma'il Al Aslami] dari [Abu Hazim] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi dzat yang jiwaku berada di tangan-Nya, dunia ini tidak akan pergi (Kiamat) sehingga ada seorang laki-laki yang melewati kuburan, lalu dia berhenti di hadapannya sambil berkata, 'Andai aku menjadi penghuni kuburan ini', bagi yang tidak punya agama maka itu adalah ujian.\""},"3990":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَبِي حُمَيْدٍ يَعْنِي مَوْلَى مُسَافِعٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَتُنْتَقَوُنَّ كَمَا يُنْتَقَى التَّمْرُ مِنْ أَغْفَالِهِ فَلْيَذْهَبَنَّ خِيَارُكُمْ وَلَيَبْقَيَنَّ شِرَارُكُمْ فَمُوتُوا إِنْ اسْتَطَعْتُمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Thalhah bin Yahya] dari [Yunus] dari [Az Zuhri] dari [Abu Humaid] -yaitu bekas budak Musafi'- dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh kelak kalian akan dipilah-pilah sebagaimana kurma di pilah-pilah dari yang mentah, karena itu, orang-orang terbaik kalian akan pergi dan yang tersisa adalah orang-orang jahat di antara kalian, maka matilah segera jika kalian bisa.\""},"3991":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ إِدْرِيسَ الشَّافِعِيُّ حَدَّثَنِي مُحَمَّدُ بْنُ خَالِدٍ الْجَنَدِيُّ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزْدَادُ الْأَمْرُ إِلَّا شِدَّةً وَلَا الدُّنْيَا إِلَّا إِدْبَارًا وَلَا النَّاسُ إِلَّا شُحًّا وَلَا تَقُومُ السَّاعَةُ إِلَّا عَلَى شِرَارِ النَّاسِ وَلَا الْمَهْدِيُّ إِلَّا عِيسَى ابْنُ مَرْيَمَ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la] telah menceritakan kepada kami [Muhammad bin Idris As Syafi'i] telah menceritakan kepadaku [Muhammad bin Khalid Al Janadi] dari [Aban bin Shalih] dari [Al Hasan] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah urusan ini bertambah kecuali hanya kekerasan, dan tidaklah dunia ini juga bertambah kecuali akan semakin mundur, dan tidak pula manusia semakin bertambah melainkan akan semakin kikir, dan tidak akan terjadi hari kiamat kecuali pada seburuk-buruk manusia dan tidaklah muncul Al Mahdi kecuali muncul 'Isa bin Maryam.\""},"3992":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ وَأَبُو هِشَامٍ الرِّفَاعِيُّ مُحَمَّدُ بْنُ يَزِيدَ قَالَا حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَاتَيْنِ وَجَمَعَ بَيْنَ إِصْبَعَيْهِ","id":"Telah menceritakan kepada kami [Al Hannad bin As Sarri] dan [Abu Hisyam Ar Rifa'I Muhammad bin Yazid] keduanya berkata; telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] telah menceritakan kepada kami [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diutus dengan datangnya kiamat seperti dekatnya dua ini.\" Beliau menggabungkan kedua jari-jarinya."},"3993":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ فُرَاتٍ الْقَزَّازِ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ قَالَاطَّلَعَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غُرْفَةٍ وَنَحْنُ نَتَذَاكَرُ السَّاعَةَ فَقَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَكُونَ عَشْرُ آيَاتٍ الدَّجَّالُ وَالدُّخَانُ وَطُلُوعُ الشَّمْسِ مِنْ مَغْرِبِهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Furat Al Qazzaz] dari [Abu At Thufail] dari [Hudzaifah bin Asid] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah melihat kami dari kamarnya ketika kami sedang berdiskusi tentang hari Kiamat. Lalu beliau bersabda: \"Kiamat tidak akan terjadi sehingga terjadinya sepuluh tanda-tanda; Dajjal, munculnya awan, terbitnya matahari dari barat.\""},"3994":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ حَدَّثَنِي بُسْرُ بْنُ عُبَيْدِ اللَّهِ حَدَّثَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ حَدَّثَنِي عَوْفُ بْنُ مَالِكٍ الْأَشْجَعِيُّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي غَزْوَةِ تَبُوكَ وَهُوَ فِي خِبَاءٍ مِنْ أَدَمٍ فَجَلَسْتُ بِفِنَاءِ الْخِبَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْخُلْ يَا عَوْفُ فَقُلْتُ بِكُلِّي يَا رَسُولَ اللَّهِ قَالَ بِكُلِّكَ ثُمَّ قَالَ يَا عَوْفُ احْفَظْ خِلَالًا سِتًّا بَيْنَ يَدَيْ السَّاعَةِ إِحْدَاهُنَّ مَوْتِي قَالَ فَوَجَمْتُ عِنْدَهَا وَجْمَةً شَدِيدَةً فَقَالَ قُلْ إِحْدَى ثُمَّ فَتْحُ بَيْتِ الْمَقْدِسِ ثُمَّ دَاءٌ يَظْهَرُ فِيكُمْ يَسْتَشْهِدُ اللَّهُ بِهِ ذَرَارِيَّكُمْ وَأَنْفُسَكُمْ وَيُزَكِّي بِهِ أَعْمَالَكُمْ ثُمَّ تَكُونُ الْأَمْوَالُ فِيكُمْ حَتَّى يُعْطَى الرَّجُلُ مِائَةَ دِينَارٍ فَيَظَلَّ سَاخِطًا وَفِتْنَةٌ تَكُونُ بَيْنَكُمْ لَا يَبْقَى بَيْتُ مُسْلِمٍ إِلَّا دَخَلَتْهُ ثُمَّ تَكُونُ بَيْنَكُمْ وَبَيْنَ بَنِي الْأَصْفَرِ هُدْنَةٌ فَيَغْدِرُونَ بِكُمْ فَيَسِيرُونَ إِلَيْكُمْ فِي ثَمَانِينَ غَايَةٍ تَحْتَ كُلِّ غَايَةٍ اثْنَا عَشَرَ أَلْفًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Abdullah bin Al 'Ala] telah menceritakan kepadaku [Busr bin 'Ubaidullah] telah menceritakan kepadaku [Abu Idris Al Khaulani] telah menceritakan kepadaku ['Auf bin Malik Al Asyja'i] dia berkata, \"Saya pernah datang kepada Rasulullah shallallahu 'alaihi wasallam saat beliau ikut dalam perang Tabuk. Saat itu beliau tengah berada di dalam tenda yang terbuat dari kulit, lalu aku duduk di depan tenda. Lantas beliau bersabda: \"Masuklah wahai 'Auf! \" Aku bertanya, \"Dengan seluruh tubuhku wahai Rasulullah?\" Beliau menjawab: \"Ya, dengan seluruh tubuhmu.\" Kemudian beliau bersabda: \"Wahai 'Auf, ingatlah diantara enam tanda-tanda hari Kiamat, salah satunya adalah kematianku.\" Lalu beliau melanjutkan: \"Kemudian dikuasainya Baitul Maqdis (oleh orang-orang non Muslim), munculnya penyakit yang mematikan di tengah-tengah kalian, yang dengannya Allah mematikan anak-anak dan diri-diri kalian serta membersihkan amal perbuatan kalian. Kemudian melimpahnya harta benda yang kalian miliki, sehingga walaupun ia telah diberi seratus dinar namun dirinya tetap marah (karena kurang), dan suatu fitnah yang akan terjadi di antara kalian sehingga tidak akan tersisa lagi satu rumahpun dari rumah-rumah kaum Muslimin kecuali akan dimasuki (fitnah tersebut). Kemudian antara kalain dengan Bani Ashfar akan terjadi gencatan senjata, lalu mereka mengkhianati kalian. Mereka akan datang untuk menyerang kalian dengan membawa delapan puluh bendera perang, dan setiap bendera membawahi dua belas ribu pasukan.\""},"3995":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ الدَّرَاوَرْدِيُّ حَدَّثَنَا عَمْرٌو مَوْلَى الْمُطَّلِبِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيِّ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَقْتُلُوا إِمَامَكُمْ وَتَجْتَلِدُوا بِأَسْيَافِكُمْ وَيَرِثُ دُنْيَاكُمْ شِرَارُكُمْ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Abdul 'Aziz Ad Darawardi] telah menceritakan kepada kami ['Amru bekas budak Al Mutthalib] dari [Abdullah bin Abdurrahman Al Anshari] dari [Hudzaifah bin Yaman] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari Kiamat sehingga kalian membunuh pemimpin kalian, kalian saling berperang dan dunia kalian diwarisi oleh orang-orang yang jahat.\""},"3996":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَارِزًا لِلنَّاسِ فَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ فَقَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَلَكِنْ سَأُخْبِرُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْأَمَةُ رَبَّتَهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا كَانَتْ الْحُفَاةُ الْعُرَاةُ رُءُوسَ النَّاسِ فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا تَطَاوَلَ رِعَاءُ الْغَنَمِ فِي الْبُنْيَانِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ فَتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنَزِّلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ }الْآيَةَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Abu Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam pernah muncul di hadapan orang-orang, lalu datanglah seorang laki-laki kepada beliau seraya bertanya, \"Wahai Rasulullah, kapankah akan terjadi hari Kiamat?\" beliau menjawab: \"Tidaklah yang ditanya itu lebih mengetahui daripada yang bertanya, namun akan aku beritahukan kepadamu tanda-tandanya, yaitu; jika seorang budak melahirkan tuannya maka itulah tandanya. Dan apabila orang-orang yang tak beralas kaki menjadi pemimpin manusia maka itulah tandanya. Jika para penggembala kambing berlomba-lomba meninggikan bangunan rumah maka itulah tandanya. Dari lima hal ghaib yang tidak ada seorangpun yang mengetahuinya kecuali Allah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat: \"Sesungguhnya Allah, Hanya pada sisi-Nya sajalah pengetahuan tentang hari Kiamat; dan Dia-lah yang menurunkan hujan, dan mengetahui apa yang ada dalam rahim…\", (Qs. Luqman: 34)."},"3997":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَلَا أُحَدِّثُكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُحَدِّثُكُمْ بِهِ أَحَدٌ بَعْدِي سَمِعْتُهُ مِنْهُ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يُرْفَعَ الْعِلْمُ وَيَظْهَرَ الْجَهْلُ وَيَفْشُوَ الزِّنَا وَيُشْرَبَ الْخَمْرُ وَيَذْهَبَ الرِّجَالُ وَيَبْقَى النِّسَاءُ حَتَّى يَكُونَ لِخَمْسِينَ امْرَأَةً قَيِّمٌ وَاحِدٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] saya mendengar [Qatadah] menceritakan dari [Anas bin Malik] dia berkata, \"Maukah aku ceritakan kepada kalian satu hadits yang pernah aku dengar dari Rasulullah shallallahu 'alaihi wasallam, dan tidak akan ada yang memberitahukannya lagi setelahku? Aku pernah mendengar beliau shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dari tanda-tanda (datangnya) hari Kiamat adalah diangkatnya ilmu, munculnya kebodohan, maraknya perzinahan, diminumnya khamer, meninggalnya laki-laki dan yang tersisa hanya para wanita (banyak wanita dibanding laki-laki) hingga lima puluh orang wanita ditanggung satu orang laki-laki.\""},"3998":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يَحْسُرَ الْفُرَاتُ عَنْ جَبَلٍ مِنْ ذَهَبٍ فَيَقْتَتِلُ النَّاسُ عَلَيْهِ فَيُقْتَلُ مِنْ كُلِّ عَشَرَةٍ تِسْعَةٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari Kiamat sehingga sungai Furat menyibakkan gunung emas, dan menyebabkan manusia saling berperang. Maka dari setiap sepuluh orang akan terbunuh sembilan orang.\""},"3999":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَفِيضَ الْمَالُ وَتَظْهَرَ الْفِتَنُ وَيَكْثُرَ الْهَرْجُ قَالُوا وَمَا الْهَرْجُ يَا رَسُولَ اللَّهِ قَالَ الْقَتْلُ الْقَتْلُ الْقَتْلُ ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi hari Kiamat sampai harta benda melimpah, munculnya berbagai fitnah, serta maraknya kekacauan.\" Para sahabat bertanya, \"Apakah yang dimaksud dengan kekacauan wahai Rasulullah?\" Beliau menjawab: \"Peperangan, peperangan, peperangan.\" Beliau mengucapkan sebanyak tiga kali."},"4000":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ زِيَادِ بْنِ لَبِيدٍ قَالَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَقَالَ ذَاكَ عِنْدَ أَوَانِ ذَهَابِ الْعِلْمِ قُلْتُ يَا رَسُولَ اللَّهِ وَكَيْفَ يَذْهَبُ الْعِلْمُ وَنَحْنُ نَقْرَأُ الْقُرْآنَ وَنُقْرِئُهُ أَبْنَاءَنَا وَيُقْرِئُهُ أَبْنَاؤُنَا أَبْنَاءَهُمْ إِلَى يَوْمِ الْقِيَامَةِ قَالَ ثَكِلَتْكَ أُمُّكَ زِيَادُ إِنْ كُنْتُ لَأَرَاكَ مِنْ أَفْقَهِ رَجُلٍ بِالْمَدِينَةِ أَوَلَيْسَ هَذِهِ الْيَهُودُ وَالنَّصَارَى يَقْرَءُونَ التَّوْرَاةَ وَالْإِنْجِيلَ لَا يَعْمَلُونَ بِشَيْءٍ مِمَّا فِيهِمَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al A'masy] dari [Salim bin Abu Al Ja'd] dari [Ziyad bin Labid] dia berkata, \"Nabi shallallahu 'alaihi wasallam pernah menyebutkan sesuatu, lalu beliau bersabda: \"Dan itulah saat hilangnya ilmu.\" Aku bertanya, \"Wahai Rasulullah, bagaimana ilmu bisa hilang? Sedangkan kami masih membaca Al Qur'an dan kami juga membacakannya (mengajarkannya) kepada anak-anak kami, dan anak-anak kami juga akan membacakannya kepada keturunannya sampai hari kiamat datang.\" Beliau bersabda: \"Kebangetan kamu ini wahai Ziyad, padahal aku melihatmu adalah orang yang paling memahami agama di Madinah ini! Bukankah orang-orang Yahudi dan Nashrani juga membaca Taurat dan Injil, namun mereka tidak mengamalkan sedikitpun apa yang terkandung di dalamnya.\""}};
